/// `Alt+f` (and the active-filter badge click): step the main-view Semantic
/// Filter (§12.5.2) forward (`backward == false`) or backward through its
/// category cycle, wrapping around. The cycle's `Tool(i)` entries are derived
/// from the live transcript, so a transcript with multiple tools offers one step
/// per tool; a single-tool (or no-tool) transcript cycles only the always-present
/// categories. Sets a status line naming the new category and requests a redraw
/// so the filtered view paints immediately.
fn cycle_main_semantic_filter(app: &mut TuiApp, backward: bool) {
    let tool_names = distinct_overlay_tool_names(active_transcript_entries(app));
    let next = semantic_filter::step(app.main_semantic_filter, &tool_names, backward);
    app.main_semantic_filter = next;
    // The filter swaps the entire visible row list, so every row-indexed anchor
    // now points at shifted content. Invalidate selections and re-anchor search
    // to the new row model — mirroring the resize arm — so a stale highlight band
    // or k-of-N count can't survive the filter change (deep-review #72).
    app.selection = None;
    app.selection_set.clear();
    if app.search.is_some() {
        refresh_search(app);
    }
    let key = key_hint(app, keymap::Action::CycleSemanticFilter);
    app.status = if next.is_active() {
        format!(
            "filter: {} — {key} to cycle (all to clear)",
            next.label(&tool_names)
        )
    } else {
        "filter cleared — showing all entries".to_string()
    };
    app.needs_redraw = true;
}

/// `Alt+8`: cycle the OSC 8 hyperlink mode (§11G.5) auto → on → off and surface
/// the new state. `auto` defers to the startup terminal probe; `on`/`off` force
/// the capability regardless of the probe, so a mis-detected terminal can be
/// corrected without restarting. Only the persisted exit-mirror rows carry the
/// escapes today, so this sets no `needs_redraw` — there is no live frame to
/// repaint, keeping idle redraw at zero.
fn toggle_hyperlinks(app: &mut TuiApp) {
    let (next, label) = match app.hyperlink_override {
        // auto -> on
        None => (Some(true), "on (exit-mirror links)"),
        // on -> off
        Some(true) => (Some(false), "off (plain text)"),
        // off -> auto
        Some(false) => (None, {
            if app.hyperlink_caps.osc8 {
                "auto (detected: on)"
            } else {
                "auto (detected: off)"
            }
        }),
    };
    app.hyperlink_override = next;
    app.status = format!("hyperlinks: {label}");
}

/// `Alt+r`: toggle the minimap turn rail on the main view. The rail is a render
/// element, so flipping the flag is all that is needed; the next frame paints
/// (or stops painting) it. Sets a status confirming the new state.
fn toggle_minimap(app: &mut TuiApp) {
    app.show_minimap = !app.show_minimap;
    app.status = if app.show_minimap {
        "minimap rail on — click a tick to jump (Alt+r to hide)".to_string()
    } else {
        "minimap rail off".to_string()
    };
    app.needs_redraw = true;
}

/// `Alt+p`: toggle the in-app clipboard-history picker (§12.6.1). The picker is a
/// fullscreen overlay listing Squeezy's own recent copies; opening it lets the
/// user re-copy, pin, delete, or clear an entry, and it never reads the OS
/// clipboard. Flipping the open flag is all the state change needed — the next
/// frame paints (or stops painting) the overlay — plus a status line confirming
/// the new state. Sets `needs_redraw` so the toggle paints immediately.
fn toggle_clipboard_history(app: &mut TuiApp) {
    app.clipboard_history_open = !app.clipboard_history_open;
    app.status = if app.clipboard_history_open {
        if app.clipboard_history.is_empty() {
            "clipboard history (empty) — Esc to close".to_string()
        } else {
            format!(
                "clipboard history: {} — ↑↓ select · Enter re-copy · d delete · c clear · Esc close",
                count_label_entries(app.clipboard_history.len()),
            )
        }
    } else {
        "clipboard history closed".to_string()
    };
    app.needs_redraw = true;
}

/// `"N entries"` / `"1 entry"` for the clipboard-history status line.
fn count_label_entries(count: usize) -> String {
    if count == 1 {
        "1 entry".to_string()
    } else {
        format!("{count} entries")
    }
}

/// Handle a key while the clipboard-history picker (§12.6.1) is open. Returns
/// `true` when the key was consumed by the picker (so it never leaks to the
/// composer or the global keymap). Mirrors the paste-preview question's
/// before-the-global-keymap consumption: Esc/Alt+p close, Up/Down move the
/// selection, Enter re-copies the selected entry, `d` deletes it, `p` toggles its
/// pin, and `c` clears the whole history.
fn handle_clipboard_history_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.clipboard_history_open {
        return false;
    }
    // The picker's own toggle chord (`Alt+p` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleClipboardHistory) {
        app.clipboard_history_open = false;
        app.status = "clipboard history closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    match key.code {
        KeyCode::Esc => {
            app.clipboard_history_open = false;
            app.status = "clipboard history closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up => {
            app.clipboard_history.select_up();
            app.needs_redraw = true;
        }
        KeyCode::Down => {
            app.clipboard_history.select_down();
            app.needs_redraw = true;
        }
        KeyCode::Enter => {
            recopy_selected_clipboard_entry(app);
        }
        KeyCode::Char('d') | KeyCode::Delete => {
            delete_selected_clipboard_entry(app);
        }
        KeyCode::Char('p') => {
            toggle_pin_selected_clipboard_entry(app);
        }
        KeyCode::Char('c') => {
            app.clipboard_history.clear();
            app.status = "clipboard history cleared".to_string();
            app.needs_redraw = true;
        }
        // Swallow every other key so the picker is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Build the Keybinding Editor UI (§12.7.1) row list straight from the `Action`
/// registry and the live resolver, so the editor lists *exactly* the actions the
/// TUI dispatches and a new variant appears for free. One row per
/// `keymap::Action::ALL` entry, carrying the action's currently-resolved binding
/// and whether it differs from the compiled-in default.
fn keybinding_editor_rows(app: &TuiApp) -> Vec<keybinding_editor::EditorRow> {
    keymap::Action::ALL
        .iter()
        .copied()
        .map(|action| {
            let binding = app.keymap.binding(action);
            keybinding_editor::EditorRow {
                action,
                binding,
                is_override: binding != action.default_binding(),
            }
        })
        .collect()
}

/// `Ctrl+Alt+B` (and the dispatch arm): open / close the Keybinding Editor UI
/// (§12.7.1). Opening snapshots the current map into a fresh editor state;
/// closing drops it (the resting `None`). Sets a status confirming the new state
/// and `needs_redraw` so the toggle paints immediately.
fn toggle_keybinding_editor(app: &mut TuiApp) {
    if app.keybinding_editor.is_some() {
        app.keybinding_editor = None;
        app.status = "keybinding editor closed".to_string();
        app.needs_redraw = true;
        return;
    }
    let rows = keybinding_editor_rows(app);
    app.keybinding_editor = Some(keybinding_editor::KeybindingEditorState::new(rows));
    app.status = keybinding_editor_browse_status(app);
    app.needs_redraw = true;
}

/// The status-line hint for the Keybinding Editor UI in browse mode: the selected
/// action's slug + current binding plus the verb hints.
fn keybinding_editor_browse_status(app: &TuiApp) -> String {
    let Some(editor) = app.keybinding_editor.as_ref() else {
        return String::new();
    };
    match editor.selected_row() {
        Some(row) => format!(
            "{} = {} — ↑↓ select · Enter rebind · r reset · Esc close",
            row.action.slug(),
            row.binding.display(),
        ),
        None => "no rebindable actions".to_string(),
    }
}

/// The status-line hint for the Keybinding Editor UI while capturing a chord for
/// the selected row, including any pending-chord verdict (free / conflict /
/// reserved).
fn keybinding_editor_capture_status(app: &TuiApp) -> String {
    let Some(editor) = app.keybinding_editor.as_ref() else {
        return String::new();
    };
    let slug = editor
        .selected_row()
        .map(|row| row.action.slug())
        .unwrap_or("");
    match editor.pending() {
        None => format!("press the new chord for {slug} — Esc cancels"),
        Some(pending) => match &pending.outcome {
            keybinding_editor::CaptureOutcome::Free => format!(
                "{} → {} — Enter to confirm · Esc cancels",
                slug,
                pending.binding.display(),
            ),
            keybinding_editor::CaptureOutcome::Conflict { with } => format!(
                "{} → {} CONFLICTS with {} — Enter to override anyway · Esc cancels",
                slug,
                pending.binding.display(),
                with,
            ),
            keybinding_editor::CaptureOutcome::Reserved { label } => format!(
                "{} is reserved (recovery key) — press a different chord · Esc cancels",
                label,
            ),
            keybinding_editor::CaptureOutcome::Unsafe { label } => format!(
                "{} is needed for typing — press a different chord · Esc cancels",
                label,
            ),
        },
    }
}

/// Begin capturing a new chord for the editor's selected row (the keyboard Enter
/// verb, the "Rebind" button, and a double-click all route here). A no-op when the
/// editor is closed or already capturing.
fn keybinding_editor_begin_capture(app: &mut TuiApp) {
    let began = app
        .keybinding_editor
        .as_mut()
        .is_some_and(|editor| editor.begin_capture());
    if began {
        app.status = keybinding_editor_capture_status(app);
        app.needs_redraw = true;
    }
}

/// Reset the editor's selected row to its compiled-in default (the keyboard
/// `r`/Delete verb and the "Reset" button route here). Drops the override from the
/// persisted file and rebuilds the resolver; a no-op when the row already holds
/// its default.
fn keybinding_editor_reset_selected(app: &mut TuiApp) {
    let reset = app
        .keybinding_editor
        .as_mut()
        .and_then(|editor| editor.reset_selected());
    let Some((action, binding)) = reset else {
        return;
    };
    persist_keybinding_change(app);
    app.status = format!("reset {} to default {}", action.slug(), binding.display());
    app.needs_redraw = true;
}

/// Handle a key while the Keybinding Editor UI (§12.7.1) is open. Returns `true`
/// when the key was consumed (so it never leaks to the composer or the global
/// keymap). In CAPTURE mode the next key is the captured chord (handled first so a
/// chord like Enter or an arrow is captured rather than treated as navigation); in
/// BROWSE mode the editor consumes its navigation/verb keys.
fn handle_keybinding_editor_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.keybinding_editor.is_none() {
        return false;
    }
    let capturing = app
        .keybinding_editor
        .as_ref()
        .is_some_and(|editor| editor.is_capturing());
    if capturing {
        return handle_keybinding_editor_capture_key(app, key);
    }
    handle_keybinding_editor_browse_key(app, key)
}

/// Browse-mode key handling for the Keybinding Editor UI: cursor movement, the
/// rebind / reset verbs, and close (Esc or the editor's own toggle chord). Every
/// unrecognised key is swallowed so the overlay stays modal.
fn handle_keybinding_editor_browse_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    // The editor's own toggle chord (`Ctrl+Alt+B` by default) closes it, so the
    // same key both opens and closes — without leaking to the global keymap, which
    // the modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleKeybindingEditor) {
        toggle_keybinding_editor(app);
        return true;
    }
    let Some(editor) = app.keybinding_editor.as_mut() else {
        return true;
    };
    let page = 10usize;
    match key.code {
        KeyCode::Esc => {
            app.keybinding_editor = None;
            app.status = "keybinding editor closed".to_string();
            app.needs_redraw = true;
            return true;
        }
        KeyCode::Up | KeyCode::Char('k') => editor.select_up(),
        KeyCode::Down | KeyCode::Char('j') => editor.select_down(),
        KeyCode::PageUp => editor.page_up(page),
        KeyCode::PageDown => editor.page_down(page),
        KeyCode::Home => editor.select_first(),
        KeyCode::End => editor.select_last(),
        KeyCode::Enter => {
            keybinding_editor_begin_capture(app);
            return true;
        }
        KeyCode::Char('r') | KeyCode::Delete => {
            keybinding_editor_reset_selected(app);
            return true;
        }
        // Swallow every other key so the editor is modal: a stray keystroke cannot
        // leak into the composer underneath while the overlay owns focus.
        _ => return true,
    }
    app.status = keybinding_editor_browse_status(app);
    app.needs_redraw = true;
    true
}

/// Capture-mode key handling for the Keybinding Editor UI: Esc cancels the
/// capture (back to browse); a second commit press on a pending free/conflicting
/// chord confirms it; otherwise the key is normalised and captured as the new
/// pending chord (with its conflict/reserved verdict shown). The captured chord is
/// normalised through the SAME `normalise_control_byte` the live keymap lookup
/// uses, so a captured binding matches exactly what the dispatcher will later see.
fn handle_keybinding_editor_capture_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    // Esc always cancels the in-flight capture (never the captured chord), so the
    // user is never trapped mid-rebind — Esc cannot itself be bound (it is a
    // reserved recovery key), so this is unambiguous.
    if key.code == KeyCode::Esc {
        if let Some(editor) = app.keybinding_editor.as_mut() {
            editor.cancel_capture();
        }
        app.status = keybinding_editor_browse_status(app);
        app.needs_redraw = true;
        return true;
    }
    // Enter confirms a pending, committable chord (free or a warnable conflict).
    // With no pending chord yet, Enter is itself a capturable chord and falls
    // through to the capture path below.
    let has_committable_pending = app.keybinding_editor.as_ref().is_some_and(|editor| {
        editor
            .pending()
            .is_some_and(|pending| pending.outcome.is_committable())
    });
    if key.code == KeyCode::Enter && has_committable_pending {
        let committed = app
            .keybinding_editor
            .as_mut()
            .and_then(|editor| editor.commit());
        if let Some((action, binding)) = committed {
            persist_keybinding_change(app);
            app.status = format!("bound {} to {}", action.slug(), binding.display());
            app.needs_redraw = true;
        }
        return true;
    }
    // Capture this key as the new pending chord. Normalise it exactly as the live
    // lookup path does (META→ALT, control-byte → Ctrl+letter, case-fold) so the
    // captured binding is the one the dispatcher will resolve.
    let normalised = normalise_control_byte(key);
    let binding = keymap::KeyBinding::new(normalised.code, normalised.modifiers);
    if let Some(editor) = app.keybinding_editor.as_mut() {
        editor.capture(binding);
    }
    app.status = keybinding_editor_capture_status(app);
    app.needs_redraw = true;
    true
}

/// Persist the editor's current map to `~/.squeezy/keybindings.toml` and rebuild
/// the live resolver so the new binding takes effect immediately. Called after a
/// commit or a reset. The editor's in-overlay rows already reflect the change; this
/// writes the delta-only override set the editor accumulated and re-resolves.
///
/// Best-effort: a write failure leaves the in-memory editor + resolver updated and
/// surfaces the error in the status line rather than blocking the rebind — a
/// rebind that does not survive a restart is still better than a trapped user.
fn persist_keybinding_change(app: &mut TuiApp) {
    let Some(editor) = app.keybinding_editor.as_ref() else {
        return;
    };
    // Build the delta-only override map from the editor's rows (the single source
    // the overlay edited), so the rebuilt resolver and the on-disk file agree.
    let mut overrides: BTreeMap<String, String> = BTreeMap::new();
    // Tombstone slugs: rows the user reset to default whose binding the
    // settings.toml base map specifies. Without a durable tombstone the reset is
    // simply absent from `keybindings.toml`, and `merge_user_overrides` re-merges
    // the base override on the next start, silently resurrecting the binding the
    // user reset (deep-review #96). A reset of an action the base does NOT specify
    // needs no marker — dropping the row already restores the default.
    let mut tombstones: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
    for row in editor.rows() {
        let slug = row.action.slug().to_string();
        if row.is_override {
            overrides.insert(slug, row.binding.display());
        } else if app.keymap_base.contains_key(&slug) {
            tombstones.insert(slug);
        }
    }
    // Rebuild the live resolver from the editor's overrides so the new binding is
    // active for the very next keypress (and `/keymap` reads it back). The editor
    // rows already capture every active non-default binding as an override
    // (including base-sourced ones), so a reset base binding is simply absent here
    // and falls back to its default in the live session — the tombstone only has
    // to make that survive a restart.
    app.keymap = keymap::KeymapResolver::from_overrides(&overrides);
    // Resolve the destination through the app so a pinned override (eval/test
    // harness) is honoured instead of always targeting the operator's real
    // `~/.squeezy/keybindings.toml`.
    let target = app.keybindings_save_path();
    // Write the file (best-effort). A missing home dir degrades to "in-memory
    // only" with a status note.
    if let Err(err) = write_keybindings_file(target, &overrides, &tombstones) {
        app.status = format!("rebind applied (not saved: {err})");
    }
}

/// Write the delta-only override map (plus any tombstones) to `target` (the
/// resolved `~/.squeezy/keybindings.toml`, or a harness override) atomically
/// (write to a sibling temp file, then rename). Serialises each entry as a
/// `[[bindings]]` row in the same schema `keymap_config::KeybindingsFile` reads,
/// so the editor's output round-trips through the loader on the next start. A
/// tombstone is written as `action = "<slug>"` + `reset = true`, which the loader
/// turns into a `merged.remove(slug)` so a reset base-sourced binding does not
/// resurrect (deep-review #96). The parent directory is created if missing.
/// `target == None` means no destination is resolvable (no home dir), surfaced as
/// a `NotFound` error.
fn write_keybindings_file(
    target: Option<PathBuf>,
    overrides: &BTreeMap<String, String>,
    tombstones: &std::collections::BTreeSet<String>,
) -> std::io::Result<()> {
    let path = target.ok_or_else(|| {
        std::io::Error::new(
            std::io::ErrorKind::NotFound,
            "no home directory for ~/.squeezy/keybindings.toml",
        )
    })?;
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let mut body = String::new();
    body.push_str("# Managed by the Squeezy Keybinding Editor (Ctrl+Alt+B).\n");
    body.push_str("# Only bindings that differ from the defaults are listed.\n");
    for (slug, spec) in overrides {
        body.push_str("\n[[bindings]]\n");
        body.push_str(&format!("action = {slug:?}\n"));
        body.push_str(&format!("key = {spec:?}\n"));
    }
    for slug in tombstones {
        body.push_str("\n[[bindings]]\n");
        body.push_str(&format!("action = {slug:?}\n"));
        body.push_str("reset = true\n");
    }
    let tmp = path.with_extension("toml.tmp");
    std::fs::write(&tmp, body)?;
    std::fs::rename(&tmp, &path)
}

/// `Alt+i`: toggle the Local Transcript Index overlay (§12.5.1). The overlay is a
/// fullscreen summary of the in-memory index — entry counts by category with
/// keyboard/mouse navigation. Opening it refreshes the index (a no-op rebuild
/// when the transcript has not changed since the last refresh, so the cost is
/// only paid on a real change), resets the selection cursor, and confirms via the
/// status line. Sets `needs_redraw` so the toggle paints immediately.
fn toggle_transcript_index(app: &mut TuiApp) {
    app.transcript_index_open = !app.transcript_index_open;
    if app.transcript_index_open {
        refresh_transcript_index(app);
        app.transcript_index_selected = 0;
        app.transcript_index_anchor = None;
        let total = app.transcript_index.total();
        app.status = if total == 0 {
            "transcript index (empty) — Esc to close".to_string()
        } else {
            format!(
                "transcript index: {} — \u{2191}\u{2193} category \u{00b7} Enter jump \u{00b7} Esc close",
                app.transcript_index.summary(),
            )
        };
    } else {
        app.status = "transcript index closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Local Transcript Index overlay (§12.5.1) is open.
/// Returns `true` when the key was consumed (so it never leaks to the composer or
/// global keymap). Mirrors the clipboard-history picker's before-the-global-keymap
/// modal consumption: the toggle chord (`Alt+i`) and Esc close; Up/Down (and k/j)
/// move the category cursor; Enter (and l/→) jumps the main view to the next
/// entry in the selected category, walking forward on repeat.
fn handle_transcript_index_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.transcript_index_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+i` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleTranscriptIndex) {
        app.transcript_index_open = false;
        app.status = "transcript index closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let categories = app.transcript_index.non_empty_categories();
    match key.code {
        KeyCode::Esc => {
            app.transcript_index_open = false;
            app.status = "transcript index closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            if !categories.is_empty() {
                app.transcript_index_selected = app
                    .transcript_index_selected
                    .min(categories.len() - 1)
                    .saturating_sub(1);
                // Moving categories restarts the forward walk.
                app.transcript_index_anchor = None;
            }
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if !categories.is_empty() {
                let last = categories.len() - 1;
                app.transcript_index_selected = (app.transcript_index_selected + 1).min(last);
                app.transcript_index_anchor = None;
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            transcript_index_jump_to_selected(app);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the next entry in the index overlay's selected category
/// (§12.5.1), walking forward through that category on repeat. Resolves the
/// category from the cursor, asks the index for the next id after the last jumped
/// anchor (wrapping at the end), scrolls there via the same `jump_to_entry_id`
/// path the minimap/jump-nav use, and records the new anchor. A no-op (status
/// hint) when the selected category is empty.
fn transcript_index_jump_to_selected(app: &mut TuiApp) {
    let categories = app.transcript_index.non_empty_categories();
    let Some(&category) = categories.get(app.transcript_index_selected) else {
        app.status = "transcript index: nothing to jump to".to_string();
        return;
    };
    let anchor = app.transcript_index_anchor;
    let Some(target) = app.transcript_index.next_in(category, anchor) else {
        app.status = format!("no {} to jump to", category.label());
        return;
    };
    if jump_to_entry_id(app, target) {
        app.transcript_index_anchor = Some(target);
        let position = app
            .transcript_index
            .ids(category)
            .iter()
            .position(|&id| id == target)
            .map(|p| p + 1)
            .unwrap_or(0);
        let count = app.transcript_index.count(category);
        app.status = format!(
            "transcript index: {} {position}/{count} — Enter for next \u{00b7} Esc close",
            category.label(),
        );
        app.needs_redraw = true;
    } else {
        app.status = format!("could not jump to {}", category.label());
    }
}

/// `Alt+g`: toggle the Related-Entry Links overlay (§12.5.3). The overlay lists
/// the entries related to the focused (or latest) transcript entry — its
/// prompt/reply, the tool calls it triggered, the error it caused, the follow-up
/// that fixed it, same-tool calls, and subagent breadcrumbs — and lets the user
/// jump to any of them. Opening it refreshes the relation graph (a no-op rebuild
/// when the transcript has not changed, so the cost is only paid on a real
/// change), anchors on the focused/latest entry, resets the selection cursor, and
/// confirms via the status line. Sets `needs_redraw` so the toggle paints
/// immediately.
fn toggle_related_links(app: &mut TuiApp) {
    app.related_links_open = !app.related_links_open;
    if app.related_links_open {
        refresh_related_links(app);
        app.related_links_selected = 0;
        app.related_links_anchor = related_links_anchor_id(app);
        let count = app
            .related_links_anchor
            .map_or(0, |id| app.related_links.count(id));
        app.status = if app.related_links_anchor.is_none() {
            "related links (no entry) — Esc to close".to_string()
        } else if count == 0 {
            "related links: no related entries — Esc to close".to_string()
        } else {
            format!(
                "related links: {} — \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} Esc close",
                count_label_related(count),
            )
        };
    } else {
        app.status = "related links closed".to_string();
    }
    app.needs_redraw = true;
}

/// `Alt+u`: toggle the Duplicate-Output Folds overlay (§12.5.4). The overlay is a
/// fullscreen list of detected runs of repeated / near-duplicate tool outputs,
/// each collapsed to its lead with a count. Opening it refreshes the fold model
/// (a no-op rebuild when the transcript has not changed since the last refresh,
/// so the cost is only paid on a real change), resets the selection cursor, and
/// confirms via the status line. Sets `needs_redraw` so the toggle paints
/// immediately.
fn toggle_duplicate_folds(app: &mut TuiApp) {
    app.duplicate_folds_open = !app.duplicate_folds_open;
    if app.duplicate_folds_open {
        refresh_duplicate_folds(app);
        app.duplicate_folds_selected = 0;
        let spans = app.duplicate_folds.span_count();
        app.status = if spans == 0 {
            "duplicate folds (none) — Esc to close".to_string()
        } else {
            format!(
                "duplicate folds: {} — \u{2191}\u{2193} fold \u{00b7} Enter jump/expand \u{00b7} Esc close",
                app.duplicate_folds.summary(),
            )
        };
    } else {
        app.status = "duplicate folds closed".to_string();
    }
    app.needs_redraw = true;
}

/// Pluralized "N related" / "1 related" label for the related-links readout.
fn count_label_related(count: usize) -> String {
    if count == 1 {
        "1 related entry".to_string()
    } else {
        format!("{count} related entries")
    }
}

/// Handle a key while the Related-Entry Links overlay (§12.5.3) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). Mirrors the transcript-index overlay's modal consumption: the toggle
/// chord (`Alt+g`) and Esc close; Up/Down (and k/j) move the relation cursor;
/// Enter (and l/→) jumps the main view to the selected related entry.
fn handle_related_links_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.related_links_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+g` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleRelatedLinks) {
        app.related_links_open = false;
        app.status = "related links closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app
        .related_links_anchor
        .map_or(0, |id| app.related_links.count(id));
    match key.code {
        KeyCode::Esc => {
            app.related_links_open = false;
            app.status = "related links closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.related_links_selected = app.related_links_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.related_links_selected = (app.related_links_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            related_links_jump_to_selected(app);
        }
        // Swallow every other key so the overlay is modal.
        _ => {}
    }
    true
}

/// Jump the main view to the related-links overlay's selected related entry
/// (§12.5.3). Resolves the anchor entry and the target at the cursor from the
/// relation graph, scrolls there via the same `jump_to_entry_id` path the
/// index/minimap/jump-nav use, and re-anchors the overlay on the entry it jumped
/// to so the overlay now shows *its* relations (a natural "walk the graph" flow).
/// A no-op (status hint) when there is nothing to jump to.
fn related_links_jump_to_selected(app: &mut TuiApp) {
    let Some(anchor) = app.related_links_anchor else {
        app.status = "related links: nothing to jump to".to_string();
        return;
    };
    let Some(target) = app
        .related_links
        .target_at(anchor, app.related_links_selected)
    else {
        app.status = "related links: nothing to jump to".to_string();
        return;
    };
    if jump_to_entry_id(app, target) {
        // Re-anchor on the entry we landed on so the overlay now lists its
        // relations — the user can keep walking the graph entry by entry.
        app.related_links_anchor = Some(target);
        app.related_links_selected = 0;
        let count = app.related_links.count(target);
        app.status = format!(
            "related links: jumped \u{00b7} {} here — Enter to keep walking \u{00b7} Esc close",
            count_label_related(count),
        );
        app.needs_redraw = true;
    } else {
        app.status = "related links: could not jump".to_string();
    }
}

/// Handle a key while the Duplicate-Output Folds overlay (§12.5.4) is open.
/// Returns `true` when the key was consumed (so it never leaks to the composer or
/// global keymap). Mirrors the transcript-index picker's before-the-global-keymap
/// modal consumption: the toggle chord (`Alt+u`) and Esc close; Up/Down (and k/j)
/// move the fold cursor; Enter (and l/→) jumps the main view to the selected
/// fold's lead and toggles the span expanded/collapsed.
fn handle_duplicate_folds_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.duplicate_folds_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+u` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleDuplicateFolds) {
        app.duplicate_folds_open = false;
        app.status = "duplicate folds closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let span_count = app.duplicate_folds.span_count();
    match key.code {
        KeyCode::Esc => {
            app.duplicate_folds_open = false;
            app.status = "duplicate folds closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.duplicate_folds_selected = app.duplicate_folds_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if span_count > 0 {
                let last = span_count - 1;
                app.duplicate_folds_selected = (app.duplicate_folds_selected + 1).min(last);
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            duplicate_fold_activate_selected(app);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Activate the duplicate-fold overlay's selected span (§12.5.4): jump the main
/// view to its lead entry (so the user lands on the fold), then toggle the span
/// expanded/collapsed so its retained raw members reveal/hide in place. Resolves
/// the span from the cursor; a no-op (status hint) when there are no folds.
/// Reuses the same `jump_to_entry_id` path the minimap/jump-nav use.
fn duplicate_fold_activate_selected(app: &mut TuiApp) {
    let lead = {
        let spans = app.duplicate_folds.spans();
        let Some(span) = spans.get(app.duplicate_folds_selected) else {
            app.status = "duplicate folds: nothing to expand".to_string();
            return;
        };
        span.lead_id
    };
    let count = app
        .duplicate_folds
        .span_for_lead(lead)
        .map_or(0, duplicate_fold::FoldSpan::count);
    // Land on the fold's lead in the main view (best-effort: an off-screen lead
    // still toggles, so the count is reflected even when the jump cannot scroll).
    let _ = jump_to_entry_id(app, lead);
    let expanded = app.duplicate_folds.toggle_expanded(lead).unwrap_or(false);
    let position = app.duplicate_folds_selected + 1;
    let span_count = app.duplicate_folds.span_count();
    let verb = if expanded { "expanded" } else { "collapsed" };
    app.status = format!(
        "duplicate fold {position}/{span_count} {verb} ({count} outputs) — Enter toggle \u{00b7} Esc close",
    );
    app.needs_redraw = true;
}

/// `Alt+x`: toggle the Error Lenses overlay (§12.5.6). The overlay is a
/// fullscreen list of the actionable error lines detected inside failed tool
/// outputs — each classified (rustc / cargo / test / permission / network /
/// panic / sandbox), carrying its message and any extracted `file:line`
/// location. Opening it refreshes the lens model (a no-op rebuild when the
/// transcript has not changed since the last refresh, so the cost is only paid
/// on a real change), resets the selection cursor, and confirms via the status
/// line. Sets `needs_redraw` so the toggle paints immediately.
fn toggle_error_lens(app: &mut TuiApp) {
    app.error_lens_open = !app.error_lens_open;
    if app.error_lens_open {
        refresh_error_lenses(app);
        app.error_lens_selected = 0;
        app.status = if app.error_lenses.is_empty() {
            "error lenses (none) — Esc to close".to_string()
        } else {
            format!(
                "error lenses: {} — \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} Esc close",
                app.error_lenses.summary(),
            )
        };
    } else {
        app.status = "error lenses closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Error Lenses overlay (§12.5.6) is open. Returns `true`
/// when the key was consumed (so it never leaks to the composer or global
/// keymap). Mirrors the duplicate-fold overlay's before-the-global-keymap modal
/// consumption: the toggle chord (`Alt+x`) and Esc close; Up/Down (and k/j) move
/// the lens cursor; Enter (and l/→) jumps the main view to the failing entry
/// behind the selected lens.
fn handle_error_lens_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.error_lens_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+x` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleErrorLens) {
        app.error_lens_open = false;
        app.status = "error lenses closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.error_lenses.len();
    match key.code {
        KeyCode::Esc => {
            app.error_lens_open = false;
            app.status = "error lenses closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.error_lens_selected = app.error_lens_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.error_lens_selected = (app.error_lens_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            error_lens_jump_to_selected(app, true);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the failing entry behind the error-lens overlay's
/// selected lens (§12.5.6). Resolves the lens at the cursor, scrolls to its
/// source entry via the same `jump_to_entry_id` path the index/minimap/jump-nav
/// use, and reports the class + any extracted location in the status line. A
/// no-op (status hint) when there is nothing to jump to.
///
/// `advance` controls the cursor afterward: the keyboard Enter verb passes
/// `true` so a *repeated* Enter walks forward through the lens list (wrapping at
/// the end) — the "Enter for next" idiom the status line advertises; the mouse
/// click passes `false` because a click is a precise pick that should land and
/// stay on exactly the clicked row.
fn error_lens_jump_to_selected(app: &mut TuiApp, advance: bool) {
    let Some((entry_id, class, location)) =
        app.error_lenses.get(app.error_lens_selected).map(|lens| {
            (
                lens.entry_id,
                lens.class,
                lens.location
                    .as_ref()
                    .map(error_lens::ErrorLocation::display),
            )
        })
    else {
        app.status = "error lenses: nothing to jump to".to_string();
        return;
    };
    if jump_to_entry_id(app, entry_id) {
        let position = app.error_lens_selected + 1;
        let total = app.error_lenses.len();
        let where_ = location.map(|loc| format!(" @ {loc}")).unwrap_or_default();
        app.status = format!(
            "error lens {position}/{total} [{}]{where_} — Enter for next \u{00b7} Esc close",
            class.label(),
        );
        // Walk the cursor forward to the next lens so a repeated Enter steps
        // through the whole error list (wrapping). The mouse path skips this so a
        // click stays put on the row it picked.
        if advance && let Some(next) = app.error_lenses.next_index(Some(app.error_lens_selected)) {
            app.error_lens_selected = next;
        }
        app.needs_redraw = true;
    } else {
        app.status = "error lenses: could not jump".to_string();
    }
}

/// `Alt+n`: open / close the Transcript Health Markers overlay (§12.5.7). On open
/// it refreshes the marker model (cheap when nothing changed), resets the cursor,
/// and sets a status line summarizing what was detected (or an empty-state hint).
/// Mirrors `toggle_error_lens` exactly.
fn toggle_health_markers(app: &mut TuiApp) {
    app.health_markers_open = !app.health_markers_open;
    if app.health_markers_open {
        refresh_health_markers(app);
        app.health_markers_selected = 0;
        app.status = if app.health_markers.is_empty() {
            "health markers (none) — Esc to close".to_string()
        } else {
            format!(
                "health markers: {} — \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} Esc close",
                app.health_markers.summary(),
            )
        };
    } else {
        app.status = "health markers closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Transcript Health Markers overlay (§12.5.7) is open.
/// Returns `true` when the key was consumed (so it never leaks to the composer or
/// global keymap). Mirrors the error-lens overlay's before-the-global-keymap
/// modal consumption: the toggle chord (`Alt+n`) and Esc close; Up/Down (and k/j)
/// move the marker cursor; Enter (and l/→) jumps the main view to the entry
/// behind the selected marker.
fn handle_health_markers_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.health_markers_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+n` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleHealthMarkers) {
        app.health_markers_open = false;
        app.status = "health markers closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.health_markers.len();
    match key.code {
        KeyCode::Esc => {
            app.health_markers_open = false;
            app.status = "health markers closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.health_markers_selected = app.health_markers_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.health_markers_selected = (app.health_markers_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            health_markers_jump_to_selected(app, true);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the entry behind the health-markers overlay's selected
/// marker (§12.5.7). Resolves the marker at the cursor, scrolls to its source
/// entry via the same `jump_to_entry_id` path the index/minimap/jump-nav use, and
/// reports the kind in the status line. A no-op (status hint) when there is
