// ---- Clickable Breadcrumbs (§12.1.5) ----

/// Gather the live facts the Clickable Breadcrumbs trail (§12.1.5) is built from
/// into a [`breadcrumbs::BreadcrumbContext`]. Pure read over `app` — no mutation,
/// no caching — so the renderer and the navigation path both derive the trail
/// from the same current state each frame (the spec's "derive from model each
/// frame", which is what keeps the trail from going stale after a resize/scroll/
/// fold). Cheap enough to call only while the strip is shown.
fn build_breadcrumb_context(app: &TuiApp) -> breadcrumbs::BreadcrumbContext {
    // Short session label: the trailing slice of the session id (the full id is
    // long and not user-meaningful), or `None` to let the model fall back to the
    // generic root label.
    let session_label = app.session_id.as_ref().map(|id| {
        let tail: String = id
            .chars()
            .rev()
            .take(8)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect();
        tail
    });

    // Focused entry → its stable id + a short kind label (reusing the same
    // classification the turn outline / index use, so the crumb reads the same as
    // the rest of the UI).
    let entries = active_transcript_entries(app);
    let focused_entry = active_selected_entry(app).and_then(|index| {
        entries.get(index).map(|entry| {
            let kind = outline_kind_of(entries, index);
            (entry.id, kind.label().to_string())
        })
    });

    breadcrumbs::BreadcrumbContext {
        session_label,
        following_tail: focused_entry.is_none() && active_transcript_scroll(app).is_following(),
        focused_entry,
        overlay_open: app.transcript_overlay.is_some(),
        search_query: app.search.as_ref().map(|s| s.query.clone()),
    }
}

/// `Alt+2`: show / hide the Clickable Breadcrumbs strip (§12.1.5). The strip is a
/// compact `session ▸ turn ▸ entry` trail painted on the status row that orients
/// long sessions without permanent chrome. Showing it parks the breadcrumb focus
/// on the deepest (rightmost) crumb — the user's current location — and confirms
/// via the status line. Sets `needs_redraw` so the toggle paints immediately; the
/// hidden state paints nothing and schedules no redraw.
fn toggle_breadcrumbs(app: &mut TuiApp) {
    app.breadcrumbs_open = !app.breadcrumbs_open;
    if app.breadcrumbs_open {
        let model = breadcrumbs::BreadcrumbModel::build(&build_breadcrumb_context(app));
        // Park the focus on the deepest crumb (the current location), so the first
        // ← steps back up the trail toward the session root.
        app.breadcrumbs_focus = model.len().saturating_sub(1);
        app.status = "breadcrumbs — \u{2190}\u{2192} focus \u{00b7} Enter jump \u{00b7} Alt+2 hide"
            .to_string();
    } else {
        app.status = "breadcrumbs hidden".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Clickable Breadcrumbs strip (§12.1.5) is shown. Returns
/// `true` when the key was consumed so it never leaks to the composer or global
/// keymap. The strip's own toggle chord (`Alt+2`) hides it; bare Left/Right move
/// the breadcrumb focus along the trail (clamped, no wrap).
///
/// Unlike the fullscreen overlays this is a *non-modal* strip: it claims ONLY the
/// keys that can never collide with composer text entry — its toggle chord and
/// bare Left/Right (which are not printable and have no composer-typing meaning).
/// Crucially it does NOT eat bare `Enter` (prompt submission), bare letters like
/// `h`/`l` (composer typing — eating them turned "hello" into "eo"), or bare `Esc`
/// (global dismiss / turn interrupt): those fall through so typing and submission
/// keep working while the orienting strip is visible (deep-review #6). The strip
/// is still dismissable via its toggle chord, and a crumb is still activatable by
/// mouse click.
fn handle_breadcrumbs_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.breadcrumbs_open {
        return false;
    }
    // The strip's own toggle chord (`Alt+2` by default) hides it.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleBreadcrumbs) {
        app.breadcrumbs_open = false;
        app.status = "breadcrumbs hidden".to_string();
        app.needs_redraw = true;
        return true;
    }
    // Only bare (unmodified) arrows steer the strip; a modified arrow (e.g.
    // Alt+Left word-motion / Shift+Left selection) and every printable key fall
    // through to the composer/global handling untouched.
    if !key.modifiers.is_empty() {
        return false;
    }
    let model = breadcrumbs::BreadcrumbModel::build(&build_breadcrumb_context(app));
    let count = model.len();
    match key.code {
        KeyCode::Left => {
            if let Some(prev) = model.prev_index(app.breadcrumbs_focus.min(count.saturating_sub(1)))
            {
                app.breadcrumbs_focus = prev;
            }
            app.needs_redraw = true;
            true
        }
        KeyCode::Right => {
            if let Some(next) = model.next_index(app.breadcrumbs_focus.min(count.saturating_sub(1)))
            {
                app.breadcrumbs_focus = next;
            }
            app.needs_redraw = true;
            true
        }
        // Every other key falls through: the strip is non-modal, so normal
        // composer input (letters, Enter, Esc) keeps working while it is shown.
        _ => false,
    }
}

/// Navigate to the location the breadcrumb-focused crumb stands for (§12.1.5).
/// Rebuilds the trail (so the focus index is resolved against the current trail),
/// reads the focused crumb's [`breadcrumbs::BreadcrumbTarget`], and dispatches it
/// through the same jump paths the rest of the UI uses: `Home` scrolls to the top,
/// `Tail` jumps to the latest row, `Entry` jumps by stable id, `CloseOverlay`
/// closes the Ctrl+T overlay, and `Search` re-opens the incremental search. A
/// no-op (status hint) when there is nothing focusable. Reports the destination in
/// the status line.
fn breadcrumbs_activate_focused(app: &mut TuiApp) {
    let model = breadcrumbs::BreadcrumbModel::build(&build_breadcrumb_context(app));
    let index = app.breadcrumbs_focus.min(model.len().saturating_sub(1));
    let Some((label, target)) = model.get(index).map(|c| (c.label.clone(), c.target)) else {
        app.status = "breadcrumbs: nothing to jump to".to_string();
        return;
    };
    match target {
        breadcrumbs::BreadcrumbTarget::Home => {
            jump_main_to_top_animated(app);
            app.status = format!("breadcrumbs: {label} (top)");
        }
        breadcrumbs::BreadcrumbTarget::Tail => {
            commit_main_from_bottom_animated(app, 0);
            app.status = format!("breadcrumbs: {label} (latest)");
        }
        breadcrumbs::BreadcrumbTarget::Entry(entry_id) => {
            if jump_to_entry_id(app, entry_id) {
                app.status = format!("breadcrumbs: jumped to {label}");
            } else {
                app.status = "breadcrumbs: could not jump".to_string();
            }
        }
        breadcrumbs::BreadcrumbTarget::CloseOverlay => {
            close_transcript_overlay(app);
            app.status = "breadcrumbs: closed overlay".to_string();
        }
        breadcrumbs::BreadcrumbTarget::Search => {
            open_search(app);
            app.status = "breadcrumbs: search".to_string();
        }
    }
    app.needs_redraw = true;
}

// ---- Session Timeline (§12.2.6) ----

/// `Alt+9`: toggle the Session Timeline overlay (§12.2.6). A compact
/// chronological event view of the session — prompts, turns, tool runs,
/// approvals, edits, errors, and other high-signal state changes — grouped by
/// turn. Opening it refreshes the timeline (a no-op rebuild when the transcript
/// has not changed since the last refresh, so the cost is only paid on a real
/// change), parks the cursor on the most recent event (the timeline reads
/// newest-relevant first the way a session tail does), and confirms via the
/// status line. Sets `needs_redraw` so the toggle paints immediately.
fn toggle_session_timeline(app: &mut TuiApp) {
    app.session_timeline_open = !app.session_timeline_open;
    if app.session_timeline_open {
        refresh_session_timeline(app);
        // Park the cursor on the last visible event so the timeline opens at the
        // freshest end of the session (where the user just was).
        let visible = app.session_timeline.visible_len();
        app.session_timeline_selected = visible.saturating_sub(1);
        app.status = if app.session_timeline.is_empty() {
            "session timeline (empty) — Esc to close".to_string()
        } else {
            format!(
                "session timeline: {} — \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} f filter \u{00b7} Esc close",
                app.session_timeline.summary(),
            )
        };
    } else {
        app.status = "session timeline closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Session Timeline overlay (§12.2.6) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). The toggle chord (`Alt+9`) and Esc close; Up/Down (and k/j) move the
/// event cursor over the *visible* (filtered) list; `f` cycles the per-kind
/// filter (re-parking the cursor on the new visible tail); Enter (and l/→) jumps
/// the main view to the transcript row behind the selected event.
fn handle_session_timeline_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.session_timeline_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+9` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleSessionTimeline) {
        app.session_timeline_open = false;
        app.status = "session timeline closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.session_timeline.visible_len();
    match key.code {
        KeyCode::Esc => {
            app.session_timeline_open = false;
            app.status = "session timeline closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.session_timeline_selected = app.session_timeline_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.session_timeline_selected = (app.session_timeline_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        // `f` cycles the per-kind filter (the spec's "filters"): show-all → each
        // non-empty kind → show-all. Re-park the cursor on the new visible tail so
        // a narrowed list never strands the cursor past its end.
        KeyCode::Char('f') => {
            app.session_timeline.cycle_filter();
            let visible = app.session_timeline.visible_len();
            app.session_timeline_selected = visible.saturating_sub(1);
            app.status = match app.session_timeline.filter() {
                Some(kind) => format!(
                    "session timeline: filter [{}] ({} shown) — f next \u{00b7} Esc close",
                    kind.label(),
                    visible,
                ),
                None => format!(
                    "session timeline: filter off ({} events) — f filter \u{00b7} Esc close",
                    app.session_timeline.len(),
                ),
            };
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            session_timeline_jump_to_selected(app, true);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the transcript row behind the Session Timeline
/// overlay's selected event (§12.2.6). Resolves the visible event at the cursor,
/// scrolls to its source entry via the same `jump_to_entry_id` path the
/// index/outline/minimap/jump-nav use, and reports the turn/kind in the status
/// line. A no-op (status hint) when there is nothing to jump to.
///
/// `advance` controls the cursor afterward: the keyboard Enter verb passes `true`
/// so a *repeated* Enter walks forward through the timeline (wrapping at the
/// end); the mouse click passes `false` because a click is a precise pick that
/// should land and stay on exactly the clicked row.
fn session_timeline_jump_to_selected(app: &mut TuiApp, advance: bool) {
    let Some((entry_id, kind, turn)) = app
        .session_timeline
        .visible_get(app.session_timeline_selected)
        .map(|event| (event.entry_id, event.kind, event.turn))
    else {
        app.status = "session timeline: nothing to jump to".to_string();
        return;
    };
    if jump_to_entry_id(app, entry_id) {
        let position = app.session_timeline_selected + 1;
        let total = app.session_timeline.visible_len();
        app.status = format!(
            "session timeline {position}/{total} [turn {turn} \u{00b7} {}] — Enter for next \u{00b7} Esc close",
            kind.label(),
        );
        // Walk the cursor forward to the next visible event so a repeated Enter
        // steps through the whole timeline (wrapping). The mouse path skips this
        // so a click stays put on the row it picked.
        if advance
            && let Some(next) = app
                .session_timeline
                .next_index(Some(app.session_timeline_selected))
        {
            app.session_timeline_selected = next;
        }
        app.needs_redraw = true;
    } else {
        app.status = "session timeline: could not jump".to_string();
    }
}

// ---- Subagent Timeline Panel (§12.8.1) ----

/// Open / close the Subagent Timeline Panel (§12.8.1). On open it refreshes the
/// panel from the live subagent-pane records and parks the cursor on the last
/// visible row (the freshest subagent), then reports a one-line summary; on close
/// it just notes the close. Both directions request a redraw.
fn toggle_subagent_timeline(app: &mut TuiApp) {
    app.subagent_timeline_open = !app.subagent_timeline_open;
    if app.subagent_timeline_open {
        refresh_subagent_timeline(app);
        // Park the cursor on the last visible row so the panel opens at the
        // freshest end of the session (where the user just was).
        let visible = app.subagent_timeline.visible_len();
        app.subagent_timeline_selected = visible.saturating_sub(1);
        app.status = if app.subagent_timeline.is_empty() {
            "subagent timeline (no subagents yet) — Esc to close".to_string()
        } else {
            // Lead with the live count so a glance at the status line shows how
            // many subagents are still in flight without reading the rows.
            let running = app.subagent_timeline.running_count();
            let running_note = if running > 0 {
                format!(" ({running} running)")
            } else {
                String::new()
            };
            format!(
                "subagent timeline: {}{running_note} — \u{2191}\u{2193} select \u{00b7} Enter open \u{00b7} f filter \u{00b7} Esc close",
                app.subagent_timeline.summary(),
            )
        };
    } else {
        app.status = "subagent timeline closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Subagent Timeline Panel (§12.8.1) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). The toggle chord (`Alt+5`) and Esc close; Up/Down (and k/j, plus n/p)
/// move the cursor over the *visible* (filtered) list; `f` cycles the per-status
/// filter (re-parking the cursor on the new visible tail); Enter (and l/→) jumps
/// the main view to the selected subagent's conversation.
fn handle_subagent_timeline_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.subagent_timeline_open {
        return false;
    }
    // The panel's own toggle chord (`Alt+5` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleSubagentTimeline) {
        app.subagent_timeline_open = false;
        app.status = "subagent timeline closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    // The Compare Subagent Outputs chord (`Alt+7` by default; §12.8.3) opens the
    // side-by-side compare view over the two marked subagents directly from the
    // panel — `toggle_subagent_compare` closes the panel and opens the view (or
    // leaves an honest hint when fewer than two are marked). Handled here so the
    // chord works without first closing the panel, since this modal swallows the
    // global keymap below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleSubagentCompare) {
        toggle_subagent_compare(app);
        return true;
    }
    let count = app.subagent_timeline.visible_len();
    match key.code {
        KeyCode::Esc => {
            app.subagent_timeline_open = false;
            app.status = "subagent timeline closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') | KeyCode::Char('p') => {
            app.subagent_timeline_selected = app.subagent_timeline_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') | KeyCode::Char('n') => {
            if count > 0 {
                app.subagent_timeline_selected =
                    (app.subagent_timeline_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        // `f` cycles the per-status filter (the spec's running/completed/failed/
        // capped facets): show-all → each non-empty status → show-all. Re-park the
        // cursor on the new visible tail so a narrowed list never strands it.
        KeyCode::Char('f') => {
            app.subagent_timeline.cycle_filter();
            let visible = app.subagent_timeline.visible_len();
            app.subagent_timeline_selected = visible.saturating_sub(1);
            app.status = match app.subagent_timeline.filter() {
                Some(status) => format!(
                    "subagent timeline: filter [{}] ({} shown) — f next \u{00b7} Esc close",
                    status.label(),
                    visible,
                ),
                None => format!(
                    "subagent timeline: filter off ({} subagents) — f filter \u{00b7} Esc close",
                    app.subagent_timeline.len(),
                ),
            };
            app.needs_redraw = true;
        }
        // `c` marks / unmarks the selected subagent for the Compare Subagent
        // Outputs view (§12.8.3). Resolve the visible row to its subagent id, then
        // its pane index, so the mark survives a filtered list. Marking two opens
        // the compare view (Alt+7).
        KeyCode::Char('c') => {
            if let Some(id) = app
                .subagent_timeline
                .visible_get(app.subagent_timeline_selected)
                .map(|entry| entry.id)
                && let Some(index) = subagent_record_index(app, id)
            {
                toggle_subagent_compare_mark(app, index);
            } else {
                app.status = "compare: nothing to mark".to_string();
                app.needs_redraw = true;
            }
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            subagent_timeline_jump_to_selected(app, true);
        }
        // `y` promotes the selected subagent's result into a follow-up prompt
        // (§12.8.4) — the always-available equivalent of the `Ctrl+Alt+Q` verb for
        // terminals that swallow the Meta chord, and the keyboard twin of the row's
        // promote-click affordance. Fills the composer (idle) or queues (active
        // turn); never auto-submitted.
        KeyCode::Char('y') => {
            promote_subagent_timeline_row(app, app.subagent_timeline_selected);
        }
        // Swallow every other key so the panel is modal: a stray keystroke cannot
        // leak into the composer underneath while the panel owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the conversation behind the Subagent Timeline Panel's
/// selected row (§12.8.1). Resolves the visible row at the cursor to its subagent
/// id, makes that subagent the active conversation (selecting its pane row and
/// pinning its scroll), opens the transcript overlay on it (the committed
/// subagent conversation lives in scrollback that can't be repainted in place),
/// and reports the row in the status line. A no-op (status hint) when there is
/// nothing to jump to or the subagent's record has gone.
///
/// `advance` controls the cursor afterward: the keyboard Enter verb passes `true`
/// so a *repeated* Enter walks forward through the panel (wrapping at the end);
/// the mouse click passes `false` because a click is a precise pick that should
/// land and stay on exactly the clicked row.
fn subagent_timeline_jump_to_selected(app: &mut TuiApp, advance: bool) {
    let Some((id, status)) = app
        .subagent_timeline
        .visible_get(app.subagent_timeline_selected)
        .map(|entry| (entry.id, entry.status))
    else {
        app.status = "subagent timeline: nothing to open".to_string();
        return;
    };
    // Resolve the id to its pane row (row 0 is `main`; record N lives on row
    // N + 1). A vanished record (pruned/cleared) means nothing to open.
    let Some(pos) = app
        .subagent_pane
        .records
        .iter()
        .position(|record| record.id == id)
    else {
        app.status = "subagent timeline: that subagent is no longer tracked".to_string();
        return;
    };
    app.subagent_pane.selected = pos + 1;
    app.subagent_pane.active = ConversationSource::Subagent(id);
    active_transcript_scroll_mut(app).pin_to_bottom();
    open_subagent_transcript_overlay(app);
    // Opening the transcript overlay closes the panel: it now owns the surface, so
    // leaving the panel open behind it would fight for key/mouse routing.
    app.subagent_timeline_open = false;
    let position = app.subagent_timeline_selected + 1;
    let total = app.subagent_timeline.visible_len();
    app.status = format!(
        "subagent {position}/{total} [{}] — {} to expand, Esc to close",
        status.label(),
        key_hint(app, keymap::Action::ToggleTranscriptOverlay),
    );
    // Walk the cursor forward to the next visible row so a re-open of the panel
    // resumes after the row just opened. The mouse path skips this so a click
    // stays put on the row it picked.
    if advance
        && let Some(next) = app
            .subagent_timeline
            .next_index(Some(app.subagent_timeline_selected))
    {
        app.subagent_timeline_selected = next;
    }
    app.needs_redraw = true;
}

// ---- Live Review Board (§12.8.5) ----

/// Re-park the Live Review Board cursor onto a live worker after a (re)build:
/// keep the current worker if it is still on the board, else heal to the first
/// worker, else `None` when the board is empty. Id-addressed so a pruned record or
/// an emptied lane never strands the cursor on a vanished worker.
pub(crate) fn review_board_reconcile_cursor(app: &mut TuiApp) {
    let still_present = app
        .review_board_cursor
        .is_some_and(|id| app.review_board.index_of(id).is_some());
    if !still_present {
        app.review_board_cursor = app.review_board.card_at(0).map(|card| card.id);
    }
}

/// Open / close the Live Review Board (§12.8.5). On open it refreshes the board
/// from the live records, parks the cursor on the first worker (id-addressed), and
/// reports a one-line summary (or an honest empty-state line); on close it clears
/// the status. Toggled by `ToggleReviewBoard` (`Ctrl+Alt+O`).
fn toggle_review_board(app: &mut TuiApp) {
    app.review_board_open = !app.review_board_open;
    if app.review_board_open {
        refresh_review_board(app);
        // Park on the first worker (board order: running → blocked → capped →
        // completed) so the board opens on the live end of the fan-out.
        app.review_board_cursor = app.review_board.card_at(0).map(|card| card.id);
        app.status = if app.review_board.is_empty() {
            "review board (no workers yet) — Esc to close".to_string()
        } else {
            let attention = app.review_board.attention_count();
            let attention_note = if attention > 0 {
                format!(" ({attention} need a look)")
            } else {
                String::new()
            };
            format!(
                "review board: {}{attention_note} — \u{2191}\u{2193} select \u{00b7} Enter open \u{00b7} Esc close",
                app.review_board.summary(),
            )
        };
    } else {
        app.status = "review board closed".to_string();
    }
    app.needs_redraw = true;
}

/// Close the Live Review Board (§12.8.5) without leaking the key to the surface
/// beneath. Shared by the Esc and toggle-chord paths.
fn close_review_board(app: &mut TuiApp) {
    app.review_board_open = false;
    app.status = "review board closed".to_string();
    app.needs_redraw = true;
}

/// Handle a key while the Live Review Board (§12.8.5) is open. Returns `true` when
/// the key was consumed (so it never leaks to the composer or global keymap). The
/// toggle chord (`Ctrl+Alt+O`) and Esc close; Up/Down (and k/j, plus n/p) walk the
/// cursor over the flattened lanes by stable id; Enter (and l/→) jumps the main
/// view to the selected worker's conversation. Every other key is swallowed so the
/// board is modal.
fn handle_review_board_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.review_board_open {
        return false;
    }
    // The board's own toggle chord closes it, so the same key both opens and closes
    // — without leaking to the global keymap, which the modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleReviewBoard) {
        close_review_board(app);
        return true;
    }
    // Heal the cursor against the current board before moving it, so a worker that
    // vanished between frames never strands navigation.
    review_board_reconcile_cursor(app);
    let current = app
        .review_board_cursor
        .and_then(|id| app.review_board.index_of(id));
    match key.code {
        KeyCode::Esc => {
            close_review_board(app);
        }
        KeyCode::Up | KeyCode::Char('k') | KeyCode::Char('p') => {
            if let Some(prev) = app.review_board.prev_index(current) {
                app.review_board_cursor = app.review_board.card_at(prev).map(|card| card.id);
            }
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') | KeyCode::Char('n') => {
            if let Some(next) = app.review_board.next_index(current) {
                app.review_board_cursor = app.review_board.card_at(next).map(|card| card.id);
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            review_board_jump_to_cursor(app, true);
        }
        // Swallow every other key so the board is modal: a stray keystroke cannot
        // leak into the composer underneath while the board owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the conversation behind the Live Review Board's selected
/// worker (§12.8.5). Resolves the cursor's stable id to its subagent-pane row,
/// makes that subagent the active conversation (selecting its pane row and pinning
/// its scroll), opens the transcript overlay on it, and reports the worker in the
/// status line. A no-op (status hint) when there is nothing to jump to or the
/// worker's record has gone (a capped worker has no transcript and heals to a
/// select-only hint).
///
/// `advance` walks the cursor forward to the next worker afterward (keyboard Enter)
/// so a repeated Enter steps through the board; the mouse path passes `false` so a
/// click lands and stays on exactly the clicked worker.
fn review_board_jump_to_cursor(app: &mut TuiApp, advance: bool) {
    review_board_reconcile_cursor(app);
    let Some(id) = app.review_board_cursor else {
        app.status = "review board: nothing to open".to_string();
        return;
    };
    let Some(lane) = app
        .review_board
        .index_of(id)
        .and_then(|i| app.review_board.card_at(i))
        .map(|card| card.lane)
    else {
        app.status = "review board: nothing to open".to_string();
        return;
    };
    // Resolve the id to its pane row (row 0 is `main`; record N lives on row
    // N + 1). A vanished record (pruned/cleared) or a capped worker that never ran
    // means there is no transcript to open — a select-only honest hint.
    let Some(pos) = subagent_record_index(app, id) else {
        app.status = format!(
            "review board: {} worker has no conversation to open",
            lane.title().to_lowercase(),
        );
        return;
    };
    app.subagent_pane.selected = pos + 1;
    app.subagent_pane.active = ConversationSource::Subagent(id);
    active_transcript_scroll_mut(app).pin_to_bottom();
    open_subagent_transcript_overlay(app);
    // Opening the transcript overlay closes the board: it now owns the surface.
    app.review_board_open = false;
    app.status = format!(
        "review board: opened {} worker — {} to expand, Esc to close",
        lane.title().to_lowercase(),
        key_hint(app, keymap::Action::ToggleTranscriptOverlay),
    );
    if advance && let Some(next_idx) = app.review_board.index_of(id) {
        let next = app.review_board.next_index(Some(next_idx));
        if let Some(next) = next {
            app.review_board_cursor = app.review_board.card_at(next).map(|card| card.id);
        }
    }
    app.needs_redraw = true;
}

// ---- Attention Routing (§12.8.6) ----

/// Quick-jump to the subagent that most needs attention (§12.8.6). Refreshes the
/// Attention Routing model against the live records, takes the single
/// highest-priority target (a failure first, then a cap rejection, a blocker, an
/// awaited approval, a pinned completion), and lands on it the same way the
/// subagent timeline's Enter jump does — selecting its pane row, making it the
/// active conversation, pinning its scroll, and opening its transcript overlay.
/// A no-op (status hint) when nothing wants attention or when the routed target's
/// record has vanished, so the chord never disrupts a calm session.
///
/// The keyboard verb (`Ctrl+Alt+Z`) and a click on the status-line attention
/// indicator both reach here.
fn jump_to_attention(app: &mut TuiApp) {
    refresh_attention_route(app);
    let Some((id, kind, agent)) = app
        .attention_route
        .top()
        .map(|item| (item.id, item.kind, item.agent.clone()))
    else {
        app.status = "attention: nothing needs a look right now".to_string();
        app.needs_redraw = true;
        return;
    };
    let total = app.attention_route.len();
    // Resolve the routed id to its pane row (row 0 is `main`; record N lives on
    // row N + 1). A cap-rejected subagent never ran, so it has no transcript to
    // open — surface it as a select-only status hint rather than a dead jump.
    let Some(pos) = app
        .subagent_pane
        .records
        .iter()
        .position(|record| record.id == id)
    else {
        app.status = "attention: that subagent is no longer tracked".to_string();
        app.needs_redraw = true;
        return;
    };
    let more = total.saturating_sub(1);
    let more_note = if more > 0 {
        format!(" (+{more} more)")
    } else {
        String::new()
    };
    if kind == attention::SubagentAttentionKind::Rejection {
        // A rejection has no conversation; select its pane row but leave the
        // surface where it is so the user can read the cap notice in place.
        app.subagent_pane.selected = pos + 1;
        app.status = format!(
            "attention: {agent} [{}]{more_note} — capped before it ran",
            kind.label(),
        );
        app.needs_redraw = true;
        return;
    }
    // Route through the canonical jump so the return anchor + pane cleanup
    // (subagent_return_anchor / focused = false / dismiss_subagent_preview) are
    // set exactly as the timeline Enter / double-click jump does — the two jump
    // paths can't drift. Then layer the attention-specific status on top.
    jump_to_subagent_index(app, pos);
    app.status = format!(
        "attention: {agent} [{}]{more_note} — {} to expand, Esc to close",
        kind.label(),
        key_hint(app, keymap::Action::ToggleTranscriptOverlay),
    );
    app.needs_redraw = true;
}

// ---- Compare Subagent Outputs (§12.8.3) ----

/// The 0-based pane index of the subagent record with stable `id`, or `None` when
/// no live record holds it (pruned / cleared). The single id→record resolver the
/// compare view uses, so a vanished id never repoints a pane.
fn subagent_record_index(app: &TuiApp, id: SubagentId) -> Option<usize> {
    app.subagent_pane.records.iter().position(|r| r.id == id)
}

/// Whether both subagents the compare view (§12.8.3) pins are still present in the
/// live record list. The crate root closes the view when an id has disappeared so
/// the render path never paints an empty pane (mirrors
/// `pinned_compare_entries_present`).
pub(crate) fn subagent_compare_records_present(app: &TuiApp) -> bool {
    let Some(state) = app.subagent_compare else {
        return false;
    };
    subagent_record_index(app, state.left_id).is_some()
        && subagent_record_index(app, state.right_id).is_some()
}

/// Mark / unmark the subagent at 0-based pane `index` for comparison (§12.8.3) —
/// the `c` key in the timeline panel and a marked-row click both reach here.
/// Toggling a third subagent's mark rolls the oldest mark off (the two-slot cap).
/// Reports the mark state + a hint to open the compare view once two are marked.
/// A no-op (status hint) when the index has no live record.
fn toggle_subagent_compare_mark(app: &mut TuiApp, index: usize) {
    let Some(record) = app.subagent_pane.records.get(index) else {
        app.status = "compare: nothing to mark".to_string();
        return;
    };
    let id = record.id;
    let agent = record.agent.clone();
    let now_marked = app.subagent_compare_marks.toggle(id);
    let count = app.subagent_compare_marks.len();
    app.status = if now_marked {
        if count >= 2 {
            format!(
                "compare: marked {agent} #{} ({count} marked) — {} to compare",
                index + 1,
                key_hint(app, keymap::Action::ToggleSubagentCompare),
            )
        } else {
            format!(
                "compare: marked {agent} #{} ({count}/2) — mark one more (c)",
                index + 1,
            )
        }
    } else {
        format!("compare: unmarked {agent} #{} ({count} marked)", index + 1,)
    };
    app.needs_redraw = true;
}

/// `Alt+7`: open / close the Compare Subagent Outputs view (§12.8.3). When the
/// view is open it closes (and forgets the painted-rect cache). When closed it
/// opens over the two marked subagents — but only when *exactly two distinct*
/// subagents are marked and both still live; otherwise it leaves an honest hint
/// telling the user to mark two from the timeline panel. Opening closes the
/// timeline panel so the two never fight for key/mouse routing.
fn toggle_subagent_compare(app: &mut TuiApp) {
    if app.subagent_compare.is_some() {
        close_subagent_compare(app);
        return;
    }
    let Some((left_id, right_id)) = app.subagent_compare_marks.pair() else {
        let marked = app.subagent_compare_marks.len();
        app.status = format!(
            "compare needs two marked subagents ({marked}/2) — open the subagent timeline (Alt+5), press c on two rows",
        );
        app.needs_redraw = true;
        return;
    };
    // Both marks must still resolve to live records; a pruned/cleared subagent
    // can't be compared. Heal the stale mark away and report it.
    if subagent_record_index(app, left_id).is_none()
        || subagent_record_index(app, right_id).is_none()
    {
        app.subagent_compare_marks.clear();
        app.status = "compare: a marked subagent is no longer tracked — re-mark two".to_string();
        app.needs_redraw = true;
        return;
    }
    app.subagent_compare = Some(subagent_compare::SubagentCompareState::new(
        left_id, right_id,
    ));
    app.subagent_compare_rect_cache.set(None);
    // Opening the compare view closes the timeline panel: the compare view owns
    // the surface, so leaving the panel open behind it would fight for routing.
    app.subagent_timeline_open = false;
    app.status =
        "compare subagents: Tab focus \u{00b7} scroll keys move active pane \u{00b7} x diff \u{00b7} Alt+7/Esc close"
            .to_string();
    app.needs_redraw = true;
}

/// Close the Compare Subagent Outputs view (§12.8.3), clearing the painted-rect
/// cache and leaving the marks intact (so a re-open compares the same pair). The
/// single close path the Esc key, the toggle, and a vanished-record heal share.
pub(crate) fn close_subagent_compare(app: &mut TuiApp) {
    app.subagent_compare = None;
    app.subagent_compare_rect_cache.set(None);
    app.status = "compare view closed".to_string();
    app.needs_redraw = true;
}

/// Handle a key while the Compare Subagent Outputs view (§12.8.3) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). The toggle chord (`Alt+7`) and Esc close; `Tab` flips the focused
/// pane; the scroll keys (↑↓/kj, PgUp/PgDn) move the FOCUSED pane independently;
/// `x` toggles the verbatim-content vs. clean-text-diff mode. Every other key is
/// swallowed so the view is modal.
fn handle_subagent_compare_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.subagent_compare.is_none() {
        return false;
    }
    // The view's own toggle chord (`Alt+7` by default) closes it, so the same key
    // both opens and closes — without leaking to the global keymap, which this
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleSubagentCompare) {
        close_subagent_compare(app);
        return true;
    }
    match key.code {
        KeyCode::Esc => close_subagent_compare(app),
        KeyCode::Tab | KeyCode::BackTab => {
            toggle_subagent_compare_focus(app);
        }
        KeyCode::Char('x') => {
            toggle_subagent_compare_mode(app);
        }
        KeyCode::Up | KeyCode::Char('k') => {
            scroll_subagent_compare(app, VerticalScrollDir::Up, 1);
        }
        KeyCode::Down | KeyCode::Char('j') => {
            scroll_subagent_compare(app, VerticalScrollDir::Down, 1);
        }
        KeyCode::PageUp => {
            scroll_subagent_compare(app, VerticalScrollDir::Up, 10);
        }
        KeyCode::PageDown | KeyCode::Char(' ') => {
            scroll_subagent_compare(app, VerticalScrollDir::Down, 10);
        }
        // Swallow every other key so the view is modal: a stray keystroke cannot
        // leak into the composer underneath while the view owns focus.
        _ => {}
    }
    true
}

/// Flip which compare pane the keyboard / wheel drives (the `Tab` key and a click
/// on a pane). Returns `true` when a view was open (so the caller redraws).
fn toggle_subagent_compare_focus(app: &mut TuiApp) -> bool {
    let Some(state) = app.subagent_compare.as_mut() else {
        return false;
    };
    state.focus = state.focus.toggled();
    let label = state.focus.label();
    // The cached rects are active-pane-first, so a focus flip invalidates them
    // until the next paint re-stamps the new ordering.
    app.subagent_compare_rect_cache.set(None);
    app.status = format!("compare focus: {label} pane");
    app.needs_redraw = true;
    true
}

/// Focus a specific compare pane (the mouse twin of `Tab`): a click inside a pane
/// makes it the active one. Returns `true` when the focus actually changed.
fn focus_subagent_compare_pane(app: &mut TuiApp, pane: subagent_compare::ComparePane) -> bool {
    let Some(state) = app.subagent_compare.as_mut() else {
        return false;
    };
    if state.focus == pane {
        return false;
    }
    state.focus = pane;
    let label = pane.label();
    app.subagent_compare_rect_cache.set(None);
    app.status = format!("compare focus: {label} pane");
    app.needs_redraw = true;
    true
}

/// Toggle the compare view between verbatim content and a line-based clean-text
/// diff (the `x` key). Returns `true` when a view was open.
fn toggle_subagent_compare_mode(app: &mut TuiApp) -> bool {
    let Some(state) = app.subagent_compare.as_mut() else {
        return false;
    };
    state.mode = state.mode.toggled();
    // The diff column has a different total height than either content pane, so
    // reset both offsets to the top to avoid stranding past the end.
    state.left_scroll = 0;
    state.right_scroll = 0;
    let label = state.mode.label();
    app.subagent_compare_rect_cache.set(None);
    app.status = format!("compare mode: {label}");
    app.needs_redraw = true;
    true
}

/// Scroll the *focused* compare pane by `delta` rows in `dir`, clamped to its
/// content. Returns `true` when the offset changed (so the caller redraws). Used
/// by both the keyboard scroll path and the wheel-over-pane mouse path. In diff
/// mode the two panes share one column, so whichever pane is focused scrolls the
/// same diff body.
fn scroll_subagent_compare(app: &mut TuiApp, dir: VerticalScrollDir, delta: usize) -> bool {
    let Some(focus) = app.subagent_compare.map(|state| state.focus) else {
        return false;
    };
    let Some((total, viewport)) = subagent_compare_geometry(app, focus) else {
        return false;
    };
    let Some(state) = app.subagent_compare.as_mut() else {
        return false;
    };
    let current = state.focused_scroll();
    let next = match dir {
        VerticalScrollDir::Up => current.saturating_sub(delta),
        VerticalScrollDir::Down => current.saturating_add(delta),
    };
    let next = pinned_compare::clamp_pane_scroll(next, total, viewport);
    if next == current {
        return false;
    }
    state.set_focused_scroll(next);
    app.needs_redraw = true;
    true
}

/// The fully-expanded output lines for the subagent with stable `id`, at `width`.
/// Built from the subagent's stored conversation (`record.transcript`) with the
/// same expanded formatter the Ctrl+T overlay and the pinned compare use — a
/// title line of attribution (`agent #N [status]`) then the body — so a compare
/// pane shows the subagent's actual findings/output. Empty when the id has fallen
/// out of the record list (the crate root heals that away before painting).
fn subagent_compare_pane_lines(app: &TuiApp, id: SubagentId, width: u16) -> Vec<Line<'static>> {
    let Some(index) = subagent_record_index(app, id) else {
        return Vec::new();
    };
    let record = &app.subagent_pane.records[index];
    let shortcut = key_hint(app, keymap::Action::ToggleTranscriptOverlay);
    let status = subagent_status_of(record.lifecycle);
    // Attribution header (the spec's "compare their findings with attribution"):
    // the subagent's role + ordinal + lifecycle, so each pane is self-labelled
    // even when the diff column drops the per-pane title.
    let mut logical: Vec<Line<'static>> = vec![
        Line::from(Span::styled(
            format!("{} #{} [{}]", record.agent, index + 1, status.label()),
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        )),
        Line::from(""),
    ];
    for (entry_index, entry) in record.transcript.iter().enumerate() {
        let body = format_transcript_entry_expanded(
            entry,
            false,
            ToolDetailMode::Full,
            message_outcome(&record.transcript, entry_index),
            Some(width),
            app.show_reasoning_usage,
            shortcut.as_str(),
        );
        logical.extend(body);
    }
    wrap_transcript_overlay_rows(&logical, width)
}

/// The plain text of a compare pane (one `String` per row), used to feed the
/// line-based clean-text diff. Strips styling down to concatenated content, then
/// trims trailing whitespace so a cosmetic gutter difference does not register as
/// a content change (mirrors `pinned_compare_pane_plain`).
fn subagent_compare_pane_plain(app: &TuiApp, id: SubagentId, width: u16) -> Vec<String> {
    subagent_compare_pane_lines(app, id, width)
        .iter()
        .map(|line| {
            let text: String = line.spans.iter().map(|s| s.content.as_ref()).collect();
            text.trim_end().to_string()
        })
        .collect()
}

/// The rendered rows for the diff mode: a single column of `+`/`-`/` `-gutter
/// lines from [`pinned_compare::clean_text_diff`] (left = old, right = new).
/// Falls back to a one-line notice when either side is too large to diff (the
/// spec's size-limit mitigation).
fn subagent_compare_diff_lines(app: &TuiApp, width: u16) -> Vec<Line<'static>> {
    let Some(state) = app.subagent_compare else {
        return Vec::new();
    };
    // The gutter eats one cell; diff the panes at the narrower body width so the
    // wrapped rows line up with what each side would have shown.
    let body_width = width.saturating_sub(2).max(1);
    let old = subagent_compare_pane_plain(app, state.left_id, body_width);
    let new = subagent_compare_pane_plain(app, state.right_id, body_width);
    let Some(diff) = pinned_compare::clean_text_diff(&old, &new) else {
        return vec![Line::from(Span::styled(
            format!(
                "diff skipped — output too large (> {} lines per side)",
                pinned_compare::DIFF_LINE_LIMIT
            ),
            Style::default().fg(crate::render::theme::quiet()),
        ))];
    };
    diff.into_iter()
        .map(|line| {
            let color = match line.tag {
                pinned_compare::DiffTag::Same => crate::render::theme::quiet(),
                pinned_compare::DiffTag::Added => crate::render::theme::green(),
                pinned_compare::DiffTag::Removed => crate::render::theme::red(),
            };
            Line::from(Span::styled(
                format!("{} {}", line.tag.marker(), line.text),
                Style::default().fg(color),
            ))
        })
        .collect()
}

/// `(total_rows, viewport_h)` for one compare pane. Prefers the LAST PAINTED text
/// rect (cached each frame in `subagent_compare_rect_cache`) so the scroll clamp
/// uses the geometry the user is looking at; falls back to rebuilding the rect
/// off-frame from the live terminal size before the first paint. Returns `None`
/// when no compare view is open or the area is too small to split (mirrors
/// `pinned_compare_geometry`).
fn subagent_compare_geometry(
    app: &TuiApp,
    pane: subagent_compare::ComparePane,
) -> Option<(usize, usize)> {
    let state = app.subagent_compare?;
    // The cached rects are stored active-pane-first; resolve which slot this pane
    // is in for this frame.
    let text_area = match app.subagent_compare_rect_cache.get() {
        Some((first, second)) => {
            if pane == state.focus {
                first
            } else {
                second
            }
        }
        None => {
            let (width, height) = app.off_frame_terminal_size();
            let full_area = Rect {
                x: 0,
                y: 0,
                width,
                height,
            };
            let inner = subagent_compare_inner(full_area);
            let layout = pinned_compare::split_overlay_content(inner)?;
            // Off-frame both panes share the same inner size, so either slot's
            // inset rect is a fine proxy for the clamp.
            let (first, _) = layout.panes();
            pinned_compare::pane_inner(first)
        }
    };
    if text_area.width == 0 || text_area.height == 0 {
        return None;
    }
    let rows = if state.mode == pinned_compare::CompareMode::Diff {
        subagent_compare_diff_lines(app, text_area.width)
    } else {
        subagent_compare_pane_lines(app, state.id_for(pane), text_area.width)
    };
    Some((rows.len(), usize::from(text_area.height)))
}

/// Route a mouse event while the Compare Subagent Outputs view (§12.8.3) is open.
/// A wheel scrolls whichever pane the pointer is over (focusing it first — the
/// mouse twin of `Tab` + scroll); a left-click focuses the pane under the pointer.
/// The two panes' painted text rects are cached active-pane-first each frame; a
/// click/wheel outside both is a no-op. Returns `Some(consumed)` when it acted on
/// (or intentionally ignored) the event, or `None` when no rect cache exists yet
/// (the caller still consumes the event, since the view is modal). Mirrors the
/// §12.2.3 pinned-compare wheel/click routing.
fn handle_subagent_compare_mouse(
    app: &mut TuiApp,
    mouse: crossterm::event::MouseEvent,
) -> Option<bool> {
    let state = app.subagent_compare?;
    let (first, second) = app.subagent_compare_rect_cache.get()?;
    // `first` is the active pane, `second` the other (see the render).
    let active = state.focus;
    let other = active.toggled();
    let hit = if pinned_compare::rect_contains(first, mouse.column, mouse.row) {
        Some(active)
    } else if pinned_compare::rect_contains(second, mouse.column, mouse.row) {
        Some(other)
    } else {
        None
    };
    let pane = hit?;
    match mouse.kind {
        MouseEventKind::ScrollUp => {
            focus_subagent_compare_pane(app, pane);
            Some(scroll_subagent_compare(app, VerticalScrollDir::Up, 3))
        }
        MouseEventKind::ScrollDown => {
            focus_subagent_compare_pane(app, pane);
            Some(scroll_subagent_compare(app, VerticalScrollDir::Down, 3))
        }
        MouseEventKind::Down(crossterm::event::MouseButton::Left) => {
            Some(focus_subagent_compare_pane(app, pane))
        }
        _ => Some(false),
    }
}

// ---- What Changed Since Here? (§12.2.7) ----

/// The "since here" anchor the toggle marks: the focused entry when one is
/// focused (`Ctrl+↑/↓`), else the entry currently at the top of the viewport (the
/// same reading-position anchor the bookmark / jump-mark / annotate verbs use),
/// resolved to its stable id *and* its chronological sequence (its index in the
/// active transcript). `None` only when the transcript is empty. Resolving to a
/// stable id (not a row) here is what lets the delta survive every later reflow.
fn changes_since_anchor(app: &TuiApp) -> Option<change_summary::Anchor> {
    let entries = active_transcript_entries(app);
    let target_id = if let Some(index) = active_selected_entry(app)
        && let Some(entry) = entries.get(index)
    {
        entry.id
    } else {
        current_top_entry_id(app)?
    };
    let sequence = entries.iter().position(|e| e.id == target_id)? as u32;
    Some(change_summary::Anchor {
        entry_id: target_id,
        sequence,
    })
}

/// `Alt+0`: toggle the What Changed Since Here? overlay (§12.2.7). Opening it
/// marks the "since here" point at the current reading position (the focused or
/// top-visible entry), scans every later transcript event, and surfaces the
/// changes observed since — file edits, commands/tests, errors, checkpoints,
/// approval decisions, and other tool results — grouped into a summarized delta.
/// Parks the cursor on the first change and confirms via the status line with
/// honest "observed since" framing. Sets `needs_redraw` so the toggle paints
/// immediately.
fn toggle_changes_since(app: &mut TuiApp) {
    app.changes_since_open = !app.changes_since_open;
    if app.changes_since_open {
        // Mark the anchor at the current reading position, then build the delta.
        if let Some(anchor) = changes_since_anchor(app) {
            app.change_summary.set_anchor(anchor);
        }
        refresh_change_summary(app);
        // Park the cursor on the first (oldest) change so the review reads
        // top-to-bottom like a checklist.
        app.changes_since_selected = 0;
        app.status = if !app.change_summary.has_anchor() {
            "what changed since here (no transcript to mark) — Esc to close".to_string()
        } else if app.change_summary.is_empty() {
            "what changed since here: nothing observed since this point — m re-mark \u{00b7} Esc close".to_string()
        } else {
            format!(
                "what changed since here (observed): {} — \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} m re-mark \u{00b7} Esc close",
                app.change_summary.summary(),
            )
        };
    } else {
        app.status = "what changed since here closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the What Changed Since Here? overlay (§12.2.7) is open.
/// Returns `true` when the key was consumed (so it never leaks to the composer or
/// global keymap). The toggle chord (`Alt+0`) and Esc close; Up/Down (and k/j,
/// plus n/p) move the change cursor over the flattened delta; `m` re-marks the
/// anchor at the current reading position and rebuilds; Enter (and l/→) jumps the
/// main view to the entry behind the selected change.
fn handle_changes_since_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.changes_since_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+0` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleChangesSince) {
        app.changes_since_open = false;
        app.status = "what changed since here closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.change_summary.len();
    match key.code {
        KeyCode::Esc => {
            app.changes_since_open = false;
            app.status = "what changed since here closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') | KeyCode::Char('p') => {
            app.changes_since_selected = app.changes_since_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') | KeyCode::Char('n') => {
            if count > 0 {
                app.changes_since_selected = (app.changes_since_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        // `m` re-marks the "since here" point at the current reading position and
        // rebuilds the delta, re-parking the cursor on the first change.
        KeyCode::Char('m') => {
            if let Some(anchor) = changes_since_anchor(app) {
                app.change_summary.set_anchor(anchor);
            }
            refresh_change_summary(app);
            app.changes_since_selected = 0;
            app.status = if app.change_summary.is_empty() {
                "what changed since here: re-marked — nothing observed since \u{00b7} Esc close"
                    .to_string()
            } else {
                format!(
                    "what changed since here: re-marked — {} \u{00b7} Esc close",
                    app.change_summary.summary(),
                )
            };
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            changes_since_jump_to_selected(app, true);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Jump the main view to the transcript entry behind the What Changed Since Here?
/// overlay's selected change (§12.2.7). Resolves the change at the cursor, scrolls
/// to its source entry via the same `jump_to_entry_id` path the index / outline /
/// timeline / jump-nav use, and reports the group / position in the status line. A
/// no-op (status hint) when there is nothing to jump to.
///
/// `advance` controls the cursor afterward: the keyboard Enter verb passes `true`
/// so a *repeated* Enter walks forward through the delta (wrapping at the end);
/// the mouse click passes `false` because a click is a precise pick that should
/// land and stay on exactly the clicked row.
fn changes_since_jump_to_selected(app: &mut TuiApp, advance: bool) {
    let Some((entry_id, group)) = app
        .change_summary
        .get(app.changes_since_selected)
        .map(|item| (item.entry_id, item.group))
    else {
        app.status = "what changed since here: nothing to jump to".to_string();
        return;
    };
    if jump_to_entry_id(app, entry_id) {
        let position = app.changes_since_selected + 1;
        let total = app.change_summary.len();
        app.status = format!(
            "what changed {position}/{total} [{}] — Enter for next \u{00b7} Esc close",
            group.heading(),
        );
        // Walk the cursor forward to the next change so a repeated Enter steps
        // through the whole delta (wrapping). The mouse path skips this so a click
        // stays put on the row it picked.
        if advance
            && let Some(next) = app
                .change_summary
                .next_index(Some(app.changes_since_selected))
        {
            app.changes_since_selected = next;
        }
        app.needs_redraw = true;
    } else {
        app.status = "what changed since here: could not jump".to_string();
    }
}

// ---- Contextual Action Palette (§12.1.2) ----

/// Classify the focused transcript entry into the small [`action_palette::UnitKind`]
/// set the action menu's gathering rule keys on. Reuses the same kind distinctions
/// the renderer and index already draw (user vs assistant message, reasoning, tool
/// result, plan, diff, note) so the palette's notion of "what is this" matches what
/// the user sees. Total over the entry-kind set.
fn action_palette_unit_kind(entry: &TranscriptEntry) -> action_palette::UnitKind {
    use action_palette::UnitKind;
    match &entry.kind {
        TranscriptEntryKind::Message(item) if item.role == Role::User => UnitKind::UserMessage,
        TranscriptEntryKind::Message(item) if item.role == Role::Assistant => {
            UnitKind::AssistantMessage
        }
        // A system/other-role message reads as a note for action purposes.
        TranscriptEntryKind::Message(_) => UnitKind::Note,
        TranscriptEntryKind::ToolResult(_) => UnitKind::ToolResult,
        TranscriptEntryKind::Reasoning(_) => UnitKind::Reasoning,
        TranscriptEntryKind::PlanCard(_) => UnitKind::PlanCard,
        TranscriptEntryKind::Diff(_) => UnitKind::Diff,
        TranscriptEntryKind::Log(_) | TranscriptEntryKind::SlashEcho(_) => UnitKind::Note,
    }
}

/// Largest number of characters retained in the palette header's entry title.
/// One short line: long enough to disambiguate, short enough that the header never
/// wraps the modal.
const ACTION_PALETTE_TITLE_CAP: usize = 48;

/// A short, bounded, deterministic, secret-free one-line title for the focused
/// entry — its first content line / tool name (`outline_title_of`), collapsed to a
/// single line, trimmed, and capped — for the palette header so the menu shows
/// *which* entry it acts on. Falls back to the kind noun when the source has no
/// usable text.
fn action_palette_title(entry: &TranscriptEntry, kind: action_palette::UnitKind) -> String {
    let raw = outline_title_of(entry);
    let first_line = raw.lines().map(str::trim).find(|line| !line.is_empty());
    let Some(line) = first_line else {
        return kind.noun().to_string();
    };
    let collapsed: String = line.split_whitespace().collect::<Vec<_>>().join(" ");
    if collapsed.is_empty() {
        return kind.noun().to_string();
    }
    if collapsed.chars().count() <= ACTION_PALETTE_TITLE_CAP {
        return collapsed;
    }
    let prefix: String = collapsed.chars().take(ACTION_PALETTE_TITLE_CAP).collect();
    format!("{prefix}\u{2026}")
}

/// Point the copy-scope focus at the entry with stable `entry_id` so the palette's
/// copy verbs (`copy entry`, `copy code`, `copy tool output`) act on the focused
/// unit rather than the transcript tail. Resolves the entry's first row in the
/// freshly built (collapsed) row model — the same id-keyed metadata the copy
/// formatters consume — and stamps `copy_focus`. A no-op (focus left as-is) when
/// the entry has no painted row. Built off transcript metadata, never rendered
/// terminal cells.
fn set_copy_focus_to_entry(app: &mut TuiApp, entry_id: u64) {
    let width = main_text_width(app);
    let rows = transcript_surface::build_transcript_rows(
        app,
        width,
        transcript_surface::DetailPolicy::Collapsed,
    );
    if let Some(index) = rows
        .iter()
        .position(|row| row.entry_id == Some(transcript_surface::EntryId(entry_id)))
    {
        app.copy_focus = Some(transcript_surface::RowId(index));
    }
}

/// `Alt+Enter`: open the Contextual Action Palette (§12.1.2) for the currently
/// focused transcript unit — the focused entry (`Ctrl+↑/↓`) when one is focused,
/// else the entry at the top of the viewport (the same reading-position anchor the
/// annotate / bookmark / jump-mark verbs use). Classifies the entry, gathers the
/// actions that apply to it, parks the cursor on the first, and confirms via the
/// status line. A no-op (status hint) on an empty transcript. Sets `needs_redraw`
/// so the menu paints immediately.
fn open_action_palette(app: &mut TuiApp) {
    let Some(entry_id) = annotation_target_entry_id(app) else {
        app.action_palette = None;
        app.status = "no transcript entry — nothing to act on".to_string();
        app.needs_redraw = true;
        return;
    };
    let entries = active_transcript_entries(app);
    let Some(entry) = entries.iter().find(|entry| entry.id == entry_id) else {
        app.action_palette = None;
        app.status = "no transcript entry — nothing to act on".to_string();
        app.needs_redraw = true;
        return;
    };
    let kind = action_palette_unit_kind(entry);
    let collapsed = entry.collapsed;
    let has_detail = entry_has_detail_pane_content(entry);
    let title = action_palette_title(entry, kind);
    let actions = action_palette::applicable_actions(kind, has_detail);
    app.action_palette = Some(action_palette::ActionPalette::open(
        entry_id, kind, collapsed, title, actions,
    ));
    app.status = format!(
        "actions for {} \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter run \u{00b7} Esc close",
        kind.noun(),
    );
    app.needs_redraw = true;
}

/// Classify a transcript entry into the small [`hover_preview::PreviewKind`] set
/// the popover body keys on. Tool results read as `ToolOutput` (their body is the
/// captured output), a `/diff` card or a plan reads as `Path`-style detail target,
/// and everything else reads as a generic `Entry`. Total over the entry-kind set;
/// reuses the same kind distinctions the action palette / index already draw.
fn hover_preview_kind(entry: &TranscriptEntry) -> hover_preview::PreviewKind {
    use hover_preview::PreviewKind;
    match &entry.kind {
        TranscriptEntryKind::ToolResult(_) => PreviewKind::ToolOutput,
        TranscriptEntryKind::Diff(_) | TranscriptEntryKind::PlanCard(_) => PreviewKind::Path,
        TranscriptEntryKind::SlashEcho(_) => PreviewKind::Link,
        TranscriptEntryKind::Message(_)
        | TranscriptEntryKind::Reasoning(_)
        | TranscriptEntryKind::Log(_) => PreviewKind::Entry,
    }
}

/// A bounded, secret-free body excerpt for an entry's hover preview: the first few
/// non-empty lines of its title source (`outline_title_of`), each trimmed — the
/// quiet "what does this row hold" the preview shows beneath the title. Built off
/// transcript metadata, never rendered terminal cells, and bounded so the popover
/// stays a fixed-size affordance.
fn hover_preview_body(entry: &TranscriptEntry) -> Vec<String> {
    outline_title_of(entry)
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .take(hover_preview::PREVIEW_BODY_LINES)
        .map(|line| line.to_string())
        .collect()
}

/// Build a [`hover_preview::HoverPreview`] for the entry with stable `entry_id`,
/// or `None` when no live entry carries that id. The primary activation verb is
/// the entry's [`hover_preview::policy_for`] primary (open-in-detail) only when
/// the entry actually has detail-pane content — so a double-click / Enter on a
/// one-liner previews without offering an empty detail view. Pure read over the
/// active transcript; the resulting preview is the same whether a mouse hover or
/// the keyboard verb requested it.
fn build_entry_preview(
    app: &TuiApp,
    entry_id: u64,
    source: hover_preview::PreviewSource,
) -> Option<hover_preview::HoverPreview> {
    let entry = active_transcript_entries(app)
        .iter()
        .find(|entry| entry.id == entry_id)?;
    let kind = hover_preview_kind(entry);
    let title = action_palette_title(entry, action_palette_unit_kind(entry));
    let body = hover_preview_body(entry);
    // The primary (double-click / Enter) verb mirrors the keyboard `Ctrl+Enter`
    // detail path, but only when the entry has detail-worthy content; otherwise
    // the preview is read-only. `policy_for` keeps every destructive verb out of
    // this path by construction.
    let primary = if entry_has_detail_pane_content(entry) {
        hover_preview::policy_for(interaction::TargetKey::Entry(transcript_surface::EntryId(
            entry_id,
        )))
        .primary_activate
    } else {
        None
    };
    Some(hover_preview::HoverPreview::new(
        entry_id, kind, title, body, primary, source,
    ))
}

/// `Alt+1`: toggle the Hover Preview popover (§12.1.4) for the currently focused
/// transcript unit — the focused entry (`Ctrl+↑/↓`) when one is focused, else the
/// top-visible entry (the same reading-position anchor the action-palette /
/// annotate / bookmark verbs use). The keyboard twin of a stable mouse hover: it
/// reveals a quiet, noncommittal preview without stealing focus. A second press
/// (or any other key, a click, or a scroll) dismisses it. A no-op (status hint)
/// on an empty transcript. Sets `needs_redraw` so the popover paints immediately.
fn toggle_hover_preview(app: &mut TuiApp) {
    // A second press dismisses the open preview — a clean toggle.
    if app.hover_preview.is_some() {
        app.hover_preview = None;
        app.status = "preview closed".to_string();
        app.needs_redraw = true;
        return;
    }
    let Some(entry_id) = annotation_target_entry_id(app) else {
        app.hover_preview = None;
        app.status = "no transcript entry — nothing to preview".to_string();
        app.needs_redraw = true;
        return;
    };
    let Some(preview) = build_entry_preview(app, entry_id, hover_preview::PreviewSource::Keyboard)
    else {
        app.hover_preview = None;
        app.status = "no transcript entry — nothing to preview".to_string();
        app.needs_redraw = true;
        return;
    };
    let hint = preview.activate_hint();
    let verb = if preview.can_activate() {
        "Enter opens"
    } else {
        "read-only"
    };
    app.hover_preview = Some(preview);
    app.status = format!("preview ({verb}) \u{00b7} {hint} \u{00b7} Esc / Alt+1 close");
    app.needs_redraw = true;
    // Opening a peek is the user demonstrating they already know the hover/focus
    // affordance, so the §12.1.8 Hover hint fades — once used.
    note_first_run_hint_used(app, first_run_hints::HintId::Hover);
}

/// Dismiss any live Hover Preview popover (§12.1.4). Called whenever the surface
/// shifts out from under it — a scroll, a click, a key that is not the toggle, or
/// a transcript change — so a stale preview can never linger. Returns `true` when
/// a preview was actually showing (so the caller can fold the dismissal into its
/// existing redraw decision rather than forcing an extra one when idle).
fn dismiss_hover_preview(app: &mut TuiApp) -> bool {
    if app.hover_preview.take().is_some() {
        app.needs_redraw = true;
        true
    } else {
        false
    }
}

/// Dismiss a live Hover Preview popover (§12.1.4) ONLY when it was revealed by a
/// mouse hover — a keyboard-pinned (`Alt+1`) preview is left alone. Used by the
/// mouse-move hover path so an incidental pointer drift off the target never yanks
/// a keyboard-only user's pinned peek away (only an explicit key/click does).
fn dismiss_mouse_hover_preview(app: &mut TuiApp) {
    if app.hover_preview.as_ref().is_some_and(|p| !p.is_keyboard()) {
        dismiss_hover_preview(app);
    }
}

// ===========================================================================
// Subagent Hover Preview And Double-Click Jump (§12.8.2)
// ===========================================================================

/// Distill a record's [`SubagentLifecycle`] into the preview-model
/// [`subagent_preview::SubagentStatus`]. A pure 1:1 map so the preview module
/// needn't reach back into `lib.rs`.
fn subagent_status_of(lifecycle: SubagentLifecycle) -> subagent_preview::SubagentStatus {
    match lifecycle {
        SubagentLifecycle::Running => subagent_preview::SubagentStatus::Running,
        SubagentLifecycle::Completed => subagent_preview::SubagentStatus::Done,
        SubagentLifecycle::Failed => subagent_preview::SubagentStatus::Failed,
        SubagentLifecycle::Rejected => subagent_preview::SubagentStatus::Capped,
    }
}

/// A short, secret-free metrics summary for a subagent preview (`tools=N ·
/// bytes=M`), or `None` when the record has reported no metrics yet (the running
/// / missing-metrics edge). Built off structured `TurnMetrics`, never rendered
/// terminal cells.
fn subagent_metrics_summary(record: &SubagentRecord) -> Option<String> {
    record.metrics.as_ref().map(|metrics| {
        format!(
            "tools={} \u{00b7} bytes={}",
            metrics.subagent_tool_calls.max(metrics.tool_calls),
            metrics.subagent_bytes_read.max(metrics.bytes_read)
        )
    })
}

/// Build a [`subagent_preview::SubagentPreview`] for the subagent at 0-based pane
/// `index`, or `None` when no live record holds that index (a prune resolved it
/// away). Pure read over the pane; the resulting preview is the same whether a
/// mouse hover or the keyboard verb requested it.
fn build_subagent_preview(
    app: &TuiApp,
    index: usize,
    source: hover_preview::PreviewSource,
) -> Option<subagent_preview::SubagentPreview> {
    let record = app.subagent_pane.records.get(index)?;
    let name = format!("{} #{}", record.agent, index + 1);
    let status = subagent_status_of(record.lifecycle);
    let last_activity = if record.latest.trim().is_empty() {
        compact_text(&record.prompt, 120)
    } else {
        record.latest.clone()
    };
    let metrics = subagent_metrics_summary(record);
    Some(subagent_preview::SubagentPreview::new(
        index,
        name,
        status,
        last_activity,
        metrics,
        source,
    ))
}

/// Move the pane cursor onto the subagent at 0-based `index` (pane row `index +
/// 1`) and reveal a mouse-sourced preview of it — the shared handler the mouse
/// single-click (`SubagentSelect`) and the live-hover path both reach. Bounds the
/// index against the live record list so a prune mid-gesture resolves to a no-op.
/// Returns `true` when it changed anything (so the caller folds a redraw in).
fn subagent_select_index(app: &mut TuiApp, index: usize) -> bool {
    if index >= app.subagent_pane.records.len() {
        return false;
    }
    let row = index + 1;
    let changed = app.subagent_pane.selected != row;
    app.subagent_pane.selected = row;
    if let Some(preview) = build_subagent_preview(app, index, hover_preview::PreviewSource::Hover) {
        app.subagent_preview = Some(preview);
    }
    highlight_selected_subagent_row(app);
    app.needs_redraw = true;
    changed || app.subagent_preview.is_some()
}

/// Jump to the subagent at 0-based `index`'s transcript / detail pane (§12.8.2),
/// preserving the prior conversation + scroll as a return anchor so an Esc back
/// restores the reading position. The shared handler the mouse double-click
/// (`SubagentJump`) and the `JumpToSubagent` keyboard verb both reach, so the two
/// paths are identical by construction. A capped subagent (no transcript)
/// resolves to a select-only no-op with an honest status. Returns `true` when it
/// opened a transcript.
fn jump_to_subagent_index(app: &mut TuiApp, index: usize) -> bool {
    let Some(record) = app.subagent_pane.records.get(index) else {
        return false;
    };
    let status = subagent_status_of(record.lifecycle);
    let id = record.id;
    if !status.has_transcript() {
        // No transcript to open (a capped subagent never acquired a lease): a
        // double-click / jump is a select-only no-op, not a jump to an empty pane.
        subagent_select_index(app, index);
        app.status = "subagent capped — no transcript to open".to_string();
        app.needs_redraw = true;
        return false;
    }
    // Capture the return anchor BEFORE mutating the active source, so a back
    // command restores exactly where the user was.
    let prior_was_main = matches!(app.subagent_pane.active, ConversationSource::Main);
    app.subagent_return_anchor = Some(subagent_preview::SubagentReturnAnchor::new(
        app.subagent_pane.selected,
        prior_was_main,
    ));
    // Pin the cursor + active source onto the jumped-to subagent, then surface its
    // transcript via the same full-screen overlay the Enter path uses.
    app.subagent_pane.selected = index + 1;
    app.subagent_pane.active = ConversationSource::Subagent(id);
    app.subagent_pane.focused = false;
    active_transcript_scroll_mut(app).pin_to_bottom();
    dismiss_subagent_preview(app);
    open_subagent_transcript_overlay(app);
    app.status = format!(
        "jumped to subagent — {} to expand, Esc to return",
        key_hint(app, keymap::Action::ToggleTranscriptOverlay)
    );
    app.needs_redraw = true;
    true
}

/// Restore the conversation the user was on before a subagent jump (§12.8.2),
/// consuming the return anchor. Returns `true` when an anchor was outstanding (so
/// the caller knows the back command did something). Re-pins the prior pane
/// selection and active source; a stale anchor (the prior subagent pruned away)
/// degrades gracefully to the main conversation.
fn restore_subagent_return_anchor(app: &mut TuiApp) -> bool {
    let Some(anchor) = app.subagent_return_anchor.take() else {
        return false;
    };
    app.subagent_pane.active = ConversationSource::Main;
    app.subagent_pane.focused = false;
    app.subagent_pane.selected = anchor.prior_selected.min(app.subagent_pane.records.len());
    let _ = anchor.prior_was_main;
    active_transcript_scroll_mut(app).pin_to_bottom();
    app.clamp_subagent_selection();
    app.status = "returned from subagent".to_string();
    app.needs_redraw = true;
    true
}

// ===========================================================================
// Promote Subagent Result To Prompt (§12.8.4)
// ===========================================================================

/// Distill a record's [`SubagentLifecycle`] into the promote-model
/// [`subagent_promote::PromoteStatus`]. A pure 1:1 map so the promote module
/// needn't reach back into `lib.rs`.
fn promote_status_of(lifecycle: SubagentLifecycle) -> subagent_promote::PromoteStatus {
    match lifecycle {
        SubagentLifecycle::Running => subagent_promote::PromoteStatus::Running,
        SubagentLifecycle::Completed => subagent_promote::PromoteStatus::Done,
        SubagentLifecycle::Failed => subagent_promote::PromoteStatus::Failed,
        SubagentLifecycle::Rejected => subagent_promote::PromoteStatus::Capped,
    }
}

/// Build a [`subagent_promote::PromoteSource`] for the subagent at 0-based pane
/// `index`, or `None` when no live record holds that index (a prune resolved it
/// away). The result text is the record's `latest` line — the completion summary
/// for a finished subagent, the failure diagnostic for a failed one, the latest
/// activity for a running one, or the cap reason for a rejected one (the
/// `note_subagent_*` events already fold each of those into `latest`). A blank
/// `latest` falls back to the original prompt so a running subagent that has
/// reported nothing yet still promotes the task it was given.
fn build_promote_source(app: &TuiApp, index: usize) -> Option<subagent_promote::PromoteSource> {
    let record = app.subagent_pane.records.get(index)?;
    let name = format!("{} #{}", record.agent, index + 1);
    let status = promote_status_of(record.lifecycle);
    let result = if record.latest.trim().is_empty() {
        record.prompt.clone()
    } else {
        record.latest.clone()
    };
    Some(subagent_promote::PromoteSource::new(name, status, result))
}

/// Promote the subagent at 0-based pane `index` into a follow-up prompt (§12.8.4):
/// distill its result into a clean plain-text projection and fill the composer
/// (when idle) or queue it behind the running turn (when one is in flight) —
/// **never auto-submitted**. The shared handler the panel's `y` key, the
/// `PromoteSubagentResult` verb, and the row's promote-click all reach, so the
/// paths are identical by construction. Bounds the index against the live record
/// list so a prune mid-gesture resolves to a no-op (status hint). Returns `true`
/// when it promoted a result.
fn promote_subagent_at_index(app: &mut TuiApp, index: usize) -> bool {
    let Some(source) = build_promote_source(app, index) else {
        app.status = "promote: that subagent is no longer tracked".to_string();
        app.needs_redraw = true;
        return false;
    };
    let prompt = source.project();
    // Idle fills the composer (editable draft the user reviews); an active turn
    // queues the prompt behind it. Either way the user still submits/drains it —
    // the spec is explicit that a promote never auto-submits.
    let destination = subagent_promote::PromoteDestination::for_turn(app.turn_rx.is_some());
    match destination {
        subagent_promote::PromoteDestination::Composer => {
            input::insert_input_text(app, &prompt);
        }
        subagent_promote::PromoteDestination::Queue => {
            app.prompt_queue.push_back(prompt);
            enqueue_queue_id(app);
        }
    }
    app.status = match destination {
        subagent_promote::PromoteDestination::Composer => format!(
            "promoted {} \u{2014} {}, review and submit",
            source.name,
            destination.verb(),
        ),
        subagent_promote::PromoteDestination::Queue => format!(
            "promoted {} \u{2014} {} ({} in queue)",
            source.name,
            destination.verb(),
            app.prompt_queue.len(),
        ),
    };
    app.needs_redraw = true;
    true
}

/// Promote the subagent selected on the main surface (the subagent pane's cursor)
/// into a follow-up prompt (§12.8.4) — the `PromoteSubagentResult` keyboard verb's
/// main-surface path. A no-op (status hint) when the cursor is on `main` (pane row
/// 0) or no subagent is selected, so the chord never steals a key from the
/// composer without a target.
fn promote_selected_subagent_result(app: &mut TuiApp) {
    match app.subagent_pane.selected.checked_sub(1) {
        Some(index) => {
            promote_subagent_at_index(app, index);
        }
        None => {
            app.status = "no subagent selected \u{2014} nothing to promote".to_string();
            app.needs_redraw = true;
        }
    }
}

/// Promote the subagent on the Subagent Timeline Panel's *visible* row `index`
/// into a follow-up prompt (§12.8.4) — the panel's `y` key + promote-click path.
/// Resolves the visible (filtered) row to its live pane index before promoting, so
/// a filtered list never promotes the wrong subagent. A no-op (status hint) when
/// the row resolves to nothing (an empty / over-filtered panel, or a vanished
/// record).
fn promote_subagent_timeline_row(app: &mut TuiApp, index: usize) {
    let Some(id) = app
        .subagent_timeline
        .visible_get(index)
        .map(|entry| entry.id)
    else {
        app.status = "promote: nothing to promote".to_string();
        app.needs_redraw = true;
        return;
    };
    let Some(pane_index) = app
        .subagent_pane
        .records
        .iter()
        .position(|record| record.id == id)
    else {
        app.status = "promote: that subagent is no longer tracked".to_string();
        app.needs_redraw = true;
        return;
    };
    promote_subagent_at_index(app, pane_index);
}

/// `Alt+6`: toggle the Subagent Hover Preview popover (§12.8.2) for the currently
/// selected subagent row — the keyboard twin of a stable mouse hover. A second
/// press dismisses it. A no-op (status hint) when no subagent row is selected
/// (the cursor is on `main`, or the pane is empty). Sets `needs_redraw` so the
/// popover paints immediately.
fn toggle_subagent_preview(app: &mut TuiApp) {
    // A second press dismisses the open preview — a clean toggle.
    if app.subagent_preview.is_some() {
        app.subagent_preview = None;
        app.status = "subagent preview closed".to_string();
        app.needs_redraw = true;
        return;
    }
    // Pane row 0 is `main`; a subagent lives on row `index + 1`.
    let Some(index) = app.subagent_pane.selected.checked_sub(1) else {
        app.status = "no subagent selected — nothing to preview".to_string();
        app.needs_redraw = true;
        return;
    };
    let Some(preview) = build_subagent_preview(app, index, hover_preview::PreviewSource::Keyboard)
    else {
        app.status = "no subagent selected — nothing to preview".to_string();
        app.needs_redraw = true;
        return;
    };
    let hint = preview.activate_hint();
    let verb = if preview.can_jump() {
        format!("{} jumps", key_hint(app, keymap::Action::JumpToSubagent))
    } else {
        "read-only".to_string()
    };
    app.subagent_preview = Some(preview);
    app.status = format!("subagent preview ({verb}) \u{00b7} {hint} \u{00b7} Esc / Alt+6 close");
    app.needs_redraw = true;
}

/// Dismiss any live Subagent Hover Preview popover (§12.8.2). Called whenever the
/// surface shifts out from under it — a scroll, a click, a key that is not the
/// toggle, or a pane change — so a stale preview can never linger. Returns `true`
/// when a preview was actually showing (so the caller can fold the dismissal into
/// its existing redraw decision rather than forcing an extra one when idle).
fn dismiss_subagent_preview(app: &mut TuiApp) -> bool {
    if app.subagent_preview.take().is_some() {
        app.needs_redraw = true;
        true
    } else {
        false
    }
}

/// Dismiss a live Subagent Hover Preview popover (§12.8.2) ONLY when it was
/// revealed by a mouse hover — a keyboard-pinned (`Alt+6`) preview is left alone,
/// mirroring [`dismiss_mouse_hover_preview`]. Used by the mouse-move hover path so
/// an incidental pointer drift off the row never yanks a keyboard-only user's
/// pinned peek away.
fn dismiss_mouse_subagent_preview(app: &mut TuiApp) {
    if app
        .subagent_preview
        .as_ref()
        .is_some_and(|p| !p.is_keyboard())
    {
        dismiss_subagent_preview(app);
    }
}

/// Handle a key while the Contextual Action Palette (§12.1.2) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). The toggle chord (`Alt+Enter`) and Esc close; Up/Down (and k/j) move
/// the action cursor; Enter (and l/→) runs the selected action on the focused
/// unit.
fn handle_action_palette_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.action_palette.is_none() {
        return false;
    }
    // The overlay's own toggle chord (`Alt+Enter` by default) closes it, so the
    // same key both opens and closes — without leaking to the global keymap, which
    // the modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::OpenActionPalette) {
        app.action_palette = None;
        app.status = "actions closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    match key.code {
        KeyCode::Esc => {
            app.action_palette = None;
            app.status = "actions closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            if let Some(palette) = app.action_palette.as_mut() {
                palette.move_up();
            }
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if let Some(palette) = app.action_palette.as_mut() {
                palette.move_down();
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char('l') | KeyCode::Right => {
            run_selected_action_palette_action(app);
        }
        // Swallow every other key so the palette is modal: a stray keystroke
        // cannot leak into the composer underneath while the palette owns focus.
        _ => {}
    }
    true
}

/// Run the action under the Contextual Action Palette's cursor (§12.1.2) on the
/// focused unit, then close the palette. Resolves the palette's stable entry id to
/// a live entry (a no-op status hint if it dropped out), focuses it so every
/// downstream handler — copy / quote / annotate / detail / fold / related / jump —
/// acts on the right unit, and routes the action to the SAME handler its own chord
/// already drives. The palette closes after running so the menu is a one-shot
/// pick. Closing-actions (annotate / open-in-detail / related links) open their own
/// surface; the rest leave the main view in place.
fn run_selected_action_palette_action(app: &mut TuiApp) {
    let Some(palette) = app.action_palette.as_ref() else {
        return;
    };
    let entry_id = palette.entry_id;
    let Some(action) = palette.selected_action() else {
        app.action_palette = None;
        app.status = "actions: nothing to run".to_string();
        app.needs_redraw = true;
        return;
    };
    // Resolve the focused entry to a live index up front; if it dropped out of the
    // transcript while the palette was open, report an honest no-op.
    let Some(index) = active_selected_index_for_entry(app, entry_id) else {
        app.action_palette = None;
        app.status = "actions: entry is gone".to_string();
        app.needs_redraw = true;
        return;
    };
    // Focus the entry so every downstream handler acts on it (annotate / detail /
    // fold key off `selected_entry`; the copy verbs key off `copy_focus`).
    app.selected_entry = Some(index);
    set_copy_focus_to_entry(app, entry_id);
    // The palette is a one-shot pick: close it before running so a handler that
    // opens its own overlay (annotate / detail / related) is not painted under a
    // stale palette.
    app.action_palette = None;

    use action_palette::PaletteAction;
    match action {
        PaletteAction::CopyEntry => {
            copy_transcript_scope(app, copy::CopyScope::FocusedEntry, app.copy_format);
        }
        PaletteAction::CopyCode => {
            copy_transcript_scope(app, copy::CopyScope::AllCode, app.copy_format);
        }
        PaletteAction::CopyToolOutput => {
            copy_transcript_scope(app, copy::CopyScope::CurrentToolOutput, app.copy_format);
        }
        PaletteAction::QuoteToCompose => {
            quote_entry_to_compose(app, entry_id);
        }
        PaletteAction::Annotate => {
            annotate_focused_entry(app);
        }
        PaletteAction::OpenInDetail => {
            open_focused_entry_in_detail(app);
        }
        PaletteAction::ToggleFold => {
            if toggle_transcript_entry_fold(app, index) {
                let collapsed = app.transcript[index].collapsed;
                app.status = if collapsed {
                    "entry collapsed".to_string()
                } else {
                    "entry expanded".to_string()
                };
            }
        }
        PaletteAction::RelatedLinks => {
            toggle_related_links(app);
        }
        PaletteAction::JumpToEntry => {
            if jump_to_entry_id(app, entry_id) {
                app.status = "jumped to entry".to_string();
            } else {
                app.status = "could not jump to entry".to_string();
            }
        }
    }
    app.needs_redraw = true;
}

// ---- Actionable Tool Outputs (§12.3.1) ----

/// Largest number of characters of a tool result's output we scan for actionable
/// elements. A huge output (a multi-megabyte log dump) is bounded here so the
/// one-shot detection stays cheap; the actionable head is overwhelmingly where the
/// paths/errors/commands live.
const TOOL_ACTIONS_SCAN_CAP: usize = 64 * 1024;

/// Extract the human-visible output text of a tool result entry for actionable-
/// element detection (§12.3.1), or `None` when the entry is not a tool result.
/// Joins the common output channels (stdout, stderr, error, message, output, text)
/// the way the renderer surfaces them, falling back to the canonical content blob
/// for a structured-only payload — so a path/url/error printed on any channel is
/// scanned. Bounded by [`TOOL_ACTIONS_SCAN_CAP`].
fn tool_actions_output_text(entry: &TranscriptEntry) -> Option<String> {
    let TranscriptEntryKind::ToolResult(tool) = &entry.kind else {
        return None;
    };
    let content = &tool.result.content;
    let mut parts: Vec<String> = Vec::new();
    for key in ["stdout", "output", "text", "stderr", "error", "message"] {
        if let Some(text) = content.get(key).and_then(|v| v.as_str())
            && !text.trim().is_empty()
        {
            parts.push(text.to_string());
        }
    }
    let joined = if parts.is_empty() {
        // Structured-only result: scan the canonical content blob so an
        // `{"error": ...}`-shaped payload still surfaces.
        content.to_string()
    } else {
        parts.join("\n")
    };
    if joined.len() > TOOL_ACTIONS_SCAN_CAP {
        // Keep the actionable head on a char boundary.
        let mut end = TOOL_ACTIONS_SCAN_CAP;
        while !joined.is_char_boundary(end) {
            end -= 1;
        }
        Some(joined[..end].to_string())
    } else {
        Some(joined)
    }
}

/// A short, bounded, secret-free title for the focused tool result the overlay
/// acts on — its tool name. Falls back to a generic noun when the name is empty.
fn tool_actions_title(entry: &TranscriptEntry) -> String {
    let TranscriptEntryKind::ToolResult(tool) = &entry.kind else {
        return "tool result".to_string();
    };
    let name = tool.result.tool_name.trim();
    if name.is_empty() {
        "tool result".to_string()
    } else {
        let capped: String = name.chars().take(ACTION_PALETTE_TITLE_CAP).collect();
        capped
    }
}

/// `Ctrl+Alt+A`: open / close the Actionable Tool Outputs overlay (§12.3.1) for the
/// focused (or top-visible) tool result. On open it resolves the focused entry, and
/// — when that entry is a tool result — scans its output once into actionable items
/// (file paths, URLs, errors, diffs, commands) and opens the list parked on the
/// first item. When the focused entry is not a tool result (or the transcript is
/// empty) it reports an honest status hint and opens nothing. The items are a
/// one-shot snapshot, so there is no per-frame rebuild and an idle session pays
/// nothing.
fn toggle_tool_actions(app: &mut TuiApp) {
    if app.tool_actions.is_some() {
        app.tool_actions = None;
        app.status = "tool actions closed".to_string();
        app.needs_redraw = true;
        return;
    }
    let Some(entry_id) = annotation_target_entry_id(app) else {
        app.status = "no transcript entry — nothing to act on".to_string();
        app.needs_redraw = true;
        return;
    };
    let entries = active_transcript_entries(app);
    let Some(entry) = entries.iter().find(|entry| entry.id == entry_id) else {
        app.status = "no transcript entry — nothing to act on".to_string();
        app.needs_redraw = true;
        return;
    };
    let Some(text) = tool_actions_output_text(entry) else {
        app.status = "tool actions: focus a tool result first".to_string();
        app.needs_redraw = true;
        return;
    };
    let title = tool_actions_title(entry);
    let items = tool_actions::detect_actionable_items(entry_id, &text);
    let overlay = tool_actions::ToolActions::open(entry_id, title.clone(), items);
    app.status = if overlay.is_empty() {
        format!("tool actions for {title} (none detected) — Esc to close")
    } else {
        format!(
            "tool actions: {} — \u{2191}\u{2193} select \u{00b7} Enter copy \u{00b7} j jump \u{00b7} Esc close",
            overlay.summary(),
        )
    };
    app.tool_actions = Some(overlay);
    app.needs_redraw = true;
}

/// Handle a key while the Actionable Tool Outputs overlay (§12.3.1) is open.
/// Returns `true` when the key was consumed (so it never leaks to the composer or
/// global keymap). The overlay's own toggle chord (`Ctrl+Alt+A`) and Esc close;
/// Up/Down (and k/j... wait — `j` is the jump verb here, so only `k`/Up move up and
/// only Down moves down) move the item cursor; Enter (and `c`) copies the selected
/// element; `j`/→/`l` jumps the main view to the source tool result.
fn handle_tool_actions_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.tool_actions.is_none() {
        return false;
    }
    // The overlay's own toggle chord closes it, so the same key both opens and
    // closes — without leaking to the global keymap, which the modal swallows.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleToolActions) {
        app.tool_actions = None;
        app.status = "tool actions closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    match key.code {
        KeyCode::Esc => {
            app.tool_actions = None;
            app.status = "tool actions closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            if let Some(actions) = app.tool_actions.as_mut() {
                actions.move_up();
            }
            app.needs_redraw = true;
        }
        KeyCode::Down => {
            if let Some(actions) = app.tool_actions.as_mut() {
                actions.move_down();
            }
            app.needs_redraw = true;
        }
        // Enter / `c` copy the matched element — the primary, always-available verb.
        KeyCode::Enter | KeyCode::Char('c') => {
            tool_actions_copy_selected(app);
        }
        // `j` / → / `l` jump the main view to the source tool result.
        KeyCode::Char('j') | KeyCode::Right | KeyCode::Char('l') => {
            tool_actions_jump_to_source(app);
        }
        // Swallow every other key so the overlay is modal: a stray keystroke cannot
        // leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Copy the selected actionable item's matched element to the clipboard (§12.3.1),
/// routing through the single `deliver_copy` funnel so the copy lands, is recorded
/// in the in-app clipboard history, and toasts exactly like every other copy verb.
/// A no-op status hint when there is nothing selected (an empty detection). The
/// overlay stays open so the user can copy several elements in a row.
fn tool_actions_copy_selected(app: &mut TuiApp) {
    let Some((kind, text, primary)) = app
        .tool_actions
        .as_ref()
        .and_then(|a| a.selected_item())
        // The clipboard payload is the untruncated `copy_text`, never the capped
        // display `text` — copying must never deliver a `\u{2026}`-ellipsized slice.
        .map(|item| (item.kind, item.copy_text.clone(), item.primary_action()))
    else {
        app.status = "tool actions: nothing to copy".to_string();
        app.needs_redraw = true;
        return;
    };
    // The item's primary (Enter / click) action; copy today, but routed through the
    // model so a future primary verb lands here without a new dispatch site.
    match primary {
        tool_actions::WorkflowAction::Copy => {
            deliver_copy(app, &text, &format!("{} (tool action)", kind.label()));
        }
        tool_actions::WorkflowAction::Jump => {
            tool_actions_jump_to_source(app);
            return;
        }
    }
    app.needs_redraw = true;
}

/// Jump the main view to the tool result the selected actionable item came from
/// (§12.3.1) and close the overlay, reusing the same `jump_to_entry_id` path the
/// index / minimap / error-lens jumps use. A no-op status hint when there is
/// nothing selected or the source entry has dropped out of the transcript.
fn tool_actions_jump_to_source(app: &mut TuiApp) {
    let Some(entry_id) = app.tool_actions.as_ref().map(|a| a.entry_id()) else {
        app.status = "tool actions: nothing to jump to".to_string();
        app.needs_redraw = true;
        return;
    };
    app.tool_actions = None;
    if jump_to_entry_id(app, entry_id) {
        app.status = "jumped to tool result".to_string();
    } else {
        app.status = "tool actions: could not jump".to_string();
    }
    app.needs_redraw = true;
}

/// Resolve a stable transcript entry id to its current index in the active
/// transcript, or `None` when the id is no longer present. Identity is the stable
/// id; the position is derived on demand so a concurrent rebuild cannot stale it.
fn active_selected_index_for_entry(app: &TuiApp, entry_id: u64) -> Option<usize> {
    active_transcript_entries(app)
        .iter()
        .position(|entry| entry.id == entry_id)
}

/// Quote the focused entry's prose into the composer (the palette's "quote into
/// composer" verb, §12.1.2). Pulls the entry's plain content (message body or
/// reasoning text), wraps it as a Markdown blockquote via the same
/// `quote_compose::quote_block` formatter the selection-quote verb uses, and
/// inserts it at the cursor. A no-op (status hint) when the entry has no quotable
/// prose. Builds off transcript metadata, never rendered cells, so it cannot leak
/// a wall of terminal chrome into the composer.
fn quote_entry_to_compose(app: &mut TuiApp, entry_id: u64) {
    let text = active_transcript_entries(app)
        .iter()
        .find(|entry| entry.id == entry_id)
        .and_then(|entry| match &entry.kind {
            TranscriptEntryKind::Message(item) => Some(item.content.clone()),
            TranscriptEntryKind::Reasoning(snapshot) => Some(snapshot.display_text.clone()),
            _ => None,
        });
    let Some(text) = text else {
        app.status = "nothing to quote from this entry".to_string();
        return;
    };
    let Some(block) = quote_compose::quote_block(&text) else {
        app.status = "nothing to quote from this entry".to_string();
        return;
    };
    let lines = block.lines().filter(|l| !l.is_empty()).count();
    input::insert_input_text(app, &block);
    app.status = if lines == 1 {
        "quoted entry (1 line) into composer".to_string()
    } else {
        format!("quoted entry ({lines} lines) into composer")
    };
}

// ---- Universal Command Palette (§12.1.1) ----

/// `Ctrl+Alt+P`: toggle the Universal Command Palette (§12.1.1). Opening it builds
/// the command list fresh from the keymap action registry + the slash-command help
/// table (so an unopened session pays nothing), parks the cursor at the top, and
/// confirms via the status line; closing it drops the model entirely. Sets
/// `needs_redraw` so the toggle paints immediately.
fn toggle_command_palette(app: &mut TuiApp) {
    if app.command_palette.is_some() {
        app.command_palette = None;
        app.status = "command palette closed".to_string();
    } else {
        let palette = command_palette::CommandPalette::build(&app.keymap, app.turn_rx.is_some());
        app.status = format!(
            "command palette: {} commands \u{00b7} type to filter \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter run \u{00b7} Esc close",
            palette.len(),
        );
        app.command_palette = Some(palette);
    }
    app.needs_redraw = true;
    // Opening (or closing) the command palette is the user demonstrating they
    // already know the chord, so the §12.1.8 PaletteChord hint fades — once used.
    note_first_run_hint_used(app, first_run_hints::HintId::PaletteChord);
}

/// `Ctrl+Alt+H`: toggle Mouse Hover Intent (§12.1.3) on/off. Flips the
/// [`hover_intent::HoverIntentState`] enable flag (which also clears any in-flight
/// hover target when turning off, so a stale affordance can't linger), reports the
/// new state on the status line, and requests a redraw so the change paints
/// immediately.
fn toggle_hover_intent(app: &mut TuiApp) {
    let enabled = app.hover_intent.toggle();
    app.status = if enabled {
        "hover intent on".to_string()
    } else {
        "hover intent off".to_string()
    };
    app.needs_redraw = true;
    // Toggling hover intent (and a live hover reveal) is the user demonstrating they
    // already know the peek affordance, so the §12.1.8 Hover hint fades — once used.
    note_first_run_hint_used(app, first_run_hints::HintId::Hover);
}

/// Record that the user performed the interaction a §12.1.8 first-run hint teaches,
/// so the hint *fades once used*. Latches the hint seen; if a hint line was actually
/// painted, requests one final redraw to erase it. A cheap no-op once the engine is
/// quiet, so the call sites pay nothing after every hint is learned.
fn note_first_run_hint_used(app: &mut TuiApp, id: first_run_hints::HintId) {
    if app.first_run_hints.note_used(id) {
        app.needs_redraw = true;
    }
}

/// `Ctrl+Alt+N` (and a click on the dim hint strip): dismiss the gentle First-Run
/// Interaction Hint (§12.1.8) currently shown, latching it seen so it never returns.
/// Returns `true` when a hint was actually dismissed (so the keymap dispatch reports
/// the key consumed); `false` — a fall-through — when nothing was showing, so the
/// chord never steals a key from the composer or the surface beneath.
fn dismiss_first_run_hint(app: &mut TuiApp) -> bool {
    match app.first_run_hints.dismiss() {
        Some(_) => {
            app.status = "hint dismissed".to_string();
            app.needs_redraw = true;
            true
        }
        None => false,
    }
}

/// The live message for a §12.1.8 hint, with the user's *current* binding for the
/// interaction it teaches substituted in (so a rebound key shows the real chord,
/// never a stale default). Pure read over the keymap.
fn first_run_hint_message(app: &TuiApp, id: first_run_hints::HintId) -> String {
    let chord = match id {
        first_run_hints::HintId::PaletteChord => {
            key_hint(app, keymap::Action::ToggleCommandPalette)
        }
        // Jumping has two verbs (prev/next user turn); the "next" binding is the
        // representative chord shown, matching how the breadcrumbs/jump family names
        // its forward verb.
        first_run_hints::HintId::Jump => key_hint(app, keymap::Action::JumpNextUserTurn),
        // The Hover hint carries no chord (it names the focus keys inline), so the
        // substitution argument is ignored.
        first_run_hints::HintId::Hover => String::new(),
    };
    id.message(&chord)
}

/// Whether the §12.1.8 first-run hint strip must stay hidden this frame: a modal,
/// fullscreen overlay, command palette, search input, or paste flow owns the
/// surface (the spec's "suppress during modals, approvals, command palette, search
/// input, paste preview, and inline edits"). Pure read over `app`. When `true`, the
/// hint neither paints nor burns its single showing — it reappears (still un-seen)
/// once the surface clears.
fn first_run_hint_suppressed(app: &TuiApp) -> bool {
    app.config_screen.is_some()
        || app.status_line_setup.is_some()
        || app.transcript_overlay.is_some()
        || app.command_palette.is_some()
        || app.action_palette.is_some()
        || app.tool_actions.is_some()
        || app.paste_preview.is_some()
        || app.paste_transform.is_some()
        || app.clipboard_history_open
        || app.snippets_open
        || app.scratchpad_open
        || app.templates_open
        || app.search.is_some()
        || app.pending_approval.is_some()
        || app.pending_request_user_input.is_some()
        || app.pending_mcp_elicitation.is_some()
        // Any fullscreen §12 overlay owns the surface; while one is open the hint
        // would paint behind it, so suppress.
        || app.transcript_index_open
        || app.related_links_open
        || app.duplicate_folds_open
        || app.error_lens_open
        || app.health_markers_open
        || app.turn_outline_open
        || app.lane_fold_open
        || app.bookmarks_open
        || app.session_timeline_open
        || app.subagent_timeline_open
        || app.changes_since_open
        || app.annotations_open
        || app.breadcrumbs_open
        || app.editor_handoff.is_some()
        || app.theme_editor.is_some()
        || app.workspace_profile.is_some()
        // The Session Auto-Save Checkpoints overlay (§12.9.5) owns the surface too.
        || app.session_checkpoint_overlay.is_some()
        // The remaining §12.7 fullscreen overlays own the surface too, so the hint
        // would paint behind them — suppress for all six consistently.
        || app.keybinding_editor.is_some()
        || app.terminal_profile_editor.is_some()
        || app.gesture_settings_editor.is_some()
        || app.glyph_mode_editor.is_some()
        // The Smart Split Panes inspector (§12.4.2) owns the surface too, so the
        // hint would paint behind it — suppress.
        || app.smart_split.is_some()
        // Zen Mode (§12.4.5) is the distraction-free layout; the gentle teaching
        // hint is exactly the secondary noise zen exists to hide, so suppress it
        // while zen is on.
        || app.zen.chrome_suppressed()
}

/// Detect the degraded-terminal suggestion to offer this frame (§12.9.4), or
/// `None` when the terminal is not degraded (or already at every suggested mode).
/// Reads the live §12.7.3 capability probe, the painted size, and the modes the
/// renderer is currently drawing with, then defers to the pure
/// [`degraded_mode::DegradedModeSuggestor::detect`] rule so the banner render and
/// the unit tests evaluate identical logic. Best-effort and side-effect-free.
fn detect_degraded_suggestion(app: &TuiApp) -> Option<degraded_mode::DegradedSuggestion> {
    let caps = terminal_profile::TerminalCapabilities::detect();
    let (cols, rows) = app.off_frame_terminal_size();
    // The mouse policy the renderer would resolve for this terminal (the §12.7.3
    // override pin if the user set one this session, else the built-in default), so
    // a "mouse off" suggestion is suppressed when mouse is already off.
    let current_mouse = app
        .terminal_profile_override
        .map(|p| p.mouse)
        .unwrap_or_else(|| terminal_profile::TerminalProfile::resolve(caps).mouse);
    degraded_mode::DegradedModeSuggestor::detect(
        caps,
        cols,
        rows,
        app.glyph_mode,
        app.density_override,
        current_mouse,
    )
}

/// Whether the §12.9.4 degraded-mode suggestion banner must stay hidden this frame.
/// Shares the §12.1.8 first-run-hint suppression set (a modal / fullscreen overlay
/// / command palette / search / paste flow owns the surface), so the proactive
/// banner never paints behind a modal. Pure read over `app`.
fn degraded_suggestion_suppressed(app: &TuiApp) -> bool {
    first_run_hint_suppressed(app)
}

/// `Ctrl+Alt+;` (and a click on the banner's `[accept]` affordance): accept the
/// proactively-shown degraded-mode suggestion (§12.9.4), applying the suggested
/// minimal-glyph chrome / compact density / mouse-off modes to the live session and
/// persisting them, then latching the suggestion so it never nags again. Returns
/// `true` only when a suggestion was actually showing (so the keymap dispatch
/// reports the key consumed); `false` — a fall-through — when nothing is showing, so
/// the chord never steals a key from the composer or the surface beneath.
fn accept_degraded_suggestion(app: &mut TuiApp) -> bool {
    // Only act when a banner is actually on screen (the same gate the dismiss path
    // uses), so the accept chord is a no-op fall-through otherwise.
    if !app.degraded_suggestion.is_showing() {
        return false;
    }
    let Some(suggestion) = detect_degraded_suggestion(app) else {
        // Showing flag set but the condition cleared this frame: latch it closed
        // without applying anything stale.
        app.degraded_suggestion.accept();
        app.needs_redraw = true;
        return true;
    };
    let target = suggestion.target();
    let mut applied: Vec<&'static str> = Vec::new();

    // Glyph mode → ASCII chrome: apply in-session immediately (the renderer reads
    // `app.glyph_mode` every frame) and persist via the same `[tui].glyph_mode`
    // path the §12.7.6 editor commits through.
    if let Some(mode) = target.glyph_mode {
        app.glyph_mode = mode;
        persist_glyph_mode(app, mode);
        applied.push("ASCII chrome");
    }
    // Density → pinned compact: apply in-session and persist via the same
    // `[tui].density` path the §12.4.1 cycle persists through.
    if let Some(mode) = target.density {
        app.density_override = mode;
        persist_density(app, mode);
        applied.push("compact density");
    }
    // Mouse → off: record the §12.7.3 per-terminal policy override (mouse disabled)
    // so the preference is honored and persisted; the live capture state is owned by
    // the terminal guard and reconciled on the next enter-setup.
    if let Some(mouse) = target.mouse {
        apply_degraded_mouse_override(app, mouse);
        applied.push("mouse off");
    }

    app.degraded_suggestion.accept();
    app.status = if applied.is_empty() {
        "degraded-mode suggestion accepted".to_string()
    } else {
        format!("\u{2713} degraded mode: {}", applied.join(" + "))
    };
    app.needs_redraw = true;
    true
}

/// `Ctrl+Alt+'` (and a click on the banner's `[dismiss]` affordance): dismiss the
/// proactively-shown degraded-mode suggestion (§12.9.4), latching it for the session
/// so the same suggestion never returns. Returns `true` when a suggestion was
/// actually showing; `false` — a fall-through — when nothing is showing.
fn dismiss_degraded_suggestion(app: &mut TuiApp) -> bool {
    if !app.degraded_suggestion.is_showing() {
        return false;
    }
    app.degraded_suggestion.dismiss();
    app.status = "degraded-mode suggestion dismissed".to_string();
    app.needs_redraw = true;
    true
}

/// Persist a Minimal Glyph Mode pick to the user-scope config (§12.7.6) at
/// `[tui].glyph_mode`, mirroring the §12.7.6 editor's commit path. Best-effort: a
/// write failure leaves the in-session value in place and notes it in the status
/// line. Factored out so the §12.9.4 accept path persists exactly like the editor.
fn persist_glyph_mode(app: &mut TuiApp, mode: glyph_mode::GlyphMode) {
    use squeezy_core::settings_writer::{EditOp, SettingsEdit, SettingsScope, apply_edits};

    let target_path = app.user_settings_path();
    let scope_target = SettingsScope::user(&target_path);
    let edit = SettingsEdit {
        path: &["tui", "glyph_mode"],
        op: EditOp::SetString(mode.as_str().to_string()),
    };
    if let Err(err) = apply_edits(&scope_target, &[edit]) {
        app.status = format!("glyph mode set, but save failed: {err}");
    }
}

/// Record a §12.7.3 per-terminal mouse policy override (here: mouse disabled) for
/// the detected terminal and persist it under `[tui.terminal_profiles.<kind>]`, so
/// the §12.9.4 "mouse off" suggestion is honored and survives a restart. Caches the
/// override on the app so the §12.7.3 editor (and the next `detect`) sees it.
/// Best-effort: a write failure leaves the in-session override in place.
fn apply_degraded_mouse_override(app: &mut TuiApp, mouse: terminal_profile::MouseMode) {
    use squeezy_core::settings_writer::{EditOp, SettingsEdit, SettingsScope, apply_edits};

    let caps = terminal_profile::TerminalCapabilities::detect();
    let base = app
        .terminal_profile_override
        .unwrap_or_else(|| terminal_profile::TerminalProfile::resolve(caps));
    let working = terminal_profile::TerminalProfile { mouse, ..base };
    app.terminal_profile_override = Some(working);

    let kind = caps.kind.as_str();
    let [(glyph_k, glyph_v), (mouse_k, mouse_v), (color_k, color_v)] = working.as_config_pairs();
    let target_path = app.user_settings_path();
    let scope_target = SettingsScope::user(&target_path);
    let edit = SettingsEdit {
        path: &[],
        op: EditOp::SetTableEntry {
            table_path: &["tui", "terminal_profiles"],
            key: kind.to_string(),
            fields: vec![
                (glyph_k, EditOp::SetString(glyph_v.to_string())),
                (mouse_k, EditOp::SetString(mouse_v.to_string())),
                (color_k, EditOp::SetString(color_v.to_string())),
            ],
        },
    };
    if let Err(err) = apply_edits(&scope_target, &[edit]) {
        app.status = format!("mouse policy set, but save failed: {err}");
    }
}

/// Handle a key while the Universal Command Palette (§12.1.1) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). The toggle chord (`Ctrl+Alt+P`) and Esc close; Up/Down (and Ctrl+P/
/// Ctrl+N) move the cursor over the *visible* (filtered) list; Backspace edits the
/// query; a printable char types into the query (so a query containing 'k'/'j'/'n'
/// is never mistaken for a list verb — the list is fuzzy-filtered as you type);
/// Enter arms the highlighted command for the run loop to execute.
fn handle_command_palette_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.command_palette.is_none() {
        return false;
    }
    // The overlay's own toggle chord (`Ctrl+Alt+P` by default) closes it, so the
    // same key both opens and closes — without leaking to the global keymap, which
    // the modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleCommandPalette) {
        app.command_palette = None;
        app.status = "command palette closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    match key.code {
        KeyCode::Esc => {
            app.command_palette = None;
            app.status = "command palette closed".to_string();
            app.needs_redraw = true;
        }
        // Ctrl+P/Ctrl+N mirror the Up/Down cursor (the readline / editor idiom for
        // a filter list) so a hand on the home row can move without the arrows.
        KeyCode::Up | KeyCode::Char('p') if key.modifiers.contains(KeyModifiers::CONTROL) => {
            if let Some(palette) = app.command_palette.as_mut() {
                palette.move_up();
            }
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('n') if key.modifiers.contains(KeyModifiers::CONTROL) => {
            if let Some(palette) = app.command_palette.as_mut() {
                palette.move_down();
            }
            app.needs_redraw = true;
        }
        KeyCode::Backspace => {
            if let Some(palette) = app.command_palette.as_mut() {
                palette.pop_char();
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter => command_palette_run_selected(app),
        // A printable character (no Ctrl/Alt) types into the fuzzy query.
        KeyCode::Char(ch)
            if !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT) =>
        {
            if let Some(palette) = app.command_palette.as_mut() {
                palette.push_char(ch);
            }
            app.needs_redraw = true;
        }
        // Swallow every other key so the overlay is modal: a stray keystroke cannot
        // leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Run the highlighted command in the Universal Command Palette (§12.1.1). The
/// mouse twin (a row click → [`command_palette_select_run`]) routes here too via a
/// resolved visible index. A disabled command reports its reason and stays open; an
/// available command closes the palette and arms `command_palette_pending` for the
/// run loop to execute (the loop owns the `agent`, so a keymap action re-dispatches
/// through exactly the path its keybinding uses, and a slash command is handed to
/// the composer). A no-op (status hint) on an empty filtered list.
fn command_palette_run_selected(app: &mut TuiApp) {
    let Some(entry) = app
        .command_palette
        .as_ref()
        .and_then(|palette| palette.selected_entry())
    else {
        app.status = "command palette: no command matches".to_string();
        app.needs_redraw = true;
        return;
    };
    arm_command_palette_run(app, entry);
}

/// Resolve a *visible* command row (the click path) and run it (§12.1.1). Keeps the
/// mouse and keyboard run paths on one body so they can never diverge.
fn command_palette_select_run(app: &mut TuiApp, index: usize) {
    let Some(entry) = app
        .command_palette
        .as_ref()
        .and_then(|palette| palette.entry_at(index))
    else {
        app.status = "command palette: no command there".to_string();
        app.needs_redraw = true;
        return;
    };
    arm_command_palette_run(app, entry);
}

/// Shared tail for both palette run paths: a disabled command reports its reason and
/// stays open; an available one closes the palette and arms the pending run.
fn arm_command_palette_run(app: &mut TuiApp, entry: command_palette::CommandEntry) {
    if let Some(reason) = entry.disabled_reason {
        app.status = format!("{} {reason}", entry.label);
        app.needs_redraw = true;
        return;
    }
    app.command_palette = None;
    app.command_palette_pending = Some(entry.run);
    app.needs_redraw = true;
}

/// Drain a command armed by the Universal Command Palette (§12.1.1). Called from
/// the run loop after a key / mouse event, where the `agent` is in scope. A keymap
/// action is re-dispatched through `dispatch_keymap_action` — the exact path its
/// keybinding uses, so the palette can never diverge from the bound key — by
/// synthesizing the action's resolved `KeyEvent`. A slash command is handed back to
/// the composer: a parameter command is pre-seeded with a trailing space and parks
/// the user in the composer (the spec's "second step"), and a parameterless command
/// is filled in ready to send. A no-op when nothing is pending.
async fn drain_command_palette_run(app: &mut TuiApp, agent: &mut Agent) -> Result<()> {
    let Some(run) = app.command_palette_pending.take() else {
        return Ok(());
    };
    match run {
        command_palette::PaletteRun::Action(action) => {
            // Dispatch the SELECTED action directly (not via a synthesized key).
            // The reverse-lookup `by_key` table keeps only one winner per chord, so
            // re-deriving the action from the chord would silently run the colliding
            // WINNER when the user picked the LOSER by name (deep-review #109).
            // Routing through `dispatch_resolved_keymap_action` still applies the
            // same context guards and macro capture a pressed key would.
            let _ = dispatch_resolved_keymap_action(app, agent, action);
            app.needs_redraw = true;
        }
        command_palette::PaletteRun::Slash {
            name,
            has_parameter,
        } => {
            // Hand the command to the composer through the same `set_input` path the
            // rest of the TUI uses (it clears stale prompt attachments and clamps the
            // slash-menu / cursor invariants). A parameter command leaves a trailing
            // space and parks the user there to complete it; a parameterless command
            // is filled in ready to send with Enter.
            let text = if has_parameter {
                format!("{name} ")
            } else {
                name.to_string()
            };
            input::set_input(app, text);
            app.status = if has_parameter {
                format!("{name} — add arguments, then Enter to send")
            } else {
                format!("{name} — Enter to send")
            };
            app.needs_redraw = true;
        }
    }
    Ok(())
}

/// `Alt+z`: toggle the Collapsible Reasoning/Tool Lanes overlay (§12.2.2). The
/// overlay is a per-entry panel that splits the focused transcript entry into
/// foldable lanes (reasoning, assistant text, tool input/output, system notice,
/// approval, error, plan), each with a collapse toggle so whole lanes can be
/// folded away. Opening it refreshes the lane panel for the focused entry (a
/// no-op rebuild when neither the entry nor the collapse state changed since the
/// last refresh, so the cost is only paid on a real change), resets the lane
/// cursor, and confirms via the status line. Sets `needs_redraw` so the toggle
/// paints immediately.
fn toggle_lane_fold(app: &mut TuiApp) {
    app.lane_fold_open = !app.lane_fold_open;
    if app.lane_fold_open {
        refresh_lane_fold(app);
        app.lane_fold_selected = 0;
        app.status = if app.lane_panel.is_empty() {
            "lane folds (no entry to fold) — Esc to close".to_string()
        } else {
            format!(
                "lane folds: {} — \u{2191}\u{2193} select \u{00b7} Enter fold \u{00b7} Esc close",
                app.lane_panel.summary(),
            )
        };
    } else {
        app.status = "lane folds closed".to_string();
    }
    app.needs_redraw = true;
}

/// Handle a key while the Collapsible Reasoning/Tool Lanes overlay (§12.2.2) is
/// open. Returns `true` when the key was consumed (so it never leaks to the
/// composer or global keymap). Mirrors the other overlays'
/// before-the-global-keymap modal consumption: the toggle chord (`Alt+z`) and
/// Esc close; Up/Down (and k/j) move the lane cursor; Enter/Space toggle the
/// selected lane's collapsed state; `c` collapses every lane and `o` expands
/// every lane (the bulk verbs the status line advertises).
fn handle_lane_fold_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.lane_fold_open {
        return false;
    }
    // The overlay's own toggle chord (`Alt+z` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap, which the
    // modal swallows below.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleLaneFold) {
        app.lane_fold_open = false;
        app.status = "lane folds closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.lane_panel.len();
    match key.code {
        KeyCode::Esc => {
            app.lane_fold_open = false;
            app.status = "lane folds closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.lane_fold_selected = app.lane_fold_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.lane_fold_selected = (app.lane_fold_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        KeyCode::Enter | KeyCode::Char(' ') => {
            lane_fold_toggle_selected(app);
        }
        // Collapse every lane / expand every lane in one go.
        KeyCode::Char('c') => lane_fold_set_all(app, true),
        KeyCode::Char('o') => lane_fold_set_all(app, false),
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Toggle the collapsed state of the lane the overlay cursor is on (§12.2.2).
/// Resolves the lane at the cursor, flips its `(entry_id, lane_id)` entry in the
/// persisted [`lane_fold::LaneFoldStore`], refreshes the panel so the new state
/// is reflected, and reports the lane/state in the status line. A no-op (status
/// hint) when there is nothing to toggle.
fn lane_fold_toggle_selected(app: &mut TuiApp) {
    let Some((key, lane_id)) = app
        .lane_panel
        .get(app.lane_fold_selected)
        .map(|lane| (lane.key, lane.id()))
    else {
        app.status = "lane folds: nothing to fold".to_string();
        return;
    };
    let now_collapsed = app.lane_folds.toggle(key);
    // The toggle bumped the store generation, so the panel fingerprint moved;
    // refresh re-projects with the new collapse state.
    refresh_lane_fold(app);
    let position = app.lane_fold_selected + 1;
    let total = app.lane_panel.len();
    let verb = if now_collapsed {
        "collapsed"
    } else {
        "expanded"
    };
    app.status = format!(
        "lane folds {position}/{total} [{}] {verb} — Esc close",
        lane_id.label(),
    );
    app.needs_redraw = true;
}

/// Collapse (`collapse = true`) or expand (`collapse = false`) every lane of the
/// focused entry in one pass (§12.2.2) — the overlay's `c`/`o` bulk verbs. Mutates
/// the persisted store once, refreshes the panel, and reports the result.
fn lane_fold_set_all(app: &mut TuiApp, collapse: bool) {
    let keys = app.lane_panel.keys();
    if keys.is_empty() {
        app.status = "lane folds: nothing to fold".to_string();
        return;
    }
    if collapse {
        app.lane_folds.collapse_all(keys);
    } else {
        app.lane_folds.expand_all(keys);
    }
    refresh_lane_fold(app);
    let verb = if collapse {
        "collapsed all lanes"
    } else {
        "expanded all lanes"
    };
    app.status = format!("lane folds: {verb} — Esc close");
    app.needs_redraw = true;
}

// ---- Reading Position Bookmarks (§12.2.4) ----

/// `Alt+t`: drop a Reading Position Bookmark at the entry currently at the top of
/// the viewport (§12.2.4). The bookmark anchors to the entry's stable id, so it
/// survives every later append, resize, fold, and filter. Dropped anonymous (the
/// overlay can name it later). A no-op (status hint) on an empty transcript.
fn drop_bookmark(app: &mut TuiApp) {
    let Some(entry_id) = current_top_entry_id(app) else {
        app.status = "no transcript to bookmark".to_string();
        return;
    };
    app.bookmarks.add(entry_id, None);
    let label = jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
    let count = app.bookmarks.len();
    app.status = format!("bookmark dropped at {label} ({count} total) — Alt+q to list");
    app.needs_redraw = true;
}

/// `Alt+q`: toggle the Reading Position Bookmarks overlay (§12.2.4) — a list of
/// every bookmark in transcript-reading order. Opening it parks the cursor on the
/// nearest bookmark to the current reading position (so the list opens where the
/// user is looking), leaves rename mode off, and confirms via the status line.
/// Sets `needs_redraw` so the toggle paints immediately.
fn toggle_bookmarks(app: &mut TuiApp) {
    app.bookmarks_open = !app.bookmarks_open;
    if app.bookmarks_open {
        app.bookmark_rename = None;
        // Park the cursor on the bookmark nearest the current reading position so
        // the list opens where the user is looking. Stale-but-still-anchored
        // bookmarks are kept and shown as "unresolved" at paint time (per the
        // spec) rather than pruned; a hard transcript reset clears the whole store
        // at the rebuild site instead.
        app.bookmarks_selected = bookmark_cursor_near_current(app);
        app.status = if app.bookmarks.is_empty() {
            "bookmarks (none yet) — Alt+t to drop one \u{00b7} Esc close".to_string()
        } else {
            format!(
                "bookmarks: {} \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} r rename \u{00b7} d delete \u{00b7} Esc close",
                app.bookmarks.len(),
            )
        };
    } else {
        app.bookmark_rename = None;
        app.status = "bookmarks closed".to_string();
    }
    app.needs_redraw = true;
}

/// The list index of the bookmark nearest the current top-of-view reading
/// position, so the overlay opens with its cursor where the user is. Prefers the
/// first bookmark at or after the position; when the view sits past every bookmark
/// (nothing after it) it parks on the last bookmark via the reverse walk instead
/// of wrapping to the top. `0` on an empty store.
fn bookmark_cursor_near_current(app: &TuiApp) -> usize {
    let current = current_top_entry_id(app);
    // Prefer the first bookmark at or after the view; when the view sits past
    // every bookmark, `prev` parks on the last one rather than wrapping to the
    // top. Both use the store's reading-order walks.
    let after_is_real = current
        .map(|id| app.bookmarks.list().iter().any(|b| b.entry_id > id))
        .unwrap_or(true);
    let target = if after_is_real {
        app.bookmarks.next(current)
    } else {
        app.bookmarks.prev(current)
    };
    target
        .and_then(|b| app.bookmarks.index_of(b.id))
        .unwrap_or(0)
}

/// Step the overlay cursor to the next (`forward == true`) or previous bookmark in
/// the list (§12.2.4), wrapping around the ends — the overlay's `n`/`p`
/// "next/previous bookmark" verbs. The list is already in transcript-reading
/// order, so a position step is a reading-order step. A no-op on an empty list.
fn bookmark_step(app: &mut TuiApp, forward: bool) {
    let count = app.bookmarks.len();
    if count == 0 {
        return;
    }
    app.bookmarks_selected = if forward {
        (app.bookmarks_selected + 1) % count
    } else {
        (app.bookmarks_selected + count - 1) % count
    };
    app.needs_redraw = true;
}

/// Handle a key while the Reading Position Bookmarks overlay (§12.2.4) is open.
/// Returns `true` when the key was consumed (so it never leaks to the composer or
/// global keymap). In list mode: the toggle chord (`Alt+q`) and Esc close; ↑↓/kj
/// move the cursor; n/p step next/previous; Enter jumps to the selected
/// bookmark's entry; `r` enters rename mode; `d`/Delete deletes the selected
/// bookmark. In rename mode: free text edit, Enter commits, Esc cancels.
fn handle_bookmarks_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.bookmarks_open {
        return false;
    }
    // Rename mode owns every key: type a name, Enter commits, Esc cancels. Handled
    // first so a name containing 'd'/'n'/'q' is never mistaken for a list verb.
    if app.bookmark_rename.is_some() {
        handle_bookmark_rename_key(app, key);
        return true;
    }
    // The overlay's own toggle chord (`Alt+q` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleBookmarks) {
        app.bookmarks_open = false;
        app.status = "bookmarks closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.bookmarks.len();
    match key.code {
        KeyCode::Esc => {
            app.bookmarks_open = false;
            app.status = "bookmarks closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.bookmarks_selected = app.bookmarks_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.bookmarks_selected = (app.bookmarks_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        // Next / previous bookmark by reading order — the spec's next/previous
        // commands. Resolved through the store relative to the selected bookmark's
        // anchor so the step honors transcript order and wraps around the list.
        KeyCode::Char('n') => bookmark_step(app, true),
        KeyCode::Char('p') => bookmark_step(app, false),
        KeyCode::Enter => bookmark_jump_to_selected(app),
        // Begin renaming the selected bookmark: seed the buffer with its current
        // name so an edit (rather than a retype) is one keystroke away.
        KeyCode::Char('r') => bookmark_begin_rename(app),
        // Delete the selected bookmark.
        KeyCode::Char('d') | KeyCode::Delete => bookmark_delete_selected(app),
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Handle a key while the bookmark overlay is in rename mode (§12.2.4). Enter
/// commits the typed name (a blank clears the label, turning the bookmark
/// anonymous), Esc cancels without changing anything, Backspace deletes a char,
/// and a printable char is appended. Everything else is swallowed.
fn handle_bookmark_rename_key(app: &mut TuiApp, key: KeyEvent) {
    match key.code {
        KeyCode::Enter => {
            let name = app.bookmark_rename.take().unwrap_or_default();
            if let Some(bookmark) = app.bookmarks.get(app.bookmarks_selected) {
                let id = bookmark.id;
                app.bookmarks.rename(id, Some(name.clone()));
                let shown = if name.trim().is_empty() {
                    "(anonymous)".to_string()
                } else {
                    name.trim().to_string()
                };
                app.status = format!("bookmark renamed to {shown} — Esc close");
            } else {
                app.status = "bookmarks: nothing to rename".to_string();
            }
            app.needs_redraw = true;
        }
        KeyCode::Esc => {
            app.bookmark_rename = None;
            app.status = "rename cancelled — Esc close".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Backspace => {
            if let Some(buf) = app.bookmark_rename.as_mut() {
                buf.pop();
            }
            app.needs_redraw = true;
        }
        KeyCode::Char(ch) => {
            if let Some(buf) = app.bookmark_rename.as_mut() {
                buf.push(ch);
            }
            app.needs_redraw = true;
        }
        _ => {}
    }
}

/// Jump the main view to the entry the cursor's bookmark anchors (§12.2.4). The
/// mouse twin (a row click) routes here too. Resolves the anchor through the live
/// transcript; when the anchored entry is gone (a rebuild dropped it) the
/// bookmark is shown as unresolved rather than jumping incorrectly, per the spec's
/// stale-anchor risk mitigation. A no-op (status hint) on an empty list.
fn bookmark_jump_to_selected(app: &mut TuiApp) {
    let Some((entry_id, name)) = app
        .bookmarks
        .get(app.bookmarks_selected)
        .map(|b| (b.entry_id, b.display_name().to_string()))
    else {
        app.status = "bookmarks: nothing to jump to".to_string();
        return;
    };
    if jump_to_entry_id(app, entry_id) {
        let label = jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
        app.bookmarks_open = false;
        app.status = format!("jumped to bookmark {name} at {label}");
        app.needs_redraw = true;
    } else {
        // The anchored entry is gone (transcript rebuilt). Show it as unresolved
        // rather than jumping somewhere wrong.
        app.status = format!("bookmark {name} is unresolved (its entry is gone)");
        app.needs_redraw = true;
    }
}

/// Begin renaming the selected bookmark (§12.2.4): seed the rename buffer with the
/// bookmark's current name (empty for an anonymous one) so the overlay enters
/// text-input mode. A no-op (status hint) on an empty list.
fn bookmark_begin_rename(app: &mut TuiApp) {
    let Some(bookmark) = app.bookmarks.get(app.bookmarks_selected) else {
        app.status = "bookmarks: nothing to rename".to_string();
        return;
    };
    app.bookmark_rename = Some(bookmark.name.clone().unwrap_or_default());
    app.status = "rename bookmark: type a name \u{00b7} Enter save \u{00b7} Esc cancel".to_string();
    app.needs_redraw = true;
}

/// Delete the selected bookmark (§12.2.4), clamping the cursor so it stays in
/// range, and report the new count. A no-op (status hint) on an empty list.
fn bookmark_delete_selected(app: &mut TuiApp) {
    let Some(bookmark) = app.bookmarks.get(app.bookmarks_selected) else {
        app.status = "bookmarks: nothing to delete".to_string();
        return;
    };
    let id = bookmark.id;
    let name = bookmark.display_name().to_string();
    app.bookmarks.remove(id);
    let count = app.bookmarks.len();
    // Keep the cursor in range after the removal.
    if count == 0 {
        app.bookmarks_selected = 0;
    } else {
        app.bookmarks_selected = app.bookmarks_selected.min(count - 1);
    }
    app.status = format!("bookmark {name} deleted ({count} left) — Esc close");
    app.needs_redraw = true;
}

// ---- Entry Annotations (§12.2.5) ----

/// The transcript entry id the annotate verb attaches a note to: the focused
/// entry when one is focused (`Ctrl+↑/↓`), else the entry currently at the top of
/// the viewport (the same reading-position anchor the bookmark/jump-mark verbs
/// use). `None` only when the transcript is empty. Resolving to a stable id here
/// (not a row) is what lets the note survive every later reflow.
fn annotation_target_entry_id(app: &TuiApp) -> Option<u64> {
    if let Some(index) = active_selected_entry(app)
        && let Some(entry) = active_transcript_entries(app).get(index)
    {
        return Some(entry.id);
    }
    current_top_entry_id(app)
}

/// `Alt+/`: annotate the focused (or top-visible) transcript entry (§12.2.5).
/// Opens the annotations overlay straight into its composer so the user types the
/// note and presses Enter to attach it — the note lives only in session UI
/// metadata, never in the model transcript. When the targeted entry already
/// carries a note this edits the first one rather than stacking a duplicate. A
/// no-op (status hint) on an empty transcript.
fn annotate_focused_entry(app: &mut TuiApp) {
    let Some(entry_id) = annotation_target_entry_id(app) else {
        app.status = "no transcript entry to annotate".to_string();
        return;
    };
    app.annotations_open = true;
    // If the entry already has a note, edit the first one in place; otherwise
    // start a fresh note bound to this entry id (committed on Enter).
    if let Some(index) = app.annotations.first_index_for_entry(entry_id) {
        app.annotations_selected = index;
        let seed = app
            .annotations
            .get(index)
            .map(|a| a.text.clone())
            .unwrap_or_default();
        app.annotation_edit = Some(seed);
        app.annotation_edit_new_entry = None;
        app.status =
            "edit annotation: type a note \u{00b7} Enter save \u{00b7} Esc cancel".to_string();
    } else {
        app.annotation_edit = Some(String::new());
        app.annotation_edit_new_entry = Some(entry_id);
        let label = jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
        app.status =
            format!("annotate {label}: type a note \u{00b7} Enter save \u{00b7} Esc cancel");
    }
    app.needs_redraw = true;
}

/// `Alt+\\`: toggle the Entry Annotations overlay (§12.2.5) — a list of every
/// annotation in transcript-reading order. Opening it parks the cursor on the
/// annotation nearest the current reading position, leaves edit mode off, and
/// confirms via the status line. Sets `needs_redraw` so the toggle paints
/// immediately.
fn toggle_annotations(app: &mut TuiApp) {
    app.annotations_open = !app.annotations_open;
    if app.annotations_open {
        app.annotation_edit = None;
        app.annotation_edit_new_entry = None;
        app.annotations_selected = annotation_cursor_near_current(app);
        app.status = if app.annotations.is_empty() {
            "annotations (none yet) — Alt+/ to add one \u{00b7} Esc close".to_string()
        } else {
            format!(
                "annotations: {} \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} e edit \u{00b7} d delete \u{00b7} Esc close",
                app.annotations.len(),
            )
        };
    } else {
        app.annotation_edit = None;
        app.annotation_edit_new_entry = None;
        app.status = "annotations closed".to_string();
    }
    app.needs_redraw = true;
}

/// The list index of the annotation nearest the current top-of-view reading
/// position, so the overlay opens with its cursor where the user is. Prefers the
/// first annotation at or after the position; when the view sits past every
/// annotation it parks on the last one via the reverse walk instead of wrapping
/// to the top. `0` on an empty store.
fn annotation_cursor_near_current(app: &TuiApp) -> usize {
    let current = current_top_entry_id(app);
    let after_is_real = current
        .map(|id| app.annotations.list().iter().any(|a| a.entry_id > id))
        .unwrap_or(true);
    let target = if after_is_real {
        app.annotations.next(current)
    } else {
        app.annotations.prev(current)
    };
    target
        .and_then(|a| app.annotations.index_of(a.id))
        .unwrap_or(0)
}

/// Step the overlay cursor to the next (`forward == true`) or previous annotation
/// in the list (§12.2.5), wrapping around the ends — the overlay's `n`/`p`
/// "next/previous annotation" verbs. The list is already in transcript-reading
/// order, so a position step is a reading-order step. A no-op on an empty list.
fn annotation_step(app: &mut TuiApp, forward: bool) {
    let count = app.annotations.len();
    if count == 0 {
        return;
    }
    app.annotations_selected = if forward {
        (app.annotations_selected + 1) % count
    } else {
        (app.annotations_selected + count - 1) % count
    };
    app.needs_redraw = true;
}

/// Handle a key while the Entry Annotations overlay (§12.2.5) is open. Returns
/// `true` when the key was consumed (so it never leaks to the composer or global
/// keymap). In list mode: the toggle chord (`Alt+\\`) and Esc close; ↑↓/kj move the
/// cursor; n/p step next/previous; Enter jumps to the selected annotation's entry;
/// `e` edits the note in the composer; `d`/Delete deletes the selected annotation.
/// In edit mode: free text edit, Enter commits, Esc cancels.
fn handle_annotations_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if !app.annotations_open {
        return false;
    }
    // Edit mode owns every key: type a note, Enter commits, Esc cancels. Handled
    // first so a note containing 'd'/'n'/'e' is never mistaken for a list verb.
    if app.annotation_edit.is_some() {
        handle_annotation_edit_key(app, key);
        return true;
    }
    // The overlay's own toggle chord (`Alt+\\` by default) closes it, so the same
    // key both opens and closes — without leaking to the global keymap.
    if app.keymap.lookup(key.code, key.modifiers) == Some(keymap::Action::ToggleAnnotations) {
        app.annotations_open = false;
        app.status = "annotations closed".to_string();
        app.needs_redraw = true;
        return true;
    }
    let count = app.annotations.len();
    match key.code {
        KeyCode::Esc => {
            app.annotations_open = false;
            app.status = "annotations closed".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Up | KeyCode::Char('k') => {
            app.annotations_selected = app.annotations_selected.saturating_sub(1);
            app.needs_redraw = true;
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if count > 0 {
                app.annotations_selected = (app.annotations_selected + 1).min(count - 1);
            }
            app.needs_redraw = true;
        }
        // Next / previous annotation by reading order — the spec's next/previous
        // commands. The list is already in reading order, so a position step
        // honors transcript order and wraps around the list.
        KeyCode::Char('n') => annotation_step(app, true),
        KeyCode::Char('p') => annotation_step(app, false),
        KeyCode::Enter => annotation_jump_to_selected(app),
        // Begin editing the selected annotation's note: seed the composer with its
        // current text so a tweak (rather than a retype) is one keystroke away.
        KeyCode::Char('e') => annotation_begin_edit(app),
        // Delete the selected annotation.
        KeyCode::Char('d') | KeyCode::Delete => annotation_delete_selected(app),
        // Swallow every other key so the overlay is modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Handle a key while the annotations overlay is in edit/compose mode (§12.2.5).
/// Enter commits the typed note (a blank note deletes an existing annotation, or
/// cancels a brand-new one), Esc cancels without changing anything, Backspace
/// deletes a char, and a printable char is appended. Everything else is swallowed.
fn handle_annotation_edit_key(app: &mut TuiApp, key: KeyEvent) {
    match key.code {
        KeyCode::Enter => annotation_commit_edit(app),
        KeyCode::Esc => {
            app.annotation_edit = None;
            app.annotation_edit_new_entry = None;
            app.status = "edit cancelled — Esc close".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Backspace => {
            if let Some(buf) = app.annotation_edit.as_mut() {
                buf.pop();
            }
            app.needs_redraw = true;
        }
        KeyCode::Char(ch) => {
            if let Some(buf) = app.annotation_edit.as_mut() {
                buf.push(ch);
            }
            app.needs_redraw = true;
        }
        _ => {}
    }
}

/// Commit the composer buffer (§12.2.5). For a brand-new note (`Alt+/` on an
/// un-annotated entry) this adds the annotation; a blank note cancels instead of
/// adding an empty one. For an edit of an existing note, a blank note deletes it,
/// otherwise the text is replaced. Parks the cursor on the affected annotation.
fn annotation_commit_edit(app: &mut TuiApp) {
    let text = app.annotation_edit.take().unwrap_or_default();
    let new_entry = app.annotation_edit_new_entry.take();
    if let Some(entry_id) = new_entry {
        // Brand-new note. A blank note is a cancel, not an empty annotation.
        match app.annotations.add(entry_id, &text) {
            Some(id) => {
                if let Some(index) = app.annotations.index_of(id) {
                    app.annotations_selected = index;
                }
                let label =
                    jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
                app.status = format!("annotation added to {label} — Esc close");
            }
            None => {
                app.status = "empty note — nothing added".to_string();
            }
        }
    } else if let Some(annotation) = app.annotations.get(app.annotations_selected) {
        // Edit of an existing note. A blank note deletes it (set_text handles that).
        let id = annotation.id;
        app.annotations.set_text(id, &text);
        let count = app.annotations.len();
        if count == 0 {
            app.annotations_selected = 0;
        } else {
            app.annotations_selected = app.annotations_selected.min(count - 1);
        }
        app.status = if text.trim().is_empty() {
            "annotation deleted (empty note) — Esc close".to_string()
        } else {
            "annotation updated — Esc close".to_string()
        };
    } else {
        app.status = "annotations: nothing to edit".to_string();
    }
    app.needs_redraw = true;
}

/// Jump the main view to the entry the cursor's annotation anchors (§12.2.5). The
/// mouse twin (a row click) routes here too. Resolves the anchor through the live
/// transcript; when the anchored entry is gone the annotation is shown as
/// unresolved rather than jumping incorrectly. A no-op (status hint) on an empty
/// list.
fn annotation_jump_to_selected(app: &mut TuiApp) {
    let Some(entry_id) = app
        .annotations
        .get(app.annotations_selected)
        .map(|a| a.entry_id)
    else {
        app.status = "annotations: nothing to jump to".to_string();
        return;
    };
    if jump_to_entry_id(app, entry_id) {
        let label = jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
        app.annotations_open = false;
        app.status = format!("jumped to annotation at {label}");
        app.needs_redraw = true;
    } else {
        app.status = "annotation is unresolved (its entry is gone)".to_string();
        app.needs_redraw = true;
    }
}

/// Begin editing the selected annotation's note (§12.2.5): seed the composer with
/// its current text so the overlay enters text-input mode. A no-op (status hint)
/// on an empty list.
fn annotation_begin_edit(app: &mut TuiApp) {
    let Some(annotation) = app.annotations.get(app.annotations_selected) else {
        app.status = "annotations: nothing to edit".to_string();
        return;
    };
    app.annotation_edit = Some(annotation.text.clone());
    app.annotation_edit_new_entry = None;
    app.status = "edit annotation: type a note \u{00b7} Enter save \u{00b7} Esc cancel".to_string();
    app.needs_redraw = true;
}

/// Delete the selected annotation (§12.2.5), clamping the cursor so it stays in
/// range, and report the new count. A no-op (status hint) on an empty list.
fn annotation_delete_selected(app: &mut TuiApp) {
    let Some(annotation) = app.annotations.get(app.annotations_selected) else {
        app.status = "annotations: nothing to delete".to_string();
        return;
    };
    let id = annotation.id;
    app.annotations.remove(id);
    let count = app.annotations.len();
    if count == 0 {
        app.annotations_selected = 0;
    } else {
        app.annotations_selected = app.annotations_selected.min(count - 1);
    }
    app.status = format!("annotation deleted ({count} left) — Esc close");
    app.needs_redraw = true;
}

/// Open the Entry Annotations overlay (§12.2.5) parked on the first annotation of
/// `entry_id` — the handler behind a click on an entry's inline annotation marker.
/// A no-op when the entry has no annotation (the marker would not have painted).
fn open_annotations_for_entry(app: &mut TuiApp, entry_id: u64) {
    let Some(index) = app.annotations.first_index_for_entry(entry_id) else {
        return;
    };
    app.annotations_open = true;
    app.annotation_edit = None;
    app.annotation_edit_new_entry = None;
    app.annotations_selected = index;
    app.status = format!(
        "annotations: {} \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} e edit \u{00b7} d delete \u{00b7} Esc close",
        app.annotations.len(),
    );
    app.needs_redraw = true;
}

// ---- Inline Rename Labels (§12.1.7) ----

/// `Ctrl+Alt+R`: open the inline rename editor on the focused (or, when nothing is
/// focused, the top-visible) transcript entry (§12.1.7). Seeds the editor with the
/// entry's current label (empty for a fresh one) and enters in-place text-input
/// mode; the label is UI-only metadata that paints as a small badge and never
/// enters the model transcript. A no-op (status hint) on an empty transcript.
fn rename_focused_entry(app: &mut TuiApp) {
    let Some(entry_id) = annotation_target_entry_id(app) else {
        app.status = "no transcript entry to rename".to_string();
        return;
    };
    begin_rename_for_entry(app, entry_id);
}

/// Open the inline rename editor for the transcript entry with stable id
/// `entry_id` (§12.1.7) — the shared handler behind both the `Ctrl+Alt+R` verb and
/// a click on the entry's label badge. Seeds the editor buffer with the entry's
/// existing label (so a tweak is one keystroke away) and records whether this is a
/// brand-new label (so a blank save cancels a creation rather than deleting).
fn begin_rename_for_entry(app: &mut TuiApp, entry_id: u64) {
    let target = rename_labels::LabelTargetId::Entry(entry_id);
    let is_new = !app.rename_labels.has_label(target);
    let seed = app
        .rename_labels
        .label_for(target)
        .unwrap_or_default()
        .to_string();
    app.rename_edit = Some(rename_labels::InlineEditState::new(target, seed, is_new));
    let what = jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
    app.status = if is_new {
        format!("rename {what}: type a label \u{00b7} Enter save \u{00b7} Esc cancel")
    } else {
        format!("edit label for {what}: Enter save \u{00b7} Esc cancel (blank clears)")
    };
    app.needs_redraw = true;
}

/// Handle a key while the inline rename editor (§12.1.7) is active. The editor is
/// modal — it owns every key while present: Enter commits the typed label (a blank
/// commit clears an existing label or cancels a brand-new one), Esc cancels without
/// changing anything, Backspace deletes a char, and a printable char is appended
/// (clamped to the label limit). Everything else is swallowed so no key leaks to
/// the composer or global keymap mid-rename.
fn handle_rename_edit_key(app: &mut TuiApp, key: KeyEvent) {
    match key.code {
        KeyCode::Enter => rename_commit_edit(app),
        KeyCode::Esc => {
            app.rename_edit = None;
            app.status = "rename cancelled".to_string();
            app.needs_redraw = true;
        }
        KeyCode::Backspace => {
            if let Some(edit) = app.rename_edit.as_mut() {
                edit.backspace();
            }
            app.needs_redraw = true;
        }
        KeyCode::Char(ch) => {
            if let Some(edit) = app.rename_edit.as_mut() {
                edit.push(ch);
            }
            app.needs_redraw = true;
        }
        // Swallow every other key: the editor is modal while active.
        _ => {}
    }
}

/// Commit the inline rename editor buffer (§12.1.7). For a brand-new label a blank
/// commit cancels (adds nothing); otherwise the label is stored. For an edit of an
/// existing label a blank commit clears it, otherwise the text is replaced. Closes
/// the editor and reports the outcome in the status line.
fn rename_commit_edit(app: &mut TuiApp) {
    let Some(edit) = app.rename_edit.take() else {
        return;
    };
    let target = edit.target;
    let stored = app.rename_labels.set(target, &edit.buffer);
    let what = match target {
        rename_labels::LabelTargetId::Entry(entry_id) => {
            jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"))
        }
        rename_labels::LabelTargetId::QueueItem(index) => format!("queued #{}", index + 1),
    };
    app.status = if stored {
        let label = app.rename_labels.label_for(target).unwrap_or_default();
        format!(
            "labelled {what}: \u{201c}{label}\u{201d} ({} label{} total)",
            app.rename_labels.len(),
            if app.rename_labels.len() == 1 {
                ""
            } else {
                "s"
            },
        )
    } else if edit.is_new {
        "empty label — nothing added".to_string()
    } else {
        format!("label cleared from {what}")
    };
    app.needs_redraw = true;
}

/// Re-copy the picker's selected entry back to the clipboard through the same
/// `deliver_copy` service every copy uses (so it re-records, re-toasts, and lands
/// via the provider chain identically). A no-op on an empty history. Resolves the
/// entry by its stable id so a concurrent eviction can never re-copy the wrong
/// row.
fn recopy_selected_clipboard_entry(app: &mut TuiApp) {
    let Some(entry) = app.clipboard_history.selected_entry() else {
        return;
    };
    let id = entry.id;
    recopy_clipboard_entry(app, id);
}

/// Re-copy the clipboard-history entry with `id` (the shared keyboard/mouse
/// path). Clones the payload out first so the immutable `&str` borrow ends before
/// `deliver_copy` takes `&mut app`.
fn recopy_clipboard_entry(app: &mut TuiApp, id: u64) {
    let Some(text) = app.clipboard_history.text_of(id).map(str::to_string) else {
        return;
    };
    deliver_copy(app, &text, "clipboard history");
    app.needs_redraw = true;
}

/// Delete the picker's selected entry. A no-op on an empty history.
fn delete_selected_clipboard_entry(app: &mut TuiApp) {
    let Some(id) = app.clipboard_history.selected_entry().map(|e| e.id) else {
        return;
    };
    if app.clipboard_history.delete(id) {
        app.status = if app.clipboard_history.is_empty() {
            "clipboard history (empty)".to_string()
        } else {
            "clipboard entry deleted".to_string()
        };
        app.needs_redraw = true;
    }
}

/// Toggle the pinned flag of the picker's selected entry (a pinned entry is
/// exempt from cap eviction). A no-op on an empty history.
fn toggle_pin_selected_clipboard_entry(app: &mut TuiApp) {
    let Some(id) = app.clipboard_history.selected_entry().map(|e| e.id) else {
        return;
    };
    if let Some(pinned) = app.clipboard_history.toggle_pin(id) {
        app.status = if pinned {
            "clipboard entry pinned".to_string()
        } else {
            "clipboard entry unpinned".to_string()
        };
        app.needs_redraw = true;
    }
}

/// `Alt+e`: open the composer text in the user's `$VISUAL`/`$EDITOR` (§12.6.5
/// External Editor Handoff). Resolves the editor from the environment; when none
/// is configured (or this is a non-Unix build, where the suspend/spawn plumbing
/// is not wired) this degrades to a safe status hint and changes nothing.
/// Otherwise it stamps a [`editor_handoff::EditorHandoffRequest`] for the run
/// loop to execute on its next turn — the loop owns the terminal guard, so it
/// (not this side-effect-light arm) does the alt-screen suspend / spawn /
/// restore. Editing during a live turn is fine: the composer text is independent
/// of the running turn.
fn open_composer_in_editor(app: &mut TuiApp) {
    // Off Unix the suspend/spawn/terminal-restore differs sharply (see the spec's
    // platform notes), so the spawn is Unix-only; the non-Unix build keeps the
    // keybinding reachable but degrades to the same hint as "no editor set".
    #[cfg(not(unix))]
    {
        app.status = "external editor handoff is only available on Unix builds".to_string();
    }
    #[cfg(unix)]
    {
        let Some(command) = editor_handoff::resolve_editor(|key| std::env::var_os(key)) else {
            app.status =
                "no editor configured — set $VISUAL or $EDITOR to edit in your editor".to_string();
            return;
        };
        app.pending_editor_handoff = Some(editor_handoff::EditorHandoffRequest {
            target: editor_handoff::EditorTarget::Composer,
            initial_text: app.input.clone(),
            command,
        });
        // The loop runs the handoff before its next draw; surface the editor we
        // are about to hand off to so the brief alt-screen leave is explained.
        app.status = format!(
            "opening composer in {} …",
            app.pending_editor_handoff
                .as_ref()
                .map(|r| r.command.display())
                .unwrap_or_default(),
        );
    }
}

/// Apply a completed editor handoff to the app: a real change opens the
/// accept/reopen/discard confirmation overlay (§12.6.5) seeded with the edited
/// text; an unchanged buffer just confirms via the status line. Shared by the
/// loop's run path and the overlay's "Reopen" round-trip so both land in the
/// same place. Marks a redraw since the overlay (or status) is a visible change.
///
/// Driven only from the Unix spawn path (and the tests); off Unix the spawn is
/// not wired, so this is dead in a non-Unix lib build — hence the `dead_code`
/// allow for the Windows clippy gate.
#[cfg_attr(not(unix), allow(dead_code))]
pub(crate) fn apply_editor_handoff_outcome(
    app: &mut TuiApp,
    target: editor_handoff::EditorTarget,
    original: &str,
    outcome: editor_handoff::HandoffOutcome,
) {
    match outcome {
        editor_handoff::HandoffOutcome::Changed(edited) => {
            let review = editor_handoff::EditorHandoffReview::new(target, original, edited);
            app.status = format!("edited in editor · {} — Enter accept", review.summary());
            app.editor_handoff = Some(review);
        }
        editor_handoff::HandoffOutcome::Unchanged => {
            app.status = "editor closed — no changes".to_string();
        }
    }
    app.needs_redraw = true;
}

/// Report a failed editor handoff (spawn error, read-back failure, …) on the
/// status line. The terminal is already restored by the loop's run path before
/// this is called, so this only surfaces the error text — nothing is applied to
/// the composer. Driven only from the Unix spawn path, so dead off Unix — hence
/// the `dead_code` allow for the Windows clippy gate.
#[cfg_attr(not(unix), allow(dead_code))]
pub(crate) fn report_editor_handoff_error(app: &mut TuiApp, error: &std::io::Error) {
    app.status = format!("editor handoff failed: {error}");
    app.needs_redraw = true;
}

/// Handle a key while the External Editor Handoff confirmation overlay (§12.6.5)
/// is open. Returns `true` when the key was consumed (so it never leaks to the
/// composer or the global keymap). Mirrors the other modal overlays: Esc / `q`
/// discard, Up/Down (and `k`/`j`) move the action cursor, Enter applies the
/// highlighted action, and the action's first letter (a/r/d) is a direct
/// shortcut. The keyboard twin of clicking an action button.
fn handle_editor_handoff_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.editor_handoff.is_none() {
        return false;
    }
    match key.code {
        KeyCode::Esc | KeyCode::Char('q') | KeyCode::Char('Q') => {
            discard_editor_handoff(app);
        }
        KeyCode::Up | KeyCode::Char('k') => {
            if let Some(review) = app.editor_handoff.as_mut() {
                review.move_up();
                app.needs_redraw = true;
            }
        }
        KeyCode::Down | KeyCode::Char('j') => {
            if let Some(review) = app.editor_handoff.as_mut() {
                review.move_down();
                app.needs_redraw = true;
            }
        }
        KeyCode::Enter => {
            apply_editor_handoff_review(app);
        }
        // Direct first-letter shortcuts for each action, so the user need not
        // arrow to a button first. Lower/upper both accepted.
        KeyCode::Char('a') | KeyCode::Char('A') => {
            select_and_apply_editor_handoff(app, editor_handoff::ReviewAction::Accept);
        }
        KeyCode::Char('r') | KeyCode::Char('R') => {
            select_and_apply_editor_handoff(app, editor_handoff::ReviewAction::Reopen);
        }
        KeyCode::Char('d') | KeyCode::Char('D') => {
            select_and_apply_editor_handoff(app, editor_handoff::ReviewAction::Discard);
        }
        // Swallow every other key so the overlay stays modal: a stray keystroke
        // cannot leak into the composer underneath while the overlay owns focus.
        _ => {}
    }
    true
}

/// Move the review cursor onto `action` and apply it (the shared first-letter /
/// mouse path). A click or a letter shortcut both select and apply in one go.
fn select_and_apply_editor_handoff(app: &mut TuiApp, action: editor_handoff::ReviewAction) {
    if let Some(index) = editor_handoff::ReviewAction::ALL
        .iter()
        .position(|a| *a == action)
        && let Some(review) = app.editor_handoff.as_mut()
    {
        review.select(index);
    }
    apply_editor_handoff_review(app);
}

/// Apply the highlighted review action: Accept re-imports the edited text into
/// the composer, Reopen hands the edited text back to the editor for another
/// pass, and Discard throws the edit away. Closes the overlay (except Reopen,
/// which closes it and re-queues a fresh handoff).
fn apply_editor_handoff_review(app: &mut TuiApp) {
    let Some(review) = app.editor_handoff.as_ref() else {
        return;
    };
    match review.selected_action() {
        editor_handoff::ReviewAction::Accept => {
            let Some(review) = app.editor_handoff.take() else {
                return;
            };
            // Replace the composer outright with the edited buffer; the handoff
            // edits the whole composer, not a fragment, so a full replace (not an
            // insert) is correct, and parks the caret at the end.
            input::set_input(app, review.edited_text);
            app.status = "composer updated from editor".to_string();
            app.needs_redraw = true;
        }
        editor_handoff::ReviewAction::Reopen => {
            // Hand the edited text back to the editor for another pass. Off Unix
            // (where the spawn is not wired) the queued request never runs, so
            // fall back to accepting the edit rather than silently discarding it.
            let Some(review) = app.editor_handoff.take() else {
                return;
            };
            #[cfg(unix)]
            {
                let target = review.target;
                let text = review.edited_text;
                if let Some(command) = editor_handoff::resolve_editor(|key| std::env::var_os(key)) {
                    app.pending_editor_handoff = Some(editor_handoff::EditorHandoffRequest {
                        target,
                        initial_text: text,
                        command,
                    });
                    app.status = "reopening in editor …".to_string();
                    app.needs_redraw = true;
                } else {
                    // Editor disappeared between passes — keep the edit.
                    input::set_input(app, text);
                    app.status = "editor no longer configured — kept the edit".to_string();
                    app.needs_redraw = true;
                }
            }
            #[cfg(not(unix))]
            {
                input::set_input(app, review.edited_text);
                app.status = "composer updated from editor".to_string();
                app.needs_redraw = true;
            }
        }
        editor_handoff::ReviewAction::Discard => {
            discard_editor_handoff(app);
        }
    }
}

/// Close the editor-handoff confirmation overlay without applying the edit. A
/// no-op when nothing is in flight. The composer keeps its pre-edit text.
fn discard_editor_handoff(app: &mut TuiApp) {
    if app.editor_handoff.take().is_some() {
        app.status = "editor changes discarded".to_string();
        app.needs_redraw = true;
    }
}

/// Direction for a wide-block horizontal pan (§11G.4). `Left` pans toward the
/// flush-left edge; `Right` toward the widest line's last column.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum HorizontalDir {
    Left,
    Right,
}

/// Flip the main view between soft-wrap and no-wrap horizontal-scroll, then
/// surface the new mode in the status line. Re-enabling wrap drops any pan; the
/// next render rebuilds the transcript at the new wrap setting.
fn toggle_soft_wrap(app: &mut TuiApp) {
    app.wide_block.toggle_wrap();
    app.status = app.wide_block.status_hint().to_string();
}

/// Pan the no-wrap main view one step in `dir`, clamped to the widest painted
/// line. A no-op while soft-wrap is on (returns `true` so the keystroke is still
/// consumed and re-surfaces the "turn wrap off first" hint rather than leaking to
/// the composer). Returns whether the dispatch consumed the key.
fn scroll_wide_block(app: &mut TuiApp, dir: HorizontalDir) -> bool {
    if app.wide_block.soft_wrap() {
        // No horizontal axis while wrapping; consume the key and nudge the user
        // toward the toggle so the chord never silently does nothing.
        app.status = app.wide_block.status_hint().to_string();
        return true;
    }
    let (content_width, viewport_width) = wide_block_horizontal_metrics(app);
    // Re-clamp the stored offset against the live geometry first, so a pan after
    // a resize (which the immutable render path could only clamp for paint, not
    // for the stored value) starts from an in-range offset rather than a stale
    // wide-block one.
    app.wide_block.clamp(content_width, viewport_width);
    let moved = match dir {
        HorizontalDir::Left => app
            .wide_block
            .scroll_left(wide_block::HORIZONTAL_STEP_COLUMNS),
        HorizontalDir::Right => app.wide_block.scroll_right(
            wide_block::HORIZONTAL_STEP_COLUMNS,
            content_width,
            viewport_width,
        ),
    };
    if moved {
        app.status = app.wide_block.status_hint().to_string();
    }
    true
}

/// Measure the `(content_width, viewport_width)` the wide-block pan clamps
/// against: the widest UNWRAPPED main-transcript line vs. the painted text
/// column. `content_width` is computed from the no-wrap line build (`width =
/// None`) so a pan can reach the last column of the widest line and no further;
/// `viewport_width` is the live painted text width stamped each frame by
/// `render_transcript`. Falls back to the live area width before the first paint.
fn wide_block_horizontal_metrics(app: &TuiApp) -> (u16, u16) {
    let viewport_width = app.main_text_width.get().max(1);
    // The no-wrap (logical-line) build is the same one the renderer paints when
    // soft-wrap is off, so its widest display column is exactly how far the pan
    // can travel.
    let lines = transcript_lines_for_render(app, None, true);
    let content_width = lines
        .iter()
        .map(line_display_width)
        .max()
        .unwrap_or(0)
        .min(u16::MAX as usize) as u16;
    (content_width, viewport_width)
}

/// Display width (terminal columns) of a styled line: the sum of its spans'
/// unicode display widths. Used to measure how far the no-wrap view can pan.
fn line_display_width(line: &Line<'static>) -> usize {
    line.spans
        .iter()
        .map(|span| UnicodeWidthStr::width(span.content.as_ref()))
        .sum()
}

/// The category of transcript entry a jump command targets.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum JumpTarget {
    UserTurn,
    Assistant,
    ToolCall,
    Error,
}

/// Search direction for a jump command, relative to the entry currently at the
/// top of the viewport.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum JumpDirection {
    Prev,
    Next,
}

/// True when entry `index` matches the jump `target`. Pure over the entry slice
/// + grouping flags, mirroring the classifications the renderer uses.
fn entry_matches_jump_target(
    entries: &[TranscriptEntry],
    index: usize,
    target: JumpTarget,
    coalesce_tool_runs: bool,
) -> bool {
    let Some(entry) = entries.get(index) else {
        return false;
    };
    match target {
        JumpTarget::UserTurn => {
            matches!(&entry.kind, TranscriptEntryKind::Message(item) if item.role == Role::User)
        }
        JumpTarget::Assistant => {
            matches!(&entry.kind, TranscriptEntryKind::Message(item) if item.role == Role::Assistant)
        }
        JumpTarget::ToolCall => {
            // Land on a coalesced run's lead, not its suppressed members.
            matches!(&entry.kind, TranscriptEntryKind::ToolResult(_))
                && matches!(
                    tool_run_info(entries, index, coalesce_tool_runs),
                    None | Some(ToolRun::Lead { .. })
                )
        }
        JumpTarget::Error => entry_is_error(entries, index),
    }
}

/// True when entry `index` is a failure surface: a failed tool result, a
/// failure log, or a message whose `message_outcome` is `Failed`.
fn entry_is_error(entries: &[TranscriptEntry], index: usize) -> bool {
    let Some(entry) = entries.get(index) else {
        return false;
    };
    match &entry.kind {
        TranscriptEntryKind::ToolResult(tool) => tool.result.status != ToolStatus::Success,
        TranscriptEntryKind::Log(log) => is_failure_log(log.message()),
        TranscriptEntryKind::Message(_) => {
            message_outcome(entries, index) == MessageOutcome::Failed
        }
        _ => false,
    }
}

/// The distinct tool names appearing in `entries`, in first-seen order. Used to
/// build the per-tool overlay filter set ([`OverlayFilter::Tool`] indexes into
/// this list). Only tool-result leads contribute, so a coalesced run's name is
/// counted once.
fn distinct_overlay_tool_names(entries: &[TranscriptEntry]) -> Vec<String> {
    let mut names: Vec<String> = Vec::new();
    for entry in entries {
        if let TranscriptEntryKind::ToolResult(tool) = &entry.kind {
            let name = &tool.result.tool_name;
            if !names.iter().any(|existing| existing == name) {
                names.push(name.clone());
            }
        }
    }
    names
}

/// Index of the last user-message entry, i.e. the start of the "current turn".
/// `0` when there is no user message (the whole transcript is the current
/// turn). Computed once over the unfiltered slice so [`OverlayFilter::CurrentTurn`]
/// keeps the right boundary even while filtering.
fn current_turn_start(entries: &[TranscriptEntry]) -> usize {
    entries
        .iter()
        .rposition(|entry| {
            matches!(&entry.kind, TranscriptEntryKind::Message(item) if item.role == Role::User)
        })
        .unwrap_or(0)
}

/// True when entry `index` survives the active overlay `filter`. Pure over the
/// entry slice; reuses [`entry_matches_jump_target`] / [`entry_is_error`] so the
/// classifications match the renderer and jump-nav. `tool_names` is the derived
/// distinct-tool-name list; `turn_start` is [`current_turn_start`] of the same
/// (unfiltered) slice.
fn entry_matches_overlay_filter(
    entries: &[TranscriptEntry],
    index: usize,
    filter: OverlayFilter,
    coalesce_tool_runs: bool,
    tool_names: &[String],
    turn_start: usize,
) -> bool {
    let Some(entry) = entries.get(index) else {
        return false;
    };
    match filter {
        OverlayFilter::All => true,
        OverlayFilter::Conversation => {
            matches!(&entry.kind, TranscriptEntryKind::Message(_))
        }
        OverlayFilter::ToolCalls => {
            entry_matches_jump_target(entries, index, JumpTarget::ToolCall, coalesce_tool_runs)
        }
        OverlayFilter::Errors => entry_is_error(entries, index),
        OverlayFilter::Subagent => {
            matches!(&entry.kind, TranscriptEntryKind::Log(log) if log.kind == LogKind::Subagent)
        }
        OverlayFilter::Tool(i) => {
            matches!(&entry.kind, TranscriptEntryKind::ToolResult(tool)
                if tool_names.get(i).is_some_and(|name| name == &tool.result.tool_name))
        }
        OverlayFilter::CurrentTurn => index >= turn_start,
    }
}

/// True when entry `index` survives the active MAIN-view semantic `category`
/// (§12.5.2). Pure over the entry slice; reuses the SAME classifiers the overlay
/// filter and jump-nav use, so the main inline view, the Ctrl+T overlay, and the
/// jump keys all agree on what "an error" / "a tool call" / "this tool" is.
///
/// Categories that have a [`OverlayFilter`] twin delegate to
/// [`entry_matches_overlay_filter`] (so there is one matcher, not two);
/// `UserTurns`/`Assistant` — which the overlay lumps into `Conversation` — apply
/// the message-role test directly, the same one
/// [`entry_matches_jump_target`] uses for `JumpTarget::UserTurn`/`Assistant`.
fn entry_matches_semantic_category(
    entries: &[TranscriptEntry],
    index: usize,
    category: semantic_filter::SemanticCategory,
    coalesce_tool_runs: bool,
    tool_names: &[String],
    turn_start: usize,
) -> bool {
    match category.to_overlay_filter() {
        Some(filter) => entry_matches_overlay_filter(
            entries,
            index,
            filter,
            coalesce_tool_runs,
            tool_names,
            turn_start,
        ),
        None => match category {
            semantic_filter::SemanticCategory::UserTurns => {
                entry_matches_jump_target(entries, index, JumpTarget::UserTurn, coalesce_tool_runs)
            }
            semantic_filter::SemanticCategory::Assistant => {
                entry_matches_jump_target(entries, index, JumpTarget::Assistant, coalesce_tool_runs)
            }
            // `to_overlay_filter` only returns `None` for the two role
            // categories above; any other category took the `Some` arm.
            _ => true,
        },
    }
}

/// The list of overlay filters worth cycling through for the current
/// transcript: the always-available ones, plus one `Tool(i)` per distinct tool
/// when more than one tool appears (a single-tool transcript already has
/// `ToolCalls`). Order is the cycle order the overlay's `f` key walks.
fn overlay_filter_cycle(tool_names: &[String]) -> Vec<OverlayFilter> {
    let mut filters = vec![
        OverlayFilter::All,
        OverlayFilter::Conversation,
        OverlayFilter::ToolCalls,
        OverlayFilter::Errors,
        OverlayFilter::Subagent,
        OverlayFilter::CurrentTurn,
    ];
    if tool_names.len() > 1 {
        for i in 0..tool_names.len() {
            filters.push(OverlayFilter::Tool(i));
        }
    }
    filters
}

/// Execute a jump-navigation command: find the previous/next entry matching
/// `target` relative to the entry currently anchored at the viewport top, then
/// scroll (with a smooth ease) so that entry sits at the top. Returns `true`
/// when it moved, `false` when guarded out or no such entry exists.
fn jump_transcript_nav(app: &mut TuiApp, target: JumpTarget, direction: JumpDirection) -> bool {
    if app.config_screen.is_some() || app.status_line_setup.is_some() {
        return false;
    }
    // The Alt+arrow jump defaults collide with the composer's word-motion
    // (Alt+Left/Right) and prompt-history recall (Alt+Up/Down). While the composer
    // holds text, defer to those readline handlers — mirroring the
    // TranscriptHome/End empty-composer convention — so editing a prompt is never
    // hijacked by a transcript jump (deep-review #13 / #30). The jump verbs stay
    // reachable with an empty composer (or via their non-Alt-arrow chords).
    if !app.input.is_empty() {
        return false;
    }
    let (width, height) = app.off_frame_terminal_size();
    let area = Rect {
        x: 0,
        y: 0,
        width,
        height,
    };
    // Adaptive Density (§12.4.1): match the render path's density-scaled
    // startup-card gate so this off-frame scroll geometry counts the same rows
    // the renderer paints.
    let include_startup_card = include_startup_card_for(app, area);
    let viewport_h = main_transcript_height(app, area, include_startup_card) as usize;
    // Carve the minimap rail (when shown) AND the scrollbar gutter, exactly as
    // `render_transcript` does, so the painted-row units match (deep-review #129).
    let text_width = main_painted_text_width(app, area).max(1);
    // Match the renderer: soft-wrap off builds UNWRAPPED rows (one per logical
    // line), so off-frame jump geometry must measure the same row model or its
    // offsets/total point at phantom wrapped rows the user never sees.
    let build_width = main_geometry_build_width(app, text_width);
    let (rows, entry_offsets) =
        transcript_lines_and_entry_offsets(app, build_width, include_startup_card);
    let total_rows = rows.len();
    if entry_offsets.is_empty() || total_rows == 0 {
        return false;
    }
    // The wrapped-row currently at the top of the viewport.
    let top_row = active_transcript_scroll(app).offset(total_rows, viewport_h);
    // Index of the matching entry to jump to.
    let entries = active_transcript_entries(app);
    let coalesce = app.coalesce_tool_runs;
    let target_index = match direction {
        JumpDirection::Prev => (0..entries.len())
            .rev()
            .filter(|&i| entry_matches_jump_target(entries, i, target, coalesce))
            .find(|&i| entry_offsets[i] < top_row),
        JumpDirection::Next => (0..entries.len())
            .filter(|&i| entry_matches_jump_target(entries, i, target, coalesce))
            .find(|&i| entry_offsets[i] > top_row),
    };
    let Some(target_index) = target_index else {
        return false;
    };
    // Convert the target row into a `from_bottom`: top-line scroll
    // `entry_offsets[target]` ⇒ `from_bottom = max_scroll - scroll`.
    let max_scroll = total_rows.saturating_sub(viewport_h);
    let from_bottom = max_scroll.saturating_sub(entry_offsets[target_index].min(max_scroll));
    commit_main_from_bottom_animated(app, from_bottom);
    // A successful turn-to-turn jump is the user demonstrating they already know the
    // jump navigation, so the §12.1.8 Jump hint fades — once used.
    note_first_run_hint_used(app, first_run_hints::HintId::Jump);
    true
}

/// The viewport geometry the main transcript renders at right now: the
/// per-entry header row offsets, the wrapped row total, and the viewport
/// height — all measured against the same text width `render()` paints with so
/// the scroll math agrees with the screen. Shared by the jump-mark set/jump
/// path. Returns `None` when there is nothing to navigate (empty transcript or
/// a degenerate zero-height viewport).
fn jump_nav_geometry(app: &TuiApp) -> Option<(Vec<usize>, usize, usize)> {
    let (width, height) = app.off_frame_terminal_size();
    transcript_nav_geometry_at(app, width, height)
}

/// Same per-entry offset / total-row / viewport geometry as [`jump_nav_geometry`],
/// but measured against an explicit `(width, height)` instead of the
/// last-painted size. The Focus-Preserving Resize re-anchor (§12.4.3) uses this
/// to measure the *post*-resize geometry from the `Event::Resize` dimensions
/// before that frame has actually painted (so `off_frame_terminal_size` still
/// reports the old size).
fn transcript_nav_geometry_at(
    app: &TuiApp,
    width: u16,
    height: u16,
) -> Option<(Vec<usize>, usize, usize)> {
    let area = Rect {
        x: 0,
        y: 0,
        width,
        height,
    };
    // Adaptive Density (§12.4.1): match the render path's density-scaled
    // startup-card gate so this off-frame scroll geometry counts the same rows
    // the renderer paints.
    let include_startup_card = include_startup_card_for(app, area);
    let viewport_h = main_transcript_height(app, area, include_startup_card) as usize;
    // Carve the minimap rail (when shown) AND the scrollbar gutter, exactly as
    // `render_transcript` does, so the painted-row units match (deep-review #129).
    let text_width = main_painted_text_width(app, area).max(1);
    // Match the renderer: soft-wrap off builds UNWRAPPED rows (one per logical
    // line), so off-frame nav geometry must measure the same row model.
    let build_width = main_geometry_build_width(app, text_width);
    let (rows, entry_offsets) =
        transcript_lines_and_entry_offsets(app, build_width, include_startup_card);
    let total_rows = rows.len();
    if entry_offsets.is_empty() || total_rows == 0 {
        return None;
    }
    Some((entry_offsets, total_rows, viewport_h))
}

/// Stable entry id of the entry currently at (or nearest above) the top of the
/// main viewport — the "current transcript row" a jump mark records. Picks the
/// entry with the greatest header offset that is still at or above the top
/// visible row, so a mark lands on the entry the user is actually looking at.
/// `None` when the transcript is empty.
fn current_top_entry_id(app: &TuiApp) -> Option<u64> {
    let (entry_offsets, total_rows, viewport_h) = jump_nav_geometry(app)?;
    let top_row = active_transcript_scroll(app).offset(total_rows, viewport_h);
    let entries = active_transcript_entries(app);
    // Greatest header offset that is <= top_row (the entry occupying the top
    // row). If we are scrolled above every header, fall back to the first.
    let index = entry_offsets
        .iter()
        .enumerate()
        .filter(|&(_, &off)| off <= top_row)
        .map(|(i, _)| i)
        .next_back()
        .unwrap_or(0);
    entries.get(index).map(|entry| entry.id)
}

/// Scroll (with a smooth ease) so the entry with stable id `entry_id` sits at
/// the top of the viewport. Returns `true` when the entry exists and the view
/// moved there; `false` when no live entry carries that id (e.g. it was dropped
/// by a transcript rebuild) or there is nothing to navigate.
fn jump_to_entry_id(app: &mut TuiApp, entry_id: u64) -> bool {
    let Some((entry_offsets, total_rows, viewport_h)) = jump_nav_geometry(app) else {
        return false;
    };
    let entries = active_transcript_entries(app);
    let Some(index) = entries.iter().position(|entry| entry.id == entry_id) else {
        return false;
    };
    let Some(&offset) = entry_offsets.get(index) else {
        return false;
    };
    let max_scroll = total_rows.saturating_sub(viewport_h);
    let from_bottom = max_scroll.saturating_sub(offset.min(max_scroll));
    commit_main_from_bottom_animated(app, from_bottom);
    true
}

/// Classify one transcript entry into its primary [`transcript_index::EntryCategory`]
/// for the Local Transcript Index (§12.5.1). Reuses the same role / `LogKind` /
/// `entry_is_error` predicates the renderer and jump-nav use, so the index's
/// notion of "this is a tool call / error / subagent" matches what the user
/// sees. The error cross-cut (a failed tool/message also counting under the
/// error bucket) is computed separately via `entry_is_error` in
/// [`build_index_entries`].
fn index_category_of(entries: &[TranscriptEntry], index: usize) -> transcript_index::EntryCategory {
    use transcript_index::EntryCategory;
    let entry = &entries[index];
    match &entry.kind {
        TranscriptEntryKind::Message(item) if item.role == Role::User => EntryCategory::UserTurn,
        TranscriptEntryKind::Message(item) if item.role == Role::Assistant => {
            // A failed assistant message still reads primarily as assistant; the
            // error cross-cut tags it for the error bucket in addition.
            EntryCategory::Assistant
        }
        TranscriptEntryKind::Message(_) => EntryCategory::Note,
        TranscriptEntryKind::ToolResult(_) => EntryCategory::ToolCall,
        TranscriptEntryKind::Reasoning(_) => EntryCategory::Reasoning,
        TranscriptEntryKind::PlanCard(_) => EntryCategory::Plan,
        TranscriptEntryKind::Diff(_) => EntryCategory::Diff,
        TranscriptEntryKind::SlashEcho(_) => EntryCategory::Note,
        TranscriptEntryKind::Log(log) => match log.kind {
            LogKind::Subagent => EntryCategory::Subagent,
            LogKind::Error => EntryCategory::Error,
            _ => EntryCategory::Note,
        },
    }
}

/// A CHEAP staleness fingerprint folded over the raw transcript's `(id, revision)`
/// sequence — O(entries) with no string clones, no per-entry classification, and
/// no detail-line rendering. The sequence of `(id, revision)` fully determines
/// every derived per-entry fact the overlay models build (category, error flag,
/// tool name, elision counts), because those are pure functions of the entry
/// content (captured by `revision`) and its neighbors (captured by sequence
/// position). So an unchanged value means an unchanged built candidate set, and a
/// `refresh_*` site can skip its expensive `build_*` pass entirely on this cheap
/// `u64` comparison — the "one u64 comparison per idle frame" contract the overlay
/// docs promise (deep-review #43/#44). Verbosity- or keybinding-dependent models
/// (health markers) fold those extra inputs in on top of this.
fn transcript_source_fingerprint(entries: &[TranscriptEntry]) -> u64 {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    entries.len().hash(&mut hasher);
    for entry in entries {
        entry.id.hash(&mut hasher);
        entry.revision.hash(&mut hasher);
    }
    hasher.finish()
}

#[cfg(test)]
thread_local! {
    /// Per-thread count of how many times [`build_index_entries`] actually ran,
    /// so a test can prove `refresh_transcript_index`'s cheap pre-build gate skips
    /// the O(transcript-bytes) build on an unchanged repaint (deep-review #43).
    /// Thread-local so parallel `cargo test` threads never race a global atomic.
    static INDEX_ENTRIES_BUILDS: std::cell::Cell<u64> = const { std::cell::Cell::new(0) };
}

/// Test-only: record one [`build_index_entries`] pass.
#[cfg(test)]
fn note_index_entries_build() {
    INDEX_ENTRIES_BUILDS.with(|c| c.set(c.get() + 1));
}

/// Test-only: reset this thread's [`build_index_entries`] build counter.
#[cfg(test)]
pub(crate) fn reset_index_entries_builds() {
    INDEX_ENTRIES_BUILDS.with(|c| c.set(0));
}

/// Test-only: this thread's [`build_index_entries`] build count since the reset.
#[cfg(test)]
pub(crate) fn index_entries_builds() -> u64 {
    INDEX_ENTRIES_BUILDS.with(|c| c.get())
}

/// Build the per-entry classification slice the index consumes from the active
/// transcript. Each entry contributes its stable id, content revision (so a
/// mutation re-indexes), primary category, error cross-cut flag, and — for tool
/// results — its tool name (for per-tool lookup). Pure over the entry slice.
fn build_index_entries(entries: &[TranscriptEntry]) -> Vec<transcript_index::IndexedEntry> {
    #[cfg(test)]
    note_index_entries_build();
    entries
        .iter()
        .enumerate()
        .map(|(i, entry)| {
            let tool_name = match &entry.kind {
                TranscriptEntryKind::ToolResult(tool) => Some(tool.result.tool_name.clone()),
                _ => None,
            };
            transcript_index::IndexedEntry {
                id: entry.id,
                revision: entry.revision,
                primary: index_category_of(entries, i),
                is_error: entry_is_error(entries, i),
                tool_name,
            }
        })
        .collect()
}

/// Refresh the Local Transcript Index (§12.5.1) against the active transcript,
/// rebuilding **only** when the transcript's (id, revision, category, error,
/// tool) fingerprint has moved since the last refresh. Called lazily — right
/// before the index overlay opens or renders — so an idle session that never
/// opens the overlay pays nothing, and an open overlay re-indexes only on a real
/// transcript change (append, stream settle, revision bump, clear, compaction,
/// fold toggle, resume) rather than every frame.
pub(crate) fn refresh_transcript_index(app: &mut TuiApp) {
    // Cheap pre-build gate (deep-review #43): the per-frame `build_index_entries`
    // is O(transcript-bytes) (it clones every tool name and re-classifies every
    // entry), so skip it entirely when the raw `(id, revision)` sequence is
    // unchanged — the actual "one u64 comparison per idle frame" the overlay docs
    // promise. Only when the cheap fingerprint moves do we pay the build + the
    // model's own finer-grained `rebuild_if_stale` guard.
    let source_fp = transcript_source_fingerprint(active_transcript_entries(app));
    if app.transcript_index_source_fp.get() == Some(source_fp) {
        return;
    }
    let entries = build_index_entries(active_transcript_entries(app));
    let fingerprint = transcript_index::TranscriptIndex::fingerprint_of(entries.iter());
    app.transcript_index.rebuild_if_stale(fingerprint, &entries);
    app.transcript_index_source_fp.set(Some(source_fp));
}

/// Classify one transcript entry into its [`transcript_relations::RelationEntryKind`]
/// for the Related-Entry Links graph (§12.5.3). Folds the index's category
/// (reusing `index_category_of`, so the two stay in lock-step) onto the smaller
/// relation-kind set the derivation rules branch on.
fn relation_kind_of(
    entries: &[TranscriptEntry],
    index: usize,
) -> transcript_relations::RelationEntryKind {
    use transcript_index::EntryCategory;
    use transcript_relations::RelationEntryKind;
    match index_category_of(entries, index) {
        EntryCategory::UserTurn => RelationEntryKind::User,
        EntryCategory::Assistant => RelationEntryKind::Assistant,
        EntryCategory::ToolCall => RelationEntryKind::ToolCall,
        EntryCategory::Reasoning => RelationEntryKind::Reasoning,
        EntryCategory::Error => RelationEntryKind::Error,
        EntryCategory::Subagent => RelationEntryKind::Subagent,
        EntryCategory::Plan | EntryCategory::Diff | EntryCategory::Note => RelationEntryKind::Other,
    }
}

/// Build the per-entry classification slice the relation graph consumes from the
/// active transcript (§12.5.3). Each entry contributes its stable id, content
/// revision (so a mutation re-derives), relation kind, error flag, and — for
/// tool results — its tool name (for same-tool links). Pure over the entry slice.
fn build_relation_entries(entries: &[TranscriptEntry]) -> Vec<transcript_relations::RelationEntry> {
    entries
        .iter()
        .enumerate()
        .map(|(i, entry)| {
            let tool_name = match &entry.kind {
                TranscriptEntryKind::ToolResult(tool) => Some(tool.result.tool_name.clone()),
                _ => None,
            };
            transcript_relations::RelationEntry {
                id: entry.id,
                revision: entry.revision,
                kind: relation_kind_of(entries, i),
                is_error: entry_is_error(entries, i),
                tool_name,
            }
        })
        .collect()
}

/// The comparison text for a tool-result entry used by Duplicate-Output Folding
/// (§12.5.4). Prefers a textual `stdout`/`output`/`text` field of the result
/// content (the human-visible output a `shell`/`verify` style tool emits), and
/// otherwise falls back to the serialized content blob, so two structurally
/// identical results still fingerprint equal. `None` for a non-tool entry — only
/// tool outputs participate in output folding.
fn fold_output_text(entry: &TranscriptEntry) -> Option<String> {
    let TranscriptEntryKind::ToolResult(tool) = &entry.kind else {
        return None;
    };
    let content = &tool.result.content;
    for key in ["stdout", "output", "text", "message"] {
        if let Some(text) = content.get(key).and_then(|v| v.as_str())
            && !text.trim().is_empty()
        {
            return Some(text.to_string());
        }
    }
    // Structured-only result: fall back to the canonical content blob so two
    // identical structured results still fold together.
    Some(content.to_string())
}

/// Build the per-entry fold-candidate slice the duplicate-fold model consumes
/// from the active transcript. Only tool-result entries contribute (the only
/// outputs that can repeat); each carries its stable id, content revision (so a
/// mutation recomputes), normalized output fingerprint, and error flag (an error
/// is never folded). Pure over the entry slice.
fn build_fold_candidates(entries: &[TranscriptEntry]) -> Vec<duplicate_fold::FoldableOutput> {
    entries
        .iter()
        .enumerate()
        .filter_map(|(i, entry)| {
            let text = fold_output_text(entry)?;
            Some(duplicate_fold::FoldableOutput {
                // `i` is the entry's position in the *full* transcript, not in
                // this tool-only candidate slice, so the fold model can require
                // genuine transcript adjacency and never fold two outputs that
                // are separated by intervening conversation.
                seq: i,
                id: entry.id,
                revision: entry.revision,
                output: duplicate_fold::output_fingerprint(&text),
                is_error: entry_is_error(entries, i),
            })
        })
        .collect()
}

/// Refresh the Related-Entry Links graph (§12.5.3) against the active transcript,
/// rebuilding **only** when the transcript's (id, revision, kind, error, tool)
/// fingerprint has moved since the last refresh. Called lazily — right before the
/// overlay opens or renders — so an idle session that never opens the overlay
/// pays nothing, and an open overlay re-derives only on a real transcript change.
pub(crate) fn refresh_related_links(app: &mut TuiApp) {
    let entries = build_relation_entries(active_transcript_entries(app));
    let fingerprint = transcript_relations::RelationGraph::fingerprint_of(entries.iter());
    app.related_links.rebuild_if_stale(fingerprint, &entries);
}

/// The entry id the Related-Entry Links overlay (§12.5.3) should anchor on: the
/// focused entry when one is focused, else the latest (tail) entry, so opening
/// the overlay without first focusing still has a sensible pivot. `None` only on
/// an empty transcript.
fn related_links_anchor_id(app: &TuiApp) -> Option<u64> {
    let entries = active_transcript_entries(app);
    if let Some(index) = active_selected_entry(app)
        && let Some(entry) = entries.get(index)
    {
        return Some(entry.id);
    }
    entries.last().map(|entry| entry.id)
}

/// Refresh the Duplicate-Output Folds model (§12.5.4) against the active
/// transcript, recomputing **only** when the candidates' (id, revision, output,
/// error) fingerprint has moved since the last refresh. Called lazily — right
/// before the fold overlay opens or renders — so an idle session that never opens
/// the overlay pays nothing, and an open overlay re-folds only on a real
/// transcript change rather than every frame.
pub(crate) fn refresh_duplicate_folds(app: &mut TuiApp) {
    let candidates = build_fold_candidates(active_transcript_entries(app));
    let fingerprint = duplicate_fold::DuplicateFolds::fingerprint_of(candidates.iter());
    app.duplicate_folds
        .rebuild_if_stale(fingerprint, &candidates);
}

/// The text the Error Lenses detector (§12.5.6) scans for one entry. Pulls the
/// human-visible *failure* output: for a tool result, the error/stderr/stdout/
/// output/message/text fields of the content (joined so a failure that printed
/// to both stderr and stdout is fully scanned), falling back to the serialized
/// content blob; for a failed log line, its message; for a failed assistant
/// message, its prose. `None` for an entry with no scannable text. Distinct from
/// `fold_output_text` (which only cares about a single comparison fingerprint):
/// error detection wants the *error* channels, so it prefers `error`/`stderr`.
fn error_lens_text(entry: &TranscriptEntry) -> Option<String> {
    match &entry.kind {
        TranscriptEntryKind::ToolResult(tool) => {
            let content = &tool.result.content;
            let mut parts: Vec<String> = Vec::new();
            for key in ["error", "stderr", "message", "stdout", "output", "text"] {
                if let Some(text) = content.get(key).and_then(|v| v.as_str())
                    && !text.trim().is_empty()
                {
                    parts.push(text.to_string());
                }
            }
            if parts.is_empty() {
                // Structured-only result: scan the canonical content blob so an
                // `{"error": ...}`-shaped payload still surfaces.
                Some(content.to_string())
            } else {
                Some(parts.join("\n"))
            }
        }
        TranscriptEntryKind::Log(log) => Some(log.message().to_string()),
        TranscriptEntryKind::Message(item) => Some(item.content.clone()),
        _ => None,
    }
}

/// Build the per-entry error-lens candidate slice from the active transcript
/// (§12.5.6). Only entries the renderer/jump-nav already classify as a failure
/// (`entry_is_error`) contribute — structured status decides *whether* an entry
/// failed, so the line detectors never have to. Each carries its stable id,
/// content revision (so a mutation re-detects), and its failure output text.
/// Pure over the entry slice.
fn build_error_candidates(entries: &[TranscriptEntry]) -> Vec<error_lens::ErrorCandidate> {
    entries
        .iter()
        .enumerate()
        .filter_map(|(i, entry)| {
            if !entry_is_error(entries, i) {
                return None;
            }
            let text = error_lens_text(entry)?;
            Some(error_lens::ErrorCandidate {
                id: entry.id,
                revision: entry.revision,
                text,
            })
        })
        .collect()
}

/// Refresh the Error Lenses model (§12.5.6) against the active transcript,
/// recomputing **only** when the failed candidates' (id, revision) fingerprint
/// has moved since the last refresh. Called lazily — right before the overlay
/// opens or renders — so an idle session that never opens the overlay pays
/// nothing, and an open overlay re-detects only on a real transcript change
/// rather than every frame.
pub(crate) fn refresh_error_lenses(app: &mut TuiApp) {
    let candidates = build_error_candidates(active_transcript_entries(app));
    let fingerprint = error_lens::ErrorLenses::fingerprint_of(candidates.iter());
    app.error_lenses.rebuild_if_stale(fingerprint, &candidates);
}

/// Number of preview lines a tool's inline card *hides* via head-tail elision
/// (§12.5.7), or `0` when its preview is shown in full. Reuses the SAME
/// `expanded_tool_detail_lines` + `tool_preview_line_cap` + bypass gate the
/// renderer uses to decide elision, so the marker's notion of "hidden" matches
/// exactly what the user sees folded. Tools whose body bypasses the cap (diffs,
/// patches) are never elided, so they report `0`.
fn tool_elided_line_count(
    tool: &ToolTranscript,
    verbosity: ToolOutputVerbosity,
    transcript_shortcut: &str,
) -> usize {
    if tool_bypasses_preview_cap_for_tool(tool) {
        return 0;
    }
    let detail = expanded_tool_detail_lines(
        tool,
        ToolDetailMode::Preview(verbosity),
        transcript_shortcut,
    );
    let cap = tool_preview_line_cap(tool);
    // `head_tail_truncate_lines` elides only when the line count exceeds `2*cap`,
    // hiding the middle `len - 2*cap` lines. Mirror that arithmetic exactly.
    if cap == 0 || detail.len() <= cap.saturating_mul(2) {
        0
    } else {
        detail.len().saturating_sub(cap * 2)
    }
}

#[cfg(test)]
thread_local! {
    /// Per-thread count of how many times [`build_health_candidates`] actually ran,
    /// so a test can prove `refresh_health_markers`'s cheap pre-build gate skips the
    /// detail-line-rendering build on an unchanged repaint (deep-review #44).
    /// Thread-local so parallel `cargo test` threads never race a global atomic.
    static HEALTH_CANDIDATES_BUILDS: std::cell::Cell<u64> = const { std::cell::Cell::new(0) };
}

/// Test-only: record one [`build_health_candidates`] pass.
#[cfg(test)]
fn note_health_candidates_build() {
    HEALTH_CANDIDATES_BUILDS.with(|c| c.set(c.get() + 1));
}

/// Test-only: reset this thread's [`build_health_candidates`] build counter.
#[cfg(test)]
pub(crate) fn reset_health_candidates_builds() {
    HEALTH_CANDIDATES_BUILDS.with(|c| c.set(0));
}

/// Test-only: this thread's [`build_health_candidates`] build count since reset.
#[cfg(test)]
pub(crate) fn health_candidates_builds() -> u64 {
    HEALTH_CANDIDATES_BUILDS.with(|c| c.get())
}

/// Build the per-entry Transcript Health Markers candidate slice from the active
/// transcript (§12.5.7). Reuses the renderer/jump-nav classifications
/// (`entry_is_error`, the structured tool status, `LogKind::Subagent`,
/// `is_failure_log`) so the markers' notion of "failed / elided / large" matches
/// what the user sees. Each candidate carries only *measured facts* — never the
/// raw output text — so the detector cannot leak a hidden secret line. Pure over
/// the entry slice apart from reading the shared transcript shortcut for the
/// elision measurement.
fn build_health_candidates(
    entries: &[TranscriptEntry],
    verbosity: ToolOutputVerbosity,
    transcript_shortcut: &str,
) -> Vec<transcript_health::HealthCandidate> {
    #[cfg(test)]
    note_health_candidates_build();
    let mut out: Vec<transcript_health::HealthCandidate> = Vec::new();
    for (index, entry) in entries.iter().enumerate() {
        let (title, tool_failed, subagent_failed, turn_failed, elided, hidden_lines, output_bytes) =
            match &entry.kind {
                TranscriptEntryKind::ToolResult(tool) => {
                    let failed = tool.result.status != ToolStatus::Success;
                    let hidden = tool_elided_line_count(tool, verbosity, transcript_shortcut);
                    (
                        tool.result.tool_name.clone(),
                        failed,
                        false,
                        false,
                        hidden > 0,
                        hidden,
                        tool.result.cost_hint.output_bytes,
                    )
                }
                TranscriptEntryKind::Log(log) if log.kind == LogKind::Subagent => (
                    "subagent".to_string(),
                    false,
                    is_failure_log(log.message()),
                    false,
                    false,
                    0,
                    0,
                ),
                TranscriptEntryKind::Message(item) if item.role == Role::Assistant => (
                    "turn".to_string(),
                    false,
                    false,
                    entry_is_error(entries, index),
                    false,
                    0,
                    0,
                ),
                _ => continue,
            };
        // Only entries that justify at least one marker contribute, so the
        // fingerprint and the model stay tight (no candidate per healthy entry).
        if !(tool_failed
            || subagent_failed
            || turn_failed
            || elided
            || output_bytes >= transcript_health::LARGE_OUTPUT_BYTES)
        {
            continue;
        }
        out.push(transcript_health::HealthCandidate {
            id: entry.id,
            revision: entry.revision,
            title,
            tool_failed,
            subagent_failed,
            turn_failed,
            elided,
            hidden_lines,
            output_bytes,
        });
    }
    out
}

/// Refresh the Transcript Health Markers model (§12.5.7) against the active
/// transcript, recomputing **only** when the candidates' (id, revision)
/// fingerprint has moved since the last refresh. Called lazily — right before the
/// overlay opens or renders — so an idle session that never opens the overlay
/// pays nothing, and an open overlay re-detects only on a real transcript change
/// rather than every frame.
pub(crate) fn refresh_health_markers(app: &mut TuiApp) {
    let shortcut = key_hint(app, keymap::Action::ToggleTranscriptOverlay);
    let verbosity = app.tool_output_verbosity;
    // Cheap pre-build gate (deep-review #44, the heaviest of this class):
    // `build_health_candidates` re-renders every tool output's detail lines via
    // `tool_elided_line_count` on every painted frame, so an open-but-idle health
    // overlay on a long shell/read session can visibly lag the whole TUI. Skip the
    // whole build when nothing it depends on has moved. Its inputs are the raw
    // `(id, revision)` transcript sequence PLUS the preview-cap inputs — the tool-
    // output verbosity and the transcript shortcut (both feed the elision count) —
    // so fold all three into the cheap source fingerprint.
    let source_fp = {
        let mut hasher = std::collections::hash_map::DefaultHasher::new();
        transcript_source_fingerprint(active_transcript_entries(app)).hash(&mut hasher);
        verbosity.as_str().hash(&mut hasher);
        shortcut.hash(&mut hasher);
        hasher.finish()
    };
    if app.health_markers_source_fp.get() == Some(source_fp) {
        return;
    }
    let candidates = build_health_candidates(active_transcript_entries(app), verbosity, &shortcut);
    let fingerprint = transcript_health::HealthMarkers::fingerprint_of(candidates.iter());
    app.health_markers
        .rebuild_if_stale(fingerprint, &candidates);
    app.health_markers_source_fp.set(Some(source_fp));
}

/// Fold one transcript entry's primary [`transcript_index::EntryCategory`] (reused
/// via `index_category_of`, so the outline and the index stay in lock-step) onto
/// the outline's own [`turn_outline::OutlineKind`]. The category set is a superset
/// of the outline's kinds, so this is a total mapping.
fn outline_kind_of(entries: &[TranscriptEntry], index: usize) -> turn_outline::OutlineKind {
    use transcript_index::EntryCategory;
    use turn_outline::OutlineKind;
    match index_category_of(entries, index) {
        EntryCategory::UserTurn => OutlineKind::UserTurn,
        EntryCategory::Assistant => OutlineKind::Assistant,
        EntryCategory::Reasoning => OutlineKind::Reasoning,
        EntryCategory::ToolCall => OutlineKind::ToolRun,
        EntryCategory::Error => OutlineKind::Error,
        EntryCategory::Subagent => OutlineKind::Subagent,
        EntryCategory::Plan => OutlineKind::Plan,
        EntryCategory::Diff => OutlineKind::Diff,
        EntryCategory::Note => OutlineKind::Note,
    }
}

/// Derive the raw, deterministic title source for one entry's outline node — the
/// entry's own first content line / tool name / summary, never a model-generated
/// summary. Returns an empty string for a title-less entry; the outline model's
/// `clean_title` then falls back to the kind label honestly. Secret-free: a tool
/// node is titled by its tool name (and status), never by its raw output.
fn outline_title_of(entry: &TranscriptEntry) -> String {
    match &entry.kind {
        TranscriptEntryKind::Message(item) => item.content.clone(),
        TranscriptEntryKind::ToolResult(tool) => {
            // The tool name plus a status suffix when it did not succeed, so a
            // failed run reads as "shell (error)" — honest, output-free.
            let name = tool.result.tool_name.clone();
            let status = match tool.result.status {
                ToolStatus::Success => return name,
                ToolStatus::Error => "error",
                ToolStatus::Denied => "denied",
                ToolStatus::Stale => "stale",
                ToolStatus::Cancelled => "cancelled",
            };
            format!("{name} ({status})")
        }
        TranscriptEntryKind::Reasoning(snapshot) => snapshot.display_text.clone(),
        TranscriptEntryKind::Log(log) => log.message().to_string(),
        TranscriptEntryKind::PlanCard(_) => "plan".to_string(),
        TranscriptEntryKind::Diff(data) => data.summary.clone(),
        TranscriptEntryKind::SlashEcho(echo) => {
            if echo.args.trim().is_empty() {
                format!("/{}", echo.cmd)
            } else {
                format!("/{} {}", echo.cmd, echo.args)
            }
        }
    }
}

/// Build the per-entry classification slice the Semantic Turn Outline (§12.2.1)
/// consumes from the active transcript. Each entry contributes its stable id,
/// content revision (so a mutation re-outlines), outline kind, error cross-cut
/// flag (`entry_is_error`, the same failure predicate the renderer/jump-nav use),
/// and its deterministic title source. Pure over the entry slice.
fn build_outline_entries(entries: &[TranscriptEntry]) -> Vec<turn_outline::OutlineEntry> {
    entries
        .iter()
        .enumerate()
        .map(|(i, entry)| turn_outline::OutlineEntry {
            id: entry.id,
            revision: entry.revision,
            kind: outline_kind_of(entries, i),
            is_error: entry_is_error(entries, i),
            raw_title: outline_title_of(entry),
        })
        .collect()
}

/// Refresh the Semantic Turn Outline (§12.2.1) against the active transcript,
/// rebuilding **only** when the entries' (id, revision, kind, error, title)
/// fingerprint has moved since the last refresh. Called lazily — right before the
/// outline overlay opens or renders — so an idle session that never opens the
/// overlay pays nothing, and an open overlay re-outlines only on a real
/// transcript change (append, stream settle, revision bump, clear, compaction,
/// fold/filter toggle, resume) rather than every frame.
pub(crate) fn refresh_turn_outline(app: &mut TuiApp) {
    let entries = build_outline_entries(active_transcript_entries(app));
    let fingerprint = turn_outline::OutlineIndex::fingerprint_of(entries.iter());
    app.turn_outline.rebuild_if_stale(fingerprint, &entries);
}

/// Fold one transcript entry into its Session Timeline (§12.2.6)
/// [`session_timeline::TimelineKind`]. Built on the same `index_category_of`
/// classification the index and outline use (so the timeline stays in lock-step
/// with them), then refined to the timeline's higher-signal event kinds: a
/// `/diff` snapshot reads as an `Edit`, a *denied* tool reads as an `Approval`
/// (the user's accept/deny decision is the event, not the tool), and a user
/// prompt reads as a `Prompt` / an assistant answer as a `Turn`. The category
/// set is a superset of the timeline's kinds, so this is a total mapping.
fn timeline_kind_of(entries: &[TranscriptEntry], index: usize) -> session_timeline::TimelineKind {
    use session_timeline::TimelineKind;
    use transcript_index::EntryCategory;
    // High-signal refinements that the coarse category cannot express: a denied
    // tool is the approval decision; a diff card is an edit.
    if let Some(entry) = entries.get(index) {
        match &entry.kind {
            TranscriptEntryKind::ToolResult(tool) if tool.result.status == ToolStatus::Denied => {
                return TimelineKind::Approval;
            }
            TranscriptEntryKind::Diff(_) => return TimelineKind::Edit,
            _ => {}
        }
    }
    match index_category_of(entries, index) {
        EntryCategory::UserTurn => TimelineKind::Prompt,
        EntryCategory::Assistant => TimelineKind::Turn,
        EntryCategory::Reasoning => TimelineKind::Reasoning,
        EntryCategory::ToolCall => TimelineKind::Tool,
        EntryCategory::Error => TimelineKind::Error,
        EntryCategory::Subagent => TimelineKind::Subagent,
        EntryCategory::Plan => TimelineKind::Plan,
        EntryCategory::Diff => TimelineKind::Edit,
        EntryCategory::Note => TimelineKind::Note,
    }
}

/// Build the per-entry classification slice the Session Timeline (§12.2.6)
/// consumes from the active transcript. Events are grouped by turn: the 1-based
/// turn ordinal bumps on each user prompt (so everything between two prompts —
/// the model's reasoning, tools, and answer — shares a turn). Each entry
/// contributes its stable id, content revision (so a mutation re-builds), event
/// kind, error cross-cut flag (`entry_is_error`, the same failure predicate the
/// renderer/jump-nav use), a pending flag for an in-flight (not-yet-settled,
/// streaming) assistant turn, the turn it belongs to, an optional timestamp
/// (`None` today — transcript entries carry no per-event clock, the spec's
/// "missing timestamps" case), and its deterministic label source. Pure over the
/// entry slice.
fn build_timeline_sources(entries: &[TranscriptEntry]) -> Vec<session_timeline::TimelineSource> {
    let mut turn: u32 = 0;
    entries
        .iter()
        .enumerate()
        .map(|(i, entry)| {
            // A user prompt starts a new turn; the first prompt makes turn 1.
            // Entries before any prompt belong to turn 0 (a pre-prompt preamble),
            // which is grouped honestly rather than forced into turn 1.
            if matches!(&entry.kind, TranscriptEntryKind::Message(item) if item.role == Role::User)
            {
                turn = turn.saturating_add(1);
            }
            session_timeline::TimelineSource {
                id: entry.id,
                revision: entry.revision,
                kind: timeline_kind_of(entries, i),
                is_error: entry_is_error(entries, i),
                // Transcript entries are only pushed once finalized, so a settled
                // entry is never pending; the streaming-in-flight turn is not yet
                // an entry. The flag is wired (and unit-tested) so a future
                // in-flight-turn event can mark itself pending without a schema
                // change.
                is_pending: false,
                turn,
                timestamp: None,
                raw_label: outline_title_of(entry),
            }
        })
        .collect()
}

/// Refresh the Session Timeline (§12.2.6) against the active transcript,
/// rebuilding **only** when the entries' fingerprint has moved since the last
/// refresh. Called lazily — right before the timeline overlay opens or renders —
/// so an idle session that never opens the overlay pays nothing, and an open
/// overlay re-builds only on a real transcript change (append, stream settle,
/// revision bump, clear, compaction, fold/filter toggle, resume) rather than
/// every frame. The active kind filter is preserved across the rebuild.
pub(crate) fn refresh_session_timeline(app: &mut TuiApp) {
    let sources = build_timeline_sources(active_transcript_entries(app));
    let fingerprint = session_timeline::SessionTimeline::fingerprint_of(sources.iter());
    app.session_timeline.rebuild_if_stale(fingerprint, &sources);
}

/// Refresh the What Changed Since Here? delta (§12.2.7) against the active
/// transcript, rebuilding **only** when the anchor moved or the entries'
/// fingerprint has shifted since the last refresh. Reuses the same classified
/// [`session_timeline::TimelineSource`] slice the Session Timeline builds (so the
/// "what changed" view stays in lock-step with the timeline), then folds the
/// entries *after* the marked anchor into grouped change items. Called lazily —
/// right before the overlay opens or renders — so an idle session that never marks
/// a point pays nothing, and an open overlay re-builds only on a real transcript
/// change (append, stream settle, revision bump, clear, compaction, resume) or an
/// anchor move, never every frame.
pub(crate) fn refresh_change_summary(app: &mut TuiApp) {
    let sources = build_timeline_sources(active_transcript_entries(app));
    let anchor = app.change_summary.anchor();
    let fingerprint = change_summary::ChangeSummary::fingerprint_of(anchor, sources.iter());
    app.change_summary.rebuild_if_stale(fingerprint, &sources);
}

/// Map the private [`SubagentLifecycle`] onto the pure timeline module's
/// [`subagent_timeline::SubagentTimelineStatus`]. Total and standalone so the
/// timeline module never depends on `lib.rs`.
fn subagent_timeline_status(
    lifecycle: SubagentLifecycle,
) -> subagent_timeline::SubagentTimelineStatus {
    use subagent_timeline::SubagentTimelineStatus as S;
    match lifecycle {
        SubagentLifecycle::Running => S::Running,
        SubagentLifecycle::Completed => S::Completed,
        SubagentLifecycle::Failed => S::Failed,
        SubagentLifecycle::Rejected => S::Rejected,
    }
}

/// Project the live subagent-pane records into the structured
/// [`subagent_timeline::SubagentTimelineSource`] rows the Subagent Timeline Panel
/// (§12.8.1) consumes. Pure data extraction: each row carries the subagent's id,
/// role label, lifecycle status, latest activity line, elapsed seconds (computed
/// from the record's monotonic `started` instant via a *saturating* duration — no
/// back-dated subtraction that could underflow a fresh clock), tool count, and
/// the child-reported cost in USD micros (the subagent provider's spend, falling
/// back to the main provider's). A cap-rejected record has no start time and so
/// reports `None` elapsed/cost — the spec's "accurate cost depends on child
/// metrics" / cap-rejection cases, rendered honestly downstream.
fn build_subagent_timeline_sources(app: &TuiApp) -> Vec<subagent_timeline::SubagentTimelineSource> {
    let now = std::time::Instant::now();
    app.subagent_pane
        .records
        .iter()
        .map(|record| {
            let elapsed_secs = record
                .started
                .map(|started| now.saturating_duration_since(started).as_secs());
            let (tool_count, cost_micros) = match record.metrics.as_ref() {
                Some(metrics) => {
                    let tools = metrics.subagent_tool_calls.max(metrics.tool_calls);
                    // Prefer the child's own provider spend; fall back to the
                    // main provider snapshot when the subagent ledger is empty.
                    let cost = metrics
                        .subagent_provider
                        .estimated_usd_micros
                        .or(metrics.provider.estimated_usd_micros);
                    (tools, cost)
                }
                None => (0, None),
            };
            subagent_timeline::SubagentTimelineSource {
                id: record.id,
                agent: record.agent.clone(),
                status: subagent_timeline_status(record.lifecycle),
                latest: record.latest.clone(),
                elapsed_secs,
                tool_count,
                cost_micros,
            }
        })
        .collect()
}

/// Refresh the Subagent Timeline Panel (§12.8.1) against the live subagent-pane
/// records, rebuilding **only** when the records' fingerprint has moved since the
/// last refresh. Called lazily — right before the panel opens or renders — so an
/// idle session that never opens the panel pays nothing, and an open panel
/// re-builds only on a real subagent event (start, activity, tool result,
/// completion, failure, cap rejection) rather than every frame. The active status
/// filter is preserved across the rebuild.
///
/// Note the running-elapsed wrinkle: a running subagent's `elapsed_secs` advances
/// once per wall-clock second, so the fingerprint moves (and the panel re-paints)
/// at most once a second while a subagent runs — never per frame — and an idle
/// (all-finished) session's fingerprint is stable, so it pays a single `u64`
/// comparison.
pub(crate) fn refresh_subagent_timeline(app: &mut TuiApp) {
    let sources = build_subagent_timeline_sources(app);
    let fingerprint = subagent_timeline::SubagentTimeline::fingerprint_of(sources.iter());
    app.subagent_timeline
        .rebuild_if_stale(fingerprint, &sources);
}

/// Refresh the Live Review Board (§12.8.5) against the live subagent-pane records,
/// rebuilding **only** when the records' fingerprint has moved since the last
/// refresh. Reuses the SAME `build_subagent_timeline_sources` projection the
/// Subagent Timeline Panel consumes, so the board and the panel can never disagree
/// about a worker's state. Called lazily — right before the board opens and once a
/// frame while it is open — so an idle session that never opens it pays nothing,
/// and an open board re-builds only on a real subagent event (start, activity,
/// tool result, completion, failure, cap rejection). Same zero-idle-cost shape as
/// `refresh_subagent_timeline`: a running worker moves the fingerprint at most once
/// a wall-clock second, never per frame.
pub(crate) fn refresh_review_board(app: &mut TuiApp) {
    let sources = build_subagent_timeline_sources(app);
    let fingerprint = review_board::ReviewBoard::fingerprint_of(sources.iter());
    app.review_board.rebuild_if_stale(fingerprint, &sources);
}

/// Refresh the Attention Routing model (§12.8.6) against the live subagent-pane
/// records, rebuilding **only** when the records' `(id, status, latest, pinned)`
/// fingerprint has moved since the last refresh. Reuses the same timeline-source
/// projection the Subagent Timeline Panel builds (so the two views never drift),
/// tagging each with whether the user pinned it (the compare-mark set — the
/// "selected/pinned completions" opt-in). Called from the render path before the
/// status-line indicator paints and from the `JumpToAttention` quick-jump, so a
/// calm session (everything running or quietly done) pays one `u64` comparison and
/// surfaces nothing. The routing only *surfaces* events — it never drops a
/// timeline/transcript row, so logs/evals keep every raw event.
pub(crate) fn refresh_attention_route(app: &mut TuiApp) {
    let sources = build_subagent_timeline_sources(app);
    let attention_sources: Vec<attention::AttentionSource<'_>> = sources
        .iter()
        .map(|source| attention::AttentionSource {
            source,
            pinned: app.subagent_compare_marks.contains(source.id),
        })
        .collect();
    let fingerprint = attention::AttentionRoute::fingerprint_of(attention_sources.iter());
    app.attention_route
        .rebuild_if_stale(fingerprint, &attention_sources);
}

/// Count the non-blank lines in a text blob — the body row count a lane header
/// advertises ("tool output (12 lines)"). Bounded by counting only what is
/// present; an empty/blank blob yields 0.
fn lane_line_count(text: &str) -> usize {
    text.lines().filter(|line| !line.trim().is_empty()).count()
}

/// Pull the human-visible output text of a tool result (stdout/output/text/
/// message, falling back to the serialized content blob), reusing the same field
/// order the duplicate-fold model scans. Used for the tool-output lane's line
/// count + preview.
fn lane_tool_output_text(tool: &ToolTranscript) -> String {
    let content = &tool.result.content;
    for key in ["stdout", "output", "text", "message"] {
        if let Some(text) = content.get(key).and_then(|v| v.as_str())
            && !text.trim().is_empty()
        {
            return text.to_string();
        }
    }
    content.to_string()
}

/// Decompose one transcript entry into its foldable lanes (§12.2.2). The lane set
/// is derived from the entry's kind, reusing the same `TranscriptEntryKind` /
/// `ToolStatus` / `is_failure_log` predicates the renderer uses, so the lanes the
/// user folds match what the renderer painted. `is_error` is the entry-level
/// failure cross-cut so the relevant lane keeps its always-visible header. Pure
/// over the entry.
fn build_lane_entries(entry: &TranscriptEntry, is_error: bool) -> Vec<lane_fold::LaneEntry> {
    use lane_fold::{LaneEntry, LaneId};
    let mut lanes: Vec<LaneEntry> = Vec::new();
    match &entry.kind {
        TranscriptEntryKind::Message(item) => {
            // An assistant message may carry an attached reasoning summary; it
            // becomes its own foldable reasoning lane ahead of the prose.
            if let Some(reasoning) = &item.reasoning {
                let text = reasoning.display_text.clone();
                lanes.push(LaneEntry {
                    id: LaneId::Reasoning,
                    line_count: lane_line_count(&text),
                    is_error: false,
                    preview: text,
                });
            }
            lanes.push(LaneEntry {
                id: LaneId::AssistantText,
                line_count: lane_line_count(&item.content),
                is_error,
                preview: item.content.clone(),
            });
        }
        TranscriptEntryKind::ToolResult(tool) => {
            // Tool input lane: the call name + its serialized arguments (never the
            // raw output, so a folded input stays secret-light).
            if let Some(call) = &tool.call {
                let input = if call.arguments.is_null() {
                    call.name.clone()
                } else {
                    format!("{} {}", call.name, call.arguments)
                };
                lanes.push(LaneEntry {
                    id: LaneId::ToolInput,
                    line_count: 1,
                    is_error: false,
                    preview: input,
                });
            }
            // A denied tool call is an approval *decision*: it gets its own
            // foldable approval lane so the user can collapse the denial rationale
            // while still seeing the lane header. (Denials are surfaced as the
            // tool's content, never the raw output, so a folded approval stays
            // legible.)
            if tool.result.status == ToolStatus::Denied {
                lanes.push(LaneEntry {
                    id: LaneId::Approval,
                    line_count: 1,
                    is_error: false,
                    preview: format!("{} (denied)", tool.result.tool_name),
                });
            }
            // Tool output lane: the human-visible result body. An errored tool
            // tags this lane so its header always paints (failures never hide).
            let output = lane_tool_output_text(tool);
            lanes.push(LaneEntry {
                id: LaneId::ToolOutput,
                line_count: lane_line_count(&output),
                is_error,
                preview: output,
            });
        }
        TranscriptEntryKind::Reasoning(snapshot) => {
            let text = snapshot.display_text.clone();
            lanes.push(LaneEntry {
                id: LaneId::Reasoning,
                line_count: lane_line_count(&text),
                is_error: false,
                preview: text,
            });
        }
        TranscriptEntryKind::Log(log) => {
            // A failure log is an error lane (always-visible header); any other
            // log is a system-notice lane.
            let message = log.message().to_string();
            let lane_id = if is_error || is_failure_log(&message) {
                LaneId::Error
            } else {
                LaneId::SystemNotice
            };
            lanes.push(LaneEntry {
                id: lane_id,
                line_count: lane_line_count(&message),
                is_error: is_error || matches!(lane_id, LaneId::Error),
                preview: message,
            });
        }
        TranscriptEntryKind::PlanCard(_) => {
            lanes.push(LaneEntry {
                id: LaneId::Plan,
                line_count: 1,
                is_error: false,
                preview: "plan".to_string(),
            });
        }
        TranscriptEntryKind::Diff(data) => {
            // A `/diff` snapshot reads as a system-notice lane (operational
            // breadcrumb), titled by its summary.
            lanes.push(LaneEntry {
                id: LaneId::SystemNotice,
                line_count: data.lines.len(),
                is_error: false,
                preview: data.summary.clone(),
            });
        }
        TranscriptEntryKind::SlashEcho(echo) => {
            let preview = if echo.args.trim().is_empty() {
                format!("/{}", echo.cmd)
            } else {
                format!("/{} {}", echo.cmd, echo.args)
            };
            lanes.push(LaneEntry {
                id: LaneId::SystemNotice,
                line_count: 1,
                is_error: false,
                preview,
            });
        }
    }
    lanes
}

/// The entry id whose lanes the Collapsible Reasoning/Tool Lanes overlay
/// (§12.2.2) folds: the focused entry when one is focused, else the latest (tail)
/// entry, so opening the overlay without first focusing still has a sensible
/// target. `None` only on an empty transcript.
fn lane_fold_anchor_id(app: &TuiApp) -> Option<u64> {
    let entries = active_transcript_entries(app);
    if let Some(index) = active_selected_entry(app)
        && let Some(entry) = entries.get(index)
    {
        return Some(entry.id);
    }
    entries.last().map(|entry| entry.id)
}

/// Refresh the Collapsible Reasoning/Tool Lanes panel (§12.2.2) for the focused
/// entry, rebuilding **only** when the (entry id, lane sources, fold-store
/// generation) fingerprint has moved since the last refresh. Called lazily —
/// right before the lane overlay opens or renders — so an idle session that never
/// opens the overlay pays nothing, and an open overlay re-projects only on a real
/// change (focus move, entry revision bump, or a collapse toggle) rather than
/// every frame.
pub(crate) fn refresh_lane_fold(app: &mut TuiApp) {
    let entries = active_transcript_entries(app);
    let (entry_id, lanes) = match lane_fold_anchor_id(app).and_then(|id| {
        entries
            .iter()
            .position(|entry| entry.id == id)
            .map(|i| (id, i))
    }) {
        Some((id, index)) => {
            let is_error = entry_is_error(entries, index);
            (Some(id), build_lane_entries(&entries[index], is_error))
        }
        None => (None, Vec::new()),
    };
    let fingerprint =
        lane_fold::LanePanel::fingerprint_of(entry_id, &lanes, app.lane_folds.generation());
    app.lane_panel
        .rebuild_if_stale(fingerprint, entry_id, &lanes, &app.lane_folds);
}

/// Compact human label for an entry id used in the recent-jump status readout
/// (`"#3 user"`, `"#5 tool"`). `None` when the id is no longer live.
fn jump_mark_entry_label(app: &TuiApp, entry_id: u64) -> Option<String> {
    let entries = active_transcript_entries(app);
    let index = entries.iter().position(|entry| entry.id == entry_id)?;
    let kind = match &entries[index].kind {
        TranscriptEntryKind::Message(item) if item.role == Role::User => "user",
        TranscriptEntryKind::Message(item) if item.role == Role::Assistant => "asst",
        TranscriptEntryKind::Message(_) => "msg",
        TranscriptEntryKind::ToolResult(_) => "tool",
        TranscriptEntryKind::Reasoning(_) => "think",
        TranscriptEntryKind::Log(_) => "log",
        _ => "entry",
    };
    Some(format!("#{} {kind}", index + 1))
}

/// `Alt+m`: record a jump mark at the entry currently at the top of the
/// viewport. Marks are stored by stable entry id so they survive a transcript
/// reflow. Sets a status line confirming the mark and the running mark count.
fn set_jump_mark(app: &mut TuiApp) {
    let Some(entry_id) = current_top_entry_id(app) else {
        app.status = "no transcript to mark".to_string();
        return;
    };
    let count = app.jump_marks.set(entry_id);
    let label = jump_mark_entry_label(app, entry_id).unwrap_or_else(|| format!("#{entry_id}"));
    app.status = if count == 1 {
        format!("mark set at {label}")
    } else {
        format!("mark set at {label} ({count} marks) — Alt+' to jump back")
    };
}

/// `Alt+'`: jump back to the most recently set jump mark, popping it off the
/// stack. With no marks set, surfaces the recent jump history (or a hint when
/// there is none) instead of moving the view.
fn jump_to_jump_mark(app: &mut TuiApp) {
    let current = current_top_entry_id(app);
    let Some(target) = app.jump_marks.jump_back(current) else {
        // Nothing to pop. Show the recent trail if we have one, else a hint.
        let summary = app
            .jump_marks
            .history_summary(4, |id| jump_mark_entry_label(app, id));
        app.status = if summary.is_empty() {
            "no jump marks — Alt+m to set one".to_string()
        } else {
            format!("no marks left — recent jumps: {summary}")
        };
        return;
    };
    if jump_to_entry_id(app, target) {
        let label = jump_mark_entry_label(app, target).unwrap_or_else(|| format!("#{target}"));
        let remaining = app.jump_marks.mark_count();
        app.status = if remaining == 0 {
            format!("jumped back to {label}")
        } else {
            format!("jumped back to {label} ({remaining} marks left)")
        };
    } else {
        // The mark's entry is gone (transcript rebuilt). It was already popped;
        // tell the user and try the next-older mark on the next press.
        app.status = "mark target no longer in transcript".to_string();
    }
}

/// Largest number of queue mutations kept on the undo stack. Small on
/// purpose: the queue is short-lived and one-line, so a deep history would
/// be more confusing than useful. Oldest entries fall off the front.
const QUEUE_UNDO_CAP: usize = 32;

/// A reversible queue mutation, recorded on `TuiApp::prompt_queue_undo` so a
/// later undo can restore the exact prior order and contents. Positions are
/// the Vec indices at the moment the op was applied; `undo` re-inserts /
/// re-moves against the live queue.
#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) enum QueueMutation {
    /// An item was deleted. Undo re-inserts `text` at `index` (clamped) with
    /// its original `id` so its hit-target identity is restored too.
    Deleted { index: usize, id: u64, text: String },
    /// An item was moved. Recorded by *stable id*, not absolute index, so a
    /// front-drain between the move and its undo cannot stale the record:
    /// `id` is the moved item; `prev` is the id that sat immediately before
    /// `id`'s *original* slot (`None` if it was at the front). Undo resolves
    /// both ids to live indices and re-inserts `id` right after `prev` (or at
    /// the front), no-opping if either id has since drained out.
    Reordered { id: u64, prev: Option<u64> },
    /// A multi-select group move (§11G.7) reordered several items at once.
    /// A per-item `Reordered` record can't reverse a block move coherently
    /// (each record references the post-move order), so the group move snapshots
    /// the *entire* id order from before the move; undo restores exactly that
    /// order via `apply_queue_id_order`. Ids that have since drained out are
    /// dropped on restore, so the snapshot survives a front-drain gracefully.
    BlockReordered { order: Vec<u64> },
}

/// In-flight mouse drag-reorder. Records which item id is being dragged and
/// the index it started at, so the drop can be recorded as a `Reordered`
/// mutation spanning the whole gesture (not each intermediate hop). `prev`
/// captures the stable id that sat immediately before `from` at drag start
/// (`None` if `from` was the front), so the recorded undo is index-shift-proof.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) struct QueueDrag {
    pub(crate) id: u64,
    pub(crate) from: usize,
    pub(crate) prev: Option<u64>,
}

/// Re-establish the `prompt_queue_ids.len() == prompt_queue.len()` invariant.
///
/// The overlay manipulators (delete / reorder / undo) keep both deques in
/// perfect lockstep directly. This helper is the safety net for the two
/// mutation shapes that happen *outside* the overlay: a front-drain
/// (`pop_front` as a queued prompt runs) and a back-enqueue (`push_back` as
/// the user queues new input). It models exactly those two shapes — drop ids
/// from the front when the queue shrank, stamp fresh ids on the back when it
/// grew — so an existing item's id is never silently reassigned. Called at
/// the top of every overlay manipulation and once per queue render.
fn sync_queue_ids(app: &mut TuiApp) {
    let want = app.prompt_queue.len();
    // Queue shrank from the front (drain): drop the matching number of
    // leading ids so the surviving items keep their ids aligned to the tail.
    while app.prompt_queue_ids.len() > want {
        app.prompt_queue_ids.pop_front();
    }
    // Queue grew at the back (enqueue): stamp fresh monotonic ids.
    while app.prompt_queue_ids.len() < want {
        let id = app.next_queue_id;
        app.next_queue_id += 1;
        app.prompt_queue_ids.push_back(id);
    }
}

/// Resolve a stable queue item id to its current Vec index, or `None` if the
/// id is no longer present (already drained or deleted). Identity is the stable
/// id; the position is derived on demand, so a concurrent front-drain or
/// reorder can never stale a held index.
fn queue_index_for_id(app: &TuiApp, id: u64) -> Option<usize> {
    app.prompt_queue_ids.iter().position(|qid| *qid == id)
}

/// The stable id of the item immediately before `index`, or `None` if `index`
/// is the front (or out of range). Used to record a reorder undo by the moved
/// item's left-neighbour id so a later front-drain can't stale the record.
fn queue_prev_id_at(app: &TuiApp, index: usize) -> Option<u64> {
    index
        .checked_sub(1)
        .and_then(|i| app.prompt_queue_ids.get(i).copied())
}

/// Stamp a fresh stable id for the prompt just `push_back`ed onto the queue.
/// Call immediately after each enqueue so the id sidecar stays aligned.
fn enqueue_queue_id(app: &mut TuiApp) {
    let id = app.next_queue_id;
    app.next_queue_id += 1;
    app.prompt_queue_ids.push_back(id);
}

/// Record a mutation on the bounded undo stack, dropping the oldest entry
/// once `QUEUE_UNDO_CAP` is exceeded.
fn push_queue_undo(app: &mut TuiApp, mutation: QueueMutation) {
    app.prompt_queue_undo.push(mutation);
    if app.prompt_queue_undo.len() > QUEUE_UNDO_CAP {
        app.prompt_queue_undo.remove(0);
    }
}

/// Move the item with stable `id` so it sits immediately after the item with
/// id `prev` (or at the front when `prev` is `None`). Resolves both ids to
/// live indices, so a front-drain between recording and replaying the move
/// cannot stale it. Returns `true` if it moved an item, `false` on a no-op
/// (the moved id has drained out, the anchor drained out, or it was already in
/// place). This is the id-keyed primitive that `queue_undo` replays a recorded
/// `Reordered` through.
fn queue_move_id_after(app: &mut TuiApp, id: u64, prev: Option<u64>) -> bool {
    sync_queue_ids(app);
    let Some(from) = queue_index_for_id(app, id) else {
        return false;
    };
    let to = match prev {
        None => 0,
        Some(prev_id) => {
            // Re-insert right after the anchor's current slot. If the anchor
            // drained out, the recorded position is gone: no-op rather than
            // guess a wrong slot.
            let Some(prev_index) = queue_index_for_id(app, prev_id) else {
                return false;
            };
            // Removing `id` first shifts everything after it down by one, so a
            // target that lies past `from` must compensate; landing right
            // after the anchor means `prev_index` when the anchor is before
            // `from`, and `prev_index` (post-removal) when it is after.
            if prev_index < from {
                prev_index + 1
            } else {
                prev_index
            }
        }
    };
    queue_move_indices(app, from, to)
}

/// Delete the queue item with `id`. Records the removal (text + former
/// position + id) on the undo stack, clamps the overlay focus cursor, and
/// sets a status message. No-op (returns false) if the id is gone.
fn queue_delete_by_id(app: &mut TuiApp, id: u64) -> bool {
    sync_queue_ids(app);
    let Some(index) = queue_index_for_id(app, id) else {
        return false;
    };
    let text = app
        .prompt_queue
        .remove(index)
        .expect("index from resolve is in range");
    app.prompt_queue_ids
        .remove(index)
        .expect("ids stay in lockstep with the queue");
    push_queue_undo(
        app,
        QueueMutation::Deleted {
            index,
            id,
            text: text.clone(),
        },
    );
    clamp_queue_focus(app);
    app.auto_drain_queue = false;
    app.status = format!("deleted queued prompt ({} left)", app.prompt_queue.len());
    app.needs_redraw = true;
    true
}

/// Move the item at `from` to `to` in BOTH the queue and its id sidecar,
/// keeping them in lockstep. Pure index shuffle; records no undo (callers
/// decide whether the move is an undoable op or a step of an undo itself).
/// Returns `true` if it actually moved an item, `false` on a no-op (equal
/// indices or either index out of range) so callers can surface that the
/// requested move did nothing rather than claiming success.
fn queue_move_indices(app: &mut TuiApp, from: usize, to: usize) -> bool {
    if from == to || from >= app.prompt_queue.len() || to >= app.prompt_queue.len() {
        return false;
    }
    if let Some(text) = app.prompt_queue.remove(from) {
        app.prompt_queue.insert(to, text);
    }
    if let Some(id) = app.prompt_queue_ids.remove(from) {
        app.prompt_queue_ids.insert(to, id);
    }
    true
}

/// Undo the most recent queue mutation, reversing it exactly. A deleted item
/// returns to its former position (with its original id); a reorder moves the
/// item (by stable id) back to immediately after its recorded left-neighbour.
/// Sets a status message; safe on an empty stack ("nothing to undo"). Returns
/// true if anything was undone. A reorder whose ids cannot currently be applied
/// (an anchor drained, or the queue drifted past the snapshot) is *deferred*,
/// not discarded: the record is pushed back onto the undo stack and reported as
/// "skipped (stale) — try undo again" so a later `u` retries it once the queue
/// settles, and the stack stays sequenced (deep-review #104). It never falsely
/// claims success.
fn queue_undo(app: &mut TuiApp) -> bool {
    sync_queue_ids(app);
    let Some(mutation) = app.prompt_queue_undo.pop() else {
        app.status = "nothing to undo".to_string();
        app.needs_redraw = true;
        return false;
    };
    match &mutation {
        QueueMutation::Deleted { index, id, text } => {
            let at = (*index).min(app.prompt_queue.len());
            app.prompt_queue.insert(at, text.clone());
            app.prompt_queue_ids.insert(at, *id);
            app.next_queue_id = app.next_queue_id.max(id + 1);
            app.status = "undid delete".to_string();
        }
        QueueMutation::Reordered { id, prev } => {
            // Restore the moved item to immediately after its recorded
            // left-neighbour (resolved live via id, so a front-drain can't
            // stale it). If it can't apply — the item or its anchor drained
            // out — push the record back so a later `u` retries it (the stack
            // stays sequenced) instead of discarding it and claiming there is
            // nothing to undo for a record that demonstrably existed.
            if !queue_move_id_after(app, *id, *prev) {
                return defer_stale_queue_undo(app, mutation);
            }
            app.status = "undid reorder".to_string();
        }
        QueueMutation::BlockReordered { order } => {
            // Restore the snapshotted id order, filtered to ids still live (a
            // drained id silently drops). If the surviving ids no longer span
            // the whole queue the snapshot can't faithfully restore it, so push
            // the record back for a later retry rather than clearing the queue.
            let live: Vec<u64> = order
                .iter()
                .copied()
                .filter(|id| queue_index_for_id(app, *id).is_some())
                .collect();
            if live.len() != app.prompt_queue.len() {
                // The queue drifted (a drain/enqueue) past what the snapshot can
                // faithfully restore; defer rather than mangle the order.
                return defer_stale_queue_undo(app, mutation);
            }
            apply_queue_id_order(app, &live);
            app.status = "undid group move".to_string();
        }
    }
    clamp_queue_focus(app);
    app.needs_redraw = true;
    true
}

/// A reorder undo could not be applied against the queue's current shape (an
/// anchor drained, or the queue drifted past the snapshot). Push the record
/// back onto the undo stack so a later `u` retries it once the queue settles —
/// the stack stays sequenced and the record is never silently lost — and report
/// the deferral honestly rather than as "nothing to undo" (deep-review #104).
/// Returns `false`: this invocation undid nothing.
fn defer_stale_queue_undo(app: &mut TuiApp, mutation: QueueMutation) -> bool {
    app.prompt_queue_undo.push(mutation);
    app.status = "skipped (stale) — try undo again".to_string();
    app.needs_redraw = true;
    false
}

/// Clamp the overlay focus cursor into range after the queue shrank or
/// shifted. Safe on an empty queue (cursor parks at 0).
fn clamp_queue_focus(app: &mut TuiApp) {
    if let Some(state) = app.prompt_queue_overlay.as_mut() {
        let len = app.prompt_queue.len();
        if len == 0 {
            state.selected = 0;
        } else if state.selected >= len {
            state.selected = len - 1;
        }
    }
}

// ===========================================================================
// Multi-select queued prompts (§11G.7)
//
// The reorder overlay's single focus cursor (`PromptQueueState::selected`) is
// joined by a *group* selection (`TuiApp::prompt_queue_multiselect`) keyed by
// stable ids. The group verbs — toggle, select-all, group delete, group move,
// merge-to-composer — all resolve their ids to live indices at action time, so
// a concurrent front-drain or reorder can never make them touch the wrong row.
// These are the shared handlers the overlay's keyboard path and the per-item
// mouse toggle both dispatch through, so keyboard/mouse parity holds by
// construction.
// ===========================================================================

/// The live queue id sidecar as an ordered slice (front-to-back). The single
/// place the multi-select math reads queue order from, so it always matches
/// what the overlay paints.
fn queue_live_ids(app: &TuiApp) -> Vec<u64> {
    app.prompt_queue_ids.iter().copied().collect()
}

/// Toggle the focused queue item in/out of the multi-select group. No-op on an
/// empty queue. Sets a status reflecting the new group size.
fn queue_toggle_focused_multiselect(app: &mut TuiApp) {
    sync_queue_ids(app);
    // Drop any ids that drained/deleted out from under the overlay so the
    // reported group size stays truthful.
    app.prompt_queue_multiselect
        .retain_live(&queue_live_ids(app));
    let Some(state) = app.prompt_queue_overlay.as_ref() else {
        return;
    };
    let Some(&id) = app.prompt_queue_ids.get(state.selected) else {
        return;
    };
    let added = app.prompt_queue_multiselect.toggle(id);
    let n = app.prompt_queue_multiselect.len();
    app.status = if added {
        format!("selected queued prompt ({n} in group)")
    } else if n == 0 {
        "selection cleared".to_string()
    } else {
        format!("deselected queued prompt ({n} in group)")
    };
    app.needs_redraw = true;
}

/// Toggle a specific queue item (by stable id) in/out of the group. The mouse
/// twin of [`queue_toggle_focused_multiselect`]; also seats the focus cursor on
/// the toggled row so a subsequent keyboard verb acts on the same item. No-op if
/// the id has drained out.
fn queue_toggle_id_multiselect(app: &mut TuiApp, id: u64) {
    sync_queue_ids(app);
    app.prompt_queue_multiselect
        .retain_live(&queue_live_ids(app));
    let Some(index) = queue_index_for_id(app, id) else {
        return;
    };
    if let Some(state) = app.prompt_queue_overlay.as_mut() {
        state.selected = index;
    }
    let added = app.prompt_queue_multiselect.toggle(id);
    let n = app.prompt_queue_multiselect.len();
    app.status = if added {
        format!("selected queued prompt ({n} in group)")
    } else if n == 0 {
        "selection cleared".to_string()
    } else {
        format!("deselected queued prompt ({n} in group)")
    };
    app.needs_redraw = true;
}

/// Tag every queued prompt (select-all). A subsequent toggle on a tagged row
/// peels it back out. No-op on an empty queue.
fn queue_select_all_multiselect(app: &mut TuiApp) {
    sync_queue_ids(app);
    let ids = queue_live_ids(app);
    if ids.is_empty() {
        return;
    }
    app.prompt_queue_multiselect.select_all(&ids);
    app.status = format!("selected all queued prompts ({} in group)", ids.len());
    app.needs_redraw = true;
}

/// Delete every prompt in the multi-select group as one batch. Each removal is
/// recorded on the undo stack (via `queue_delete_by_id`, resolved by id so the
/// shifting indices never matter), so an undo peels them back one at a time.
/// Returns `true` if anything was deleted. The group is cleared afterwards.
fn queue_group_delete(app: &mut TuiApp) -> bool {
    sync_queue_ids(app);
    let ids = app
        .prompt_queue_multiselect
        .ids_in_queue_order(&queue_live_ids(app));
    if ids.is_empty() {
        return false;
    }
    let mut removed = 0usize;
    for id in ids {
        if queue_delete_by_id(app, id) {
            removed += 1;
        }
    }
    app.prompt_queue_multiselect.clear();
    if removed > 0 {
        app.auto_drain_queue = false;
        app.status = format!(
            "deleted {removed} queued prompts ({} left)",
            app.prompt_queue.len()
        );
        app.needs_redraw = true;
    }
    removed > 0
}

/// Move the multi-select group one step up or down as a contiguous block.
/// Computed by stable id over the live order (`move_group`), then applied by
/// rebuilding the queue + id sidecar in the new id order, so a scattered or
/// already-contiguous group both move coherently. Records one `Reordered` undo
/// per shifted item. Returns `true` if it moved anything (blocked at the
/// boundary is a no-op). Keeps the focus cursor on the same item.
fn queue_group_move(app: &mut TuiApp, dir: prompt_queue_multiselect::MoveDir) -> bool {
    sync_queue_ids(app);
    let before = queue_live_ids(app);
    let Some(after) =
        prompt_queue_multiselect::move_group(&before, app.prompt_queue_multiselect.set(), dir)
    else {
        return false;
    };
    if after == before {
        return false;
    }
    // The focused id, so the cursor follows its row through the reshuffle.
    let focus_id = app
        .prompt_queue_overlay
        .as_ref()
        .and_then(|state| before.get(state.selected).copied());
    apply_queue_id_order(app, &after);
    // A block move is one undoable step: snapshot the pre-move id order so undo
    // restores it exactly (a per-item `Reordered` chain can't reverse a block
    // move coherently).
    push_queue_undo(app, QueueMutation::BlockReordered { order: before });
    // Re-seat the focus cursor onto the same item it was on.
    if let (Some(focus_id), Some(state)) = (focus_id, app.prompt_queue_overlay.as_mut())
        && let Some(pos) = after.iter().position(|x| *x == focus_id)
    {
        state.selected = pos;
    }
    let dir_word = match dir {
        prompt_queue_multiselect::MoveDir::Up => "up",
        prompt_queue_multiselect::MoveDir::Down => "down",
    };
    app.status = format!(
        "moved {} queued prompts {dir_word}",
        app.prompt_queue_multiselect.len()
    );
    app.needs_redraw = true;
    true
}

/// Reorder BOTH the queue and its id sidecar so the ids line up with `order`
/// (a permutation of the current ids). Rebuilds via a text lookup keyed by id,
/// so the prompt text rides with its id. Used by the group-move primitive,
/// which computes a new id order purely.
fn apply_queue_id_order(app: &mut TuiApp, order: &[u64]) {
    debug_assert_eq!(order.len(), app.prompt_queue.len());
    // Snapshot id -> text so we can re-emit in the target order.
    let by_id: std::collections::HashMap<u64, String> = app
        .prompt_queue_ids
        .iter()
        .copied()
        .zip(app.prompt_queue.iter().cloned())
        .collect();
    let mut new_queue: VecDeque<String> = VecDeque::with_capacity(order.len());
    let mut new_ids: VecDeque<u64> = VecDeque::with_capacity(order.len());
    for &id in order {
        if let Some(text) = by_id.get(&id) {
            new_queue.push_back(text.clone());
            new_ids.push_back(id);
        }
    }
    app.prompt_queue = new_queue;
    app.prompt_queue_ids = new_ids;
}

/// Merge the selected queued prompts (or, when nothing is tagged, the single
/// focused prompt) into the composer, removing them from the queue. The merged
/// text is concatenated in queue order with a blank line between prompts, and
/// appended after any existing composer draft (blank-line separated) so a
/// half-typed message isn't destroyed. Each pulled prompt records a `Deleted`
/// undo so the queue side of the merge is reversible. Closes the overlay.
/// Returns `true` if anything merged.
fn queue_merge_to_composer(app: &mut TuiApp) -> bool {
    if app.turn_rx.is_some() {
        app.status = "cannot merge while a turn is running".to_string();
        return false;
    }
    sync_queue_ids(app);
    let mut ids = app
        .prompt_queue_multiselect
        .ids_in_queue_order(&queue_live_ids(app));
    if ids.is_empty() {
        // No group: fall back to the single focused row.
        if let Some(state) = app.prompt_queue_overlay.as_ref()
            && let Some(&id) = app.prompt_queue_ids.get(state.selected)
        {
            ids.push(id);
        }
    }
    if ids.is_empty() {
        return false;
    }
    // Collect the text in queue order BEFORE deleting (deletes shift the queue).
    let mut parts: Vec<String> = Vec::with_capacity(ids.len());
    for &id in &ids {
        if let Some(index) = queue_index_for_id(app, id)
            && let Some(text) = app.prompt_queue.get(index)
        {
            parts.push(text.clone());
        }
    }
    if parts.is_empty() {
        return false;
    }
    // Remove the merged items (records per-item undo, resolves by id).
    for &id in &ids {
        queue_delete_by_id(app, id);
    }
    app.prompt_queue_multiselect.clear();
    let merged = parts.join("\n\n");
    let combined = if app.input.trim().is_empty() {
        merged
    } else {
        format!("{}\n\n{merged}", app.input)
    };
    input::set_input(app, combined);
    // Close the overlay so focus returns to the composer the text landed in.
    app.prompt_queue_overlay = None;
    app.prompt_queue_drag = None;
    app.status = format!(
        "merged {} queued prompt{} into the composer",
        parts.len(),
        if parts.len() == 1 { "" } else { "s" }
    );
    app.needs_redraw = true;
    true
}

// ===========================================================================
// Queue Groups (§12.3.4)
//
// Named batches layered over the flat prompt queue (`TuiApp::prompt_queue_groups`),
// addressed by the same stable item ids the multi-select set and the
// direct-manipulation registry use. The verbs — group the tagged (or focused)
// prompts, collapse/expand a group, pause/resume a group, dissolve a group —
// all resolve their ids to live indices at action time and prune drained
// members first, so a concurrent front-drain or reorder can never make them
// touch the wrong row. These are the shared handlers the overlay's keyboard
// verbs and the per-item mouse middle-click both dispatch through, so the
// keyboard/mouse parity holds by construction.
// ===========================================================================

/// Keep the group model honest before any group op: re-align the id sidecar to
/// the live queue, then prune members that drained / were deleted (dropping a
/// group emptied that way). Mirrors the `sync_queue_ids` + `retain_live` pair
/// the multi-select verbs run, so a stale id can never make a group op act on a
/// vanished prompt.
fn sync_queue_groups(app: &mut TuiApp) {
    sync_queue_ids(app);
    let ids = queue_live_ids(app);
    app.prompt_queue_groups.retain_live(&ids);
}

/// Group the tagged queued prompts (§12.3.4) into a fresh named batch. When the
/// multi-select set is empty, falls back to grouping the single focused prompt,
/// so the verb is useful with or without an active selection. The new group
/// becomes each member's sole owner (regrouping pulls a prompt out of any group
/// it was already in). Clears the multi-selection afterwards (the batch is now
/// the durable organization). Returns `true` if a group was formed; `false` on
/// an empty queue / stale cursor.
fn queue_create_group_from_selection(app: &mut TuiApp) -> bool {
    sync_queue_groups(app);
    let mut ids = app
        .prompt_queue_multiselect
        .ids_in_queue_order(&queue_live_ids(app));
    if ids.is_empty() {
        // No group tagged: fall back to the single focused row.
        if let Some(state) = app.prompt_queue_overlay.as_ref()
            && let Some(&id) = app.prompt_queue_ids.get(state.selected)
        {
            ids.push(id);
        }
    }
    if ids.is_empty() {
        return false;
    }
    let Some(_gid) = app.prompt_queue_groups.create_group(&ids) else {
        return false;
    };
    let count = ids.len();
    app.prompt_queue_multiselect.clear();
    app.status = format!(
        "grouped {count} queued prompt{} ({} group{})",
        if count == 1 { "" } else { "s" },
        app.prompt_queue_groups.len(),
        if app.prompt_queue_groups.len() == 1 {
            ""
        } else {
            "s"
        }
    );
    app.needs_redraw = true;
    true
}

/// The id of the group owning the focused queued prompt, or `None` when the
/// cursor sits on a loose prompt / an empty queue. The shared lookup the
/// collapse / pause / dissolve verbs resolve their target group through.
fn focused_queue_group_id(app: &TuiApp) -> Option<u64> {
    let state = app.prompt_queue_overlay.as_ref()?;
    let &id = app.prompt_queue_ids.get(state.selected)?;
    app.prompt_queue_groups.group_id_of_item(id)
}

/// Toggle the collapsed state of the group owning the focused prompt (§12.3.4).
/// A loose prompt (no group) is a quiet no-op. Returns `true` if a group toggled.
/// The single source of truth the keyboard `z` and the mouse middle-click share.
fn queue_group_toggle_collapse_focused(app: &mut TuiApp) -> bool {
    sync_queue_groups(app);
    let Some(gid) = focused_queue_group_id(app) else {
        app.status = "focused prompt is not in a group".to_string();
        app.needs_redraw = true;
        return false;
    };
    queue_group_toggle_collapse_by_id(app, gid)
}

/// Toggle the collapsed state of the group with `group_id` (§12.3.4). The
/// id-keyed primitive the focused-keyboard verb and the mouse middle-click both
/// route through, so the two stay identical by construction. No-op (returns
/// false) if the group has been dissolved / drained out.
fn queue_group_toggle_collapse_by_id(app: &mut TuiApp, group_id: u64) -> bool {
    let Some(now_collapsed) = app.prompt_queue_groups.toggle_collapsed(group_id) else {
        return false;
    };
    app.status = if now_collapsed {
        "collapsed queue group".to_string()
    } else {
        "expanded queue group".to_string()
    };
    app.needs_redraw = true;
    true
}

/// Toggle the paused state of the group owning the focused prompt (§12.3.4). A
/// paused group's prompts are held back from the drain pump until resumed (the
/// prompts are not deleted). A loose prompt is a quiet no-op. Returns `true` if a
/// group toggled.
fn queue_group_toggle_pause_focused(app: &mut TuiApp) -> bool {
    sync_queue_groups(app);
    let Some(gid) = focused_queue_group_id(app) else {
        app.status = "focused prompt is not in a group".to_string();
        app.needs_redraw = true;
        return false;
    };
    let Some(now_paused) = app.prompt_queue_groups.toggle_paused(gid) else {
        return false;
    };
    // Pausing a group is an explicit "hold this back" edit, so it disarms the
    // auto-drain pump the same way deleting a queued prompt does — otherwise the
    // pump could keep draining loose prompts while the user is mid-edit. Resuming
    // does not re-arm it; the next turn-finish drains as usual.
    if now_paused {
        app.auto_drain_queue = false;
    }
    app.status = if now_paused {
        "paused queue group (its prompts will not run)".to_string()
    } else {
        "resumed queue group".to_string()
    };
    app.needs_redraw = true;
    true
}

/// Dissolve the group owning the focused prompt (§12.3.4), returning its members
/// loose into the queue (the prompts are untouched — only the grouping is
/// removed). A loose prompt is a quiet no-op. Returns `true` if a group dissolved.
fn queue_group_dissolve_focused(app: &mut TuiApp) -> bool {
    sync_queue_groups(app);
    let Some(gid) = focused_queue_group_id(app) else {
        app.status = "focused prompt is not in a group".to_string();
        app.needs_redraw = true;
        return false;
    };
    if !app.prompt_queue_groups.dissolve(gid) {
        return false;
    }
    app.status = format!(
        "dissolved queue group ({} group{} left)",
        app.prompt_queue_groups.len(),
        if app.prompt_queue_groups.len() == 1 {
            ""
        } else {
            "s"
        }
    );
    app.needs_redraw = true;
    true
}

/// The stable id of the focused queued prompt, or `None` on an empty queue / a
/// stale cursor. The shared lookup the condition-cycle verb and its mouse twin
/// resolve their target through, so both act on the exact focused row.
fn focused_queue_id(app: &TuiApp) -> Option<u64> {
    let state = app.prompt_queue_overlay.as_ref()?;
    app.prompt_queue_ids.get(state.selected).copied()
}

/// Conditional Queue Items (§12.3.5): cycle the focused queued prompt's
/// run-condition to the next one in the editor sequence. The single source of
/// truth the keyboard `v` verb and the mouse twin share. A quiet no-op on an
/// empty queue / stale cursor. Returns `true` if a condition changed.
fn queue_cycle_condition_focused(app: &mut TuiApp) -> bool {
    sync_queue_ids(app);
    let Some(id) = focused_queue_id(app) else {
        app.status = "no queued prompt to set a condition on".to_string();
        app.needs_redraw = true;
        return false;
    };
    queue_cycle_condition_by_id(app, id)
}

/// Cycle the run-condition of the queued prompt with `id` (§12.3.5). The id-keyed
/// primitive the focused-keyboard verb and the mouse twin both route through, so
/// the two stay identical by construction. Pausing/skip policy is evaluated later
/// by the drain pump; this only edits the stored condition. Returns `true` (the
/// condition always advances — `always` cycles back to itself only by wrapping
/// through every other state).
fn queue_cycle_condition_by_id(app: &mut TuiApp, id: u64) -> bool {
    let now = app.prompt_queue_conditions.cycle(id);
    // Setting an explicit run-condition is a deliberate "hold this back unless…"
    // edit, so — like pausing a group — it disarms the auto-drain pump while the
    // user is mid-edit. Returning to `always` re-arms nothing on its own; the next
    // turn-finish drains as usual.
    if !now.is_always() {
        app.auto_drain_queue = false;
    }
    app.status = if now.is_always() {
        "queued prompt runs always (condition cleared)".to_string()
    } else {
        format!("queued prompt runs {} (§ condition)", now.label())
    };
    app.needs_redraw = true;
    true
}

/// Run Selected Queued Next (§11G.9): promote the focused queued prompt to the
/// front so it runs before everything else still waiting. When idle (no turn
/// running) the prompt is moved to the front and the auto-drain pump is armed, so
/// the next event-loop tick pops it and starts a turn immediately; when a turn is
/// running it is moved to the front only, and the existing drain-on-turn-finish
/// path runs it next ahead of the rest of the queue (the live turn is never
/// pre-empted). The reorder is recorded as a single `Reordered` undo (by stable
/// id + left-neighbour id, so a concurrent front-drain can't stale it), exactly
/// like the keyboard/mouse reorder verbs.
///
/// The single source of truth shared by the keyboard (`r`) and mouse
/// (`interaction::Action::QueueRunNext`) paths, so the two stay identical by
/// construction. Returns `true` if it changed anything (moved a row, or armed an
/// idle run); `false` when the queue is empty, the cursor is stale, or the
/// focused row is already at the front while a turn is running (nothing to do).
fn queue_run_selected_next(app: &mut TuiApp) -> bool {
    // A reorder mid-drag would fight the in-flight gesture; ignore it like the
    // edit verb does.
    if app.prompt_queue_drag.is_some() {
        return false;
    }
    sync_queue_ids(app);
    let Some(selected) = app
        .prompt_queue_overlay
        .as_ref()
        .map(|state| state.selected)
    else {
        return false;
    };
    let Some(plan) = queue_run_next::plan(selected, app.prompt_queue.len(), app.turn_rx.is_some())
    else {
        return false;
    };
    // The user explicitly chose THIS prompt to run next, so it must bypass the
    // condition gate: a `Manual` item (or an unsatisfied "if previous X") would
    // otherwise be parked or dropped by `plan_drain` and never run. Clear the
    // promoted item's run-condition (id-keyed, captured before any move) so the
    // drain pump dispatches the chosen prompt rather than silently substituting a
    // different runnable one. A no-op when the item is already unconditional.
    if let Some(id) = app.prompt_queue_ids.get(plan.from).copied() {
        app.prompt_queue_conditions
            .set(id, queue_conditions::QueueCondition::Always);
    }
    let mut changed = false;
    if plan.moves {
        // Record the undo BEFORE moving: `prev` is the id that sat immediately
        // before the focused row's original slot (None at the front), so undo
        // re-inserts the promoted item back after it, surviving a front-drain.
        let id = app.prompt_queue_ids.get(plan.from).copied();
        let prev = queue_prev_id_at(app, plan.from);
        if queue_move_indices(app, plan.from, 0) {
            if let Some(id) = id {
                push_queue_undo(app, QueueMutation::Reordered { id, prev });
            }
            // The promoted item now sits at the front; keep the overlay cursor on
            // it so a follow-up keyboard verb acts on the same prompt.
            if let Some(state) = app.prompt_queue_overlay.as_mut() {
                state.selected = 0;
            }
            // A focused-row promotion supersedes any group multi-selection: a
            // stale group must not silently act on the reshuffled queue.
            app.prompt_queue_multiselect.clear();
            changed = true;
        }
    }
    if plan.run_now {
        // Idle: arm the drain pump so the (now front) prompt runs on the next
        // tick. Close the overlay so focus returns to the transcript the running
        // turn paints into, mirroring the edit/merge verbs that hand focus back.
        app.auto_drain_queue = true;
        app.prompt_queue_overlay = None;
        app.prompt_queue_drag = None;
        app.prompt_queue_multiselect.clear();
        app.status = "running selected prompt now".to_string();
        app.needs_redraw = true;
        changed = true;
    } else if changed {
        // Busy: the reorder landed but the live turn keeps running; report that
        // the promoted prompt is queued to run next, and keep the overlay open so
        // the user can keep manipulating the queue.
        app.status = format!(
            "selected prompt will run next ({} queued)",
            app.prompt_queue.len()
        );
        app.needs_redraw = true;
    }
    changed
}

/// Toggle the prompt-queue reorder overlay. Hard-coded as a chord
/// (`Ctrl+X` then `Q`) rather than a rebindable keymap action because
/// single-Ctrl-letter defaults collide with terminal flow control
/// (`Ctrl+Q` = `XON`, `Ctrl+S` = `XOFF`) and with macOS shortcuts.
fn toggle_prompt_queue_overlay(app: &mut TuiApp) {
    if app.config_screen.is_some()
        || app.status_line_setup.is_some()
        || app.transcript_overlay.is_some()
    {
        return;
    }
    app.prompt_queue_overlay = if app.prompt_queue_overlay.is_some() {
        None
    } else {
        // Keep the id sidecar aligned to the live queue the moment the
        // overlay opens, so the very first hit-target frame is id-stable.
        sync_queue_ids(app);
        // Prune any Queue-Group members that drained while the overlay was
        // closed, so a re-opened overlay never paints a marker for a vanished
        // prompt and a fully-drained group is dropped. Groups themselves SURVIVE
        // the open/close cycle (they are a durable batch organization), unlike
        // the transient multi-selection cleared below.
        let live_ids = queue_live_ids(app);
        app.prompt_queue_groups.retain_live(&live_ids);
        Some(prompt_queue::PromptQueueState::new())
    };
    // A multi-selection never survives an open/close cycle: tags are scoped to
    // one overlay session so a stale group can't act on a re-opened queue.
    app.prompt_queue_multiselect.clear();
    if app.prompt_queue_overlay.is_none() {
        // Closing also abandons any in-flight reorder drag.
        app.prompt_queue_drag = None;
    }
    app.status = if app.prompt_queue_overlay.is_some() {
        format!(
            "prompt queue ({} queued) · ↑↓ focus · Space tag · g group · z fold · p pause · Enter/e edit · r run next · Del remove · Esc close",
            app.prompt_queue.len()
        )
    } else {
        "prompt queue closed".to_string()
    };
}

/// Begin editing the queued prompt with stable `id` (§11G.8): pull its current
/// text into the composer, remember the id on `editing_queue_id` so the next
/// submit updates that exact item, and close the overlay so the composer takes
/// focus. The single source of truth shared by the keyboard (`Enter`/`e`) and
/// mouse (double-click) edit paths, so the two stay identical by construction.
///
/// No-op (returns false) when the id has drained out, when the composer already
/// holds an unrelated draft (so a stray edit can't clobber in-progress typing),
/// or while a queued-item drag is in flight.
fn begin_queue_edit(app: &mut TuiApp, id: u64) -> bool {
    if app.prompt_queue_drag.is_some() {
        return false;
    }
    sync_queue_ids(app);
    let Some(index) = queue_index_for_id(app, id) else {
        return false;
    };
    // Refuse to overwrite a draft the user is already composing (unless it is
    // itself the same edit-in-progress for this id). Keeps the user's typed
    // text safe; they can clear the composer first if they truly want to edit.
    if !app.input.is_empty() && app.editing_queue_id != Some(id) {
        app.status = "clear the composer before editing a queued prompt".to_string();
        app.needs_redraw = true;
        return false;
    }
    let Some(pick) = queue_edit::pick_edit(&app.prompt_queue, &app.prompt_queue_ids, index) else {
        return false;
    };
    // Load the prompt into the composer. `clear_input` first resets cursor /
    // attachments / the (about-to-be-overwritten) edit id, then we install the
    // text and park the cursor at the end so the user can immediately type.
    clear_input(app);
    app.input = pick.text;
    app.input_cursor = app.input.len();
    app.editing_queue_id = Some(pick.id);
    // Pulling the prompt into the composer closes the overlay and abandons any
    // in-flight reorder; the queue keeps draining normally meanwhile.
    app.prompt_queue_overlay = None;
    app.prompt_queue_drag = None;
    app.status = "editing queued prompt — Enter saves the change".to_string();
    app.needs_redraw = true;
    true
}

/// Save the composer draft back onto the queued item being edited (§11G.8).
/// Resolves `editing_queue_id` to its live slot and replaces the text *by id*
/// (so a drain/reorder since editing began can't misdirect the save), then
/// clears the edit state and the composer. Returns `true` when it consumed the
/// submit as an in-place update; `false` (leaving `editing_queue_id` cleared)
/// when the tracked item has vanished, so the caller falls back to a normal
/// enqueue/run and the edited text is never lost.
fn save_queue_edit(app: &mut TuiApp, text: String) -> bool {
    let Some(id) = app.editing_queue_id.take() else {
        return false;
    };
    sync_queue_ids(app);
    match queue_edit::apply_edit(&mut app.prompt_queue, &app.prompt_queue_ids, id, text) {
        queue_edit::EditResult::Updated => {
            clear_input(app);
            app.status = format!("updated queued prompt ({} queued)", app.prompt_queue.len());
            app.needs_redraw = true;
            true
        }
        // The item drained/ran or was deleted while it sat in the composer:
        // the edit can't update a row that no longer exists. Report not-handled
        // so the caller treats the composer text as a fresh prompt.
        queue_edit::EditResult::Vanished => false,
    }
}

/// Resolve a focused/clicked `EntryId` back to its live transcript index, or
/// `None` when the entry no longer exists (pruned/coalesced). Keeps every
/// index-taking callee (`toggle_transcript_entry_fold`, the render highlight)
/// working unchanged while dispatch addresses the stable id.
fn entry_index_for_id(app: &TuiApp, id: transcript_surface::EntryId) -> Option<usize> {
    let transcript_surface::EntryId(want) = id;
    app.transcript.iter().position(|e| e.id == want)
}

/// Dispatch a click on a registered target. Single source of truth for what
/// each [`interaction::Action`] variant does. Every entry/row variant resolves
/// its `EntryId` back to a live index, then calls the SAME handler the keyboard
/// path calls — so keyboard/mouse parity holds by construction. Adding a new
/// button means adding a variant to [`interaction::Action`] and one arm here.
/// True when `action` is a DESTRUCTIVE clear/reset click verb whose owning overlay
/// is currently closed — meaning a click resolved this target against a STALE
/// frame-local registry (the overlay closed earlier in the same input batch, before
/// the next repaint rebuilt the click targets) and must be refused (deep-review
/// #33). Each clear verb is owned by exactly one picker/editor overlay; when that
/// overlay is open the verb is legitimate, when it is closed the target is stale.
/// Pure read over `app`.
fn destructive_click_verb_owner_closed(app: &TuiApp, action: interaction::Action) -> bool {
    match action {
        interaction::Action::SnippetClear => !app.snippets_open,
        interaction::Action::ClipboardClear => !app.clipboard_history_open,
        interaction::Action::TemplateClear => !app.templates_open,
        interaction::Action::KeybindingReset => app.keybinding_editor.is_none(),
        _ => false,
    }
}

fn dispatch_click_action(app: &mut TuiApp, action: interaction::Action) {
    // Stale-registry guard (deep-review #33): the hit-test registry is frame-local
    // and rebuilt only at draw time, so a click that arrives in the SAME input
    // batch right after an Esc closed a picker (no intervening repaint) can still
    // resolve against last frame's `Chrome(SnippetClear)` / `ClipboardClear` /
    // `TemplateClear` / `KeybindingReset` target via the unguarded catch-all chrome
    // arm in `handle_mouse`. Re-validate the DESTRUCTIVE clear/reset verbs against
    // their owning overlay's current open-state and refuse them when that overlay is
    // closed — a click can never wipe a stash whose picker is no longer on screen.
    // Non-destructive verbs are intentionally not gated here (a stale select/scroll
    // is harmless and the per-overlay arms already short-circuit the modal cases).
    if destructive_click_verb_owner_closed(app, action) {
        return;
    }
    match action {
        interaction::Action::ToggleQueueOverlay => toggle_prompt_queue_overlay(app),
        interaction::Action::ToggleEntryCollapsed(id) => {
            if let Some(index) = entry_index_for_id(app, id) {
                // Clicking the caret focuses the entry it acts on, then folds it
                // — the same handler Ctrl+O drives.
                app.selected_entry = Some(index);
                if toggle_transcript_entry_fold(app, index) {
                    let collapsed = app.transcript[index].collapsed;
                    app.status = if collapsed {
                        "entry collapsed".to_string()
                    } else {
                        "entry expanded".to_string()
                    };
                    app.needs_redraw = true;
                }
            }
        }
        interaction::Action::FocusEntry(id) => {
            if let Some(index) = entry_index_for_id(app, id) {
                app.selected_entry = Some(index);
                app.status = format!("selected transcript entry {}", app.transcript[index].id + 1);
                app.needs_redraw = true;
            }
        }
        interaction::Action::ExpandEntry(id) => {
            // Double-click a collapsed card → expand it (idempotent: a no-op on
            // an already-expanded card). Reuses the fold toggle, guarded.
            if let Some(index) = entry_index_for_id(app, id) {
                app.selected_entry = Some(index);
                if app.transcript[index].collapsed && toggle_transcript_entry_fold(app, index) {
                    app.status = "entry expanded".to_string();
                    app.needs_redraw = true;
                }
            }
        }
        interaction::Action::OpenEntryInDetail(id) => {
            if let Some(index) = entry_index_for_id(app, id) {
                app.selected_entry = Some(index);
                open_focused_entry_in_detail(app);
            }
        }
        // The per-item delete affordance in the reorder overlay. Removes the
        // item with this stable id (never a Vec position, so a concurrent
        // reorder can't make it delete the wrong row) and records the removal
        // for undo.
        interaction::Action::QueueDelete(id) => {
            queue_delete_by_id(app, id);
        }
        // The drag-handle press arms a reorder drag. The live move + drop are
        // driven from the gesture recognizer in `handle_mouse` (DragStart /
        // DragExtend / DragEnd); this arm just records which id is in flight
        // and seeds the overlay focus onto it so a keyboard finish stays on
        // the same item.
        interaction::Action::QueueReorderBegin(id) => {
            sync_queue_ids(app);
            if let Some(from) = queue_index_for_id(app, id) {
                let prev = queue_prev_id_at(app, from);
                app.prompt_queue_drag = Some(QueueDrag { id, from, prev });
                if let Some(state) = app.prompt_queue_overlay.as_mut() {
                    state.selected = from;
                }
            }
        }
        // Undo the last queue mutation (mouse twin of the keyboard verb).
        interaction::Action::QueueUndo => {
            queue_undo(app);
        }
        // Edit a queued prompt (§11G.8): pull it into the composer for editing.
        // Mouse twin of the keyboard `Enter`/`e` verb; both route through the
        // same `begin_queue_edit`, so the paths stay identical by construction.
        interaction::Action::QueueEdit(id) => {
            begin_queue_edit(app, id);
        }
        // Run a queued prompt next (§11G.9): promote it to the front of the queue
        // (runs immediately when idle, on turn-finish when busy). Mouse twin of
        // the keyboard `r` verb; both seat the overlay focus on the clicked row
        // and route through the same `queue_run_selected_next`, so the paths stay
        // identical by construction. A click on a row that has since drained out
        // resolves to a no-op.
        interaction::Action::QueueRunNext(id) => {
            sync_queue_ids(app);
            if let Some(index) = queue_index_for_id(app, id) {
                if let Some(state) = app.prompt_queue_overlay.as_mut() {
                    state.selected = index;
                }
                queue_run_selected_next(app);
            }
        }
        // Cycle a queued prompt's run-condition (§12.3.5). Mouse twin of the
        // keyboard `v` verb; both seat the overlay focus on the clicked row and
        // route through the same `queue_cycle_condition_by_id`, so the paths stay
        // identical by construction. A click on a row that has since drained out
        // resolves to a no-op.
        interaction::Action::QueueCycleCondition(id) => {
            sync_queue_ids(app);
            if let Some(index) = queue_index_for_id(app, id) {
                if let Some(state) = app.prompt_queue_overlay.as_mut() {
                    state.selected = index;
                }
                queue_cycle_condition_by_id(app, id);
            }
        }
        // Scrollbar-jump and jump-to-latest are not yet registered as targets
        // by the render paths; their handlers land with the affordances that
        // register them. Until then these arms are inert (no panic).
        interaction::Action::ScrollbarJump | interaction::Action::JumpToLatest => {}
        // Minimap turn-rail cell click: jump so the entry behind the cell sits
        // at the top of the viewport. Reuses the keyboard jump path
        // (`jump_to_entry_id`), so mouse/keyboard parity holds by construction.
        // A cell whose entry has since been dropped resolves to no-op.
        interaction::Action::MinimapJump(id) => {
            if jump_to_entry_id(app, id.0) {
                app.needs_redraw = true;
            }
        }
        // Large-paste confirmation question actions (§11G.6). Both route through
        // the same `resolve_paste_preview` the keyboard path uses, so the
        // mouse and Enter/Esc verbs are identical by construction.
        interaction::Action::ConfirmPaste => {
            resolve_paste_preview(app, paste_preview::PasteDecision::Confirm);
        }
        interaction::Action::CancelPaste => {
            resolve_paste_preview(app, paste_preview::PasteDecision::Cancel);
        }
        // Paste-transform question row click (§12.6.2): select that row, then apply
        // it — the same `resolve_paste_transform` the Enter key calls, so the
        // mouse and keyboard verbs are identical by construction.
        interaction::Action::PasteTransformSelect(index) => {
            if let Some(menu) = app.paste_transform.as_mut() {
                menu.select(index);
            }
            resolve_paste_transform(app);
        }
        // Clipboard-history picker (§12.6.1). Each routes through the same handler
        // the keyboard verb drives, so mouse/keyboard parity holds by
        // construction. Select resolves the row by its stable id; re-copy/delete
        // act on it; clear wipes the whole history.
        interaction::Action::ClipboardSelect(id) => {
            if app.clipboard_history.select_id(id) {
                app.needs_redraw = true;
            }
        }
        interaction::Action::ClipboardRecopy(id) => {
            app.clipboard_history.select_id(id);
            recopy_clipboard_entry(app, id);
        }
        interaction::Action::ClipboardDelete(id) => {
            app.clipboard_history.select_id(id);
            delete_selected_clipboard_entry(app);
        }
        interaction::Action::ClipboardClear => {
            app.clipboard_history.clear();
            app.status = "clipboard history cleared".to_string();
            app.needs_redraw = true;
        }
        // Prompt Snippets picker (§12.3.2). Each routes through the same handler
        // the keyboard verb drives, so mouse/keyboard parity holds by
        // construction. Select resolves the row by its stable id; insert/queue/
        // delete act on it; clear wipes the whole stash.
        interaction::Action::SnippetSelect(id) => {
            if app.snippets.select_id(id) {
                app.needs_redraw = true;
            }
        }
        interaction::Action::SnippetInsertCompose(id) => {
            insert_snippet_into_composer(app, id);
        }
        interaction::Action::SnippetEnqueue(id) => {
            enqueue_snippet(app, id);
        }
        interaction::Action::SnippetDelete(id) => {
            app.snippets.select_id(id);
            delete_selected_snippet(app);
        }
        interaction::Action::SnippetClear => {
            app.snippets.clear();
            app.status = "snippets cleared".to_string();
            app.needs_redraw = true;
        }
        // External Editor Handoff confirmation overlay (§12.6.5): clicking a
        // button selects that action and applies it, the same `select` +
        // `apply_editor_handoff_review` the keyboard path drives, so the mouse
        // and Enter verbs are identical by construction.
        interaction::Action::EditorHandoffSelect(index) => {
            if let Some(review) = app.editor_handoff.as_mut() {
                review.select(index);
            }
            apply_editor_handoff_review(app);
        }
        // Main-view Semantic Filter badge (§12.5.2): a click cycles the filter
        // forward through the same `cycle_main_semantic_filter` the `Alt+f`
        // keyboard verb drives, so mouse/keyboard parity holds by construction.
        interaction::Action::CycleSemanticFilter => {
            cycle_main_semantic_filter(app, false);
        }
        // A click on the status-line Attention Routing indicator (§12.8.6):
        // quick-jump to the subagent that most needs attention — the mouse twin of
        // the `JumpToAttention` (`Ctrl+Alt+Z`) keyboard verb.
        interaction::Action::JumpToAttention => {
            jump_to_attention(app);
        }
        // A click on the status-line Adaptive Density indicator (§12.4.1): cycle
        // the density override forward — the mouse twin of the `CycleDensity`
        // (`Ctrl+Alt+X`) keyboard verb, driving the same `cycle_density` handler
        // so mouse/keyboard parity holds by construction.
        interaction::Action::CycleDensity => {
            cycle_density(app);
        }
        // A click on the status-line Presentation Mode indicator (§12.4.6): toggle
        // the screen-share mode on/off — the mouse twin of the
        // `TogglePresentation` (`Ctrl+Alt+C`) keyboard verb, driving the same
        // `toggle_presentation` handler so mouse/keyboard parity holds by
        // construction.
        interaction::Action::TogglePresentation => {
            toggle_presentation(app);
        }
        // A click on the docked panel's header (§12.4.4): cycle the panel's dock
        // position forward — the mouse twin of the `CycleDockPanel` (`Ctrl+Alt+F`)
        // keyboard verb, driving the same `cycle_dock_panel` handler so
        // mouse/keyboard parity holds by construction.
        interaction::Action::CycleDockPanel => {
            cycle_dock_panel(app);
        }
        // A click on the Zen Mode minimal status line (§12.4.5): toggle the
        // distraction-free layout back off — the mouse twin of the `ToggleZenMode`
        // (`Ctrl+Alt+.`) keyboard verb, driving the same `toggle_zen_mode` handler
        // so mouse/keyboard parity holds by construction.
        interaction::Action::ToggleZenMode => {
            toggle_zen_mode(app);
        }
        // A click on the Session Auto-Save Checkpoints overlay's `[restore]`
        // affordance (§12.9.5): restore the saved checkpoint onto the running
        // session — the mouse twin of the overlay's `r` verb, driving the same
        // `restore_session_checkpoint` handler so mouse/keyboard parity holds by
        // construction.
        interaction::Action::CheckpointRestore => {
            restore_session_checkpoint(app);
        }
        // A click on a Local Transcript Index category row (§12.5.1): move the
        // cursor onto it and jump the main view to the next entry in it — the
        // mouse twin of ↑↓ + Enter, in one go. Selecting a *different* category
        // restarts that category's forward walk.
        interaction::Action::TranscriptIndexSelect(index) => {
            if app.transcript_index_selected != index {
                app.transcript_index_anchor = None;
            }
            app.transcript_index_selected = index;
            transcript_index_jump_to_selected(app);
        }
        // A click on a Related-Entry Links row (§12.5.3): move the cursor onto it
        // and jump the main view to that related entry — the mouse twin of ↑↓ +
        // Enter, in one go.
        interaction::Action::RelatedLinkSelect(index) => {
            app.related_links_selected = index;
            related_links_jump_to_selected(app);
        }
        // A click on a Duplicate-Output Folds row (§12.5.4): move the cursor onto
        // it, jump the main view to its lead, and toggle the span expanded — the
        // mouse twin of ↑↓ + Enter, in one go.
        interaction::Action::DuplicateFoldSelect(index) => {
            app.duplicate_folds_selected = index;
            duplicate_fold_activate_selected(app);
        }
        // A click on an Error Lenses row (§12.5.6): move the cursor onto it and
        // jump the main view to the failing entry behind it — the mouse twin of
        // ↑↓ + Enter, in one go.
        interaction::Action::ErrorLensSelect(index) => {
            app.error_lens_selected = index;
            error_lens_jump_to_selected(app, false);
        }
        // A click on a Transcript Health Markers row (§12.5.7): move the cursor
        // onto it and jump the main view to the entry behind it — the mouse twin
        // of ↑↓ + Enter, in one go.
        interaction::Action::HealthMarkerSelect(index) => {
            app.health_markers_selected = index;
            health_markers_jump_to_selected(app, false);
        }
        // A click on a Semantic Turn Outline node row (§12.2.1): move the cursor
        // onto it and jump the main view to the logical transcript row behind it —
        // the mouse twin of ↑↓ + Enter, in one go.
        interaction::Action::TurnOutlineSelect(index) => {
            app.turn_outline_selected = index;
            turn_outline_jump_to_selected(app, false);
        }
        // A click on a Collapsible Reasoning/Tool Lanes row (§12.2.2): move the
        // cursor onto it and toggle that lane's collapsed state — the mouse twin
        // of ↑↓ + Enter/Space, in one go.
        interaction::Action::LaneFoldToggle(index) => {
            app.lane_fold_selected = index;
            lane_fold_toggle_selected(app);
        }
        // A click on a Reading Position Bookmarks row (§12.2.4): move the cursor
        // onto it and jump the main view to the entry that bookmark anchors — the
        // mouse twin of ↑↓ + Enter, in one go.
        interaction::Action::BookmarkSelectJump(index) => {
            app.bookmarks_selected = index;
            bookmark_jump_to_selected(app);
        }
        // A click on a Session Timeline event row (§12.2.6): move the cursor onto
        // it and jump the main view to the transcript row the event stands for —
        // the mouse twin of ↑↓ + Enter, in one go. The index is into the visible
        // (filtered) event list, matching what the row registered.
        interaction::Action::TimelineSelectJump(index) => {
            app.session_timeline_selected = index;
            session_timeline_jump_to_selected(app, false);
        }
        // A click on a Subagent Timeline Panel row (§12.8.1): move the cursor onto
        // it and jump the main view to that subagent's conversation — the mouse
        // twin of ↑↓ + Enter, in one go. The index is into the visible (filtered)
        // subagent list, matching what the row registered.
        interaction::Action::SubagentTimelineSelectJump(index) => {
            app.subagent_timeline_selected = index;
            subagent_timeline_jump_to_selected(app, false);
        }
        // A click on a Subagent Timeline Panel row's `[mark]` cell (§12.8.3):
        // toggle that subagent's mark for the Compare Subagent Outputs view — the
        // mouse twin of pressing `c` on the row. The index is the subagent's
        // 0-based pane index, matching what the cell registered.
        interaction::Action::SubagentCompareMark(index) => {
            toggle_subagent_compare_mark(app, index);
        }
        // A click on a Live Review Board worker card (§12.8.5): park the cursor on
        // it (by stable id) and jump the main view to that worker's conversation —
        // the mouse twin of ↑↓ + Enter, in one go. No auto-advance (a click is a
        // precise pick that stays on the card it landed on).
        interaction::Action::ReviewBoardSelectJump(id) => {
            app.review_board_cursor = Some(id);
            review_board_jump_to_cursor(app, false);
        }
        // A click on an Entry Annotations row (§12.2.5): move the cursor onto it
        // and jump the main view to the entry that annotation anchors — the mouse
        // twin of ↑↓ + Enter, in one go.
        interaction::Action::AnnotationSelectJump(index) => {
            app.annotations_selected = index;
            annotation_jump_to_selected(app);
        }
        // A click on an entry's inline annotation marker (§12.2.5): open the
        // annotations overlay parked on that entry's first note — the mouse twin of
        // opening the list (Alt+\) and selecting the entry.
        interaction::Action::OpenAnnotationsForEntry(id) => {
            open_annotations_for_entry(app, id.0);
        }
        // A click on a What Changed Since Here? change row (§12.2.7): move the
        // cursor onto it and jump the main view to the transcript entry the change
        // stands for — the mouse twin of ↑↓ + Enter, in one go. The index is into
        // the flattened (grouped) change list, matching what the row registered.
        interaction::Action::ChangeSinceSelectJump(index) => {
            app.changes_since_selected = index;
            changes_since_jump_to_selected(app, false);
        }
        // A click on a Contextual Action Palette action row (§12.1.2): move the
        // cursor onto it and run that action on the focused unit — the mouse twin
        // of ↑↓ + Enter, in one go. The index is into the gathered action list,
        // matching what the row registered.
        interaction::Action::PaletteActionRun(index) => {
            if let Some(palette) = app.action_palette.as_mut() {
                palette.select(index);
            }
            run_selected_action_palette_action(app);
        }
        interaction::Action::CommandPaletteRun(index) => {
            // A click on a command row both selects and runs it — the same path
            // ↑↓+Enter takes — keyed by the visible (filtered) index.
            command_palette_select_run(app, index);
        }
        // A click on a breadcrumb crumb (§12.1.5): move the breadcrumb focus onto
        // it and jump to the location it stands for — the mouse twin of ←→ + Enter,
        // in one go.
        interaction::Action::BreadcrumbActivate(index) => {
            app.breadcrumbs_focus = index;
            breadcrumbs_activate_focused(app);
        }
        // A click on an entry's inline rename-label badge (§12.1.7): open the inline
        // rename editor on that entry's label — the mouse twin of focusing the entry
        // and pressing `Ctrl+Alt+R`.
        interaction::Action::OpenRenameForEntry(id) => {
            begin_rename_for_entry(app, id.0);
        }
        // A click on the dim First-Run Interaction Hint strip (§12.1.8) dismisses the
        // shown hint — the mouse twin of the `DismissFirstRunHint` verb, latching it
        // seen so it never returns.
        interaction::Action::DismissFirstRunHint => {
            dismiss_first_run_hint(app);
        }
        // A click on the Automatic Degraded-Mode Suggestions banner's `[accept]`
        // affordance (§12.9.4) applies the suggested modes — the mouse twin of the
        // `AcceptDegradedSuggestion` verb.
        interaction::Action::AcceptDegradedSuggestion => {
            accept_degraded_suggestion(app);
        }
        // A click on the banner's `[dismiss]` affordance (§12.9.4) latches the
        // suggestion dismissed — the mouse twin of the `DismissDegradedSuggestion`
        // verb.
        interaction::Action::DismissDegradedSuggestion => {
            dismiss_degraded_suggestion(app);
        }
        // A click on an Actionable Tool Outputs item row (§12.3.1): move the cursor
        // onto it and run its primary action (copy the matched element) — the mouse
        // twin of ↑↓ + Enter, in one go.
        interaction::Action::ToolActionRun(index) => {
            if let Some(actions) = app.tool_actions.as_mut() {
                actions.select(index);
            }
            tool_actions_copy_selected(app);
        }
        // Scratchpad Pane (§12.3.3). Each routes through the same handler the
        // keyboard verb drives, so mouse/keyboard parity holds by construction.
        interaction::Action::ScratchpadInsertCompose => scratchpad_insert_into_composer(app),
        interaction::Action::ScratchpadEnqueue => scratchpad_enqueue(app),
        interaction::Action::ScratchpadAppend => scratchpad_append_context(app),
        interaction::Action::ScratchpadClear => {
            app.scratchpad.clear();
            app.status = scratchpad_open_status(app);
            app.needs_redraw = true;
        }
        // Prompt Templates picker (§12.3.6): a click on a template row selects +
        // instantiates it into an editable card — the mouse twin of moving the
        // cursor with ↑↓ and pressing Enter. Resolved by stable id so a concurrent
        // delete never instantiates the wrong template.
        interaction::Action::TemplateSelect(id) => {
            instantiate_template(app, id);
        }
        // A click on a slot row in the open card focuses that slot for editing —
        // the mouse twin of Tab / ↑↓ slot movement.
        interaction::Action::TemplateFocusSlot(index) => {
            if let Some(card) = app.template_card.as_mut()
                && card.focus_index(index)
            {
                app.status = templates_open_status(app);
                app.needs_redraw = true;
            }
        }
        // The "Enqueue" button: resolve the filled card and stage it (blocked with
        // inline status while a slot is empty) — the same `enqueue_template_card`
        // the Enter key drives, so mouse/keyboard parity holds by construction.
        interaction::Action::TemplateEnqueue => {
            enqueue_template_card(app);
        }
        // The "Delete" button / list `d`: delete the template by stable id — the
        // mouse twin of the picker's `d` verb.
        interaction::Action::TemplateDelete(id) => {
            app.templates.select_id(id);
            delete_selected_template(app);
        }
        // The "Clear all" button / list `c`: drop every saved template.
        interaction::Action::TemplateClear => {
            app.templates.clear();
            app.status = "templates cleared".to_string();
            app.needs_redraw = true;
        }
        // A click on the Replayable Interaction Macros (§12.3.7) status strip:
        // stop / cancel the active recording or replay — the mouse twin of the
        // `ToggleMacroRecord` verb. Routes to the same `toggle_macro_record`
        // handler, so keyboard/mouse parity holds by construction.
        interaction::Action::MacroToggleRecord => {
            toggle_macro_record(app);
        }
        // Keybinding Editor UI (§12.7.1). Each routes through the same handler the
        // keyboard verb drives, so mouse/keyboard parity holds by construction.
        // Select moves the cursor onto the clicked row; rebind begins capturing a
        // new chord for the selected row; reset reverts it to its default.
        interaction::Action::KeybindingSelect(index) => {
            if let Some(editor) = app.keybinding_editor.as_mut()
                && editor.select_index(index)
            {
                app.status = keybinding_editor_browse_status(app);
                app.needs_redraw = true;
            }
        }
        interaction::Action::KeybindingRebind => {
            keybinding_editor_begin_capture(app);
        }
        interaction::Action::KeybindingReset => {
            keybinding_editor_reset_selected(app);
        }
        // §12.7.2: the click handlers above already short-circuit the theme-editor
        // targets (they need the agent for live preview / persistence, which this
        // agent-free dispatcher does not carry), so these arms are unreachable in
        // practice. They exist so every `interaction::Action` has a dispatch arm and
        // the accessibility audit's exhaustiveness holds.
        interaction::Action::ThemeEditorSelectRole(_)
        | interaction::Action::ThemeEditorSetChannel(_, _) => {}
        // §12.7.4: the workspace-profile overlay's own mouse handler in
        // `handle_mouse` short-circuits this target while the overlay is open, so
        // this arm is unreachable in practice. It exists so every
        // `interaction::Action` has a dispatch arm and the accessibility audit's
        // exhaustiveness holds.
        interaction::Action::WorkspaceProfileSelectField(_) => {}
        // §12.7.3: the click handler in `handle_mouse` already short-circuits the
        // terminal-profile targets (it needs the agent for persistence, which this
        // agent-free dispatcher does not carry), so this arm is unreachable in
        // practice. It exists so every `interaction::Action` has a dispatch arm and
        // the accessibility audit's exhaustiveness holds.
        interaction::Action::TerminalProfileCycleField(_) => {}
        // §12.7.5: the click handler in `handle_mouse` already short-circuits the
        // gesture-settings targets (it needs the agent for persistence, which this
        // agent-free dispatcher does not carry), so this arm is unreachable in
        // practice. It exists so every `interaction::Action` has a dispatch arm and
        // the accessibility audit's exhaustiveness holds.
        interaction::Action::GestureSettingsStepField(_) => {}
        // §12.7.6: the glyph-mode overlay's own mouse handler in `handle_mouse`
        // short-circuits this target while the overlay is open, so this arm is
        // unreachable in practice. It exists so every `interaction::Action` has a
        // dispatch arm and the accessibility audit's exhaustiveness holds.
        interaction::Action::GlyphModeSelect(_) => {}
        // §12.8.2: a single click on a subagent timeline row selects/pins it and
        // reveals a mouse-sourced preview — the same handler the keyboard pane
        // cursor reaches, so keyboard/mouse parity holds by construction.
        interaction::Action::SubagentSelect(index) => {
            subagent_select_index(app, index);
        }
        // §12.8.2: a double-click on a subagent row jumps to its transcript /
        // detail pane (preserving the prior conversation + scroll as a return
        // anchor) — the same handler the `JumpToSubagent` keyboard verb reaches.
        interaction::Action::SubagentJump(index) => {
            jump_to_subagent_index(app, index);
        }
        // §12.8.4: the promote affordance on a Subagent Timeline Panel row distills
        // that subagent's result into a follow-up prompt and fills the composer
        // (idle) or queues it (active turn) — the same handler the panel's `y` key
        // and the `PromoteSubagentResult` verb reach. The index is into the visible
        // (filtered) subagent list, matching the row's select target.
        interaction::Action::SubagentTimelinePromote(index) => {
            promote_subagent_timeline_row(app, index);
        }
        // §12.4.2: a click on a Smart Split Panes field row focuses + adjusts it —
        // the same handler the keyboard ↑↓ + →/Space path drives, so keyboard/mouse
        // parity holds by construction. The index is into
        // `smart_split::SplitField::ALL`, matching the row's click target.
        interaction::Action::SmartSplitAdjustField(index) => {
            smart_split_adjust_field(app, index);
        }
    }
}

/// How the card-affordance press path should treat a recognized gesture, so it
/// can coexist with visual text selection over the same header rows.
///
/// The main transcript's selection contract is fixed and must not regress:
/// double-click word-selects, triple-click row-selects, and a press that turns
/// into a drag range-selects. A card header therefore cannot *swallow* those
/// gestures. Only the dedicated caret zone (a non-text affordance) fully
/// consumes a click; a header single-click focuses the entry but then *falls
/// through* so the very same press still arms a (possibly empty) selection,
/// letting a drag select and a bare click clear — exactly as before the card
/// affordances existed.
enum CardPress {
    /// The gesture was a caret toggle / collapsed-card expand: consume it; do
    /// not run the selection path.
    Consumed,
    /// The gesture focused a header entry but the press must still flow into the
    /// selection path (so a drag from the header selects text).
    FocusedThenFallThrough,
    /// Not a single-click card gesture (double/triple click, or no action):
    /// leave it entirely to the selection path (word/row select).
    Ignored,
}

/// Classify and partially dispatch a recognized card gesture over the main
/// transcript view on a press. A single click on the caret toggles the entry's
/// fold and is consumed; a single click on the header focuses the entry but is
/// *not* consumed (the selection path still arms, so a drag selects); a
/// double-click on the caret expands a collapsed card and is consumed. Header
/// double/triple clicks are left untouched so the selection path word/row-selects.
fn dispatch_card_gesture(app: &mut TuiApp, gesture: interaction::Gesture) -> CardPress {
    match gesture {
        // Caret single-click → toggle the fold (a dedicated non-text zone, so it
        // fully owns the click). A header single-click → focus the entry, but
        // fall through so the same press still arms a selection for a drag.
        interaction::Gesture::Click {
            action: Some(action @ interaction::Action::ToggleEntryCollapsed(_)),
            ..
        } => {
            dispatch_click_action(app, action);
            CardPress::Consumed
        }
        interaction::Gesture::Click {
            action: Some(action @ interaction::Action::FocusEntry(_)),
            ..
        } => {
            dispatch_click_action(app, action);
            CardPress::FocusedThenFallThrough
        }
        // Double-click on the *caret* (keyed on its `ToggleEntryCollapsed` action,
        // a dedicated non-text zone, so it fully owns the click — a header TEXT
        // double-click registers `FocusEntry` and is left to the selection path for
        // word-select). This is the §12.1.4 double-click-activation path: a
        // collapsed card expands (the natural primary action when there is more to
        // see); an already-expanded card opens in the Ctrl+T detail overlay via the
        // entry's `PointerActivationPolicy::primary_activate` — the SAME
        // non-destructive verb the `Ctrl+Enter` keyboard chord and the action
        // palette's "open in detail" both reach. `policy_for` keeps every
        // destructive verb out of this path, so a double-click can never delete /
        // clear / retry by accident.
        interaction::Gesture::DoubleClick {
            action: Some(interaction::Action::ToggleEntryCollapsed(id)),
            ..
        } => {
            // A live preview is dismissed the moment a gesture activates.
            dismiss_hover_preview(app);
            let collapsed = active_transcript_entries(app)
                .iter()
                .find(|entry| entry.id == id.0)
                .is_some_and(|entry| entry.collapsed);
            let policy = hover_preview::policy_for(interaction::TargetKey::Entry(id));
            if collapsed {
                dispatch_click_action(app, interaction::Action::ExpandEntry(id));
            } else if policy.activates_on_double_click()
                && let Some(action) = policy.primary_activate
            {
                // `OpenEntryInDetail` focuses the entry itself before opening the
                // detail overlay, so no separate focus dispatch is needed.
                dispatch_click_action(app, action);
            }
            CardPress::Consumed
        }
        _ => CardPress::Ignored,
    }
}

/// Open the focused transcript entry in the Ctrl+T detail overlay (Expanded),
/// the open path `ToggleTranscriptOverlay` uses, seeded focused on the entry.
/// Single source of behaviour for both the `OpenFocusedInDetail` keymap action
/// and the `OpenEntryInDetail` click action. No-op (with a status hint) when no
/// entry is focused.
fn open_focused_entry_in_detail(app: &mut TuiApp) {
    if app.config_screen.is_some() || app.status_line_setup.is_some() {
        return;
    }
    if app.selected_entry.is_none() {
        app.status = "no focused entry — Ctrl+↑/↓ to focus one".to_string();
        return;
    }
    app.transcript_overlay_scrollbar_cache.set(None);
    // Open straight to the "see everything" expanded surface, the same target
    // the Ctrl+T toggle's open-from-nothing arm produces.
    app.transcript_overlay = Some(TranscriptOverlayState {
        detail: OverlayDetail::Expanded,
        ..TranscriptOverlayState::default()
    });
    app.status = "opened entry in detail (Ctrl+T)".to_string();
    app.needs_redraw = true;
}

/// Whether an entry kind is worth pinning into the diff/detail pane (§11G.10):
/// it carries a large diff, file excerpt, or bulky tool output. Tool results,
/// `/diff` cards, and plan cards always qualify; messages and reasoning qualify
/// only once their body is long enough to be awkward to read inline. Echo and
/// log lines are one-liners with nothing to pane.
fn entry_has_detail_pane_content(entry: &TranscriptEntry) -> bool {
    match &entry.kind {
        TranscriptEntryKind::ToolResult(_)
        | TranscriptEntryKind::Diff(_)
        | TranscriptEntryKind::PlanCard(_) => true,
        TranscriptEntryKind::Message(item) => item.content.chars().count() > LONG_ASSISTANT_CHARS,
        TranscriptEntryKind::Reasoning(snapshot) => {
            snapshot.display_text.chars().count() > LONG_ASSISTANT_CHARS
        }
        TranscriptEntryKind::Log(_) | TranscriptEntryKind::SlashEcho(_) => false,
    }
}

/// Toggle the diff/detail pane (§11G.10) for the currently focused overlay
/// entry. Opens the pane pinned to the focused entry when one is focused and
/// carries detail-worthy content; closes it when it is already open. Overlay-
/// local (handled by `handle_transcript_overlay_key`), so it only runs while the
/// Ctrl+T overlay is open.
fn toggle_diff_detail_pane(app: &mut TuiApp) {
    if app.transcript_overlay.is_none() {
        return;
    }
    if app.diff_detail_pane.is_some() {
        app.diff_detail_pane = None;
        app.diff_detail_pane_rect_cache.set(None);
        app.status = "detail pane closed".to_string();
        app.needs_redraw = true;
        return;
    }
    let entries = active_transcript_entries(app);
    let Some(index) = active_selected_entry(app) else {
        app.status = "no focused entry — Ctrl+↑/↓ to focus one, then d".to_string();
        return;
    };
    let Some(entry) = entries.get(index) else {
        app.status = "no focused entry — Ctrl+↑/↓ to focus one, then d".to_string();
        return;
    };
    if !entry_has_detail_pane_content(entry) {
        app.status = "focused entry has no diff / detail to pane".to_string();
        return;
    }
    app.diff_detail_pane = Some(diff_detail_pane::DiffDetailPaneState::new(entry.id));
    app.diff_detail_pane_rect_cache.set(None);
    app.status = "detail pane opened (Shift+↑/↓ to scroll · d/Esc to close)".to_string();
    app.needs_redraw = true;
}

/// The fully-expanded body lines for the entry pinned into the detail pane, or
/// an empty `Vec` when no pane is open / the pinned id has fallen out of the
/// transcript. Built with the same expanded formatter the overlay's "see
/// everything" surface uses, so the pane shows the raw diff/file/tool output.
fn diff_detail_pane_lines(app: &TuiApp, width: u16) -> Vec<Line<'static>> {
    let Some(pane) = app.diff_detail_pane else {
        return Vec::new();
    };
    let entries = active_transcript_entries(app);
    let Some((index, entry)) = entries
        .iter()
        .enumerate()
        .find(|(_, entry)| entry.id == pane.entry_id)
    else {
        return Vec::new();
    };
    let shortcut = key_hint(app, keymap::Action::ToggleTranscriptOverlay);
    let logical = format_transcript_entry_expanded(
        entry,
        false,
        ToolDetailMode::Full,
        message_outcome(entries, index),
        Some(width),
        app.show_reasoning_usage,
        shortcut.as_str(),
    );
    wrap_transcript_overlay_rows(&logical, width)
}

/// Whether the pinned detail-pane entry is still present in the active
/// transcript. The crate root closes the pane (heals to `None`) when the id has
/// disappeared so the render path never paints an empty pane.
fn diff_detail_pane_entry_present(app: &TuiApp) -> bool {
    let Some(pane) = app.diff_detail_pane else {
        return false;
    };
    active_transcript_entries(app)
        .iter()
        .any(|entry| entry.id == pane.entry_id)
}

/// `(total_rows, viewport_h)` for the detail pane. Prefers the LAST PAINTED text
/// rect (cached each frame in `diff_detail_pane_rect_cache`) so the scroll clamp
/// uses the exact geometry the user is looking at; falls back to rebuilding the
/// rect off-frame from the live terminal size (the way
/// `transcript_overlay_max_scroll` does) before the first paint. Returns `None`
/// when no pane is open or the overlay is too narrow to split.
fn diff_detail_pane_geometry(app: &TuiApp) -> Option<(usize, usize)> {
    app.diff_detail_pane?;
    let text_area = match app.diff_detail_pane_rect_cache.get() {
        Some(rect) if rect.width > 0 && rect.height > 0 => rect,
        _ => {
            let (width, height) = app.off_frame_terminal_size();
            let full_area = Rect {
                x: 0,
                y: 0,
                width,
                height,
            };
            let (content_area, _) = transcript_overlay_content_and_status_areas(full_area);
            let inner = transcript_overlay_inner(content_area);
            let layout = diff_detail_pane::split_overlay_content(inner)?;
            diff_detail_pane::pane_inner(layout.pane)
        }
    };
    if text_area.width == 0 || text_area.height == 0 {
        return None;
    }
    let rows = diff_detail_pane_lines(app, text_area.width);
    Some((rows.len(), usize::from(text_area.height)))
}

/// Scroll the detail pane by `delta` rows in `dir`, clamped to its content.
/// Returns `true` when the offset changed (so the caller redraws). Used by both
/// the `Shift`+scroll keyboard path and the wheel-over-pane mouse path.
fn scroll_diff_detail_pane(app: &mut TuiApp, dir: VerticalScrollDir, delta: usize) -> bool {
    let Some((total, viewport)) = diff_detail_pane_geometry(app) else {
        return false;
    };
    let Some(pane) = app.diff_detail_pane.as_mut() else {
        return false;
    };
    let next = match dir {
        VerticalScrollDir::Up => pane.scroll.saturating_sub(delta),
        VerticalScrollDir::Down => pane.scroll.saturating_add(delta),
    };
    let next = diff_detail_pane::clamp_pane_scroll(next, total, viewport);
    if next == pane.scroll {
        return false;
    }
    pane.scroll = next;
    app.needs_redraw = true;
    true
}

/// Direction for [`scroll_diff_detail_pane`].
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum VerticalScrollDir {
    Up,
    Down,
}

// ---- Pinned Compare View (§12.2.3) ----

/// Open / close the Pinned Compare View (§12.2.3) for the currently focused
/// overlay entry. Opens it pinned to the focused entry — comparing against the
/// live transcript — when one is focused and carries comparable content; closes
/// it when already open. Like the detail pane this is meaningful only while the
/// Ctrl+T overlay is open (the compare view compares against what the overlay
/// shows), but unlike the detail pane it is reached through a rebindable keymap
/// action (`Alt+t`) that the overlay guard lets through.
fn toggle_pinned_compare(app: &mut TuiApp) {
    if app.transcript_overlay.is_none() {
        app.status =
            "open the transcript overlay first (Ctrl+T), then Alt+t to compare".to_string();
        return;
    }
    if app.pinned_compare.is_some() {
        app.pinned_compare = None;
        app.pinned_compare_rect_cache.set(None);
        app.status = "compare view closed".to_string();
        app.needs_redraw = true;
        return;
    }
    let entries = active_transcript_entries(app);
    let Some(index) = active_selected_entry(app) else {
        app.status = "no focused entry — Ctrl+↑/↓ to focus one, then Alt+t".to_string();
        return;
    };
    let Some(entry) = entries.get(index) else {
        app.status = "no focused entry — Ctrl+↑/↓ to focus one, then Alt+t".to_string();
        return;
    };
    if !entry_has_detail_pane_content(entry) {
        app.status = "focused entry has no body worth comparing".to_string();
        return;
    }
    app.pinned_compare = Some(pinned_compare::PinnedCompareState::new(entry.id));
    app.pinned_compare_rect_cache.set(None);
    app.status =
        "compare view: Tab focus · scroll keys move active pane · x diff · Alt+t/Esc close"
            .to_string();
    app.needs_redraw = true;
}

/// Whether every entry the compare view pins is still present in the active
/// transcript. The pinned entry must be live; the compare target (when one is
/// pinned, rather than the live transcript) must be too. The crate root closes
/// the view when an id has disappeared so the render path never paints an empty
/// pane.
fn pinned_compare_entries_present(app: &TuiApp) -> bool {
    let Some(state) = app.pinned_compare else {
        return false;
    };
    let entries = active_transcript_entries(app);
    let pinned_live = entries.iter().any(|entry| entry.id == state.pinned_id);
    let compare_live = match state.compare_id {
        Some(id) => entries.iter().any(|entry| entry.id == id),
        None => true,
    };
    pinned_live && compare_live
}

/// The fully-expanded body lines for a transcript entry addressed by stable id,
/// at `width`. Built with the same expanded formatter the overlay and the detail
/// pane use, so the compare pane shows the raw diff/file/tool/message body. Empty
/// when the id has fallen out of the transcript.
fn pinned_compare_entry_lines(app: &TuiApp, entry_id: u64, width: u16) -> Vec<Line<'static>> {
    let entries = active_transcript_entries(app);
    let Some((index, entry)) = entries
        .iter()
        .enumerate()
        .find(|(_, entry)| entry.id == entry_id)
    else {
        return Vec::new();
    };
    let shortcut = key_hint(app, keymap::Action::ToggleTranscriptOverlay);
    let logical = format_transcript_entry_expanded(
        entry,
        false,
        ToolDetailMode::Full,
        message_outcome(entries, index),
        Some(width),
        app.show_reasoning_usage,
        shortcut.as_str(),
    );
    wrap_transcript_overlay_rows(&logical, width)
}

/// The content rows a compare pane paints, at `width`. The pinned pane shows the
/// pinned entry's expanded body; the compare pane shows either the second pinned
/// entry's body or — the spec's default — the live transcript rows the overlay
/// itself paints, so the comparison is genuinely "pinned vs. live".
fn pinned_compare_pane_lines(
    app: &TuiApp,
    pane: pinned_compare::ComparePane,
    width: u16,
) -> Vec<Line<'static>> {
    let Some(state) = app.pinned_compare else {
        return Vec::new();
    };
    match pane {
        pinned_compare::ComparePane::Pinned => {
            pinned_compare_entry_lines(app, state.pinned_id, width)
        }
        pinned_compare::ComparePane::Compare => match state.compare_id {
            Some(id) => pinned_compare_entry_lines(app, id, width),
            None => with_transcript_overlay_rows(app, width, |rows| rows.to_vec()),
        },
    }
}

/// The plain text of a compare pane (one `String` per row), used to feed the
/// line-based clean-text diff. Strips styling and the per-row spans down to their
/// concatenated content, then trims trailing whitespace so a cosmetic gutter
/// difference does not register as a content change.
fn pinned_compare_pane_plain(
    app: &TuiApp,
    pane: pinned_compare::ComparePane,
    width: u16,
) -> Vec<String> {
    pinned_compare_pane_lines(app, pane, width)
        .iter()
        .map(|line| {
            let text: String = line.spans.iter().map(|s| s.content.as_ref()).collect();
            text.trim_end().to_string()
        })
        .collect()
}

/// The rendered rows for the diff mode: a single column of `+`/`-`/` `-gutter
/// lines from [`pinned_compare::clean_text_diff`] (pinned = old, compare = new).
/// Falls back to a one-line notice when either side is too large to diff (the
/// spec's size-limit mitigation).
fn pinned_compare_diff_lines(app: &TuiApp, width: u16) -> Vec<Line<'static>> {
    // The gutter eats one cell; diff the panes at the narrower body width so the
    // wrapped rows line up with what each side would have shown.
    let body_width = width.saturating_sub(2).max(1);
    let old = pinned_compare_pane_plain(app, pinned_compare::ComparePane::Pinned, body_width);
    let new = pinned_compare_pane_plain(app, pinned_compare::ComparePane::Compare, body_width);
    // Cache the heavy LCS diff + styled-row build keyed on the width and a content
    // hash of both plain panes. The plain-text build above is a cheap cache-hitting
    // wrap; the DP table (`clean_text_diff`) is the ~2.9 MB cost we skip on a hit,
    // so an open diff overlay re-runs the alignment only when a side's content or
    // the width actually changes — not every painted frame / scroll tick.
    let key = {
        let mut hasher = std::collections::hash_map::DefaultHasher::new();
        width.hash(&mut hasher);
        old.len().hash(&mut hasher);
        for row in &old {
            row.hash(&mut hasher);
        }
        // Separate the two sides so `[a, b]` vs `[]`,`[a, b]` cannot collide.
        usize::MAX.hash(&mut hasher);
        new.len().hash(&mut hasher);
        for row in &new {
            row.hash(&mut hasher);
        }
        hasher.finish()
    };
    {
        let cache = app.pinned_compare_diff_cache.borrow();
        if cache.key == Some(key) {
            return cache.rows.clone();
        }
    }
    let rows = pinned_compare_diff_rows(&old, &new);
    let mut cache = app.pinned_compare_diff_cache.borrow_mut();
    cache.key = Some(key);
    cache.rows = rows.clone();
    rows
}

/// Build the styled diff rows from two plain panes — the LCS alignment plus the
/// `+`/`-`/` ` gutter coloring. Extracted from [`pinned_compare_diff_lines`] so the
/// cache front door wraps only the heavy part; returns the too-large fallback
/// notice when either side exceeds the diff size limit.
fn pinned_compare_diff_rows(old: &[String], new: &[String]) -> Vec<Line<'static>> {
    let Some(diff) = pinned_compare::clean_text_diff(old, new) else {
        return vec![Line::from(Span::styled(
            format!(
                "diff skipped — output too large (> {} lines per side)",
                pinned_compare::DIFF_LINE_LIMIT
            ),
            Style::default().fg(crate::render::theme::quiet()),
        ))];
    };
    diff.into_iter()
        .map(|line| {
            let color = match line.tag {
                pinned_compare::DiffTag::Same => crate::render::theme::quiet(),
                pinned_compare::DiffTag::Added => crate::render::theme::green(),
                pinned_compare::DiffTag::Removed => crate::render::theme::red(),
            };
            Line::from(Span::styled(
                format!("{} {}", line.tag.marker(), line.text),
                Style::default().fg(color),
            ))
        })
        .collect()
}

/// `(total_rows, viewport_h)` for one compare pane. Prefers the LAST PAINTED text
/// rect (cached each frame in `pinned_compare_rect_cache`) so the scroll clamp
/// uses the geometry the user is looking at; falls back to rebuilding the rect
/// off-frame from the live terminal size before the first paint. Returns `None`
/// when no compare view is open or the overlay is too small to split.
fn pinned_compare_geometry(
    app: &TuiApp,
    pane: pinned_compare::ComparePane,
) -> Option<(usize, usize)> {
    let state = app.pinned_compare?;
    // The cached rects are stored active-pane-first; resolve which slot this pane
    // is in for this frame.
    let text_area = match app.pinned_compare_rect_cache.get() {
        Some((first, second)) => {
            if pane == state.focus {
                first
            } else {
                second
            }
        }
        None => {
            let (width, height) = app.off_frame_terminal_size();
            let full_area = Rect {
                x: 0,
                y: 0,
                width,
                height,
            };
            let (content_area, _) = transcript_overlay_content_and_status_areas(full_area);
            let inner = transcript_overlay_inner(content_area);
            let layout = pinned_compare::split_overlay_content(inner)?;
            // Off-frame both panes share the same inner size, so either slot's
            // inset rect is a fine proxy for the clamp.
            let (first, _) = layout.panes();
            pinned_compare::pane_inner(first)
        }
    };
    if text_area.width == 0 || text_area.height == 0 {
        return None;
    }
    let rows = if state.mode == pinned_compare::CompareMode::Diff {
        pinned_compare_diff_lines(app, text_area.width)
    } else {
        pinned_compare_pane_lines(app, pane, text_area.width)
    };
    Some((rows.len(), usize::from(text_area.height)))
}

/// Scroll the *focused* compare pane by `delta` rows in `dir`, clamped to its
/// content. Returns `true` when the offset changed (so the caller redraws). Used
/// by both the keyboard scroll path and the wheel-over-pane mouse path. In diff
/// mode the two panes share one column, so whichever pane is focused scrolls the
/// same diff body.
fn scroll_pinned_compare(app: &mut TuiApp, dir: VerticalScrollDir, delta: usize) -> bool {
    let Some(focus) = app.pinned_compare.map(|state| state.focus) else {
        return false;
    };
    let Some((total, viewport)) = pinned_compare_geometry(app, focus) else {
        return false;
    };
    let Some(state) = app.pinned_compare.as_mut() else {
        return false;
    };
    let current = state.focused_scroll();
    let next = match dir {
        VerticalScrollDir::Up => current.saturating_sub(delta),
        VerticalScrollDir::Down => current.saturating_add(delta),
    };
    let next = pinned_compare::clamp_pane_scroll(next, total, viewport);
    if next == current {
        return false;
    }
    state.set_focused_scroll(next);
    app.needs_redraw = true;
    true
}

/// Flip which compare pane the keyboard / wheel drives (the `Tab` key and a click
/// on a pane). Returns `true` when a view was open (so the caller redraws).
fn toggle_pinned_compare_focus(app: &mut TuiApp) -> bool {
    let Some(state) = app.pinned_compare.as_mut() else {
        return false;
    };
    state.focus = state.focus.toggled();
    let label = state.focus.label();
    // The cached rects are active-pane-first, so a focus flip invalidates them
    // until the next paint re-stamps the new ordering.
    app.pinned_compare_rect_cache.set(None);
    app.status = format!("compare focus: {label} pane");
    app.needs_redraw = true;
    true
}

/// Focus a specific compare pane (the mouse twin of `Tab`): a click inside a pane
/// makes it the active one. Returns `true` when the focus actually changed.
fn focus_pinned_compare_pane(app: &mut TuiApp, pane: pinned_compare::ComparePane) -> bool {
    let Some(state) = app.pinned_compare.as_mut() else {
        return false;
    };
    if state.focus == pane {
        return false;
    }
    state.focus = pane;
    let label = pane.label();
    app.pinned_compare_rect_cache.set(None);
    app.status = format!("compare focus: {label} pane");
    app.needs_redraw = true;
    true
}

/// Toggle the compare view between verbatim content and a line-based clean-text
/// diff (the `x` key). Returns `true` when a view was open.
fn toggle_pinned_compare_mode(app: &mut TuiApp) -> bool {
    let Some(state) = app.pinned_compare.as_mut() else {
        return false;
    };
    state.mode = state.mode.toggled();
    // The diff column has a different total height than either content pane, so
    // reset both offsets to the top to avoid stranding past the end.
    state.pinned_scroll = 0;
    state.compare_scroll = 0;
    let label = state.mode.label();
    app.pinned_compare_rect_cache.set(None);
    app.status = format!("compare mode: {label}");
    app.needs_redraw = true;
    true
}

/// The `build_width` the off-frame scroll/jump geometry must wrap at to match
/// the painted row model. `render_transcript` builds soft-wrapped rows at the
/// text width (the default) but builds UNWRAPPED logical rows (one per line)
/// when soft-wrap is off (§11G.4), panning horizontally instead. The off-frame
/// measurers must mirror that branch so `max_scroll`, jump offsets, and the
/// stored `from_bottom` all line up with what is on screen.
fn main_geometry_build_width(app: &TuiApp, text_width: u16) -> Option<u16> {
    if app.wide_block.soft_wrap() {
        Some(text_width)
    } else {
        None
    }
}

/// Current `(line_count, viewport_h)` for the *active* transcript, using the
/// last-painted-frame width and the transcript area height. Mirrors the geometry
/// `render_transcript` feeds to `ScrollState::offset` so `scroll_by`/
/// `scroll_to_top`/`clamp` clamp against the same numbers the renderer uses.
///
/// Recomputed off-frame the same way `transcript_overlay_max_scroll` rebuilds
/// the overlay `Rect`, both sizing from [`TuiApp::off_frame_terminal_size`]
/// (the size the renderer last painted with) rather than a raw `terminal_size()`
/// syscall, so the math agrees with the frame on screen and is deterministic in
/// headless tests.
fn active_transcript_geometry(app: &TuiApp) -> (usize, usize) {
    let (width, height) = app.off_frame_terminal_size();
    let area = Rect {
        x: 0,
        y: 0,
        width,
        height,
    };
    // `render()` renders the main transcript only when no overlay/setup/config
    // screen is up and includes the startup card on a tall enough terminal. The
    // Adaptive Density (§12.4.1) height gate is shared with the render path so
    // this off-frame geometry counts the same rows.
    let include_startup_card = include_startup_card_for(app, area);
    let viewport_h = main_transcript_height(app, area, include_startup_card);
    // Wrap at the text width the renderer actually uses: `render_transcript`
    // carves the 1-cell minimap rail (when shown) AND the 1-cell scrollbar gutter
    // off the right edge before wrapping (so text is `width - 1`, or `- 2` with
    // the minimap). Measuring at the wider width would undercount wrapped rows, so
    // the off-frame `from_bottom` clamp would disagree with the painted line count
    // (deep-review #129).
    let text_width = main_painted_text_width(app, area);
    // Match the renderer: soft-wrap off builds UNWRAPPED rows (one visual row per
    // logical line), so the scroll geometry must measure the same row model or
    // `max_scroll` over-counts and scroll-down stalls against a phantom distance.
    let build_width = main_geometry_build_width(app, text_width);
    let lines = transcript_lines_for_render(app, build_width, include_startup_card);
    (lines.len(), viewport_h as usize)
}

/// The painted main-text width for `area`, matching `render_transcript`: carve
/// the minimap rail (when shown) then the scrollbar gutter off the right edge.
/// The off-frame scroll/jump measurers must wrap at this exact column so their
/// row counts and entry offsets line up with what is painted.
fn main_painted_text_width(app: &TuiApp, area: Rect) -> u16 {
    let show_minimap = app.show_minimap && !app.zen.chrome_suppressed();
    let (body_area, _rail) = transcript_main_body_and_rail_areas(area, show_minimap);
    let (text_area, _scrollbar) = transcript_main_text_and_scrollbar_areas(body_area);
    text_area.width
}

/// Keep an *unpinned* main-transcript view anchored to the content the user is
/// reading when new content is appended (Append-Aware Anchor).
///
/// The scroll model stores `from_bottom` (distance up from the tail), so a fresh
/// append grows `max_scroll` and the same `from_bottom` resolves to a larger
/// top-line offset — the viewport yanks forward by the appended rows. This
/// re-runs just before paint: it reads the *prior* frame's wrapped-row count from
/// `main_text_area_cache`, recomputes the *current* count at the same painted
/// width, and bumps `from_bottom` by the row delta so `offset == max_scroll -
/// from_bottom` stays put. A following view is left pinned (it intends to track
/// the tail). Gated on matching viewport+width so a reflow/resize (handled by
/// `reanchor_active_scroll_on_resize`) never double-compensates.
pub(crate) fn compensate_main_scroll_for_append(app: &mut TuiApp) {
    // Only the MAIN transcript has the append-anchor model; a subagent view is
    // log-only and always tail-tracking.
    if !matches!(app.subagent_pane.active, ConversationSource::Main) {
        return;
    }
    let Some(cache) = app.main_text_area_cache.get() else {
        return;
    };
    if active_transcript_scroll(app).is_following() {
        return;
    }
    let (new_total, viewport_h) = active_transcript_geometry(app);
    // A viewport-height change is a reflow, not an append — leave it to the
    // resize re-anchor. The painted text width is the cache's `text_area.width`;
    // `active_transcript_geometry` wraps at that same width via
    // `off_frame_terminal_size`, so a width change shows up as a viewport change
    // or a non-growth row delta and is filtered out here.
    if usize::from(cache.viewport_h) != viewport_h {
        return;
    }
    let delta = new_total.saturating_sub(cache.total_rows);
    if delta == 0 {
        return;
    }
    active_transcript_scroll_mut(app).compensate_for_growth(delta, new_total, viewport_h);
}

/// The painted main-text width for a frame of `(width, height)`: the renderer
/// carves the minimap rail (when shown) and the scrollbar gutter off the right
/// edge before wrapping, so a text selection's column indices live in this
/// narrower coordinate space, not the full frame width.
fn main_painted_text_width_for(app: &TuiApp, width: u16, height: u16) -> u16 {
    main_painted_text_width(
        app,
        Rect {
            x: 0,
            y: 0,
            width,
            height,
        },
    )
}

/// Invalidate text selections whose captured wrap width no longer matches the
/// painted width after a resize (deep-review #42).
///
/// A `Selection` records the `text_area.width` its (row, col) positions were
/// taken at; a reflow to a new width re-wraps the surface rows, so those indices
/// now point at different cells (wrong copied text / a stray highlight band).
/// `refresh_search` re-anchors search the same way; selections carry no
/// re-wrap-able anchor (and `selection_set` ranges carry no width at all), so the
/// safe minimal fix is to clear them when the width drifts. No-op when the width
/// is unchanged (a pure height resize) so a vertical-only resize keeps the
/// selection.
fn reanchor_or_clear_selection_on_resize(app: &mut TuiApp, width: u16, height: u16) {
    if app.selection.is_none() && app.selection_set.is_empty() {
        return;
    }
    let painted_width = main_painted_text_width_for(app, width, height);
    // The active selection stamps the width it was captured at; a `selection_set`
    // member carries none, so any width change invalidates it. Drive the decision
    // off the active selection's stored width when present, else off the cache.
    let captured_width = app
        .selection
        .as_ref()
        .map(|sel| sel.width)
        .or_else(|| app.main_text_area_cache.get().map(|c| c.text_area.width));
    let drifted = match captured_width {
        Some(w) => w != painted_width,
        // No stored width to compare against: be conservative and clear so a
        // stale set never survives an unknown reflow.
        None => true,
    };
    if drifted {
        app.selection = None;
        app.selection_set.clear();
    }
}

/// Re-anchor the active transcript scroll + focus to the current (post-resize)
/// geometry (Focus-Preserving Resize, §12.4.3).
///
/// A bare `from_bottom` line count is only meaningful against a fixed wrap
/// geometry, so a reflow that changes how many rows each entry occupies would
/// otherwise leave the same `from_bottom` pointing at a *different entry* — the
/// view jumps. Instead this captures the top-visible entry as a stable id
/// *before* the reflow and re-pins the scroll so that same entry stays at the
/// top *after* it. A following view stays pinned to the tail; an anchored entry
/// that was pruned/coalesced falls back to the plain clamp (no dangling anchor).
/// It also re-validates the keyboard focus so a transcript that shrank under a
/// stale `selected_entry` index never leaves a hidden/dangling focus.
fn reanchor_active_scroll_on_resize(app: &mut TuiApp, new_size: Option<(u16, u16)>) {
    // Snapshot the logical scroll anchor (entry id at the top, or "following")
    // against the geometry as it stands *before* the reflow — i.e. the
    // last-painted (old) size, the row units the current `from_bottom` is in.
    let anchor = capture_scroll_anchor_for_resize(app);

    let (line_count, viewport_h) = active_transcript_geometry(app);
    active_transcript_scroll_mut(app).clamp(line_count, viewport_h);

    // Re-pin the captured anchor against the *post*-resize geometry so the user
    // keeps looking at the same entry rather than a row that now wraps
    // differently. The new size comes from the `Event::Resize` payload because
    // `off_frame_terminal_size` still reports the old (last-painted) size until
    // the next frame lands; without it, capture and re-pin would both measure the
    // old geometry and the re-pin would be a no-op. Falls through to the clamp
    // above when the anchored entry is gone (no dangling anchor).
    let post_geometry = match new_size {
        Some((width, height)) => transcript_nav_geometry_at(app, width, height),
        None => jump_nav_geometry(app),
    };
    if let Some((entry_offsets, total_rows, viewport_h)) = post_geometry
        && let Some(entry_ids) = active_entry_ids(app)
        && let Some(from_bottom) = focus_resize::reanchor_from_bottom(
            anchor,
            &entry_offsets,
            &entry_ids,
            total_rows,
            viewport_h,
        )
    {
        active_transcript_scroll_mut(app).set_from_bottom(from_bottom, total_rows, viewport_h);
    }

    // Re-validate the keyboard focus index so a shrunk transcript never leaves a
    // dangling/hidden focus (the spec's `resolve_focus_after_layout`).
    reanchor_focus_on_resize(app);
}

/// The logical scroll anchor (top-visible entry id, or "following the tail") of
/// the active transcript as it stands *now*, for [`reanchor_active_scroll_on_resize`]
/// to re-pin after the reflow. Returns [`focus_resize::ScrollAnchor::Following`]
/// when there is nothing to anchor (empty transcript / degenerate geometry).
fn capture_scroll_anchor_for_resize(app: &TuiApp) -> focus_resize::ScrollAnchor {
    let following = active_transcript_scroll(app).is_following();
    let (Some((entry_offsets, total_rows, viewport_h)), Some(entry_ids)) =
        (jump_nav_geometry(app), active_entry_ids(app))
    else {
        return focus_resize::ScrollAnchor::Following;
    };
    let top_row = active_transcript_scroll(app).offset(total_rows, viewport_h);
    focus_resize::ScrollAnchor::capture(following, top_row, &entry_offsets, &entry_ids)
}

/// The stable ids of the active transcript's entries, in row order. `None` when
/// the active transcript is empty (no anchor to take).
fn active_entry_ids(app: &TuiApp) -> Option<Vec<u64>> {
    let ids: Vec<u64> = active_transcript_entries(app)
        .iter()
        .map(|entry| entry.id)
        .collect();
    if ids.is_empty() { None } else { Some(ids) }
}

/// Re-validate the main-view keyboard focus index after a reflow (§12.4.3): an
/// index that now dangles past a shrunk transcript clamps to the last row (or
/// clears on an empty transcript), so focus is never hidden. The subagent view
/// has no main-view focus (`active_selected_entry` returns `None` there), so
/// this only touches the main transcript's `selected_entry`.
fn reanchor_focus_on_resize(app: &mut TuiApp) {
    if active_subagent_record(app).is_some() {
        return;
    }
    app.selected_entry =
        focus_resize::resolve_focus_index(app.selected_entry, app.transcript.len());
}

fn scroll_transcript_up(app: &mut TuiApp, lines: usize) {
    // Direct nudges snap: cancel any in-flight ease so the view doesn't fight
    // the user's wheel/page input. `cancel_main_scroll_anim` makes the painted
    // position jump straight to the (about-to-change) logical state.
    cancel_main_scroll_anim(app);
    let (line_count, viewport_h) = active_transcript_geometry(app);
    active_transcript_scroll_mut(app).scroll_by(lines as isize, line_count, viewport_h);
}

fn scroll_transcript_down(app: &mut TuiApp, lines: usize) {
    cancel_main_scroll_anim(app);
    let (line_count, viewport_h) = active_transcript_geometry(app);
    active_transcript_scroll_mut(app).scroll_by(-(lines as isize), line_count, viewport_h);
}

/// Cancel any in-flight main-view smooth-scroll ease, snapping the painted
/// position to the logical destination. Called on every fresh input so an
/// animation never lingers past new scrolling.
fn cancel_main_scroll_anim(app: &mut TuiApp) {
    app.main_scroll_anim = None;
}

/// Commit an absolute `from_bottom` to the active transcript and, for a large
/// enough jump, arm a smooth-scroll ease from the previous position. The logical
/// state is set to the destination immediately (the stable anchor); the ease
/// only governs the painted position on the way there. Honours the
/// reduced-motion / instant-scroll switch (`smooth_scroll_enabled`).
fn commit_main_from_bottom_animated(app: &mut TuiApp, target_from_bottom: usize) {
    commit_main_from_bottom_animated_at(app, target_from_bottom, std::time::Instant::now());
}

/// Clock-injectable core of [`commit_main_from_bottom_animated`]: samples the
/// in-flight ease's displayed `start` against an explicit `now`. Production reads
/// the wall clock (via the wrapper above); the in-crate test suite pins one `now`
/// so the re-trigger's `start` and an earlier displayed-position read agree
/// exactly, with no wall-clock drift between the two samples.
fn commit_main_from_bottom_animated_at(
    app: &mut TuiApp,
    target_from_bottom: usize,
    now: std::time::Instant,
) {
    let (line_count, viewport_h) = active_transcript_geometry(app);
    // Sample the start from the DISPLAYED position, not the logical/committed
    // offset: while a prior ease is in flight the logical offset already equals
    // that ease's destination, so easing from it would snap the paint back to the
    // old target before easing forward. `displayed_main_from_bottom_at` returns
    // the live mid-ease position when an anim is active (deep-review #125).
    let start = displayed_main_from_bottom_at(
        app,
        active_transcript_scroll(app),
        line_count,
        viewport_h,
        now,
    );
    active_transcript_scroll_mut(app).set_from_bottom(target_from_bottom, line_count, viewport_h);
    arm_main_scroll_anim_from(app, start);
}

/// Jump the active transcript to the very top with a smooth ease. Uses
/// `scroll_to_top` so the stored `from_bottom` is the real top offset (not the
/// `usize::MAX` sentinel), keeping it meaningful for a later `clamp`.
fn jump_main_to_top_animated(app: &mut TuiApp) {
    let (line_count, viewport_h) = active_transcript_geometry(app);
    // Sample the start from the DISPLAYED (mid-ease) position so re-triggering a
    // jump while a prior ease is in flight eases from where the paint actually is,
    // not from the prior ease's logical destination (deep-review #125).
    let start =
        displayed_main_from_bottom(app, active_transcript_scroll(app), line_count, viewport_h);
    active_transcript_scroll_mut(app).scroll_to_top(line_count, viewport_h);
    arm_main_scroll_anim_from(app, start);
}

/// Arm (or clear) the smooth-scroll ease after the logical state has already
/// moved to its destination. `start` is the pre-move displayed `from_bottom`;
/// the destination is read back from the (now-updated) state. Small jumps and
/// reduced-motion both snap (no ease).
fn arm_main_scroll_anim_from(app: &mut TuiApp, start: usize) {
    let (line_count, viewport_h) = active_transcript_geometry(app);
    let target = active_transcript_scroll(app).offset_from_bottom(line_count, viewport_h);
    let distance = start.abs_diff(target);
    if app.smooth_scroll_enabled && distance >= MAIN_SCROLL_ANIM_MIN_DISTANCE {
        app.main_scroll_anim = Some(MainScrollAnim {
            start,
            target,
            started_at: std::time::Instant::now(),
        });
    } else {
        app.main_scroll_anim = None;
    }
}

fn request_turn_interrupt(app: &mut TuiApp) -> bool {
    let mut interrupted = false;
    if let Some(cancel) = &app.cancel {
        cancel.cancel();
        interrupted = true;
    }
    if let Some(pending) = app.pending_approval.take() {
        let _ = pending.decision_tx.send(ToolApprovalDecision::Cancelled);
        interrupted = true;
    }
    if let Some(pending) = app.pending_mcp_elicitation.take() {
        let _ = pending.response_tx.send(McpElicitationResponse::cancel());
        clear_mcp_elicitation_seeded_input(app);
        interrupted = true;
    }
    if interrupted {
        app.status = "interrupting".to_string();
        app.turn_visual = TurnVisualState::Failed;
        app.clear_active_tools();
    }
    interrupted
}

/// Kick off a new model turn for the given input. Shared between the
/// Enter-key submission path and slash commands like `/plan <prompt>` that
/// want to launch a turn after their side-effect.
fn toggle_config_screen(
    app: &mut TuiApp,
    agent: &Agent,
    focus: Option<squeezy_core::config_schema::SectionId>,
) {
    if app.config_screen.is_some() {
        close_config_screen(app, agent, "config closed");
        return;
    }
    // Build the screen from a freshly-merged settings config so it reflects
    // what's saved on disk — the agent snapshot can lag a settings file written
    // in an earlier session, which would otherwise leave the Permissions rows
    // (and other fields) showing a stale mode. Fall back to the running config
    // if the reload fails.
    let effective = squeezy_core::AppConfig::from_env_and_settings()
        .unwrap_or_else(|_| agent.config_snapshot());
    let mut state = config_screen::ConfigScreenState::new(effective, focus);
    // Seed the cached registry view from the live agent so the
    // McpServers section reflects in-flight enable/disable from the
    // moment it opens.
    state.mcp_servers = agent.mcp_servers();
    state.mcp_status = agent.mcp_status_snapshot();
    app.config_screen = Some(state);
    app.status = "config".to_string();
}

fn close_config_screen(app: &mut TuiApp, agent: &Agent, status: impl Into<String>) {
    let Some(mut state) = app.config_screen.take() else {
        return;
    };
    emit_config_screen_telemetry(agent, &mut state);
    app.status = status.into();
}

fn emit_config_screen_telemetry(agent: &Agent, state: &mut config_screen::ConfigScreenState) {
    for change in state.telemetry_changes.drain(..) {
        agent.record_config_change_telemetry(ConfigChangeReport {
            scope: telemetry_config_scope(change.scope),
            section: change.section,
            field: &change.field,
            apply_tier: telemetry_config_apply_tier(change.apply_tier),
            change_kind: telemetry_config_change_kind(change.change_kind),
            prev_bucket: &change.prev_value,
            new_bucket: &change.new_value,
        });
    }
}

fn telemetry_config_scope(scope: config_screen::ConfigScope) -> ConfigScopeKind {
    match scope {
        config_screen::ConfigScope::User => ConfigScopeKind::User,
        config_screen::ConfigScope::Repo => ConfigScopeKind::Project,
        config_screen::ConfigScope::Local => ConfigScopeKind::Local,
    }
}

fn telemetry_config_apply_tier(tier: squeezy_core::config_schema::ApplyTier) -> ConfigApplyTier {
    match tier {
        squeezy_core::config_schema::ApplyTier::Immediate => ConfigApplyTier::Immediate,
        squeezy_core::config_schema::ApplyTier::NextPrompt => ConfigApplyTier::NextPrompt,
        squeezy_core::config_schema::ApplyTier::Restart => ConfigApplyTier::Restart,
    }
}

fn telemetry_config_change_kind(
    kind: config_screen::ConfigTelemetryChangeKind,
) -> ConfigChangeKind {
    match kind {
        config_screen::ConfigTelemetryChangeKind::Set => ConfigChangeKind::Set,
        config_screen::ConfigTelemetryChangeKind::Unset => ConfigChangeKind::Unset,
        config_screen::ConfigTelemetryChangeKind::Reset => ConfigChangeKind::Reset,
    }
}

fn toggle_status_line_setup(app: &mut TuiApp) {
    if app.status_line_setup.is_some() {
        app.status_line_setup = None;
        app.status = "/statusline closed".to_string();
        return;
    }
    app.status_line_setup = Some(status_line_setup::StatusLineSetupState::new(
        app.status_line_items.as_deref(),
        app.status_line_use_colors,
    ));
    app.status = "/statusline".to_string();
}

/// Apply the resolved theme table in one shot so all token lookups and
/// render caches observe the same generation.
pub(crate) fn apply_theme_overrides(config: &AppConfig) {
    render::theme::set_active_theme(config);
    render::spinner::set_active_spinner(config);
}

/// Apply a `/theme` switch: flip the runtime palette override, mirror the
/// new value into the agent's in-memory config, and persist to the user-
/// scope settings file so the choice survives a restart. Persistence failures
/// surface in the status line but the live switch still takes effect — the
/// user can re-run later to retry the save.
fn apply_theme_change(app: &mut TuiApp, agent: &mut Agent, theme: String) {
    use squeezy_core::settings_writer::{EditOp, SettingsEdit, SettingsScope, apply_edits};

    let mut next = agent.config_snapshot();
    next.tui.theme = theme.clone();
    apply_theme_overrides(&next);
    agent.replace_config(next);

    let target_path = app.user_settings_path();
    let scope_target = SettingsScope::user(&target_path);
    let edits = [SettingsEdit {
        path: &["tui", "theme"],
        op: EditOp::SetString(theme.clone()),
    }];
    match apply_edits(&scope_target, &edits) {
        Ok(_) => {
            app.push_status(format!("theme → {theme}"));
            app.status = format!("theme saved to {}", target_path.display());
        }
        Err(err) => {
            app.push_warn(format!("theme switched but save failed: {err}"));
            app.status = format!("theme switched (not persisted): {err}");
        }
    }
    app.needs_redraw = true;
}

/// Persist the picker's selection to `[tui].status_line` /
/// `[tui].status_line_use_colors` in the chosen scope (user or project
/// settings file) and apply it in-memory immediately.
fn save_status_line(
    app: &mut TuiApp,
    agent: &mut Agent,
    items: Vec<status::StatusLineItem>,
    use_colors: bool,
    scope: status_line_setup::SaveScope,
) {
    use squeezy_core::settings_writer::{EditOp, SettingsEdit, SettingsScope, apply_edits};

    let scope_target = match scope {
        status_line_setup::SaveScope::User => {
            let p = app.user_settings_path();
            SettingsScope::user(&p)
        }
        status_line_setup::SaveScope::Project => {
            let p = squeezy_core::find_project_settings_path(&app.workspace_root)
                .unwrap_or_else(|| app.workspace_root.join(squeezy_core::PROJECT_SETTINGS_FILE));
            SettingsScope::project(&p)
        }
    };
    let slug_list: Vec<String> = items.iter().map(|i| i.slug().to_string()).collect();
    let edits = [
        SettingsEdit {
            path: &["tui", "status_line"],
            op: EditOp::SetArrayOfStrings(slug_list.clone()),
        },
        SettingsEdit {
            path: &["tui", "status_line_use_colors"],
            op: EditOp::SetBool(use_colors),
        },
    ];
    match apply_edits(&scope_target, &edits) {
        Ok(_) => {
            // Apply immediately in-memory.
            let mut cfg = agent.config_snapshot();
            cfg.tui.status_line = if slug_list.is_empty() {
                None
            } else {
                Some(slug_list.clone())
            };
            cfg.tui.status_line_use_colors = use_colors;
            agent.replace_config(cfg);
            app.status_line_items = Some(items);
            app.status_line_use_colors = use_colors;
            let target_display = scope_target.path.display();
            app.status = format!("status line saved to {target_display}");
            // Squeezy's settings tiers merge in the order defaults → user →
            // project → repo, with later tiers overriding earlier ones (see
            // squeezy_core::load_settings_from_paths and TuiSettings::merge).
            // So a project-scope save already wins over the user tier on
            // restart; the only thing that would override it is a per-machine
            // entry in ~/.squeezy/projects/<repo-id>/settings.toml.
            let project_note = if matches!(scope, status_line_setup::SaveScope::Project) {
                "\n\nNote: this project layout takes precedence over user settings on restart. \
                 A per-machine entry in `~/.squeezy/projects/<repo-id>/settings.toml` would \
                 still override it."
            } else {
                ""
            };
            let summary = if slug_list.is_empty() {
                format!(
                    "status line cleared (colors {}); written to {target_display}{project_note}",
                    if use_colors { "on" } else { "off" },
                )
            } else {
                format!(
                    "status line saved: {} (colors {}); written to {target_display}{project_note}",
                    slug_list.join(", "),
                    if use_colors { "on" } else { "off" },
                )
            };
            app.push_transcript_item(TranscriptItem::system(summary));
        }
        Err(err) => {
            let msg = format!("/statusline save failed: {err}");
            app.status = msg.clone();
            app.push_transcript_item(TranscriptItem::system(msg));
        }
    }
}

/// Whether the transcript should show a styled banner for this slash
/// command's invocation. Commands that open their own UI overlay
/// (`/config`, `/statusline`, …) are silenced — the overlay is the
/// affordance. `/help` is silenced: for answered topics it pushes a system
/// transcript card directly; for unknown topics the `start_user_turn` fallback
/// produces a user-message bubble — echo in either case would duplicate output.
/// `/tool-verbosity` reports when called bare but silently applies a value when
/// given an arg — echo only the second form. Unrecognized commands are not
/// echoed: they fall through to be sent as regular user prompts.
fn should_echo_slash_command(command: &str, rest: &str) -> bool {
    if !SLASH_COMMANDS.iter().any(|spec| spec.name == command) {
        return false;
    }
    match command {
        "/config" | "/options" | "/statusline" | "/model" | "/permissions" | "/mcp" | "/help" => {
            false
        }
        "/tool-verbosity" => !rest.trim().is_empty(),
        _ => true,
    }
}

pub(crate) async fn handle_slash_command(app: &mut TuiApp, agent: &mut Agent, input: &str) -> bool {
    handle_slash_command_on_surface(app, agent, input, SlashSurface::TuiComposer).await
}

async fn handle_slash_command_on_surface(
    app: &mut TuiApp,
    agent: &mut Agent,
    input: &str,
    surface: SlashSurface,
) -> bool {
    // `/export` is a TUI-local command (it reuses the in-memory transcript row
    // model + copy formatters), so it is handled here before the agent-owned
    // `DispatchCommand` parser, which does not know it.
    let raw_head = input.split_whitespace().next().unwrap_or_default();
    if raw_head == "/export" {
        let rest = input
            .strip_prefix(raw_head)
            .map(str::trim)
            .unwrap_or_default();
        record_slash_command_telemetry(
            agent,
            "/export",
            surface,
            SlashOutcome::Accepted,
            SlashAliasKind::Canonical,
            slash_arg_shape_from_rest(input),
        );
        handle_export_command(app, agent, rest);
        return true;
    }

    // `/bundle` (§12.6.6) is likewise a TUI-local command: it reuses the same
    // in-memory transcript row model + Markdown export formatter to build a
    // self-contained shareable artifact (transcript + manifest + checksum +
    // diagnostics, redacted by default), so it is handled here before the
    // agent-owned dispatch parser, which does not know it.
    if raw_head == "/bundle" {
        let rest = input
            .strip_prefix(raw_head)
            .map(str::trim)
            .unwrap_or_default();
        record_slash_command_telemetry(
            agent,
            "/bundle",
            surface,
            SlashOutcome::Accepted,
            SlashAliasKind::Canonical,
            slash_arg_shape_from_rest(input),
        );
        handle_bundle_command(app, agent, rest);
        return true;
    }

    // `/reveal` (§12.4.6) is the Presentation Mode one-shot reveal command: it
    // lifts the screen-share metadata suppression for the rest of the session
    // without leaving the mode (so a value can be shown to a viewer on demand). A
    // TUI-local display toggle that mutates nothing in the model, so it is handled
    // here before the agent-owned dispatch parser, which does not know it.
    if raw_head == "/reveal" {
        record_slash_command_telemetry(
            agent,
            "/reveal",
            surface,
            SlashOutcome::Accepted,
            SlashAliasKind::Canonical,
            slash_arg_shape_from_rest(input),
        );
        reveal_presentation(app);
        return true;
    }

    // `/terminal-reset` (§12.9.2) is the Terminal Restore Command's discoverable
    // slash twin: it forcibly returns a wedged terminal to a sane state (leave
    // alt-screen, reset modes, show cursor, disable raw mode) and re-enters the
    // fullscreen surface. A TUI-local recovery verb handled here before the
    // agent-owned dispatch parser, which does not know it — and the always-typeable
    // path when the `Ctrl+Alt+,` chord is swallowed by the corrupted terminal.
    if raw_head == "/terminal-reset" {
        record_slash_command_telemetry(
            agent,
            "/terminal-reset",
            surface,
            SlashOutcome::Accepted,
            SlashAliasKind::Canonical,
            slash_arg_shape_from_rest(input),
        );
        request_terminal_restore(app);
        return true;
    }

    let cmd = match DispatchCommand::parse(input) {
        Ok(cmd) => cmd,
        // Unknown heads fall through to the user-authored prompt
        // template catalog. A match expands the template body and
        // routes it through the regular user-turn machinery so the
        // model sees the rendered prompt, not the literal slash text.
        // No match keeps the legacy behaviour: the input is treated as
        // a normal user prompt (echoed as a slash echo upstream by
        // `reject_unknown_slash_command`).
        Err(DispatchCommandParseError::Unknown { command: _ }) => {
            if expand_prompt_template_or_fallthrough(app, agent, input, surface) {
                record_slash_command_telemetry(
                    agent,
                    "/prompt-template",
                    surface,
                    SlashOutcome::TemplateExpanded,
                    SlashAliasKind::Template,
                    slash_arg_shape_from_rest(input),
                );
                return true;
            }
            agent.record_slash_command_telemetry(
                "unknown",
                surface,
                SlashOutcome::Unknown,
                SlashAliasKind::Unknown,
                slash_arg_shape_from_rest(input),
            );
            return false;
        }
        Err(DispatchCommandParseError::NotASlashCommand)
        | Err(DispatchCommandParseError::Empty) => return false,
        // Required-arg failures preserve the pre-refactor `usage:`
        // strings so the visible affordance is unchanged.
        Err(DispatchCommandParseError::Usage { command, hint }) => {
            record_slash_command_telemetry(
                agent,
                &command,
                surface,
                SlashOutcome::UsageError,
                slash_alias_kind(&command),
                SlashArgShape::Present,
            );
            set_status_with_notice(app, hint.clone(), hint);
            return true;
        }
    };

    let raw_head = input.split_whitespace().next().unwrap_or_default();
    let slash = cmd.slash_name();
    let alias_kind = slash_alias_kind(raw_head);
    let arg_shape = telemetry_tui_slash_arg_shape(&cmd);
    if let Some(spec) = SLASH_COMMANDS.iter().find(|spec| spec.name == slash)
        && !spec.available_during_task
        && turn_in_progress(app)
    {
        record_slash_command_telemetry(
            agent,
            raw_head,
            surface,
            SlashOutcome::BlockedDuringTurn,
            alias_kind,
            arg_shape,
        );
        app.status = format!("{slash} unavailable during turn");
        return true;
    }

    let rest = input
        .strip_prefix(raw_head)
        .map(str::trim)
        .unwrap_or_default();
    if should_echo_slash_command(raw_head, rest) {
        app.push_slash_command_echo(input);
    }

    record_slash_command_telemetry(
        agent,
        raw_head,
        surface,
        SlashOutcome::Accepted,
        alias_kind,
        arg_shape,
    );
    apply_dispatch_command(app, agent, cmd).await;
    true
}

fn record_slash_command_telemetry(
    agent: &Agent,
    command: &str,
    surface: SlashSurface,
    outcome: SlashOutcome,
    alias_kind: SlashAliasKind,
    arg_shape: SlashArgShape,
) {
    agent.record_slash_command_telemetry(command, surface, outcome, alias_kind, arg_shape);
}

fn slash_alias_kind(raw_head: &str) -> SlashAliasKind {
    match raw_head.trim_start_matches('/') {
        "options" => SlashAliasKind::CompatOptions,
        "" => SlashAliasKind::Unknown,
        _ => SlashAliasKind::Canonical,
    }
}

fn slash_arg_shape_from_rest(input: &str) -> SlashArgShape {
    let Some(head) = input.split_whitespace().next() else {
        return SlashArgShape::None;
    };
    let rest = input.strip_prefix(head).map(str::trim).unwrap_or_default();
    if rest.is_empty() {
        SlashArgShape::None
    } else {
        SlashArgShape::Present
    }
}

fn telemetry_tui_slash_arg_shape(cmd: &DispatchCommand) -> SlashArgShape {
    match cmd {
        DispatchCommand::Cost
        | DispatchCommand::Context
        | DispatchCommand::Reviewer
        | DispatchCommand::Mcp
        | DispatchCommand::Model
        | DispatchCommand::Permissions
        | DispatchCommand::Attachments
        | DispatchCommand::Clear
        | DispatchCommand::Diff
        | DispatchCommand::Tasks
        | DispatchCommand::Pins
        | DispatchCommand::Sessions
        | DispatchCommand::Fork
        | DispatchCommand::Checkpoints
        | DispatchCommand::Undo
        | DispatchCommand::Statusline
        | DispatchCommand::Keymap
        | DispatchCommand::Cheap
        | DispatchCommand::Parent
        | DispatchCommand::Terminal => SlashArgShape::None,
        DispatchCommand::CheckpointsDoctor => SlashArgShape::FixedSubcommand,
        DispatchCommand::Attach { .. } => SlashArgShape::Path,
        DispatchCommand::Plan { prompt } | DispatchCommand::Build { prompt } => {
            slash_option_shape(prompt.as_ref(), SlashArgShape::FreeText)
        }
        DispatchCommand::Help { topic } => {
            slash_option_shape(topic.as_ref(), SlashArgShape::FreeText)
        }
        DispatchCommand::Theme { theme } => {
            slash_option_shape(theme.as_ref(), SlashArgShape::FixedSubcommand)
        }
        DispatchCommand::Effort { value }
        | DispatchCommand::ToolVerbosity { value }
        | DispatchCommand::Router { value } => {
            slash_option_shape(value.as_ref(), SlashArgShape::FixedSubcommand)
        }
        DispatchCommand::Config { section } => {
            slash_option_shape(section.as_ref(), SlashArgShape::FixedSubcommand)
        }
        DispatchCommand::Compact { subcommand } => match subcommand {
            CompactSubcommand::Undo | CompactSubcommand::History => SlashArgShape::FixedSubcommand,
            CompactSubcommand::Run => SlashArgShape::None,
        },
        DispatchCommand::Plans { args }
        | DispatchCommand::Feedback { args }
        | DispatchCommand::Report { args } => {
            if args.trim().is_empty() {
                SlashArgShape::None
            } else {
                SlashArgShape::FixedSubcommand
            }
        }
        DispatchCommand::Task { .. }
        | DispatchCommand::TaskCancel { .. }
        | DispatchCommand::Unpin { .. }
        | DispatchCommand::Resume { .. }
        | DispatchCommand::SessionExport { .. }
        | DispatchCommand::Checkpoint { .. }
        | DispatchCommand::RevertTurn { .. }
        | DispatchCommand::Detach { .. } => SlashArgShape::Id,
        DispatchCommand::Pin { target } => {
            if target.is_some() {
                SlashArgShape::Id
            } else {
                SlashArgShape::None
            }
        }
        DispatchCommand::Session { .. }
        | DispatchCommand::SessionRename { .. }
        | DispatchCommand::SessionLabel { .. } => SlashArgShape::FixedSubcommand,
        DispatchCommand::SessionExportHtml { path, .. } => {
            if path.is_some() {
                SlashArgShape::Path
            } else {
                SlashArgShape::Id
            }
        }
    }
}

fn slash_option_shape(value: Option<&String>, present: SlashArgShape) -> SlashArgShape {
    if value.map(|value| !value.trim().is_empty()).unwrap_or(false) {
        present
    } else {
        SlashArgShape::None
    }
}

fn set_status_notice(app: &mut TuiApp, message: impl Into<String>) {
    let message = message.into();
    app.status = message.clone();
    app.push_transcript_item(TranscriptItem::system(message));
}

fn set_status_with_notice(app: &mut TuiApp, status: impl Into<String>, notice: impl Into<String>) {
    app.status = status.into();
    app.push_transcript_item(TranscriptItem::system(notice.into()));
}

async fn handle_inline_slash_command(app: &mut TuiApp, agent: &mut Agent, input: &str) -> bool {
    let Some(occurrence) = input::find_inline_slash_dispatch_command(input) else {
        return false;
    };
    let slash = occurrence.command.name;
    if !occurrence.command.available_during_task && turn_in_progress(app) {
        let arg_shape = match slash {
            "/attach" => SlashArgShape::Path,
            "/help" | "/plan" | "/build" => SlashArgShape::FreeText,
            _ => SlashArgShape::Present,
        };
        record_slash_command_telemetry(
            agent,
            slash,
            SlashSurface::TuiInline,
            SlashOutcome::BlockedDuringTurn,
            SlashAliasKind::Canonical,
            arg_shape,
        );
        app.status = format!("{slash} unavailable during turn");
        return true;
    }
    match slash {
        "/attach" => {
            handle_inline_attach_command(app, agent, input, occurrence.start, occurrence.end)
        }
        "/help" | "/plan" | "/build" => {
            let command_input =
                inline_prompt_command_input(input, occurrence.start, occurrence.end, slash);
            let before_command_input = app.input.clone();
            if handle_slash_command_on_surface(app, agent, &command_input, SlashSurface::TuiInline)
                .await
            {
                let preserve_input =
                    app.preserve_input_after_slash_command || app.input != before_command_input;
                app.preserve_input_after_slash_command = false;
                if !preserve_input {
                    clear_input(app);
                }
                app.input_history_index = None;
                app.input_history_draft.clear();
                app.slash_menu_index = 0;
                return true;
            }
            false
        }
        _ => false,
    }
}

fn inline_prompt_command_input(input: &str, start: usize, end: usize, slash: &str) -> String {
    let before = input[..start].trim();
    let after = input[end..].trim();
    let prompt = if slash == "/help" {
        after.to_string()
    } else {
        [before, after]
            .into_iter()
            .filter(|part| !part.is_empty())
            .collect::<Vec<_>>()
            .join(" ")
    };
    if prompt.is_empty() {
        slash.to_string()
    } else {
        format!("{slash} {prompt}")
    }
}

fn handle_inline_attach_command(
    app: &mut TuiApp,
    agent: &Agent,
    input: &str,
    command_start: usize,
    command_end: usize,
) -> bool {
    let Some((path, path_end)) = inline_attach_path(input, command_end) else {
        record_slash_command_telemetry(
            agent,
            "/attach",
            SlashSurface::TuiInline,
            SlashOutcome::UsageError,
            SlashAliasKind::Canonical,
            SlashArgShape::Path,
        );
        set_status_notice(app, "usage: /attach <path>");
        return true;
    };
    let original_input = app.input.clone();
    let original_cursor = app.input_cursor;
    app.input.replace_range(command_start..path_end, "");
    app.input_cursor = command_start;
    match insert_file_prompt_attachment(app, &path) {
        Ok(status) => {
            record_slash_command_telemetry(
                agent,
                "/attach",
                SlashSurface::TuiInline,
                SlashOutcome::Accepted,
                SlashAliasKind::Canonical,
                SlashArgShape::Path,
            );
            app.status = status;
        }
        Err(error) => {
            record_slash_command_telemetry(
                agent,
                "/attach",
                SlashSurface::TuiInline,
                SlashOutcome::Error,
                SlashAliasKind::Canonical,
                SlashArgShape::Path,
            );
            app.input = original_input;
            app.input_cursor = original_cursor;
            app.preserve_input_after_slash_command = true;
            app.status = format!("attach failed: {error}");
        }
    }
    true
}

fn inline_attach_path(input: &str, command_end: usize) -> Option<(String, usize)> {
    let (relative_start, first) = input[command_end..]
        .char_indices()
        .find(|(_, ch)| !ch.is_whitespace())?;
    let path_start = command_end + relative_start;
    if first == '"' || first == '\'' {
        let value_start = path_start + first.len_utf8();
        let close = input[value_start..]
            .char_indices()
            .find(|(_, ch)| *ch == first)
            .map(|(index, _)| value_start + index)?;
        let path = input[value_start..close].to_string();
        let path_end = close + first.len_utf8();
        return (!path.is_empty()).then_some((path, path_end));
    }
    let path_end = input[path_start..]
        .char_indices()
        .find(|(_, ch)| ch.is_whitespace())
        .map(|(index, _)| path_start + index)
        .unwrap_or(input.len());
    let path = input[path_start..path_end].to_string();
    (!path.is_empty()).then_some((path, path_end))
}

/// Attempt to resolve an unknown `/foo …` head against the user-
/// authored prompt-template catalog. On a hit the rendered body is
/// routed through the normal user-turn flow (echo + history + queue
/// or start) so the model sees the expanded prompt; on a miss this
/// returns `false` so the legacy "unknown command" path runs and the
/// input becomes a regular user prompt.
///
/// Templates take precedence only over the *unknown* slot — built-in
/// `DispatchCommand` heads (e.g. `/help`, `/diff`) cannot be shadowed
/// by a same-named template file so muscle memory keeps working.
fn expand_prompt_template_or_fallthrough(
    app: &mut TuiApp,
    agent: &mut Agent,
    input: &str,
    _surface: SlashSurface,
) -> bool {
    let Some((expanded, source, arg_count)) = app.prompt_templates.expand_with_info(input) else {
        return false;
    };
    app.push_slash_command_echo(input);
    let queued = app.turn_rx.is_some();
    // Fire prompt-template telemetry: source, arg-count bucket, and
    // queued-vs-started outcome.
    agent.record_prompt_template_telemetry(source.as_str(), arg_count, queued);
    if queued {
        app.prompt_queue.push_back(expanded);
        enqueue_queue_id(app);
        app.status = format!("queued ({})", app.prompt_queue.len());
        return true;
    }
    app.cancelled_prompt = Some(expanded.clone());
    push_input_history(app, expanded.clone());
    start_user_turn(app, agent, expanded);
    true
}

/// Run the typed slash-command on the TUI. The parsing is done by
/// [`DispatchCommand::parse`] in [`handle_slash_command`]; this
/// function only routes to the existing helpers that own the TUI
/// state. Agent-only dispatch lives on [`Agent::dispatch_command`] and
/// is invoked by non-TUI drivers (eval, RPC).
async fn apply_dispatch_command(app: &mut TuiApp, agent: &mut Agent, cmd: DispatchCommand) {
    match cmd {
        DispatchCommand::Config { section } => {
            let slug = section.as_deref();
            let id = slug.and_then(squeezy_core::config_schema::section_from_slug);
            // `/config <slug>` used to silently fall back to the Models
            // section when the slug was a valid `SectionId` variant that
            // had no `ConfigSectionMeta` entry (Skills, Tools, Providers,
            // Context, McpServers, ShellSandbox, PermissionRules) or was
            // simply unrecognised. Make the fallback explicit so the user
            // knows their argument was ignored.
            if let Some(raw) = slug
                && !raw.is_empty()
                && id.is_none()
            {
                app.push_warn(format!(
                    "/config: '{raw}' is not a navigable section — opening the default view. \
                     Press / to search field labels."
                ));
            }
            toggle_config_screen(app, agent, id);
        }
        DispatchCommand::Mcp => {
            toggle_config_screen(
                app,
                agent,
                Some(squeezy_core::config_schema::SectionId::McpServers),
            );
        }
        DispatchCommand::Statusline => toggle_status_line_setup(app),
        DispatchCommand::Plan { prompt } => {
            switch_mode(app, agent, Some(SessionMode::Plan), "tui_command");
            if let Some(prompt) = prompt {
                app.cancelled_prompt = Some(prompt.clone());
                clear_input(app);
                push_input_history(app, prompt.clone());
                start_user_turn(app, agent, prompt);
            }
        }
        DispatchCommand::Build { prompt } => {
            switch_mode(app, agent, Some(SessionMode::Build), "tui_command");
            if let Some(prompt) = prompt {
                app.cancelled_prompt = Some(prompt.clone());
                clear_input(app);
                push_input_history(app, prompt.clone());
                start_user_turn(app, agent, prompt);
            }
        }
        DispatchCommand::Plans { args } => handle_plans_command(app, &args),
        DispatchCommand::Cost => {
            let snapshot = agent.session_accounting_snapshot().await;
            app.apply_status_context_snapshot(&snapshot);
            app.status = "cost snapshot".to_string();
            app.push_transcript_item(TranscriptItem::system(commands::format_cost_command(
                &snapshot,
            )));
        }
        DispatchCommand::Context => {
            let snapshot = agent.session_accounting_snapshot().await;
            app.apply_status_context_snapshot(&snapshot);
            app.status = "context snapshot".to_string();
            app.push_transcript_item(TranscriptItem::system(commands::format_context_command(
                &snapshot,
            )));
        }
        DispatchCommand::Reviewer => {
            let entries = agent.reviewer_audit_snapshot();
            if entries.is_empty() {
                app.status = "no AI reviewer decisions recorded yet".to_string();
            } else {
                app.status = format!("{} AI reviewer decision(s)", entries.len());
            }
            app.push_transcript_item(TranscriptItem::system(commands::format_reviewer_command(
                &entries,
                std::time::SystemTime::now(),
            )));
        }
        DispatchCommand::Help { topic } => {
            handle_help_command(app, agent, topic.as_deref().unwrap_or(""));
        }
        DispatchCommand::Model => {
            toggle_config_screen(
                app,
                agent,
                Some(squeezy_core::config_schema::SectionId::Models),
            );
        }
        DispatchCommand::Permissions => {
            toggle_config_screen(
                app,
                agent,
                Some(squeezy_core::config_schema::SectionId::Permissions),
            );
        }
        DispatchCommand::Feedback { args } => {
            handle_feedback_command(app, agent, &args).await;
        }
        DispatchCommand::Report { args } => {
            handle_report_command(app, agent, &args).await;
        }
        DispatchCommand::Attach { path } => {
            let original_input = app.input.clone();
            let original_cursor = app.input_cursor;
            clear_input(app);
            match insert_file_prompt_attachment(app, &path) {
                Ok(status) => app.status = status,
                Err(error) => {
                    app.input = original_input;
                    app.input_cursor = original_cursor;
                    app.preserve_input_after_slash_command = true;
                    app.status = format!("attach failed: {error}");
                }
            }
        }
        DispatchCommand::Attachments => {
            app.attachments = agent.context_attachments_snapshot().await;
            if app.attachments.is_empty() {
                set_status_with_notice(
                    app,
                    "no attached context",
                    "No attached context yet. Use `/attach <path>` to add a file or directory token to your next prompt.",
                );
            } else {
                app.status = format!("{} attached context item(s)", app.attachments.len());
                app.push_transcript_item(TranscriptItem::system(format_attachment_list(
                    &app.attachments,
                )));
            }
        }
        DispatchCommand::Detach { id } => match agent.detach_context_attachment(&id).await {
            Ok(attachment) => {
                app.attachments = agent.context_attachments_snapshot().await;
                app.status = format!("detached {}", attachment.id);
                app.push_log(format!("detached context attachment {}", attachment.id));
            }
            Err(error) => {
                set_status_with_notice(
                    app,
                    format!("detach failed: {error}"),
                    format!(
                        "Detach failed: {error}\nRun `/attachments` to see current attachment ids."
                    ),
                );
            }
        },
        DispatchCommand::Compact { subcommand } => {
            if matches!(subcommand, CompactSubcommand::History) {
                app.context_compaction = agent.context_compaction_snapshot().await;
                let compaction = &app.context_compaction;
                if compaction.history.is_empty() {
                    set_status_with_notice(
                        app,
                        "no compaction history",
                        "No compaction events recorded for this session yet.",
                    );
                } else {
                    app.status = format!(
                        "compaction history: {} generation(s)",
                        compaction.history.len()
                    );
                    let lines: Vec<String> = compaction
                        .history
                        .iter()
                        .map(|record| {
                            let undo_mark = if record.replacement_id.is_some() {
                                " [undoable]"
                            } else {
                                ""
                            };
                            format!(
                                "gen={} trigger={} {before}→{after} tok dropped={dropped}{undo_mark}",
                                record.generation,
                                record.trigger.as_str(),
                                before = record.before.estimated_tokens,
                                after = record.after.estimated_tokens,
                                dropped = record.dropped_items,
                            )
                        })
                        .collect();
                    app.push_transcript_item(TranscriptItem::system(format!(
                        "Compaction history ({} generation(s)):\n{}",
                        compaction.history.len(),
                        lines.join("\n"),
                    )));
                }
            } else if matches!(subcommand, CompactSubcommand::Undo) {
                match agent.compact_context_undo().await {
                    Ok(Some(record)) => {
                        app.context_compaction = agent.context_compaction_snapshot().await;
                        app.context_estimate = agent.context_estimate_snapshot().await;
                        app.clear_status_context_request_tokens();
                        app.status = format!(
                            "undid compaction gen={} ({} item(s) restored)",
                            record.generation, record.dropped_items,
                        );
                        app.push_log(format!(
                            "context compaction undone gen={} items={}",
                            record.generation, record.dropped_items,
                        ));
                    }
                    Ok(None) => {
                        set_status_with_notice(
                            app,
                            "no compaction checkpoint to undo",
                            "No context compaction checkpoint is available to undo.",
                        );
                    }
                    Err(error) => {
                        set_status_notice(app, format!("compact undo failed: {error}"));
                    }
                }
            } else {
                match agent.compact_context_manual().await {
                    Ok(Some(report)) => {
                        app.context_compaction = agent.context_compaction_snapshot().await;
                        app.context_estimate = report.record.after.clone();
                        app.clear_status_context_request_tokens();
                        app.status = compaction_status_line(&report.record);
                        app.push_log(format!(
                            "context compacted gen={} items={} tok {}->{}",
                            report.record.generation,
                            report.record.dropped_items,
                            report.record.before.estimated_tokens,
                            report.record.after.estimated_tokens
                        ));
                        let undo_hint = if report.record.replacement_id.is_some() {
                            " Run `/compact undo` to restore."
                        } else {
                            ""
                        };
                        app.push_transcript_item(TranscriptItem::system(format!(
                            "/compact discarded {dropped} item(s); context {before}→{after} tokens.{undo_hint}",
                            dropped = report.record.dropped_items,
                            before = report.record.before.estimated_tokens,
                            after = report.record.after.estimated_tokens,
                        )));
                    }
                    Ok(None) => {
                        set_status_with_notice(
                            app,
                            "nothing to compact yet",
                            "Nothing to compact yet; the current context is still below the compaction threshold.",
                        );
                    }
                    Err(error) => {
                        set_status_notice(app, format!("compact failed: {error}"));
                    }
                }
            }
        }
        DispatchCommand::Pins => {
            app.context_compaction = agent.context_compaction_snapshot().await;
            if app.context_compaction.pinned.is_empty() {
                set_status_with_notice(
                    app,
                    "no pinned context",
                    "No pinned context yet. Run `/pin` to pick a transcript item (or `/pin last`) to keep it through compaction.",
                );
            } else {
                app.status = format!(
                    "{} pinned context item(s)",
                    app.context_compaction.pinned.len()
                );
                app.push_transcript_item(TranscriptItem::system(format_pin_list(
                    &app.context_compaction,
                )));
            }
        }
        DispatchCommand::Pin { target } => match target.as_deref() {
            // Bare `/pin` (or the legacy `selected`) opens the picker so the
            // user can choose which transcript item to pin; `/pin last` keeps
            // the no-prompt shortcut for the most recent item.
            None | Some("selected") => open_pin_picker(app),
            Some("last") => match pin_source(app, "last") {
                PinSourceResult::Found(label, summary, source) => {
                    match agent.pin_context_entry(label, summary, source).await {
                        Ok(pin) => {
                            app.context_compaction = agent.context_compaction_snapshot().await;
                            app.status = format!("pinned {}", pin.id);
                            app.push_log(format!("pinned context {}", pin.id));
                        }
                        Err(error) => {
                            set_status_notice(app, format!("pin failed: {error}"));
                        }
                    }
                }
                PinSourceResult::NoEntry => {
                    set_status_with_notice(
                        app,
                        "no transcript entry to pin",
                        "Nothing in the transcript to pin yet.",
                    );
                }
                PinSourceResult::UnknownTarget => {
                    set_status_notice(app, "usage: /pin (opens a picker) · /pin last");
                }
            },
            Some(_) => {
                set_status_notice(app, "usage: /pin (opens a picker) · /pin last");
            }
        },
        DispatchCommand::Unpin { id } => match agent.unpin_context_entry(&id).await {
            Ok(pin) => {
                app.context_compaction = agent.context_compaction_snapshot().await;
                app.status = format!("unpinned {}", pin.id);
                app.push_log(format!("unpinned context {}", pin.id));
            }
            Err(error) => {
                set_status_with_notice(
                    app,
                    format!("unpin failed: {error}"),
                    format!("Unpin failed: {error}\nRun `/pins` to see current pin ids."),
                );
            }
        },
        DispatchCommand::Diff => handle_slash_diff(app),
        DispatchCommand::Cheap => {
            agent.request_routing_force_cheap();
            let cheap = agent.cheap_model();
            let provider = agent.provider_name();
            let raw_parent = agent.config().model.as_str();
            let parent_model =
                squeezy_core::resolve_model_alias(provider, raw_parent).unwrap_or(raw_parent);
            const FALLBACK_NOTE_SUFFIX: &str = "the next turn will fall back to the parent model.";
            let note = match cheap.as_deref() {
                Some(c) if c == parent_model => format!(
                    "\nNote: the cheap model resolves to the same model as the parent; \
                     {FALLBACK_NOTE_SUFFIX}"
                ),
                None => format!(
                    "\nNote: no distinct cheap model is configured for this provider; \
                     {FALLBACK_NOTE_SUFFIX}"
                ),
                Some(_) => String::new(),
            };
            app.push_transcript_item(TranscriptItem::system(format!(
                "next turn forced to the cheap model (one-shot){note}"
            )));
            app.status = "routing: forced cheap next turn".to_string();
        }
        DispatchCommand::Parent => {
            agent.request_routing_force_parent();
            app.push_transcript_item(TranscriptItem::system(
                "next turn forced to the parent model (one-shot)".to_string(),
            ));
            app.status = "routing: forced parent next turn".to_string();
        }
        DispatchCommand::Router { value } => handle_slash_router(app, agent, value.as_deref()),
        DispatchCommand::Effort { value } => handle_slash_effort(app, agent, value.as_deref()),
        DispatchCommand::ToolVerbosity { value } => {
            handle_slash_tool_verbosity(app, agent, value.as_deref());
        }
        DispatchCommand::Theme { theme: None } => {
            toggle_config_screen(
                app,
                agent,
                Some(squeezy_core::config_schema::SectionId::Themes),
            );
        }
        DispatchCommand::Theme { theme: Some(theme) } => {
            let Some(parsed) = squeezy_core::normalize_tui_theme_name(&theme) else {
                set_status_with_notice(
                    app,
                    format!("unknown theme {theme:?}; expected a theme slug"),
                    format!(
                        "Unknown theme {theme:?}. Run `/theme` to open theme settings, or use one of: {}.",
                        render::theme::available_theme_names(&agent.config_snapshot()).join(", ")
                    ),
                );
                return;
            };
            if !render::theme::theme_exists(&agent.config_snapshot(), &parsed) {
                let available =
                    render::theme::available_theme_names(&agent.config_snapshot()).join(", ");
                set_status_with_notice(
                    app,
                    format!("unknown theme {theme:?}; available: {available}"),
                    format!("Unknown theme {theme:?}. Available themes: {available}."),
                );
                return;
            }
            apply_theme_change(app, agent, parsed);
        }
        DispatchCommand::Keymap => {
            let body = keymap::format_keymap_command(&app.keymap);
            let overrides = keymap::Action::ALL
                .iter()
                .copied()
                .filter(|a| app.keymap.binding(*a) != a.default_binding())
                .count();
            app.status = if overrides == 0 {
                "keymap (defaults)".to_string()
            } else {
                format!("keymap ({overrides} override(s))")
            };
            app.push_transcript_item(TranscriptItem::system(body));
        }
        DispatchCommand::Terminal => {
            let sync_policy = agent.config().tui.synchronized_output;
            let body = build_terminal_diagnostic(app, sync_policy);
            app.status = "terminal diagnostics".to_string();
            app.push_transcript_item(TranscriptItem::system(body));
        }
        DispatchCommand::Tasks => {
            sync_jobs_from_agent(app, agent);
            let body = format_tasks_list(app, agent);
            app.status = if app.jobs.is_empty() {
                "no background tasks".to_string()
            } else {
                format!("{} tasks", app.jobs.len())
            };
            app.push_transcript_item(TranscriptItem::system(body));
        }
        DispatchCommand::Task { id } => {
            apply_task_detail(app, agent, &id);
        }
        DispatchCommand::TaskCancel { id } => {
            apply_task_cancel(app, agent, &id);
        }
        DispatchCommand::Sessions => match agent.list_sessions(&SessionQuery::default()) {
            Ok(sessions) => {
                app.status = format!("{} sessions", sessions.len());
                let body = if sessions.is_empty() {
                    "No saved sessions found yet.".to_string()
                } else {
                    sessions
                        .into_iter()
                        .take(10)
                        .map(|session| {
                            format!(
                                "{} {} {}",
                                session.session_id,
                                session.status.as_str(),
                                session
                                    .first_user_task
                                    .or(session.latest_summary)
                                    .unwrap_or_default()
                                    .replace('\n', " ")
                            )
                        })
                        .collect::<Vec<_>>()
                        .join("\n")
                };
                app.push_transcript_item(TranscriptItem::system(body));
            }
            Err(error) => set_status_notice(app, format!("session list failed: {error}")),
        },
        DispatchCommand::Session { id } => match agent.show_session(&id) {
            Ok(record) => {
                app.status = format!(
                    "session {}: {} events={} redactions={}",
                    record.metadata.session_id,
                    record.metadata.status.as_str(),
                    record.metadata.event_count,
                    record.metadata.redactions
                );
                app.push_transcript_item(TranscriptItem::system(format!(
                    "{}\nstatus={} started={} branch={} task={}",
                    record.metadata.session_id,
                    record.metadata.status.as_str(),
                    record.metadata.started_at_ms,
                    record.metadata.branch.unwrap_or_else(|| "-".to_string()),
                    record.metadata.first_user_task.unwrap_or_default()
                )));
            }
            Err(error) => {
                set_status_with_notice(
                    app,
                    format!("session show failed: {error}"),
                    format!(
                        "Session lookup failed: {error}\nRun `/sessions` to see recent session ids."
                    ),
                );
            }
        },
        DispatchCommand::SessionRename { name } => {
            let parameter = if name.trim().is_empty() {
                None
            } else {
                Some(name.clone())
            };
            match agent.set_session_display_name(parameter) {
                Ok(metadata) => match metadata.display_name {
                    Some(display) => {
                        app.status = format!("renamed session → {display}");
                        app.push_transcript_item(TranscriptItem::system(format!(
                            "session {} renamed to {display}",
                            metadata.session_id
                        )));
                    }
                    None => {
                        app.status = format!("cleared session name ({})", metadata.session_id);
                        app.push_transcript_item(TranscriptItem::system(format!(
                            "session {} display_name cleared",
                            metadata.session_id
                        )));
                    }
                },
                Err(error) => set_status_notice(app, format!("rename failed: {error}")),
            }
        }
        DispatchCommand::SessionLabel { name } => match agent.add_session_label(name.clone()) {
            Ok((metadata, added)) => {
                let label_list = if metadata.labels.is_empty() {
                    "(none)".to_string()
                } else {
                    metadata.labels.join(", ")
                };
                if added {
                    app.status = format!("labelled session #{name}");
                    app.push_transcript_item(TranscriptItem::system(format!(
                        "session {} labels: {label_list}",
                        metadata.session_id
                    )));
                } else {
                    set_status_notice(app, format!("label #{name} already on session"));
                }
            }
            Err(error) => set_status_notice(app, format!("label failed: {error}")),
        },
        DispatchCommand::Fork => match agent.fork_current().await {
            Ok(new_id) => {
                app.status = format!("forked session → {new_id}");
                app.push_transcript_item(TranscriptItem::system(format!(
                    "/fork started session {new_id}; the original session is saved and \
                     remains resumable via /resume."
                )));
            }
            Err(error) => app.status = format!("fork failed: {error}"),
        },
        DispatchCommand::Clear => match agent.clear_conversation().await {
            Ok(new_session) => {
                // Drop the visible transcript and any in-flight render
                // state so the screen matches the now-empty conversation.
                // `/clear` is refused mid-turn, so the streaming/cancel
                // fields are already idle; clearing them is defensive.
                app.transcript.clear();
                // Re-arm follow-tail so the fresh conversation tracks its live
                // tail rather than inheriting the prior scrolled-up anchor (the
                // system clear-notice push does not re-pin), and cancel any
                // in-flight ease against the now-gone geometry (deep-review #66).
                app.transcript_scroll = scroll::ScrollState::pinned();
                cancel_main_scroll_anim(app);
                app.selected_entry = None;
                app.next_entry_id = 0;
                // Entry ids restart from 0 after a clear, so old marks would
                // point at unrelated new entries — drop them.
                app.jump_marks = jump_marks::JumpMarkStack::new();
                // Reading Position Bookmarks (§12.2.4) are keyed by entry id too,
                // so they would likewise re-anchor to unrelated entries — drop them.
                app.bookmarks = bookmarks::BookmarkStore::new();
                // Entry Annotations (§12.2.5) are keyed by entry id too, so they
                // would likewise re-anchor to unrelated entries — drop them.
                app.annotations = annotations::AnnotationStore::new();
                // Search matches and text selections are anchored by raw painted-
                // row indices, so a full-transcript replacement re-anchors them to
                // unrelated content even more readily than the id-keyed stores
                // above — reset them too (deep-review #74).
                app.search = None;
                app.selection = None;
                app.selection_set = multi_selection::SelectionSet::new();
                app.clear_turn_divider();
                app.render_cache_session = render::cache::next_session_id();
                app.attachments = agent.context_attachments_snapshot().await;
                app.context_compaction = agent.context_compaction_snapshot().await;
                app.context_estimate = agent.context_estimate_snapshot().await;
                app.clear_status_context_request_tokens();
                app.context_compaction_nudge_shown = false;
                app.pending_assistant.clear();
                app.pending_reasoning.clear();
                app.task_state = None;
                app.task_panel_collapsed = false;
                app.turn_rx = None;
                app.cancel = None;
                app.clear_prompt_attachments();
                app.prompt_queue.clear();
                app.prompt_queue_ids.clear();
                app.prompt_queue_undo.clear();
                app.prompt_queue_drag = None;
                app.prompt_queue_overlay = None;
                app.editing_queue_id = None;
                app.prompt_queue_multiselect.clear();
                // The Queue-Groups (§12.3.4) batches are keyed by queue-item ids
                // that are all gone now, so drop them too rather than leave them
                // naming vanished prompts.
                app.prompt_queue_groups = queue_groups::QueueGroups::new();
                // Conditional Queue Items (§12.3.5) are keyed by the same
                // now-gone item ids; drop them so no phantom condition survives a
                // clear.
                app.prompt_queue_conditions = queue_conditions::QueueConditions::new();
                app.auto_drain_queue = false;
                app.transcript_overlay = None;
                app.transcript_overlay_scrollbar_cache.set(None);
                app.transcript_overlay_text_width.set(None);
                app.overlay = None;
                app.overlay_active_id = None;
                app.mention_popup = None;
                app.subagent_pane = SubagentPaneState {
                    next_synthetic_id: app.subagent_pane.next_synthetic_id,
                    ..SubagentPaneState::default()
                };
                app.clear_active_tools();
                app.toasts.clear();
                app.cost = squeezy_core::CostSnapshot::default();
                app.metrics = squeezy_core::TurnMetrics::default();
                let note = match new_session {
                    Some(new_id) => format!(
                        "Conversation cleared. The previous conversation is saved and remains \
                         resumable via /resume; this is now session {new_id}."
                    ),
                    None => "Conversation cleared.".to_string(),
                };
                app.status = "conversation cleared".to_string();
                app.push_transcript_item(TranscriptItem::system(note));
                app.request_terminal_clear();
            }
            Err(error) => app.status = format!("clear failed: {error}"),
        },
        DispatchCommand::Resume { id } => switch_to_session(app, agent, &id).await,
        DispatchCommand::SessionExport { id } => match agent.export_session(&id) {
            Ok(value) => {
                let bytes = serde_json::to_string(&value).map_or(0, |text| text.len());
                app.status = format!("session export {} bytes", bytes);
                app.push_transcript_item(TranscriptItem::system(format!(
                    "Session export for `{id}` is ready ({bytes} bytes)."
                )));
            }
            Err(error) => set_status_notice(app, format!("session export failed: {error}")),
        },
        DispatchCommand::SessionExportHtml { id, path } => {
            let target = path
                .map(PathBuf::from)
                .unwrap_or_else(|| PathBuf::from(format!("squeezy-session-{id}.html")));
            match agent.show_session(&id).and_then(|record| {
                squeezy_agent::export_session_to_html(
                    &record,
                    &squeezy_agent::ExportOpts::default(),
                )
                .map_err(|err| {
                    squeezy_core::SqueezyError::Tool(format!("failed to render html: {err}"))
                })
                .and_then(|html| {
                    std::fs::write(&target, &html).map_err(squeezy_core::SqueezyError::from)?;
                    Ok(html.len())
                })
            }) {
                Ok(len) => {
                    app.status = format!("wrote {} ({} bytes)", target.display(), len);
                    app.push_transcript_item(TranscriptItem::system(format!(
                        "Wrote session export HTML to {} ({} bytes).",
                        target.display(),
                        len
                    )));
                }
                Err(error) => {
                    set_status_notice(app, format!("session export html failed: {error}"))
                }
            }
        }
        DispatchCommand::Checkpoints => {
            start_local_checkpoint_job(app, agent, "checkpoint_list", serde_json::json!({}))
        }
        DispatchCommand::CheckpointsDoctor => {
            start_local_checkpoint_job(app, agent, "checkpoint_doctor", serde_json::json!({}))
        }
        DispatchCommand::Undo => {
            start_local_checkpoint_job(app, agent, "checkpoint_undo", serde_json::json!({}))
        }
        DispatchCommand::Checkpoint { id } => start_local_checkpoint_job(
            app,
            agent,
            "checkpoint_show",
            serde_json::json!({ "checkpoint_id": id }),
        ),
        DispatchCommand::RevertTurn { group_id } => start_local_checkpoint_job(
            app,
            agent,
            "checkpoint_revert",
            serde_json::json!({ "group_id": group_id }),
        ),
    }
}

fn apply_task_detail(app: &mut TuiApp, agent: &Agent, raw_id: &str) {
    let Some(id) = parse_job_id(raw_id) else {
        set_status_notice(app, "task id must be a number");
        return;
    };
    sync_jobs_from_agent(app, agent);
    match app
        .jobs
        .get(&id)
        .cloned()
        .or_else(|| agent.job_snapshot(id))
    {
        Some(job) => {
            app.status = format!("task {} {}", job.id, job.status.as_str());
            app.push_transcript_item(TranscriptItem::system(format_job_detail(&job)));
        }
        None => set_status_with_notice(
            app,
            format!("task {id} not found"),
            format!("Task {id} was not found. Run `/tasks` to list background tasks."),
        ),
    }
}

fn apply_task_cancel(app: &mut TuiApp, agent: &Agent, raw_id: &str) {
    let Some(id) = parse_job_id(raw_id) else {
        set_status_notice(app, "task id must be a number");
        return;
    };
    if agent.cancel_job(id) {
        app.status = format!("cancelling task {id}");
        app.push_log(format!("cancelling task {id}"));
        sync_jobs_from_agent(app, agent);
    } else {
        set_status_with_notice(
            app,
            format!("task {id} not active"),
            format!(
                "Task {id} is not active or does not exist. Run `/tasks` to list background tasks."
            ),
        );
    }
}

fn start_local_checkpoint_job(
    app: &mut TuiApp,
    agent: &Agent,
    name: &'static str,
    arguments: serde_json::Value,
) {
    let job = agent.start_local_tool_job(ToolCall {
        call_id: format!("tui-{name}"),
        name: name.to_string(),
        arguments,
    });
    app.jobs.insert(job.id, job.clone());
    app.status = format!("started job {} {}", job.id, job.title);
    app.push_log(format!("started job {} {}", job.id, job.title));
}

/// Dispatch for `/plans [list|show|delete|set-active|open] [<id>]`.
/// Bare `/plans` (or `/plans list`) renders a table; the other
/// subcommands take an id (or any unique prefix of one). Plan ids are
/// resolved within the active session's plan dir; sibling sessions
/// are intentionally invisible.
fn handle_plans_command(app: &mut TuiApp, rest: &str) {
    let mut parts = rest.split_whitespace();
    let sub = parts.next().unwrap_or("list");
    let arg = parts.next();
    let sid = app.plan_session_id().to_string();
    match sub {
        "list" | "ls" => render_plans_list(app, &sid),
        "show" | "view" | "cat" => {
            if let Some(plan_id) = plans_resolve(app, &sid, arg) {
                plans_show(app, &sid, &plan_id);
            }
        }
        "delete" | "rm" => {
            if let Some(plan_id) = plans_resolve(app, &sid, arg) {
                plans_delete(app, &sid, &plan_id, parts.next());
            }
        }
        "set-active" | "activate" | "use" => {
            if let Some(plan_id) = plans_resolve(app, &sid, arg) {
                plans_set_active(app, &sid, &plan_id);
            }
        }
        "open" | "edit" => {
            if let Some(plan_id) = plans_resolve(app, &sid, arg) {
                plans_open(app, &sid, &plan_id);
            }
        }
        "help" | "?" | "--help" | "-h" => {
            app.status = "plans help".to_string();
            app.push_transcript_item(TranscriptItem::system(plans_usage()));
        }
        other => {
            app.status = format!("unknown /plans subcommand `{other}`");
            app.push_transcript_item(TranscriptItem::system(plans_usage()));
        }
    }
}

fn plans_usage() -> String {
    [
        "usage:",
        "  /plans              — list saved plans in this session",
        "  /plans list",
        "  /plans show <id>    — render a plan body",
        "  /plans delete <id>  — remove a plan (add --yes to skip confirm)",
        "  /plans set-active <id>",
        "  /plans open <id>    — print path for opening in your editor",
    ]
    .join("\n")
}

/// Resolve the user's `<id>` argument to an exact plan id within the
/// session. Sets status/transcript on error and returns `None` so the
/// caller can early-out. On success returns the canonical plan id.
fn plans_resolve(app: &mut TuiApp, sid: &str, raw: Option<&str>) -> Option<String> {
    let Some(needle) = raw else {
        set_status_with_notice(
            app,
            "usage: /plans <subcommand> <id-or-prefix>",
            format!(
                "Missing plan id.\n{}\n\nRun `/plans` to list saved plans in this session.",
                plans_usage()
            ),
        );
        return None;
    };
    match proposed_plan::resolve_plan_prefix(&app.workspace_root, sid, needle) {
        Ok(plan_id) => Some(plan_id),
        Err(proposed_plan::PlanLookupError::NotFound) => {
            let entries = proposed_plan::list_plans(&app.workspace_root, sid);
            let notice = if entries.is_empty() {
                format!(
                    "No plan matches `{needle}` because this session has no saved plans yet.\n\
                     Plans are saved when Plan mode produces a completed `<proposed_plan>` block."
                )
            } else {
                format!(
                    "No plan matches `{needle}` in this session.\nRun `/plans` to list available plan ids."
                )
            };
            set_status_with_notice(
                app,
                format!("no plan matches `{needle}` in this session"),
                notice,
            );
            None
        }
        Err(proposed_plan::PlanLookupError::Ambiguous(matches)) => {
            app.status = format!("`{needle}` is ambiguous ({} matches)", matches.len());
            let body = format!(
                "Multiple plans match `{needle}`. Disambiguate by re-running with a longer prefix:\n{}",
                matches
                    .iter()
                    .map(|id| format!("  {id}"))
                    .collect::<Vec<_>>()
                    .join("\n")
            );
            app.push_transcript_item(TranscriptItem::system(body));
            None
        }
    }
}

fn render_plans_list(app: &mut TuiApp, sid: &str) {
    let entries = proposed_plan::list_plans(&app.workspace_root, sid);
    if entries.is_empty() {
        set_status_with_notice(
            app,
            "no plans persisted in this session",
            "No plans saved in this session yet.\nPlans are saved when Plan mode produces a completed `<proposed_plan>` block.",
        );
        return;
    }
    app.status = format!("{} plan(s) in this session", entries.len());
    let now = std::time::SystemTime::now();
    let mut lines = Vec::with_capacity(entries.len() + 1);
    lines.push("  ACTIVE  ID                    AGE       OBJECTIVE".to_string());
    for entry in &entries {
        let age = format_age_short(now, entry.modified);
        let marker = if entry.is_active {
            "  *     "
        } else {
            "        "
        };
        let objective = truncate_for_display(&entry.objective, 60);
        lines.push(format!(
            "{marker}{id:<22} {age:<9} {objective}",
            id = entry.plan_id,
            age = age,
            objective = objective,
        ));
    }
    app.push_transcript_item(TranscriptItem::system(lines.join("\n")));
}

/// Render a short relative-age string (`12s`, `4m`, `3h`, `5d`) for
/// `/plans list`. Anything older than 99 days collapses to `>99d`.
fn format_age_short(now: std::time::SystemTime, when: std::time::SystemTime) -> String {
    let elapsed = now.duration_since(when).unwrap_or_default();
    let secs = elapsed.as_secs();
    if secs < 60 {
        format!("{secs}s")
    } else if secs < 3600 {
        format!("{}m", secs / 60)
    } else if secs < 86_400 {
        format!("{}h", secs / 3600)
    } else if secs < 86_400 * 100 {
        format!("{}d", secs / 86_400)
    } else {
        ">99d".to_string()
    }
}

/// Trim `s` to at most `max_chars` codepoints, appending `…` when
/// truncation actually happens. Empty input is rendered as `-`.
fn truncate_for_display(s: &str, max_chars: usize) -> String {
    if s.is_empty() {
        return "-".to_string();
    }
    let mut iter = s.chars();
    let head: String = (&mut iter).take(max_chars).collect();
    if iter.next().is_some() {
        format!("{head}…")
    } else {
        head
    }
}

fn plans_show(app: &mut TuiApp, sid: &str, plan_id: &str) {
    let path = proposed_plan::plan_file_for(&app.workspace_root, sid, plan_id);
    match proposed_plan::read_plan_body(&path) {
        Ok(body) => {
            app.status = format!("plan {plan_id}");
            let header = format!("# Plan {plan_id}\n{}", compact_path(&path));
            app.push_transcript_item(TranscriptItem::system(format!(
                "{header}\n\n{}",
                body.trim_end()
            )));
        }
        Err(err) => set_status_notice(app, format!("plans show failed: {err}")),
    }
}

fn plans_delete(app: &mut TuiApp, sid: &str, plan_id: &str, flag: Option<&str>) {
    // Confirmation gate: destructive ops require an explicit `--yes`
    // (or `-y`). The user can re-run the same command after seeing the
    // prompt without losing context.
    let confirmed = matches!(flag, Some("--yes") | Some("-y") | Some("yes"));
    if !confirmed {
        app.status = format!("re-run with --yes to delete {plan_id}");
        app.push_transcript_item(TranscriptItem::system(format!(
            "/plans delete is destructive. Re-run as `/plans delete {plan_id} --yes` to confirm."
        )));
        return;
    }
    match proposed_plan::delete_plan(&app.workspace_root, sid, plan_id) {
        Ok(path) => {
            // Clear the in-memory active plan id if this was it; the
            // pointer file has already been cleaned by `delete_plan`.
            if app.current_plan_id.as_deref() == Some(plan_id) {
                app.current_plan_id = None;
                app.pending_plan_handoff = None;
                app.plan_handoff_turns_seen = 0;
            }
            app.status = format!("deleted plan {plan_id}");
            app.push_log(format!("plan {plan_id} deleted ({})", compact_path(&path)));
        }
        Err(err) => set_status_notice(app, format!("plans delete failed: {err}")),
    }
}

fn plans_set_active(app: &mut TuiApp, sid: &str, plan_id: &str) {
    match proposed_plan::set_active_plan(&app.workspace_root, sid, plan_id) {
        Ok(()) => {
            app.current_plan_id = Some(plan_id.to_string());
            app.status = format!("active plan → {plan_id}");
            app.push_log(format!("set active plan: {plan_id}"));
        }
        Err(err) => set_status_notice(app, format!("plans set-active failed: {err}")),
    }
}

fn plans_open(app: &mut TuiApp, sid: &str, plan_id: &str) {
    // The TUI owns the terminal in alternate-screen mode, so launching
    // a foreground editor (vi/nano) inline would scramble the display.
    // PR-E scope keeps this surface simple: print the path and the
    // recommended editor command so the user can run it from another
    // shell. The terminal-suspend integration is a follow-up.
    let path = proposed_plan::plan_file_for(&app.workspace_root, sid, plan_id);
    let editor = std::env::var("VISUAL")
        .ok()
        .or_else(|| std::env::var("EDITOR").ok())
        .filter(|s| !s.trim().is_empty())
        .unwrap_or_else(|| {
            if cfg!(windows) {
                "notepad".to_string()
            } else {
                "vi".to_string()
            }
        });
    app.status = format!("plan {plan_id} path printed");
    app.push_transcript_item(TranscriptItem::system(format!(
        "plan {plan_id}\nfile: {}\nopen with: {editor} {}",
        compact_path(&path),
        path.display()
    )));
}

fn handle_help_command(app: &mut TuiApp, agent: &mut Agent, rest: &str) {
    let prompt = if rest.trim().is_empty() {
        "/help".to_string()
    } else {
        format!("/help {}", rest.trim())
    };
    // Attempt to answer locally from the bundled skills knowledge base before
    // sending the turn to the model. Pass the redacted config inspect so the
    // local answer can include relevant config sections, matching the quality
    // of the agent-level `resolve_help_turn` path.
    //
    // `answer_for_input` always returns `Some` for `/help`-prefixed input
    // (parse_help_command always matches). A `None` result or `Unsupported`
    // status means the topic isn't covered locally; both fall through to the
    // model turn so the agent's doc-help subagent can handle broader questions.
    let config_inspect = agent.config_snapshot().inspect_redacted();
    let help = SqueezyHelp::new(config_inspect);
    if let Some(answer) = help.answer_for_input(&prompt)
        && answer.status == HelpStatus::Answered
    {
        app.push_transcript_item(TranscriptItem::system(answer.render_markdown()));
        app.status = format!("help: {}", answer.topic);
        return;
    }
    // Topic not covered locally — fall back to a model turn (network).
    start_user_turn(app, agent, prompt);
}

async fn handle_feedback_command(app: &mut TuiApp, agent: &Agent, rest: &str) {
    match rest {
        "send" => {
            submit_pending_feedback(app, agent).await;
        }
        "cancel" => {
            discard_pending_feedback(app);
        }
        "" => {
            set_status_with_notice(
                app,
                "usage: /feedback <what happened>",
                "Usage: `/feedback <what happened>` previews maintainer feedback before sending.",
            );
        }
        message => match agent.prepare_feedback(message) {
            Ok(feedback) => {
                let preview = format!(
                    "feedback preview\nfeedback_id={}\nbytes={} redactions={}\n\n{}\n\nPress Enter to send or Esc to discard.",
                    feedback.feedback_id,
                    feedback.message_bytes,
                    feedback.redactions,
                    feedback.message
                );
                app.pending_feedback = Some(feedback);
                app.status = "feedback ready: Enter send · Esc discard".to_string();
                app.push_transcript_item(TranscriptItem::system(preview));
            }
            Err(error) => set_status_notice(app, format!("feedback preview failed: {error}")),
        },
    }
}

async fn submit_pending_feedback(app: &mut TuiApp, agent: &Agent) {
    let Some(feedback) = app.pending_feedback.take() else {
        set_status_with_notice(
            app,
            "no feedback pending",
            "No feedback preview is pending. Run `/feedback <what happened>` first.",
        );
        return;
    };
    match agent.submit_feedback(&feedback).await {
        Ok(result) => {
            app.status = format!("feedback sent {}", result.id);
            app.push_transcript_item(TranscriptItem::system(format!(
                "feedback sent\nfeedback_id={}",
                result.id
            )));
        }
        Err(error) => {
            app.pending_feedback = Some(feedback);
            set_status_notice(app, format!("feedback send failed: {error}"));
        }
    }
}

fn discard_pending_feedback(app: &mut TuiApp) {
    app.pending_feedback = None;
    app.status = "feedback discarded".to_string();
}

async fn handle_report_command(app: &mut TuiApp, agent: &Agent, rest: &str) {
    match rest {
        "send" => {
            let Some(report) = app.pending_report.take() else {
                set_status_with_notice(
                    app,
                    "no report pending",
                    "No bug report preview is pending. Run `/report` first.",
                );
                return;
            };
            match agent.submit_bug_report(&report).await {
                Ok(result) => {
                    app.status = format!("report sent {}", result.id);
                    app.push_transcript_item(TranscriptItem::system(format!(
                        "report sent\nreport_id={}",
                        result.id
                    )));
                }
                Err(error) => {
                    app.pending_report = Some(report);
                    set_status_notice(app, format!("report send failed: {error}"));
                }
            }
        }
        "cancel" => {
            app.pending_report = None;
            app.status = "report cancelled".to_string();
        }
        _ => {
            let (session_id, excluded_sections) =
                match commands::parse_report_preview_args(agent, rest) {
                    Ok(value) => value,
                    Err(error) => {
                        set_status_notice(app, error);
                        return;
                    }
                };
            let options = BugReportOptions {
                excluded_sections,
                ..BugReportOptions::default()
            };
            match agent.build_bug_report(&session_id, options) {
                Ok(report) => {
                    let mut preview = report.preview_text();
                    preview.push_str("\nRun /report send to upload or /report cancel.");
                    app.pending_report = Some(report);
                    app.status = "report preview ready".to_string();
                    app.push_transcript_item(TranscriptItem::system(preview));
                }
                Err(error) => set_status_notice(app, format!("report preview failed: {error}")),
            }
        }
    }
}

fn format_attachment_list(attachments: &[ContextAttachment]) -> String {
    if attachments.is_empty() {
        return "No attached context.".to_string();
    }
    attachments
        .iter()
        .map(format_attachment_line)
        .collect::<Vec<_>>()
        .join("\n")
}

fn format_attachment_line(attachment: &ContextAttachment) -> String {
    let preview = attachment.preview.replace('\n', " ");
    let preview = preview.chars().take(80).collect::<String>();
    format!(
        "{} {} {} {}B {}",
        attachment.id,
        attachment.source.as_str(),
        attachment.kind.as_str(),
        attachment.original_bytes,
        preview
    )
}

fn format_pin_list(context: &ContextCompactionState) -> String {
    if context.pinned.is_empty() {
        return "No pinned context.".to_string();
    }
    context
        .pinned
        .iter()
        .map(|pin| {
            format!(
                "{} {} {}",
                pin.id,
                pin.label,
                compact_text(&pin.summary, 120)
            )
        })
        .collect::<Vec<_>>()
        .join("\n")
}

pub(crate) fn compaction_status_line(record: &ContextCompactionRecord) -> String {
    format!(
        "compacted context {}->{} tok",
        record.before.estimated_tokens, record.after.estimated_tokens
    )
}

enum PinSourceResult {
    Found(String, String, String),
    NoEntry,
    UnknownTarget,
}

fn pin_source(app: &TuiApp, target: &str) -> PinSourceResult {
    let entry = match target {
        "selected" => app
            .selected_entry
            .and_then(|index| app.transcript.get(index))
            .or_else(|| last_pinnable_entry(app)),
        "last" => last_pinnable_entry(app),
        _ => return PinSourceResult::UnknownTarget,
    };
    match entry {
        Some(entry) => {
            let (label, summary, source) = entry.pin_payload();
            PinSourceResult::Found(label, summary, source)
        }
        None => PinSourceResult::NoEntry,
    }
}

fn last_pinnable_entry(app: &TuiApp) -> Option<&TranscriptEntry> {
    app.transcript
        .iter()
        .rev()
        .find(|entry| !matches!(entry.kind, TranscriptEntryKind::SlashEcho(_)))
}

/// Open the `/pin` picker on the last pinnable transcript entry. While open,
/// `handle_pin_picker_key` owns the keyboard (↑/↓ move, Enter pins, Esc
/// cancels), so the candidate survives until the user commits it.
fn open_pin_picker(app: &mut TuiApp) {
    let Some(start) = app
        .transcript
        .iter()
        .rposition(|entry| !matches!(entry.kind, TranscriptEntryKind::SlashEcho(_)))
    else {
        set_status_notice(app, "nothing in the transcript to pin yet");
        return;
    };
    app.selected_entry = Some(start);
    app.pin_picker_active = true;
    update_pin_picker_status(app);
}

/// Step the picker highlight by `dir` (±1) to the nearest pinnable entry,
/// clamping at the transcript ends.
fn move_pin_picker(app: &mut TuiApp, dir: isize) {
    let len = app.transcript.len();
    if len == 0 {
        return;
    }
    let mut idx = app.selected_entry.unwrap_or(0) as isize;
    loop {
        let next = idx + dir;
        if next < 0 || next >= len as isize {
            break;
        }
        idx = next;
        if !matches!(
            app.transcript[idx as usize].kind,
            TranscriptEntryKind::SlashEcho(_)
        ) {
            app.selected_entry = Some(idx as usize);
            break;
        }
    }
    update_pin_picker_status(app);
}

fn update_pin_picker_status(app: &mut TuiApp) {
    let preview = app
        .selected_entry
        .and_then(|index| app.transcript.get(index))
        .map(|entry| entry.pin_payload().0)
        .unwrap_or_else(|| "—".to_string());
    app.status = format!("pin: {preview} · ↑/↓ choose · Enter pin · Esc cancel");
}

async fn handle_pin_picker_key(app: &mut TuiApp, agent: &mut Agent, key: KeyEvent) -> bool {
    match key.code {
        KeyCode::Up => move_pin_picker(app, -1),
        KeyCode::Down => move_pin_picker(app, 1),
        KeyCode::Enter => {
            app.pin_picker_active = false;
            if let Some(index) = app.selected_entry.take() {
                pin_transcript_index(app, agent, index).await;
            }
        }
        KeyCode::Esc => {
            app.pin_picker_active = false;
            app.selected_entry = None;
            app.status = "pin cancelled".to_string();
        }
        KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => {
            app.pin_picker_active = false;
            app.selected_entry = None;
            app.status = "pin cancelled".to_string();
        }
        _ => {}
    }
    false
}

async fn pin_transcript_index(app: &mut TuiApp, agent: &mut Agent, index: usize) {
    let payload = app.transcript.get(index).map(|entry| entry.pin_payload());
    let Some((label, summary, source)) = payload else {
        set_status_notice(app, "no transcript entry to pin");
        return;
    };
    match agent.pin_context_entry(label, summary, source).await {
        Ok(pin) => {
            app.context_compaction = agent.context_compaction_snapshot().await;
            app.status = format!("pinned {}", pin.id);
            app.push_log(format!("pinned context {}", pin.id));
        }
        Err(error) => set_status_notice(app, format!("pin failed: {error}")),
    }
}

fn sync_jobs_from_agent(app: &mut TuiApp, agent: &Agent) {
    app.jobs = agent
        .jobs_snapshot()
        .into_iter()
        .map(|job| (job.id, job))
        .collect();
    app.notifications = agent.job_notifications().into_iter().collect();
}

fn parse_job_id(raw: &str) -> Option<JobId> {
    raw.parse().ok()
}

/// Render the `/tasks` view: every background job followed by a `reviewer`
/// line so the AI reviewer surfaces alongside ordinary jobs even though it
/// does not yet have its own task type. Each line is "{id} {status} {kind}
/// {title}"; reviewer uses `reviewer` for both id and kind.
fn format_tasks_list(app: &TuiApp, agent: &Agent) -> String {
    let mut lines: Vec<String> = app
        .jobs
        .values()
        .rev()
        .take(MAX_JOB_NOTIFICATIONS)
        .map(|job| {
            format!(
                "{} {} {} {}",
                job.id,
                job.status.as_str(),
                job.kind.as_str(),
                sanitize_inline(&job.title)
            )
        })
        .collect();
    lines.push(format_reviewer_task_line(agent));
    lines.join("\n")
}

fn format_reviewer_task_line(agent: &Agent) -> String {
    let entries = agent.reviewer_audit_snapshot();
    if entries.is_empty() {
        "reviewer idle ai-reviewer no decisions yet".to_string()
    } else {
        format!(
            "reviewer ready ai-reviewer {} recent decision(s)",
            entries.len()
        )
    }
}

fn format_job_detail(job: &JobSnapshot) -> String {
    let progress = job
        .progress
        .as_ref()
        .map(|progress| progress.message.as_str())
        .unwrap_or("-");
    let summary = job.result_summary.as_deref().unwrap_or("-");
    let handle = job.output_handle.as_deref().unwrap_or("-");
    let tool_name = job.tool_name.as_deref().unwrap_or("-");
    let call_id = job.call_id.as_deref().unwrap_or("-");
    format!(
        "job {id}\nstatus={status}\nkind={kind}\ntool={tool}\ncall_id={call_id}\ntitle={title}\nprogress={progress}\nsummary={summary}\noutput_handle={handle}",
        id = job.id,
        status = job.status.as_str(),
        kind = job.kind.as_str(),
        tool = tool_name,
        call_id = call_id,
        title = sanitize_inline(&job.title),
        progress = sanitize_inline(progress),
        summary = sanitize_inline(summary),
        handle = sanitize_inline(handle),
    )
}

fn sanitize_inline(text: &str) -> String {
    text.replace(['\n', '\r'], " ")
}

/// Build the production clipboard provider chain from env-probed
/// capabilities, over the given side-effect sink. OSC 52 (when believed
/// honoured) → platform command → durable temp-file fallback. Used by the
/// semantic copy/export path. The sink is injected (rather than hard-wired to
/// [`clipboard::RealSink`]) so the field is a `ClipboardChain<Box<dyn
/// ClipboardSink>>` and an app-layer copy test can drive a `RecordingSink`
/// with no real terminal/clipboard/subprocess I/O.
fn build_clipboard_chain(
    sink: Box<dyn clipboard::ClipboardSink + Send>,
) -> clipboard::ClipboardChain<Box<dyn clipboard::ClipboardSink + Send>> {
    let env_get = |key: &str| std::env::var_os(key);
    #[cfg_attr(not(test), allow(unused_mut))]
    let mut caps = clipboard::detect_clipboard_capabilities_from_env(env_get);
    // Under the crate's own `cfg(test)` build, force an OSC 52-PREFERRED chain so
    // every copy-funnel test is host-independent. `deliver_copy` takes the
    // observable `app.clipboard` fast path only when `clipboard_chain.prefers_osc52()`
    // is true; that depends on the env probe (`caps.osc52` true on a dev Mac but
    // FALSE on headless CI) AND on locality (a LOCAL Mac now prefers the platform
    // command over OSC 52 — see `default_chain`). So we pin BOTH signals here:
    // `osc52 = true` makes OSC 52 capable, and `ssh = true` keeps it the PREFERRED
    // (first) provider so the fast path is taken regardless of host platform
    // commands — otherwise the copy would route to an unobserved platform sink and
    // leave an injected `RecordingClipboard` empty. Pinning at this single
    // chain-construction funnel fixes the `test_app_with_clipboard` helper AND
    // every direct `new_with_clipboard` / `set_clipboard_sink_for_test` caller at
    // once. Tests that intentionally model a LOCAL OSC 52-ignoring terminal call
    // `set_clipboard_chain_for_test` after construction, replacing this whole
    // chain, so they still override it.
    #[cfg(test)]
    {
        caps.osc52 = true;
        caps.ssh = true;
    }
    let platform = clipboard::platform_commands(env_get);
    // TODO(copy-confirm): the chain supports a large-payload confirmation gate
    // (`set_confirm_threshold` → `CopyOutcome::NeedsConfirmation`), but wiring an
    // interactive confirm requires a pending-confirm app state plus a
    // repeat/confirm key handler in the key dispatch, which is owned by a
    // separate phase. Until that lands we deliberately leave the threshold unset
    // so `deliver_copy` never has to surface `NeedsConfirmation`, and large
    // copies degrade gracefully through the platform command / temp-file
    // fallback instead. See the matching TODO in `deliver_copy`.
    clipboard::ClipboardChain::default_chain(sink, caps, platform)
}

/// Pre-build path for [`CopyScope::LastAssistant`]: when the assistant is still
/// streaming, the live pending text is the freshest answer and has no committed
/// entry/row yet. Matches the historical `last_assistant_clipboard_text`
/// pending-stream check.
fn pending_assistant_clipboard_text(app: &TuiApp) -> Option<String> {
    if active_subagent_record(app).is_none() && !app.pending_assistant.trim_is_empty() {
        return Some(app.pending_assistant.text());
    }
    None
}

/// Set of `EntryId`s whose entry is an assistant `Message`. Resolved here (in
/// `lib.rs`, where `Role` is in scope) so the row model stays role-agnostic;
/// the `copy` scope resolvers take this as an `is_assistant` predicate.
fn assistant_entry_ids(app: &TuiApp) -> std::collections::HashSet<u64> {
    active_transcript_entries(app)
        .iter()
        .filter_map(|entry| match &entry.kind {
            TranscriptEntryKind::Message(item) if item.role == Role::Assistant => Some(entry.id),
            _ => None,
        })
        .collect()
}

/// Live main-viewport `RowId` range (inclusive) over a row list of
/// `total_rows`, derived from the cached scrollbar geometry. Returns the whole
/// list when no cache is present (content fits the viewport).
fn main_viewport_row_range(
    app: &TuiApp,
    total_rows: usize,
) -> Option<(transcript_surface::RowId, transcript_surface::RowId)> {
    use transcript_surface::RowId;
    if total_rows == 0 {
        return None;
    }
    let last = total_rows - 1;
    let Some(cache) = app.main_scrollbar_cache.get() else {
        // Content fits: the whole list is visible.
        return Some((RowId(0), RowId(last)));
    };
    let viewport_h = cache.viewport_h as usize;
    if viewport_h == 0 {
        return Some((RowId(last), RowId(last)));
    }
    // The logical scroll state holds the destination `from_bottom`; the visible
    // window is the `viewport_h`-tall slice anchored that far from the bottom.
    let state = active_transcript_scroll(app);
    let from_bottom = state.offset_from_bottom(total_rows, viewport_h);
    let end = last.saturating_sub(from_bottom);
    let start = end.saturating_sub(viewport_h.saturating_sub(1));
    Some((RowId(start), RowId(end)))
}

/// The single semantic-copy entrypoint. Builds the transcript row model at the
/// live painted width, resolves `scope` to a row subset, formats it in
/// `format`, and sends the payload through the clipboard provider chain,
/// reporting the outcome on the status line and as a toast.
///
/// Returns `true` when the action was handled (always — even a "nothing to
/// copy" no-op is a handled keystroke).
fn copy_transcript_scope(
    app: &mut TuiApp,
    scope: copy::CopyScope,
    format: copy::CopyFormat,
) -> bool {
    // An active visual selection wins over the requested semantic unit: every
    // copy chord copies the selection when one is present, otherwise the focused
    // unit. The clean-text comes from the selection's own painted surface.
    if copy_active_selection(app) {
        return true;
    }

    // Pending-stream special case: the freshest assistant answer may not be a
    // committed row yet. Copy it directly before building the row model.
    if scope == copy::CopyScope::LastAssistant
        && let Some(text) = pending_assistant_clipboard_text(app)
    {
        deliver_copy(app, &text, scope.label());
        return true;
    }

    let Some(text) = build_scope_payload(app, scope, format) else {
        let message = format!("nothing to copy for {}", scope.label());
        app.status = message.clone();
        app.toasts.push(message, toast::ToastVariant::Info);
        return true;
    };
    deliver_copy(app, &text, scope.label());
    true
}

/// Build (but do not deliver) the payload for `scope`/`format`. Split out so
/// `/export` reuses the exact same scope resolution + formatting the clipboard
/// copies use. `None` when the scope resolves to nothing.
fn build_scope_payload(
    app: &TuiApp,
    scope: copy::CopyScope,
    format: copy::CopyFormat,
) -> Option<String> {
    // Copy with full detail so a folded tool card yields its complete output,
    // not the truncated preview — the user-intuitive behaviour, independent of
    // what is painted. The Viewport scope is the exception: its row window is
    // derived from the painted surface's scroll geometry (`viewport_h` +
    // `from_bottom`), so it must index into the SAME surface's rows. Building it
    // `Expanded` (a different, taller row model) would slice the wrong rows when
    // a card is folded on screen, so Viewport builds the row model `Collapsed`
    // — folded exactly like the inline view the window measures.
    let detail = if scope == copy::CopyScope::Viewport {
        transcript_surface::DetailPolicy::Collapsed
    } else {
        transcript_surface::DetailPolicy::Expanded
    };
    let width = main_text_width(app);
    let rows = transcript_surface::build_transcript_rows(app, width, detail);

    let assistant_ids = assistant_entry_ids(app);
    let is_assistant = |id: transcript_surface::EntryId| assistant_ids.contains(&id.0);

    let viewport = if scope == copy::CopyScope::Viewport {
        main_viewport_row_range(app, rows.len())
    } else {
        None
    };

    // Code-Aware Copy/Export (§12.5.5): the AllCode scope is not a plain text
    // projection — it extracts every fenced code block (languages preserved,
    // rails stripped) and re-emits clean fences. Resolve it to the focused
    // entry's rows, then run the code extractor; if that entry carried NO code,
    // widen the search to the whole transcript before giving up.
    if scope == copy::CopyScope::AllCode {
        return build_all_code_payload(&rows, app.copy_focus, &is_assistant, format);
    }

    copy::gather(
        &rows,
        app.copy_focus,
        scope,
        format,
        &is_assistant,
        viewport,
    )
}

/// Code-Aware Copy (§12.5.5) payload: extract every fenced code block from the
/// focused entry's rows, and — when that entry held none — from the WHOLE
/// transcript, so an `Alt+j` parked on a user prompt still gathers the answer's
/// code. `format` chooses the serialization: Markdown re-emits clean
/// ```` ```lang ```` fences (the round-trippable form); every other format
/// yields the bare interiors (paste-into-an-editor). `None` when the transcript
/// holds no fenced block at all.
fn build_all_code_payload(
    rows: &[transcript_surface::TranscriptRow],
    focus: Option<transcript_surface::RowId>,
    is_assistant: &dyn Fn(transcript_surface::EntryId) -> bool,
    format: copy::CopyFormat,
) -> Option<String> {
    let style = if format == copy::CopyFormat::Markdown {
        copy_code::CodePayloadStyle::Fenced
    } else {
        copy_code::CodePayloadStyle::Bare
    };

    // First try the focused entry's run.
    if let Some((lo, hi)) =
        copy::resolve_scope(rows, focus, copy::CopyScope::AllCode, is_assistant, None)
        && let Some(payload) = copy_code::gather_code(&rows[lo..=hi.min(rows.len() - 1)], style)
    {
        return Some(payload);
    }
    // Fall back to the whole transcript so a focus outside any code-bearing
    // entry still finds the code.
    copy_code::gather_code(rows, style)
}

/// The width to rebuild the row model at for an off-frame copy/export: the last
/// painted main text width, falling back to a sane default before the first
/// frame.
pub(crate) fn main_text_width(app: &TuiApp) -> u16 {
    let width = app.main_text_width.get();
    if width == 0 { 80 } else { width }
}

/// Send `text` to the clipboard and report the outcome on the status line + a
/// toast. Used by every semantic copy.
///
/// The primary sink is the injectable [`TuiApp::clipboard`] (an
/// [`Osc52Clipboard`] in production, a recording fake under test). When that
/// sink rejects an *oversized* payload — past the OSC 52 8 KiB cap, the common
/// failure for a full-transcript or large-viewport copy — we fall through to
/// the richer [`clipboard::ClipboardChain`] (`clipboard.rs`), which can still
/// land the copy via the host's platform command (`pbcopy`/`wl-copy`/…) or,
/// failing that, a durable temp file. So small copies stay on the fast OSC 52
/// path and large ones degrade gracefully instead of silently failing. Any
/// other primary failure (e.g. the terminal clipboard genuinely unavailable)
/// is reported as-is — the fallback chain only earns its keep for the cap case.
///
/// CRITICAL (deep-review #11): the fast OSC 52-only write reports `Ok` as soon
/// as the escape is flushed to stdout — it cannot observe whether the terminal
/// honoured it. On a terminal that ignores OSC 52 (Apple Terminal, GNOME/VTE,
/// or iTerm2 with its default OSC 52 clipboard-write block) that would surface a
/// false "copied N chars" while the clipboard stays empty and the
/// `pbcopy`/`xclip`/`wl-copy` sinks this PR added are never consulted.
///
/// So the fast OSC 52-only path is taken ONLY when OSC 52 is the chain's
/// *preferred* provider (`clipboard_chain.prefers_osc52()`): a remote/SSH
/// session (where OSC 52 is the only sink that reaches the user's local
/// clipboard) or a host with no platform command. On a LOCAL session with a
/// verifiable platform command (`pbcopy`/`wl-copy`/…) the chain prefers that
/// command first, so we route every payload — including the common ≤8 KiB case
/// — through the capability-aware chain, which lands the copy on the platform
/// sink and confirms it via the command's exit status.
fn deliver_copy(app: &mut TuiApp, text: &str, label: &str) {
    // Take the fast OSC 52-only path only when OSC 52 is the chain's preferred
    // provider (SSH/remote, or no platform command). Otherwise the fast path's
    // `Ok` is unobservable and would falsely report success; route through the
    // chain so the verifiable local platform sink (`pbcopy`/…) actually lands it.
    if !app.clipboard_chain.prefers_osc52() {
        deliver_copy_via_chain(app, text, label, None);
        return;
    }
    let chars = text.chars().count();
    match app.clipboard.copy_text(text) {
        Ok(()) => {
            app.status = format!("copied {label} ({chars} chars)");
            app.toasts.push(
                format!("copied {label} ({chars} chars)"),
                toast::ToastVariant::Success,
            );
            // In-app clipboard history (§12.6.1): record every copy that actually
            // landed so the user can recover/re-copy it from the picker. Recorded
            // here in the single copy funnel, never by scraping the OS clipboard.
            app.clipboard_history.record(text, label);
        }
        Err(primary_err) => {
            // Only an oversized payload (past the OSC 52 cap) benefits from the
            // richer chain — that is where the platform command / temp file add
            // value. For any other primary failure, report it directly. Gauge
            // the size by the *base64-encoded* length (what the escape actually
            // carries), matching `build_osc52_sequence`'s cap: otherwise a raw
            // payload in (6144, 8192] whose encoding overflows 8 KiB would be
            // reported as a hard failure instead of falling through to the
            // platform-command chain (deep-review #41).
            let encoded_len = 4 * text.len().div_ceil(3);
            if encoded_len <= OSC52_MAX_PAYLOAD_BYTES {
                app.status = format!("copy failed: {primary_err}");
                app.toasts
                    .push(app.status.clone(), toast::ToastVariant::Error);
                return;
            }
            deliver_copy_via_chain(app, text, label, Some(primary_err));
        }
    }
}

/// Deliver `text` through the capability-aware [`clipboard::ClipboardChain`]
/// (platform command `pbcopy`/`wl-copy`/… → durable temp file) and report the
/// outcome on the status line + a toast, recording a landed copy in the in-app
/// history. Shared by the two routes into the chain: an OSC 52-ignoring
/// terminal (where the fast OSC 52-only write would falsely report success —
/// deep-review #11) and an oversized payload that overflowed the OSC 52 cap.
///
/// `primary_err` carries the original OSC 52 sink's failure reason for the
/// oversized-payload route, surfaced if even the chain fails (it is the most
/// actionable message). It is `None` on the OSC 52-unsupported route, where no
/// fast-path write was attempted; that route reports the chain's own reason.
fn deliver_copy_via_chain(app: &mut TuiApp, text: &str, label: &str, primary_err: Option<String>) {
    let chars = text.chars().count();
    // TODO(copy-confirm): when the large-payload confirmation gate is
    // wired (see the TODO in `build_clipboard_chain`), pass
    // `request.confirmed` through from a pending-confirm app state and
    // add a `CopyOutcome::NeedsConfirmation` arm here that sets that
    // state + an info toast and confirms on a repeat/confirm key. Until
    // then the threshold is unset, so `copy` never returns
    // `NeedsConfirmation` and it falls into the generic failure arm.
    let request = clipboard::CopyRequest::new(text, label);
    let outcome = app.clipboard_chain.copy(&request);
    let (toast_msg, variant) = outcome.toast();
    match &outcome {
        clipboard::CopyOutcome::Copied { provider, .. } => {
            app.status = format!("copied {label} ({chars} chars)");
            // Dogfood telemetry (§12.10.3): bucket the copy by the
            // bounded provider kind that serviced it (never the bytes).
            app.dogfood_metrics
                .record_copy(dogfood_copy_provider(*provider));
            // In-app clipboard history (§12.6.1): the chain landed it too, so
            // record it for recovery just like the fast-path success above.
            app.clipboard_history.record(text, label);
        }
        clipboard::CopyOutcome::WroteTempFile { .. } => {
            app.status = toast_msg.clone();
            // The temp-file fallback is itself a (degraded) copy outcome.
            app.dogfood_metrics
                .record_copy(dogfood::CopyProvider::TempFile);
            // Still a delivered payload (to a durable file); record it so
            // the user can re-copy it from the in-app history (§12.6.1).
            app.clipboard_history.record(text, label);
        }
        _ => {
            // Even the fallback chain failed: surface the original sink's
            // reason when we have one (most actionable), else the chain's.
            app.status = match &primary_err {
                Some(err) => format!("copy failed: {err}"),
                None => toast_msg.clone(),
            };
        }
    }
    app.toasts.push(toast_msg, variant);
}

/// Handle `/export <md|txt|json> [destination]` (§12.6.4): render the full
/// transcript in the requested format (reusing the same scope resolution +
/// formatters the clipboard copies use) and deliver it to the chosen
/// destination. Destinations: an explicit file path, `clipboard`, `stdout`
/// (echoed into the transcript so it reaches the terminal + clean-exit
/// mirror), a `dir:<name>` configured workspace directory, or — with no
/// destination token — the session-storage default
/// (`<workspace>/.squeezy/exports/<session_id>/transcript-<ts>.<ext>`).
///
/// All file-backed destinations share the same atomic-write pipeline; the
/// clipboard destination reuses [`deliver_copy`] (provider chain + clipboard
/// history). The payload is rendered exactly once, then routed.
fn handle_export_command(app: &mut TuiApp, agent: &Agent, rest: &str) {
    let request = match export_destination::parse_export_request(rest) {
        Ok(request) => request,
        Err(usage) => {
            set_status_with_notice(app, usage.clone(), usage);
            return;
        }
    };

    let Some(payload) = build_scope_payload(app, copy::CopyScope::FullTranscript, request.format)
    else {
        set_status_notice(app, "nothing to export yet");
        return;
    };

    // Resolve the destination to a concrete file target (or `None` for the
    // non-file destinations), then deliver. Keeping the file target resolution
    // separate lets clipboard/stdout skip the filesystem entirely.
    use export_destination::ExportDestination;
    let file_target = match &request.destination {
        ExportDestination::Default => Some(default_export_path(app, agent, request.format)),
        ExportDestination::File(path) => Some(resolve_workspace_path(&app.workspace_root, path)),
        ExportDestination::ConfiguredDir(dir) => {
            Some(configured_dir_export_path(app, dir, request.format))
        }
        ExportDestination::Clipboard | ExportDestination::Stdout => None,
    };

    match (&request.destination, file_target) {
        (_, Some(target)) => {
            // Only the explicit-path form can collide (the timestamped Default /
            // ConfiguredDir targets are unique), so the existence guard applies
            // there; for the collision-free destinations `force` is implicit.
            let force = request.force
                || !matches!(
                    request.destination,
                    export_destination::ExportDestination::File(_)
                );
            export_to_file(app, &payload, &target, request.format, force)
        }
        (ExportDestination::Clipboard, None) => {
            // Reuse the single semantic-copy funnel: provider chain, status +
            // toast, and one-time clipboard-history recording (§12.6.1).
            deliver_copy(app, &payload, "transcript export");
        }
        (ExportDestination::Stdout, None) => {
            // The alt screen owns real stdout, so "stdout" means echo the
            // payload into the transcript: it appears in-app now and lands in
            // the native scrollback via the clean-exit mirror.
            let bytes = payload.len();
            app.push_transcript_item(TranscriptItem::system(payload));
            app.status = format!("exported transcript to stdout ({bytes} bytes)");
            app.toasts.push(
                format!("exported transcript to stdout ({bytes} bytes)"),
                toast::ToastVariant::Success,
            );
        }
        // Unreachable: every `None` file target is a clipboard/stdout
        // destination handled above, and every other destination yields
        // `Some(target)`. Kept exhaustive so a new destination can't silently
        // no-op.
        (
            ExportDestination::Default
            | ExportDestination::File(_)
            | ExportDestination::ConfiguredDir(_),
            None,
        ) => {
            set_status_notice(app, "export failed: could not resolve a destination path");
        }
    }
}

/// Write a rendered `payload` to `target` atomically and surface the outcome on
/// the status line, a toast, and a transcript system row. Shared by every
/// file-backed export destination (default, explicit path, configured dir).
fn export_to_file(
    app: &mut TuiApp,
    payload: &str,
    target: &Path,
    format: copy::CopyFormat,
    force: bool,
) {
    match write_export_atomically(target, payload, force) {
        Ok(()) => {
            let bytes = payload.len();
            app.status = format!("wrote {} ({bytes} bytes)", target.display());
            app.toasts.push(
                format!("exported transcript to {}", target.display()),
                toast::ToastVariant::Success,
            );
            app.push_transcript_item(TranscriptItem::system(format!(
                "Exported transcript ({}) to {} ({bytes} bytes).",
                format.file_extension(),
                target.display(),
            )));
        }
        Err(error) => {
            // An existing target is refused unless `force` was given; point the
            // user at the overwrite token rather than a bare OS error.
            let message = if error.kind() == std::io::ErrorKind::AlreadyExists {
                format!(
                    "export failed: {} already exists (append `!` to overwrite)",
                    target.display(),
                )
            } else {
                format!("export failed: {error}")
            };
            app.status = message.clone();
            app.toasts.push(message.clone(), toast::ToastVariant::Error);
            app.push_transcript_item(TranscriptItem::system(message));
        }
    }
}

/// Destination path for `/export <fmt> dir:<name>`: a timestamped transcript
/// file under `<workspace>/<name>/`. The `dir` name is already validated
/// (workspace-relative, no traversal) by `parse_export_request`, so this only
/// composes the final path.
fn configured_dir_export_path(app: &TuiApp, dir: &str, format: copy::CopyFormat) -> PathBuf {
    let ts = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0);
    app.workspace_root
        .join(dir)
        .join(format!("transcript-{ts}.{}", format.file_extension()))
}

/// Default `/export` destination under session storage:
/// `<workspace>/.squeezy/exports/<session_id>/transcript-<unix_ts>.<ext>`. Uses
/// `"default"` for the session segment before a session id exists.
fn default_export_path(app: &TuiApp, agent: &Agent, format: copy::CopyFormat) -> PathBuf {
    let session = agent
        .session_id()
        .or_else(|| app.session_id.clone())
        .unwrap_or_else(|| "default".to_string());
    let ts = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0);
    app.workspace_root
        .join(".squeezy")
        .join("exports")
        .join(session)
        .join(format!("transcript-{ts}.{}", format.file_extension()))
}

/// Derive the atomic-write tmp path for an export `target`.
///
/// Built from the FULL file name (not `Path::with_extension`, which strips the
/// format extension) so `transcript-<ts>.md` and `transcript-<ts>.json` get
/// DISTINCT tmp paths instead of colliding on a single
/// `transcript-<ts>.squeezy-export-tmp`.
fn export_tmp_path(target: &Path) -> PathBuf {
    target.with_file_name(format!(
        "{}.squeezy-export-tmp",
        target
            .file_name()
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or("export")
    ))
}

/// Write `content` to `target` atomically (write to `<target>.tmp` then
/// rename), creating the parent directory if missing. Mirrors the best-effort
/// atomic-write pattern used for plan pointers.
///
/// When `force` is `false` an already-existing `target` is refused with
/// [`std::io::ErrorKind::AlreadyExists`] *before* any tmp file is written, so a
/// `/export md notes.md` can never silently clobber a workspace source. The
/// timestamped destinations (and `/bundle`) pass `force = true` because their
/// paths are collision-free by construction.
fn write_export_atomically(target: &Path, content: &str, force: bool) -> std::io::Result<()> {
    if !force && target.exists() {
        return Err(std::io::Error::new(
            std::io::ErrorKind::AlreadyExists,
            format!("{} already exists", target.display()),
        ));
    }
    if let Some(parent) = target.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let tmp = export_tmp_path(target);
    std::fs::write(&tmp, content)?;
    // On a rename failure (e.g. `target` is an existing directory), remove the
    // tmp file so a failed export never litters the workspace.
    if let Err(e) = std::fs::rename(&tmp, target) {
        let _ = std::fs::remove_file(&tmp);
        return Err(e);
    }
    Ok(())
}

/// Handle `/bundle [md|json] [no-redact]` (§12.6.6): build a self-contained,
/// shareable artifact for support/handoff — the rendered transcript plus a
/// manifest (session metadata), a checksum over the (redacted) transcript body,
/// and the terminal/environment diagnostics — and write it atomically under
/// session storage, then echo a *preview* into the transcript so the user can
/// review what they are about to share before sending the file.
///
/// Reuses the export pipeline end to end: the transcript text is the same
/// Markdown payload `/export md` produces ([`build_scope_payload`]), and the
/// file is written through the same atomic-write helper. Redaction is on by
/// default (the share-safe default); `no-redact` opts out for a local-only
/// bundle, and both the manifest and the preview say plainly which it is.
fn handle_bundle_command(app: &mut TuiApp, agent: &Agent, rest: &str) {
    let request = match session_bundle::parse_bundle_request(rest) {
        Ok(request) => request,
        Err(usage) => {
            set_status_with_notice(app, usage.clone(), usage);
            return;
        }
    };

    // Render the transcript through the shared Markdown export formatter so the
    // bundle never grows a second transcript renderer.
    let Some(transcript) = build_scope_payload(
        app,
        copy::CopyScope::FullTranscript,
        copy::CopyFormat::Markdown,
    ) else {
        set_status_notice(app, "nothing to bundle yet");
        return;
    };

    let meta = bundle_meta_for(app, agent);
    let diagnostics = bundle_diagnostics(app);
    let bundle = session_bundle::SessionBundle::build(
        request.format,
        &meta,
        &diagnostics,
        &transcript,
        request.redact,
    );

    let target = bundle_export_path(app, &meta, request.format);
    // The bundle path is timestamped and collision-free, so overwrite-guarding it
    // would only ever produce a false positive; write with `force = true`.
    match write_export_atomically(&target, &bundle.artifact, true) {
        Ok(()) => {
            app.status = format!(
                "wrote bundle {} ({} bytes)",
                target.display(),
                bundle.report.bytes
            );
            app.toasts.push(
                format!("session bundle written to {}", target.display()),
                toast::ToastVariant::Success,
            );
            // Preview the manifest essentials + redaction status in-app so the
            // user reviews what they are about to share before handing the file
            // off (the spec's mandatory preview affordance).
            app.push_transcript_item(TranscriptItem::system(format!(
                "{}\n\nWritten to {}",
                bundle.preview(&meta),
                target.display(),
            )));
        }
        Err(error) => {
            let message = format!("bundle failed: {error}");
            app.status = message.clone();
            app.toasts.push(message.clone(), toast::ToastVariant::Error);
            app.push_transcript_item(TranscriptItem::system(message));
        }
    }
}

/// Gather the manifest facts for a bundle from the live app + agent. Pure read;
/// the bundle module owns all assembly.
fn bundle_meta_for(app: &TuiApp, agent: &Agent) -> session_bundle::BundleMeta {
    let session_id = agent
        .session_id()
        .or_else(|| app.session_id.clone())
        .unwrap_or_else(|| "default".to_string());
    let generated_at_unix = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0);
    session_bundle::BundleMeta {
        session_id,
        model: app.model.clone(),
        mode: title_case_mode(app.mode).to_ascii_lowercase(),
        provider: app.provider_name.to_string(),
        version: app.version.to_string(),
        workspace: session_bundle::portable_path(&app.workspace_root.to_string_lossy()),
        transcript_entries: app.transcript.len(),
        generated_at_unix,
    }
}

/// The terminal/environment diagnostic rows embedded in a bundle. A compact,
/// sanitized subset of the `/terminal` diagnostic — enough to reproduce
/// rendering context without leaking the environment. Env values are never
/// included verbatim beyond the small terminal-identity set, and the bundle
/// redactor still runs over the whole artifact when redaction is on.
fn bundle_diagnostics(app: &TuiApp) -> Vec<(String, String)> {
    let mut rows: Vec<(String, String)> = Vec::new();
    rows.push(("term".to_string(), env_var_label("TERM")));
    rows.push(("colorterm".to_string(), env_var_label("COLORTERM")));
    let mux = if env::var_os("TMUX").is_some() {
        "tmux"
    } else if env::var_os("STY").is_some() {
        "screen"
    } else {
        "none"
    };
    rows.push(("multiplexer".to_string(), mux.to_string()));
    rows.push((
        "hyperlinks".to_string(),
        if app.hyperlink_caps.osc8 {
            "osc8".to_string()
        } else {
            "plain".to_string()
        },
    ));
    rows.push((
        "directory".to_string(),
        session_bundle::portable_path(&app.directory),
    ));
    rows
}

/// Destination path for a `/bundle` artifact: a timestamped bundle file under
/// session storage (`<workspace>/.squeezy/bundles/<session>/`). Mirrors the
/// `/export` session-storage layout so both land beside each other.
fn bundle_export_path(
    app: &TuiApp,
    meta: &session_bundle::BundleMeta,
    format: session_bundle::BundleFormat,
) -> PathBuf {
    app.workspace_root
        .join(".squeezy")
        .join("bundles")
        .join(&meta.session_id)
        .join(format!(
            "session-bundle-{}.{}",
            meta.generated_at_unix,
            format.file_extension()
        ))
}

/// Build a compact terminal diagnostic string for the `/terminal` command.
/// Reports the key capabilities and environment settings that affect TUI
/// behaviour, especially on Linux where terminal variety is high.
fn build_terminal_diagnostic(app: &TuiApp, sync_policy: TuiSynchronizedOutput) -> String {
    let mut rows: Vec<(&'static str, String)> = Vec::new();

    // TTY status
    let stdout_tty = if io::stdout().is_terminal() {
        "yes"
    } else {
        "no (redirected)"
    };
    let stdin_tty = if io::stdin().is_terminal() {
        "yes"
    } else {
        "no (piped)"
    };
    rows.push(("stdout tty", stdout_tty.to_string()));
    rows.push(("stdin tty", stdin_tty.to_string()));

    // Terminal identity. Use `env::var_os` + `to_string_lossy` so a
    // set-but-non-UTF-8 $TERM / $COLORTERM is reported (lossily) rather
    // than silently misclassified as "(unset)".
    rows.push(("$TERM", env_var_label("TERM")));
    rows.push(("$COLORTERM", env_var_label("COLORTERM")));

    // Multiplexer
    let in_tmux = env::var_os("TMUX").is_some();
    let in_screen = env::var_os("STY").is_some();
    let mux = match (in_tmux, in_screen) {
        (true, _) => "tmux".to_string(),
        (_, true) => "screen".to_string(),
        _ => "none".to_string(),
    };
    rows.push(("multiplexer", mux));

    // Synchronized output — report the configured policy and, for Auto, the
    // heuristic result so the user can see what was actually decided. ASCII
    // arrow stays consistent with the rest of the table.
    let sync_out = match sync_policy {
        TuiSynchronizedOutput::Always => "Always".to_string(),
        TuiSynchronizedOutput::Never => "Never".to_string(),
        TuiSynchronizedOutput::Auto => {
            let detected = detect_synchronized_output_support_from_env(|k| env::var_os(k));
            format!("Auto -> {}", if detected { "enabled" } else { "disabled" })
        }
    };
    rows.push(("synchronized output", sync_out));

    // Mouse capture — report the SAME resolution the renderer actually uses
    // (`resolve_mouse_capture`: on by default, only `SQUEEZY_MOUSE_CAPTURE=0`
    // disables) so diagnostics never contradict the live behavior.
    let mouse = if resolve_mouse_capture(|k| env::var_os(k)) {
        "enabled by default (set SQUEEZY_MOUSE_CAPTURE=0 to disable)"
    } else {
        "disabled (SQUEEZY_MOUSE_CAPTURE=0)"
    };
    rows.push(("mouse capture", mouse.to_string()));

    // Clipboard method
    rows.push((
        "clipboard",
        format!(
            "OSC52 (cap {} bytes; terminal acceptance not verifiable)",
            OSC52_MAX_PAYLOAD_BYTES
        ),
    ));

    // Notifications — use the resolved backend from the live notifier.
    // `resolved()` only returns None, Some(Bel), or Some(Osc9); Auto and
    // Off are consumed internally before returning. Enumerate the impossible
    // arms explicitly so a new `NotificationMethod` variant trips this match
    // at compile time instead of silently surfacing a `Debug`-formatted
    // value to users.
    let notif = match app.desktop_notifier.resolved() {
        None => "off".to_string(),
        Some(squeezy_core::NotificationMethod::Bel) => "BEL".to_string(),
        Some(squeezy_core::NotificationMethod::Osc9) => "OSC9".to_string(),
        Some(squeezy_core::NotificationMethod::Off)
        | Some(squeezy_core::NotificationMethod::Auto) => {
            unreachable!("DesktopNotifier::resolved() never returns Off or Auto")
        }
    };
    rows.push(("notifications", notif));

    // Effective shell — shared with the agent's `[shell: ...]` failure hint
    // so the two surfaces always print the same value.
    rows.push(("effective shell", squeezy_tools::effective_shell_label()));

    // Format as a two-column table
    let label_width = rows.iter().map(|(k, _)| k.len()).max().unwrap_or(0);
    let mut lines = vec!["Terminal diagnostics".to_string(), String::new()];
    for (key, val) in &rows {
        lines.push(format!("  {:<width$}  {}", key, val, width = label_width));
    }
    lines.push(String::new());
    lines.push("Remedies:".to_string());
    lines.push("  - tmux OSC52: `set-option -g allow-passthrough on`".to_string());
    lines.push(
        "  - native text selection: mouse capture is on by default; SQUEEZY_MOUSE_CAPTURE=0 to free it (or Shift+drag)"
            .to_string(),
    );
    lines.push("  - shell: set SQUEEZY_SHELL (e.g. SQUEEZY_SHELL=/bin/bash)".to_string());
    lines.join("\n")
}

/// Read an environment variable as a user-facing label, using `env::var_os`
/// and lossy decoding so a set-but-non-UTF-8 value still shows up in the
/// `/terminal` diagnostic rather than being misclassified as `(unset)`.
fn env_var_label(key: &str) -> String {
    env::var_os(key)
        .map(|v| v.to_string_lossy().into_owned())
        .unwrap_or_else(|| "(unset)".to_string())
}

fn parse_tool_output_verbosity(value: &str) -> Option<ToolOutputVerbosity> {
    match value {
        "compact" => Some(ToolOutputVerbosity::Compact),
        "normal" => Some(ToolOutputVerbosity::Normal),
        "verbose" => Some(ToolOutputVerbosity::Verbose),
        _ => None,
    }
}

/// `/effort` sets `model.reasoning_effort` in the live in-memory config so the
/// next turn picks it up via `request_reasoning_effort`. `auto` (or `clear`,
/// `unset`, `none`) drops the override and falls back to the model default. The
/// command is session-scoped — to persist across runs, edit `model.reasoning_effort`
/// via `/config`. `SQUEEZY_REASONING_EFFORT` env var still wins on next load, so
/// surface that fact when set.
fn handle_slash_effort(app: &mut TuiApp, agent: &mut Agent, value: Option<&str>) {
    let Some(raw) = value else {
        let current = agent.config_snapshot().reasoning_effort.map_or_else(
            || "unset (model default)".to_string(),
            |e| e.as_str().to_string(),
        );
        app.status = format!("reasoning effort: {current}");
        app.push_transcript_item(TranscriptItem::system(format!(
            "reasoning effort = {current}\nusage: /effort [low|medium|high|xhigh|auto]"
        )));
        return;
    };
    let next_effort = match raw.trim().to_ascii_lowercase().as_str() {
        "auto" | "clear" | "unset" | "none" => None,
        other => match squeezy_core::ReasoningEffort::parse(other) {
            Some(effort) => Some(effort),
            None => {
                set_status_notice(
                    app,
                    format!("unknown effort {raw:?}; expected low, medium, high, xhigh, or auto"),
                );
                return;
            }
        },
    };
    let mut next = agent.config_snapshot();
    next.reasoning_effort = next_effort;
    agent.replace_config(next);
    app.reasoning_effort = next_effort;
    let label = next_effort.map_or_else(
        || "auto (model default)".to_string(),
        |e| e.as_str().to_string(),
    );
    // squeezy-a19z (audit U1): status line only; the previous
    // app_notification push duplicated feedback and diverged from
    // /tool-verbosity, which only used notifications. Unify on the
    // status line — it's the immediate-feedback surface for these
    // session-scoped switches.
    app.status = format!("reasoning effort → {label}");
    if std::env::var("SQUEEZY_REASONING_EFFORT").is_ok() {
        app.push_warn("SQUEEZY_REASONING_EFFORT overrides this on next load".to_string());
    }
}

/// `/router [on|off]`. Bare opens the Routing config page (like `/model`),
/// where the global toggles and the per-provider reroute/judge models live.
/// `on` re-enables session-wide auto-routing to the cheap tier; `off` disables
/// it (explicit `/cheap` still works). The toggle is session-scoped (persists
/// for the rest of the session and across `resume`) — the user's persisted
/// `[routing].enabled` config is not touched.
fn handle_slash_router(app: &mut TuiApp, agent: &mut Agent, value: Option<&str>) {
    let Some(raw) = value else {
        toggle_config_screen(
            app,
            agent,
            Some(squeezy_core::config_schema::SectionId::Routing),
        );
        return;
    };
    let disabled = match raw.trim().to_ascii_lowercase().as_str() {
        "on" | "enable" | "enabled" | "true" | "1" => false,
        "off" | "disable" | "disabled" | "false" | "0" => true,
        _ => {
            set_status_notice(
                app,
                format!("unknown router state {raw:?}; expected on or off"),
            );
            return;
        }
    };
    agent.set_routing_session_disabled(disabled);
    let label = if disabled { "disabled" } else { "enabled" };
    app.status = format!("routing → {label} (session only)");
    app.push_transcript_item(TranscriptItem::system(format!(
        "Cheap-model routing {label} for this session.\n\
         This is a session-only toggle and does not change `[routing].enabled` in your config.\n\
         To persist the change, run `/config` and edit the Routing section.",
    )));
}

/// `/tool-verbosity [compact|normal|verbose]`. Bare prints + usage hint;
/// with an explicit value, sets `tui.tool_output_verbosity` and reports via
/// the status line. squeezy-a19z + squeezy-3ys0.
fn handle_slash_tool_verbosity(app: &mut TuiApp, agent: &mut Agent, value: Option<&str>) {
    let Some(raw) = value else {
        let current = agent.config_snapshot().tui.tool_output_verbosity;
        app.status = format!("tool output verbosity: {}", current.as_str());
        app.push_transcript_item(TranscriptItem::system(format!(
            "tool output verbosity = {}\nusage: /tool-verbosity [compact|normal|verbose]",
            current.as_str()
        )));
        return;
    };
    let Some(verbosity) = parse_tool_output_verbosity(raw) else {
        set_status_notice(
            app,
            format!("unknown tool output verbosity {raw:?}; expected compact, normal, or verbose"),
        );
        return;
    };
    app.tool_output_verbosity = verbosity;
    let mut next = agent.config_snapshot();
    next.tui.tool_output_verbosity = verbosity;
    agent.replace_config(next);
    app.status = format!("tool output verbosity → {}", verbosity.as_str());
}

/// Collapse (or expand) every transcript entry, returning the number of
/// revision bumps applied. Driven by the Ctrl+T overlay's `c`/`e` keys. Each
/// toggle cancels any in-flight settle-fold so the requested state sticks, then
/// flips `collapsed`; both mutations bump the entry's revision so the line cache
/// (keyed on `revision`) re-renders. Fold state lives on the entry (id-keyed,
/// layout-independent), so it is preserved through resize and remembered across
/// overlay opens.
fn set_all_transcript_collapsed(app: &mut TuiApp, collapsed: bool) -> usize {
    let mut changed = 0;
    for entry in &mut app.transcript {
        // An explicit collapse/expand toggle is the user taking manual
        // control of the node's height, which cancels any in-flight
        // settle-fold so the requested state sticks instead of being
        // overridden by the animation's folded render.
        if entry.settle.take().is_some() {
            entry.bump_revision();
            changed += 1;
        }
        if entry.collapsed != collapsed {
            entry.collapsed = collapsed;
            entry.bump_revision();
            changed += 1;
        }
    }
    changed
}

/// Toggle the collapsed state of a single transcript entry by index. Mirrors
/// `set_all_transcript_collapsed`'s per-entry recipe exactly (cancel any
/// in-flight settle-fold, then flip `collapsed`, bumping the revision on each
/// mutation so the line cache invalidates). The fold state it sets lives on the
/// entry itself, which `transcript_lines_for_render` already honours, so it
/// survives resize and persists after the overlay closes. Returns `false` when
/// `index` is out of range.
fn toggle_transcript_entry_fold(app: &mut TuiApp, index: usize) -> bool {
    let Some(entry) = app.transcript.get_mut(index) else {
        return false;
    };
    if entry.settle.take().is_some() {
        entry.bump_revision();
    }
    entry.collapsed = !entry.collapsed;
    entry.bump_revision();
    // Folding/unfolding changes the painted row count, so every row-indexed
    // anchor below the entry now points at shifted content. Invalidate the
    // selection and re-anchor search to the new row model — the same treatment
    // the resize arm gives a reflow — so a stale highlight band or k-of-N count
    // can't survive the fold (deep-review #73). Covers the mouse caret-click,
    // double-click expand, keyboard Ctrl+O, and palette fold paths uniformly.
    app.selection = None;
    app.selection_set.clear();
    if app.search.is_some() {
        refresh_search(app);
    }
    true
}

/// Move the focused-entry cursor one entry earlier, used by the per-entry fold
/// controls. `selected_entry` is the single source of truth; this steps it back
/// one index, parking on the last entry when nothing is focused yet.
fn select_previous_transcript_entry(app: &mut TuiApp) {
    if app.transcript.is_empty() {
        app.status = "transcript is empty".to_string();
        return;
    }
    let last = app.transcript.len() - 1;
    let index = match app.selected_entry {
        Some(i) => i.min(last).saturating_sub(1),
        None => last,
    };
    app.selected_entry = Some(index);
    app.status = format!("selected transcript entry {}", app.transcript[index].id + 1);
}

/// Move the focused-entry cursor one entry later, used by the per-entry fold
/// controls. `selected_entry` is the single source of truth; this steps it
/// forward one index, parking on the first entry when nothing is focused yet.
fn select_next_transcript_entry(app: &mut TuiApp) {
    if app.transcript.is_empty() {
        app.status = "transcript is empty".to_string();
        return;
    }
    let last = app.transcript.len() - 1;
    let index = match app.selected_entry {
        Some(i) => (i + 1).min(last),
        None => 0,
    };
    app.selected_entry = Some(index);
    app.status = format!("selected transcript entry {}", app.transcript[index].id + 1);
}

/// Handle a keystroke while the full-screen transcript overlay is open.
/// Returns `true` when the key was consumed so the caller does not also
/// dispatch it to the normal input/turn paths.
/// Close the transcript overlay. When it was surfacing a subagent conversation
/// (opened from the pane via Enter), back all the way out to the main
/// conversation in one step, mirroring the pane's own Esc.
fn close_transcript_overlay(app: &mut TuiApp) {
    app.transcript_overlay_scrollbar_cache.set(None);
    app.transcript_overlay_text_width.set(None);
    app.transcript_overlay = None;
    // The detail pane only lives alongside the overlay; closing the overlay
    // closes the pane too so it can never linger as orphaned state.
    app.diff_detail_pane = None;
    app.diff_detail_pane_rect_cache.set(None);
    // The Pinned Compare View (§12.2.3) likewise lives only alongside the
    // overlay; tear it down so it can never linger as orphaned state.
    app.pinned_compare = None;
    app.pinned_compare_rect_cache.set(None);
    if matches!(app.subagent_pane.active, ConversationSource::Subagent(_)) {
        // A §12.8.2 jump left a return anchor: restore the user's prior reading
        // position (selection + active source) rather than resetting to main with a
        // lost cursor, so jumping away then closing the transcript never strands
        // them. Falls back to the historical reset when no anchor is outstanding
        // (e.g. the subagent was surfaced by the Enter path, not a jump).
        if !restore_subagent_return_anchor(app) {
            app.subagent_pane.focused = false;
            app.subagent_pane.active = ConversationSource::Main;
            app.subagent_pane.selected = 0;
            active_transcript_scroll_mut(app).pin_to_bottom();
            app.status = "main conversation selected".to_string();
        }
    } else {
        // The overlay was not on a subagent — drop any stale anchor so it can't
        // surprise a later, unrelated Esc.
        app.subagent_return_anchor = None;
        app.status = "transcript overlay closed".to_string();
    }
}

fn handle_transcript_overlay_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.transcript_overlay.is_none() {
        return false;
    }
    const PAGE: usize = 10;
    // Pinned Compare View (§12.2.3). When it is open it OWNS the overlay's inner
    // area (the single transcript is replaced by two panes), so it claims the
    // overlay keys: the scroll keys move the ACTIVE pane, `Tab` flips focus, `x`
    // toggles the clean-text diff, and `Esc` closes the compare view first (one
    // level at a time). The `Alt+t` toggle itself flows through the global keymap
    // dispatch before this handler. Handled before the detail-pane and plain
    // scroll arms so the compare view wins while it is up.
    if app.pinned_compare.is_some() {
        match key.code {
            KeyCode::Tab | KeyCode::BackTab => {
                toggle_pinned_compare_focus(app);
                return true;
            }
            KeyCode::Char('x') | KeyCode::Char('X')
                if !key
                    .modifiers
                    .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::META) =>
            {
                toggle_pinned_compare_mode(app);
                return true;
            }
            KeyCode::Up => {
                scroll_pinned_compare(app, VerticalScrollDir::Up, 1);
                return true;
            }
            KeyCode::Down => {
                scroll_pinned_compare(app, VerticalScrollDir::Down, 1);
                return true;
            }
            KeyCode::PageUp => {
                scroll_pinned_compare(app, VerticalScrollDir::Up, PAGE);
                return true;
            }
            KeyCode::PageDown => {
                scroll_pinned_compare(app, VerticalScrollDir::Down, PAGE);
                return true;
            }
            KeyCode::Home => {
                scroll_pinned_compare(app, VerticalScrollDir::Up, usize::MAX);
                return true;
            }
            KeyCode::End => {
                scroll_pinned_compare(app, VerticalScrollDir::Down, usize::MAX);
                return true;
            }
            KeyCode::Esc => {
                app.pinned_compare = None;
                app.pinned_compare_rect_cache.set(None);
                app.status = "compare view closed".to_string();
                app.needs_redraw = true;
                return true;
            }
            _ => return true, // modal: swallow everything else
        }
    }
    // Detail pane (§11G.10) scroll. When the pane is open, `Shift`+the scroll
    // keys move the PANE while the plain keys keep moving the transcript — so
    // the transcript context the spec wants preserved stays reachable. Matched
    // before the plain scroll arms (which ignore Shift) so the modifier wins.
    if app.diff_detail_pane.is_some() && key.modifiers.contains(KeyModifiers::SHIFT) {
        match key.code {
            KeyCode::Up => {
                scroll_diff_detail_pane(app, VerticalScrollDir::Up, 1);
                return true;
            }
            KeyCode::Down => {
                scroll_diff_detail_pane(app, VerticalScrollDir::Down, 1);
                return true;
            }
            KeyCode::PageUp => {
                scroll_diff_detail_pane(app, VerticalScrollDir::Up, PAGE);
                return true;
            }
            KeyCode::PageDown => {
                scroll_diff_detail_pane(app, VerticalScrollDir::Down, PAGE);
                return true;
            }
            KeyCode::Home => {
                scroll_diff_detail_pane(app, VerticalScrollDir::Up, usize::MAX);
                return true;
            }
            KeyCode::End => {
                scroll_diff_detail_pane(app, VerticalScrollDir::Down, usize::MAX);
                return true;
            }
            _ => {}
        }
    }
    match key.code {
        KeyCode::Esc => {
            // Esc closes the detail pane first (one level at a time) so a user
            // reading a diff backs out to the transcript before leaving it.
            if app.diff_detail_pane.is_some() {
                app.diff_detail_pane = None;
                app.diff_detail_pane_rect_cache.set(None);
                app.status = "detail pane closed".to_string();
                app.needs_redraw = true;
                return true;
            }
            close_transcript_overlay(app);
            true
        }
        KeyCode::PageUp => {
            adjust_transcript_overlay_scroll(app, |scroll| scroll.saturating_sub(PAGE));
            true
        }
        KeyCode::PageDown => {
            adjust_transcript_overlay_scroll(app, |scroll| scroll.saturating_add(PAGE));
            true
        }
        KeyCode::Up => {
            adjust_transcript_overlay_scroll(app, |scroll| scroll.saturating_sub(1));
            true
        }
        KeyCode::Down => {
            adjust_transcript_overlay_scroll(app, |scroll| scroll.saturating_add(1));
            true
        }
        KeyCode::Home => {
            set_transcript_overlay_scroll(app, 0);
            true
        }
        KeyCode::End => {
            let end =
                transcript_overlay_max_scroll(app).unwrap_or(TRANSCRIPT_OVERLAY_SCROLL_BOTTOM);
            set_transcript_overlay_scroll(app, end);
            true
        }
        KeyCode::Char('m') | KeyCode::Char('M')
            if !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::META) =>
        {
            toggle_transcript_overlay_mouse_capture(app);
            true
        }
        KeyCode::Char('f') | KeyCode::Char('F')
            if !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::META) =>
        {
            // Cycle the overlay entry filter. Backward when Shift is held
            // (uppercase `F`), forward otherwise. Like `m`, this is a local key
            // handled here rather than through the global keymap (the dispatch
            // guard blocks non-toggle actions while the overlay is open).
            let backward = key.modifiers.contains(KeyModifiers::SHIFT);
            cycle_transcript_overlay_filter(app, backward);
            true
        }
        KeyCode::Char('d') | KeyCode::Char('D')
            if !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::META) =>
        {
            // Open / close the diff/detail pane (§11G.10) for the focused entry.
            // Like `m`/`f`, an overlay-local key handled here (the global keymap
            // dispatch guard blocks non-toggle actions while the overlay is up).
            toggle_diff_detail_pane(app);
            true
        }
        KeyCode::Char('e') | KeyCode::Char('E')
            if !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::META) =>
        {
            // Expand every entry. Force `detail = Collapsed` so the per-entry
            // `collapsed` flag is honoured in the overlay (Expanded would force
            // every body open regardless of the flag, hiding the effect); the
            // expand still applies inline after the overlay closes.
            let n = set_all_transcript_collapsed(app, false);
            if let Some(state) = app.transcript_overlay.as_mut() {
                state.detail = OverlayDetail::Collapsed;
            }
            set_transcript_overlay_scroll(app, TRANSCRIPT_OVERLAY_SCROLL_BOTTOM);
            app.status = format!("expanded all entries ({n} updated)");
            true
        }
        KeyCode::Char('c') | KeyCode::Char('C')
            if !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::META) =>
        {
            // Collapse every entry. `detail = Collapsed` so the fold is visible
            // in the overlay too (not just inline after it closes).
            let n = set_all_transcript_collapsed(app, true);
            if let Some(state) = app.transcript_overlay.as_mut() {
                state.detail = OverlayDetail::Collapsed;
            }
            set_transcript_overlay_scroll(app, TRANSCRIPT_OVERLAY_SCROLL_BOTTOM);
            app.status = format!("collapsed all entries ({n} updated)");
            true
        }
        _ => true, // swallow everything else so the overlay stays modal
    }
}

/// Advance the overlay's entry filter to the next (or previous, when
/// `backward`) variant in [`overlay_filter_cycle`], wrapping around. Resets the
/// overlay scroll to the bottom (the filtered row count changed, so the old
/// offset is meaningless) and reports the new filter in the status line.
fn cycle_transcript_overlay_filter(app: &mut TuiApp, backward: bool) {
    let tool_names = distinct_overlay_tool_names(active_transcript_entries(app));
    let cycle = overlay_filter_cycle(&tool_names);
    let Some(state) = app.transcript_overlay.as_mut() else {
        return;
    };
    let current = cycle.iter().position(|f| *f == state.filter).unwrap_or(0);
    let len = cycle.len();
    let next = if backward {
        (current + len - 1) % len
    } else {
        (current + 1) % len
    };
    state.filter = cycle[next];
    let label = state.filter.label(&tool_names);
    set_transcript_overlay_scroll(app, TRANSCRIPT_OVERLAY_SCROLL_BOTTOM);
    app.status = format!("filter: {label}");
}

fn toggle_transcript_overlay_mouse_capture(app: &mut TuiApp) {
    if let Some(state) = app.transcript_overlay.as_mut() {
        state.mode = match state.mode {
            TranscriptOverlayMode::NativeSelection => TranscriptOverlayMode::ScrollbarDrag,
            TranscriptOverlayMode::ScrollbarDrag => TranscriptOverlayMode::NativeSelection,
        };
        let capture = state.mode.mouse_capture();
        app.status = if capture {
            "transcript scrollbar drag on (Shift-drag selects text)"
        } else {
            "transcript native selection mode"
        }
        .to_string();
        // Mouse Hover Intent (§12.1.3): turning capture off (native-selection
        // mode) means the terminal stops forwarding reliable motion, so suppress
        // (and hide) any hover reveal and reset the recognizer's hover arm. The
        // reveal degrades to keyboard focus, exactly the spec's fallback. The
        // set+clear records the honest reason for the transition without latching.
        if !capture {
            app.hover_intent
                .set_suppression(Some(hover_intent::SuppressReason::CaptureOff));
            app.hover_intent.set_suppression(None);
            app.gestures.reset();
        }
    }
}

/// Consume a multi-select verb (§11G.7) while the reorder overlay is open.
///
/// Returns `true` when the key was a group verb (so the caller stops). The
/// bindings, all modal to the overlay:
///   - `Space` / `x` — toggle the focused prompt in/out of the group.
///   - `a` — select all queued prompts.
///   - `Esc`-adjacent: `c` clears the group without closing the overlay.
///   - `m` — merge the group (or the focused prompt) into the composer.
///   - `Delete` / `Backspace` — when the group is non-empty, delete the group;
///     an empty group falls through to the single-item delete.
///   - `Shift+Up` / `Shift+Down` — when the group is non-empty, move the group;
///     an empty group falls through to the single-item swap.
///
/// All bindings are plain or shifted printable keys (no Ctrl/Alt chord), so
/// none collide with the global keymap (`dispatch_keymap_action` runs first but
/// has no binding for these) and the overlay keeps owning them.
fn handle_queue_multiselect_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    use crossterm::event::{KeyCode, KeyModifiers};
    let shift = key.modifiers.contains(KeyModifiers::SHIFT);
    let group_active = !app.prompt_queue_multiselect.is_empty();
    match key.code {
        KeyCode::Char(' ') | KeyCode::Char('x') | KeyCode::Char('X') => {
            queue_toggle_focused_multiselect(app);
            true
        }
        KeyCode::Char('a') | KeyCode::Char('A') => {
            queue_select_all_multiselect(app);
            true
        }
        KeyCode::Char('c') | KeyCode::Char('C') if group_active => {
            app.prompt_queue_multiselect.clear();
            app.status = "selection cleared".to_string();
            app.needs_redraw = true;
            true
        }
        KeyCode::Char('m') | KeyCode::Char('M') => {
            queue_merge_to_composer(app);
            true
        }
        // Queue Groups (§12.3.4). `g` folds the tagged (or focused) prompts into
        // a named batch; `Shift+g` (`G`) dissolves the group under focus;
        // `z` collapses/expands it; `p` pauses/resumes it (a paused group's
        // prompts are skipped by the drain pump). All are plain printable keys
        // not used by the existing overlay verbs, so they keep the overlay's
        // "consume before the global keymap" pattern without colliding. `G` is
        // matched before `g` so the shifted variant is not swallowed as a bare
        // group-create.
        KeyCode::Char('G') => {
            queue_group_dissolve_focused(app);
            true
        }
        KeyCode::Char('g') => {
            queue_create_group_from_selection(app);
            true
        }
        KeyCode::Char('z') | KeyCode::Char('Z') => {
            queue_group_toggle_collapse_focused(app);
            true
        }
        KeyCode::Char('p') | KeyCode::Char('P') => {
            queue_group_toggle_pause_focused(app);
            true
        }
        // Conditional Queue Items (§12.3.5). `v` cycles the focused prompt's
        // run-condition (always → if-succeeded → if-failed → if-edited →
        // if-no-edits → manual → always). A plain printable key not used by any
        // other overlay verb, so it keeps the "consume before the global keymap"
        // pattern without colliding.
        KeyCode::Char('v') | KeyCode::Char('V') => {
            queue_cycle_condition_focused(app);
            true
        }
        // Group delete / move only claim the key when a group is active; an
        // empty group falls through to `PromptQueueState::dispatch` so the
        // single-row Delete / Shift+arrow semantics are unchanged.
        KeyCode::Delete | KeyCode::Backspace if group_active => {
            queue_group_delete(app);
            true
        }
        KeyCode::Up if shift && group_active => {
            queue_group_move(app, prompt_queue_multiselect::MoveDir::Up);
            true
        }
        KeyCode::Down if shift && group_active => {
            queue_group_move(app, prompt_queue_multiselect::MoveDir::Down);
            true
        }
        _ => false,
    }
}

/// Handle a key while the prompt-queue reorder overlay is open.
///
/// The overlay keeps the established "consume keys before the global keymap"
/// pattern: it owns Up/Down (focus), Shift+Up/Down (reorder), and Delete via
/// `PromptQueueState::dispatch`, exactly as before. The new wrinkle is that
/// each manipulation must also keep the id sidecar aligned and record an undo
/// step. Rather than re-implement the cursor/swap/delete logic, we let
/// `dispatch` mutate the queue, then *reconcile*: diff the queue before/after
/// to recognise the single op that happened (delete or adjacent swap) and
/// mirror it onto the ids + undo stack. This reuses the pure-state dispatcher
/// (so its semantics and tests stay the single source of truth) while making
/// the mutation id-stable and undoable.
///
/// `QueueUndo` (bare `u`) is handled earlier by `dispatch_keymap_action`; it
/// never reaches here. Esc/Enter close the overlay.
fn handle_prompt_queue_overlay_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    if app.prompt_queue_overlay.is_none() {
        return false;
    }
    // Multi-select verbs (§11G.7) are consumed here, before the pure
    // `PromptQueueState::dispatch`. They follow the same "modal, before the
    // global keymap" pattern as the rest of the overlay's keys. When the group
    // is empty the group-aware bindings (Delete / Shift+Up/Down) fall through to
    // the single-item dispatch below, so the base overlay is unchanged. None of
    // these keys (Space / a / c / m / group Delete / Shift+arrow) overlap the
    // edit verbs below, so the two interceptors compose cleanly.
    if handle_queue_multiselect_key(app, key) {
        return true;
    }
    // Edit Queued Prompt (§11G.8): Enter or `e` on the focused queued prompt
    // opens it in the composer for editing. Intercepted ahead of the pure-state
    // dispatch (which would otherwise treat Enter as "close"), and only when the
    // queue is non-empty — on an empty queue Enter must still fall through to
    // close the overlay as before. `e` carries no modifiers so it never
    // shadows a chord. Esc stays a plain close (handled by `dispatch`).
    let wants_edit = matches!(key.code, KeyCode::Enter)
        || (matches!(key.code, KeyCode::Char('e'))
            && !key
                .modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER));
    if wants_edit && !app.prompt_queue.is_empty() {
        sync_queue_ids(app);
        let selected = app
            .prompt_queue_overlay
            .as_ref()
            .expect("checked is_some above")
            .selected;
        if let Some(&id) = app.prompt_queue_ids.get(selected) {
            begin_queue_edit(app, id);
        }
        // Whether or not the edit started, the key is consumed by the overlay
        // (it never leaks into the composer underneath).
        return true;
    }
    // Run Selected Queued Next (§11G.9): `r` promotes the focused queued prompt
    // to the front so it runs ahead of the rest of the queue (immediately when
    // idle, on turn-finish when busy). Intercepted ahead of the pure-state
    // dispatch like the edit verb. `r` carries no modifiers so it never shadows a
    // chord; the key is consumed by the overlay whether or not it changed
    // anything (an empty queue / already-front-while-busy is a quiet no-op rather
    // than leaking into the composer).
    let wants_run_next = matches!(key.code, KeyCode::Char('r') | KeyCode::Char('R'))
        && !key
            .modifiers
            .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER);
    if wants_run_next {
        queue_run_selected_next(app);
        return true;
    }
    sync_queue_ids(app);
    let before: Vec<String> = app.prompt_queue.iter().cloned().collect();
    // Capture the cursor's stable identity BEFORE the dispatch mutates the
    // queue. `PromptQueueState` deletes/swaps relative to `selected`, so this
    // is the exact slot the op acts on — id-exact like the mouse path, immune
    // to the adjacent-duplicate ambiguity a before/after value diff has.
    let cursor = {
        let state = app
            .prompt_queue_overlay
            .as_ref()
            .expect("checked is_some above");
        let selected = state.selected;
        PreDispatchCursor {
            selected,
            id: app.prompt_queue_ids.get(selected).copied(),
            prev_id: queue_prev_id_at(app, selected),
        }
    };
    let mut state = app
        .prompt_queue_overlay
        .take()
        .expect("checked is_some above");
    let outcome = state.dispatch(&mut app.prompt_queue, key);
    app.prompt_queue_overlay = Some(state);
    match outcome {
        prompt_queue::QueueDispatch::Close => {
            app.prompt_queue_overlay = None;
            app.prompt_queue_drag = None;
            // A multi-selection is scoped to the open overlay; closing drops it.
            app.prompt_queue_multiselect.clear();
            app.status = "prompt queue closed".to_string();
        }
        prompt_queue::QueueDispatch::Handled => {
            reconcile_queue_after_dispatch(app, &before, cursor, key);
        }
        // Stay modal: swallow the key so stray input can't leak into the
        // composer while the overlay owns the surface.
        prompt_queue::QueueDispatch::Ignored => {}
    }
    true
}

/// The overlay cursor's identity captured *before* `dispatch`, so the id
/// sidecar + undo can be reconciled against the exact slot the keyboard op
/// acted on (rather than re-inferred by diffing queue contents, which is
/// ambiguous when adjacent items are equal).
#[derive(Debug, Clone, Copy)]
struct PreDispatchCursor {
    /// The focused index at dispatch time (the slot delete/swap acts on).
    selected: usize,
    /// The stable id at `selected` (None if the queue was empty).
    id: Option<u64>,
    /// The stable id immediately before `selected` (None if it was the front).
    prev_id: Option<u64>,
}

/// After `PromptQueueState::dispatch` mutated `prompt_queue`, mirror the one
/// op it performed onto the id sidecar + undo stack. `before` is the queue's
/// contents prior to the dispatch; `cursor` is the focused slot's identity
/// captured before dispatch; `key` is the dispatched key so a swap (Shift+↑/↓)
/// is told apart from a pure cursor move (↑/↓) WITHOUT diffing the content —
/// the content diff is ambiguous when adjacent items are textually identical.
/// Recognises exactly the two mutating ops the dispatcher can do — a single
/// delete (length shrank by one) or an adjacent swap (same length) — and leaves
/// the ids untouched for a pure cursor move. Both ops key off `cursor` (the exact
/// acted-on slot), so they stay id-exact even for adjacent duplicate prompts.
fn reconcile_queue_after_dispatch(
    app: &mut TuiApp,
    before: &[String],
    cursor: PreDispatchCursor,
    key: KeyEvent,
) {
    let after_len = app.prompt_queue.len();
    if after_len + 1 == before.len() {
        // A delete: `PromptQueueState::delete` removed `cursor.selected`, so
        // that exact index/id is the removed slot — no diffing, no ambiguity
        // with leading duplicates.
        let index = cursor.selected.min(before.len() - 1);
        let next_id = app.next_queue_id;
        let id = app
            .prompt_queue_ids
            .remove(index)
            .or(cursor.id)
            .unwrap_or(next_id);
        push_queue_undo(
            app,
            QueueMutation::Deleted {
                index,
                id,
                text: before[index].clone(),
            },
        );
        app.auto_drain_queue = false;
        app.status = format!("deleted queued prompt ({after_len} left)");
        app.needs_redraw = true;
    } else if after_len == before.len() {
        // Either a pure cursor move (queue unchanged) or an adjacent swap. Only
        // Shift+↑/↓ swaps — a bare ↑/↓ just moves the cursor. Classify off the key
        // (not a content diff) so two identical adjacent prompts that swap are
        // still mirrored onto the id sidecar. The dispatcher updates `selected` to
        // follow the moved item, so a real swap shifts it by ±1; an edge swap
        // (Shift+↑ at the front / Shift+↓ at the back) is a no-op and leaves it
        // put — detected by `new_selected == cursor.selected`.
        let is_swap_key = matches!(key.code, KeyCode::Up | KeyCode::Down)
            && key.modifiers.contains(KeyModifiers::SHIFT);
        let new_selected = app
            .prompt_queue_overlay
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(cursor.selected);
        if is_swap_key && new_selected != cursor.selected {
            // The two swapped slots are the cursor's old and new positions; their
            // lower index is the left member of the swapped pair.
            let lo = cursor.selected.min(new_selected);
            if lo + 1 < app.prompt_queue_ids.len() {
                // Mirror the swap on the ids and record undo by the moved item's
                // stable id (the one at `cursor.selected`) + its original
                // left-neighbour, so undo survives a front-drain.
                app.prompt_queue_ids.swap(lo, lo + 1);
                if let Some(id) = cursor.id {
                    push_queue_undo(
                        app,
                        QueueMutation::Reordered {
                            id,
                            prev: cursor.prev_id,
                        },
                    );
                }
                app.status = "moved queued prompt".to_string();
                app.needs_redraw = true;
            }
        }
        // else: cursor-only move (or an edge no-op swap) — nothing to mirror.
    }
    clamp_queue_focus(app);
}

/// Handle a mouse event while the prompt-queue reorder overlay is open.
///
/// Returns `Some(consumed)` when the event belongs to the overlay (so the
/// caller stops), or `None` to fall through to the transcript arms (e.g. a
/// wheel scroll, or a press outside any queue affordance). The recognizer's
/// `DragState` is the sole drag authority here, disjoint from the scrollbar
/// and text-selection drags.
fn handle_queue_overlay_mouse(
    app: &mut TuiApp,
    mouse: crossterm::event::MouseEvent,
) -> Option<bool> {
    use crossterm::event::MouseButton;
    let now = std::time::Instant::now();
    // The always-on fullscreen renderer registers the queue-item targets in
    // absolute screen coordinates, so the hit-test runs against the raw mouse
    // row — the same coordinate convention the painted rows use.
    let hit_test = |app: &TuiApp, mouse: &crossterm::event::MouseEvent| {
        app.click_target_at(mouse.column, mouse.row)
    };
    use crossterm::event::KeyModifiers;
    // A modified press (Ctrl or Shift) toggles multi-select instead of
    // arming a drag/delete — the mouse twin of the keyboard Space toggle
    // (§11G.7). Crossterm only reports mouse modifiers when key-modifier
    // capture is on, so the keyboard Space path remains the always-available
    // equivalent.
    let multiselect_chord = mouse
        .modifiers
        .intersects(KeyModifiers::CONTROL | KeyModifiers::SHIFT);
    match mouse.kind {
        MouseEventKind::Down(MouseButton::Left) => {
            let hit = hit_test(app, &mouse);
            // Only claim presses that land on a queue item; a press elsewhere
            // (e.g. the indicator strip, handled by the footer arm, or empty
            // space) falls through.
            match hit {
                Some((interaction::TargetKey::QueueItem(id), _)) if multiselect_chord => {
                    // Ctrl/Shift-click toggles the row's group membership
                    // (§11G.7) — checked before the plain-click delete/reorder/
                    // double-click-edit logic so a modified click never deletes
                    // or arms a drag.
                    app.gestures.recognize(interaction::Phase::Press, hit, now);
                    queue_toggle_id_multiselect(app, id);
                    Some(true)
                }
                Some((interaction::TargetKey::QueueItem(id), action)) => {
                    let gesture = app.gestures.recognize(interaction::Phase::Press, hit, now);
                    // A double-click on a queue row opens it in the composer for
                    // editing (§11G.8) — the mouse twin of the keyboard Enter/`e`
                    // verb. A double-click on the delete `x` still deletes (the
                    // first click already removed the row), so only the body
                    // (`QueueReorderBegin`) escalates into an edit. A single
                    // click keeps its press behaviour: delete fires immediately;
                    // the body arms a reorder drag.
                    if matches!(gesture, interaction::Gesture::DoubleClick { .. })
                        && matches!(action, interaction::Action::QueueReorderBegin(_))
                    {
                        // The first click of the pair armed a (never-moved)
                        // reorder drag; the second escalates to an edit, so
                        // cancel that armed drag before opening the composer
                        // (otherwise `begin_queue_edit` would bail on the
                        // mid-drag guard).
                        app.prompt_queue_drag = None;
                        dispatch_click_action(app, interaction::Action::QueueEdit(id));
                    } else {
                        dispatch_click_action(app, action);
                    }
                    Some(true)
                }
                _ => None,
            }
        }
        // Right-click on a queue row runs it next (§11G.9) — the mouse twin of
        // the keyboard `r` verb. The left-button row is full (drag handle + delete
        // zone), so run-next rides the right button rather than crowding a third
        // left-click zone. Routes through the same `QueueRunNext` dispatch the
        // keyboard verb shares. A press off any queue item falls through.
        //
        // A Ctrl+Right-click instead cycles the row's run-condition (§12.3.5) —
        // the mouse twin of the keyboard `v` verb. Crossterm only reports mouse
        // modifiers when key-modifier capture is on, so the keyboard `v` remains
        // the always-available equivalent; this is the convenience overlay.
        MouseEventKind::Down(MouseButton::Right) => match hit_test(app, &mouse) {
            Some((interaction::TargetKey::QueueItem(id), _)) => {
                if mouse.modifiers.intersects(KeyModifiers::CONTROL) {
                    dispatch_click_action(app, interaction::Action::QueueCycleCondition(id));
                } else {
                    dispatch_click_action(app, interaction::Action::QueueRunNext(id));
                }
                Some(true)
            }
            _ => None,
        },
        // Middle-click on a queue row toggles the collapse of the group that owns
        // it (§12.3.4) — the mouse twin of the keyboard `z` verb. Both seat the
        // overlay focus on the row, then route through the same
        // `queue_group_toggle_collapse_by_id`, so the paths stay identical by
        // construction. A click on a loose (ungrouped) row or one that has since
        // drained out resolves to a quiet no-op. A press off any queue item falls
        // through.
        MouseEventKind::Down(MouseButton::Middle) => match hit_test(app, &mouse) {
            Some((interaction::TargetKey::QueueItem(id), _)) => {
                sync_queue_groups(app);
                if let Some(index) = queue_index_for_id(app, id) {
                    if let Some(state) = app.prompt_queue_overlay.as_mut() {
                        state.selected = index;
                    }
                    if let Some(gid) = app.prompt_queue_groups.group_id_of_item(id) {
                        queue_group_toggle_collapse_by_id(app, gid);
                    } else {
                        app.status = "queued prompt is not in a group".to_string();
                        app.needs_redraw = true;
                    }
                }
                Some(true)
            }
            _ => None,
        },
        // Drag/Release are only queue gestures while a reorder drag is armed;
        // otherwise fall through (a held drag with no queue drag is a
        // text-selection / scrollbar gesture the later arms own).
        MouseEventKind::Drag(MouseButton::Left) if app.prompt_queue_drag.is_some() => {
            let hit = hit_test(app, &mouse);
            app.gestures.recognize(interaction::Phase::Drag, hit, now);
            queue_drag_move_to(app, hit);
            Some(true)
        }
        MouseEventKind::Up(MouseButton::Left) if app.prompt_queue_drag.is_some() => {
            let hit = hit_test(app, &mouse);
            app.gestures
                .recognize(interaction::Phase::Release, hit, now);
            finalize_queue_drag(app);
            Some(true)
        }
        // Wheel / move / other buttons are not queue gestures.
        _ => None,
    }
}

/// During a reorder drag, move the dragged item live to the row currently
/// under the pointer. The destination is derived from the hovered
/// `QueueItem` id (id→position), never from the raw pointer row, so a resize
/// mid-drag re-resolves cleanly. Intermediate hops are NOT pushed to the undo
/// stack; only the whole-gesture move is recorded on release.
fn queue_drag_move_to(
    app: &mut TuiApp,
    hit: Option<(interaction::TargetKey, interaction::Action)>,
) {
    let Some(drag) = app.prompt_queue_drag else {
        return;
    };
    let Some((interaction::TargetKey::QueueItem(over_id), _)) = hit else {
        return;
    };
    sync_queue_ids(app);
    let (Some(from), Some(to)) = (
        queue_index_for_id(app, drag.id),
        queue_index_for_id(app, over_id),
    ) else {
        return;
    };
    if from == to {
        return;
    }
    queue_move_indices(app, from, to);
    if let Some(state) = app.prompt_queue_overlay.as_mut() {
        state.selected = to;
    }
    app.status = "moving queued prompt".to_string();
    app.needs_redraw = true;
}

/// Finalize a reorder drag on release: record the whole-gesture move (start
/// position → final position) on the undo stack, then clear the drag state.
fn finalize_queue_drag(app: &mut TuiApp) {
    let Some(drag) = app.prompt_queue_drag.take() else {
        return;
    };
    sync_queue_ids(app);
    if let Some(to) = queue_index_for_id(app, drag.id)
        && to != drag.from
    {
        // Record by stable id + the id that originally preceded the dragged
        // item (captured at drag start), so undo survives a front-drain.
        push_queue_undo(
            app,
            QueueMutation::Reordered {
                id: drag.id,
                prev: drag.prev,
            },
        );
        app.status = "moved queued prompt".to_string();
        app.needs_redraw = true;
    }
}

fn queue_input_behind_running_turn(app: &mut TuiApp, input: String) {
    app.prune_prompt_attachments();
    if app
        .prompt_attachments
        .iter()
        .any(|attachment| input.contains(&attachment.placeholder))
    {
        app.status = "prompt attachments cannot be queued; wait for the current turn".to_string();
        return;
    }
    app.prompt_queue.push_back(input.clone());
    enqueue_queue_id(app);
    clear_input(app);
    push_input_history(app, input);
    app.input_history_index = None;
    app.input_history_draft.clear();
    app.slash_menu_index = 0;
    app.status = format!("queued ({})", app.prompt_queue.len());
}

/// The Conditional Queue Items (§12.3.5) + Queue Groups (§12.3.4) drain decision
/// for the current front of the queue, computed from the live id sidecar and the
/// two state maps. Pure-state lives in `queue_conditions::plan_drain`; this just
/// materialises the per-item facts (paused flag + condition) in queue order and
/// hands them over. Assumes `sync_queue_ids` + `retain_live` ran so the sidecar
/// and maps are aligned with the live queue.
pub(crate) fn queue_drain_action(app: &TuiApp) -> queue_conditions::DrainAction {
    let items: Vec<queue_conditions::DrainItem> = app
        .prompt_queue_ids
        .iter()
        .map(|id| queue_conditions::DrainItem {
            paused: app.prompt_queue_groups.is_item_paused(*id),
            condition: app.prompt_queue_conditions.get(*id),
        })
        .collect();
    queue_conditions::plan_drain(&items, app.last_turn_outcome)
}

pub(crate) async fn drain_prompt_queue_if_idle(app: &mut TuiApp, agent: &mut Agent) {
    while app.turn_rx.is_none() && !prompt_queue_drain_blocked(app) {
        // Keep the id sidecar aligned before consulting the group/condition models
        // so a front-drain since the last tick can't stale the pause / condition
        // lookup. Prune conditions for any drained id too, so the gate never reads
        // a phantom condition.
        sync_queue_ids(app);
        let live_ids = queue_live_ids(app);
        app.prompt_queue_conditions.retain_live(&live_ids);
        match queue_drain_action(app) {
            queue_conditions::DrainAction::Run(index) => {
                let Some(next) = app.prompt_queue.remove(index) else {
                    return;
                };
                // Carry the id sidecar with the removed slot so the two stay aligned.
                app.prompt_queue_ids.remove(index);
                // The pump can run while the reorder overlay is open (it omits
                // `prompt_queue_overlay` from `prompt_queue_drain_blocked`), so the
                // queue just shrank under the cursor. `selected` is the one piece of
                // overlay state that is NOT id-stabilised, so clamp it before the
                // next iteration or it could exceed `len - 1` and make Enter/'e'/'r'
                // resolve `ids.get(selected)` to `None` (a dead key).
                clamp_queue_focus(app);
                let remaining = app.prompt_queue.len();
                app.status = if remaining == 0 {
                    "running queued prompt".to_string()
                } else {
                    format!("running queued prompt ({remaining} more queued)")
                };
                submit_queued_input(app, agent, next).await;
            }
            queue_conditions::DrainAction::Drop(index) => {
                // The item's "if previous X" condition can't be satisfied by this
                // outcome: drop it (the §12.3.5 "skipped" state) and re-plan. We
                // carry the id sidecar with the slot and loop without running a
                // turn, so a run of skip-bound prompts clears in order.
                let skipped = app.prompt_queue.remove(index);
                let skipped_id = app.prompt_queue_ids.remove(index);
                if let Some(text) = skipped {
                    let preview = text.lines().next().unwrap_or("").trim();
                    app.push_log(format!(
                        "skipped queued prompt (condition not met): {preview}"
                    ));
                    // A condition-skip silently removes a queued prompt the user
                    // wrote, so record it on the undo stack (mirroring a manual
                    // delete) — QueueUndo can then recover an `IfPrevFailed`
                    // recovery prompt that was dropped after a success, etc.
                    if let Some(id) = skipped_id {
                        push_queue_undo(app, QueueMutation::Deleted { index, id, text });
                    }
                }
                // Same as the Run arm: the queue shrank under an open overlay, so
                // stabilise the positional cursor before re-planning.
                clamp_queue_focus(app);
                app.status = format!("skipped queued prompt ({} left)", app.prompt_queue.len());
                app.needs_redraw = true;
                // Loop: re-plan against the now-shorter queue.
            }
            queue_conditions::DrainAction::Stop => return,
        }
    }
}

fn prompt_queue_drain_blocked(app: &TuiApp) -> bool {
    app.config_screen.is_some()
        || app.status_line_setup.is_some()
        || app.transcript_overlay.is_some()
        || app.overlay.is_some()
        || app.paste_preview.is_some()
        || app.paste_transform.is_some()
        || app.pending_approval.is_some()
        || app.pending_mcp_elicitation.is_some()
        || app.pending_request_user_input.is_some()
        || app.pending_plan_choice.is_some()
        || app.pending_feedback.is_some()
}

async fn submit_queued_input(app: &mut TuiApp, agent: &mut Agent, raw_input: String) {
    let input = raw_input.trim().to_string();
    if input.is_empty() {
        app.status = "skipped empty queued prompt".to_string();
        return;
    }
    if handle_slash_command(app, agent, &input).await {
        app.input_history_index = None;
        app.input_history_draft.clear();
        app.slash_menu_index = 0;
        return;
    }
    if handle_inline_slash_command(app, agent, &raw_input).await {
        return;
    }
    if reject_unknown_slash_command(app, &input) {
        return;
    }
    app.cancelled_prompt = Some(input.clone());
    start_user_turn(app, agent, input);
}

/// Kick off a user-driven turn. Drains any pending config swap, consumes a
/// queued plan handoff (prepending the plan body to `input`), and hands
/// the resulting prompt to the agent. Used by the Enter key handler and
/// by the post-plan Execute action so both paths share the same plan
/// prefix and turn-state bookkeeping.
pub(crate) fn start_user_turn(app: &mut TuiApp, agent: &mut Agent, input: String) {
    let prompt = prepare_prompt_turn_input(app, input);
    start_user_turn_prepared(app, agent, prompt);
}

#[derive(Debug, Clone)]
struct PreparedPromptTurn {
    display_input: String,
    model_input: String,
    transient_input_items: Vec<LlmInputItem>,
}

fn prepare_prompt_turn_input(app: &mut TuiApp, input: String) -> PreparedPromptTurn {
    app.prune_prompt_attachments();
    let mut model_input = input.clone();
    let mut transient_input_items = Vec::new();
    for attachment in app.prompt_attachments.clone() {
        if !input.contains(&attachment.placeholder) {
            continue;
        }
        match attachment.payload {
            PromptAttachmentPayload::Text { replacement, .. } => {
                model_input = model_input.replace(&attachment.placeholder, &replacement);
            }
            PromptAttachmentPayload::Image { media_type, bytes } => {
                transient_input_items.push(LlmInputItem::Image { media_type, bytes });
            }
        }
    }
    PreparedPromptTurn {
        display_input: input,
        model_input,
        transient_input_items,
    }
}

fn start_user_turn_prepared(app: &mut TuiApp, agent: &mut Agent, prompt: PreparedPromptTurn) {
    if let Some(swap) = agent.drain_pending_swap() {
        app.provider_name = swap
            .provider
            .as_ref()
            .map(|provider| provider.name())
            .unwrap_or_else(|| squeezy_llm::provider_name(&swap.config.provider));
        app.apply_config_change(&swap.config);
        let note = swap
            .display_note
            .clone()
            .unwrap_or_else(|| "config applied".to_string());
        app.push_status(format!("✓ applied: {note}"));
    }
    let cancel = CancellationToken::new();
    app.task_state = None;
    app.task_panel_collapsed = false;
    app.note_turn_started();
    let (display_input, model_input) = match take_pending_plan_prefix(app) {
        Some(prefix) => (
            format!("{prefix}{}", prompt.display_input),
            format!("{prefix}{}", prompt.model_input),
        ),
        None => (prompt.display_input, prompt.model_input),
    };
    app.turn_rx = Some(agent.start_turn_with_display_input(
        display_input,
        model_input,
        prompt.transient_input_items,
        cancel.clone(),
        app.response_verbosity,
    ));
    app.cancel = Some(cancel);
    app.status = "starting turn".to_string();
    app.turn_visual = TurnVisualState::Running;
}

/// If a Plan→Build handoff is queued, return the prefix to prepend to the
/// next user input. Turn 0 (the first call after Plan→Build) returns the
/// full plan body so the model receives it verbatim; turns 1+ return a
/// short `[plan still in effect — <path>]` marker so the plan continues
/// to anchor the conversation without re-paying body tokens each turn
/// (issue 16). The handoff is cleared automatically when the file is
/// missing; routine clears (Build→Plan, discard, successful apply_patch)
/// happen elsewhere.
/// Strip the plan-handoff prefix that [`take_pending_plan_prefix`] prepended
/// to the user-typed text. The agent still receives the full wrapped body —
/// this only hides the duplicate echo in the rendered transcript, because the
/// Plan card a few entries above already shows the same body. Returns `None`
/// when the message has no plan-handoff prefix.
pub(crate) fn strip_plan_handoff_prefix(content: &str) -> Option<String> {
    let mut rest = content;
    let mut changed = false;

    if let Some(after) = rest.strip_prefix("[resuming from plan ")
        && let Some(end) = after.find("]\n")
    {
        rest = &after[end + 2..];
        changed = true;
    }

    if let Some(after) = rest.strip_prefix("[plan from previous session — ")
        && let Some(header_end) = after.find("]\n")
    {
        let body_start = &after[header_end + 2..];
        if let Some(close) = body_start.find("\n[end plan]\n") {
            let mut tail = &body_start[close + "\n[end plan]\n".len()..];
            tail = tail.strip_prefix('\n').unwrap_or(tail);
            rest = tail;
            changed = true;
        }
    } else if let Some(after) = rest.strip_prefix("[plan still in effect — ")
        && let Some(end) = after.find("]\n")
    {
        let mut tail = &after[end + 2..];
        tail = tail.strip_prefix('\n').unwrap_or(tail);
        rest = tail;
        changed = true;
    }

    if changed {
        Some(rest.to_string())
    } else {
        None
    }
}

fn take_pending_plan_prefix(app: &mut TuiApp) -> Option<String> {
    let plan_path = app.pending_plan_handoff.clone()?;
    if app.plan_handoff_turns_seen > 0 {
        // Subsequent turns: lightweight marker.
        let marker = proposed_plan::BUILD_PLAN_STILL_IN_EFFECT_FORMAT
            .replace("{path}", &plan_path.display().to_string());
        return Some(marker);
    }
    // Strip the YAML front-matter (PR-D) before handing the body off
    // to the model: the model should see the plan content, not the
    // metadata block that the TUI uses for /plans rendering.
    match proposed_plan::read_plan_body(&plan_path) {
        Ok(body) => {
            let trimmed = body.trim_end();
            app.plan_handoff_turns_seen = app.plan_handoff_turns_seen.saturating_add(1);
            // PR-G item 6: when this Plan→Build crossing is a resume
            // from a Shift+Tab pause, prefix the body with a short
            // marker so the model knows it's mid-execution and learns
            // whether the plan was refined during the pause window.
            let resume_marker = app.plan_resume_marker.take().unwrap_or_default();
            Some(format!(
                "{resume_marker}[plan from previous session — {path}]\n{trimmed}\n[end plan]\n\n",
                path = plan_path.display(),
            ))
        }
        Err(err) => {
            app.push_log(format!(
                "could not read plan file {} for Build handoff: {err}",
                compact_path(&plan_path)
            ));
            app.pending_plan_handoff = None;
            app.plan_handoff_turns_seen = 0;
            None
        }
    }
}

fn switch_mode(
    app: &mut TuiApp,
    agent: &Agent,
    requested: Option<SessionMode>,
    source: &'static str,
) {
    let target = requested.unwrap_or(match app.mode {
        SessionMode::Plan => SessionMode::Build,
        SessionMode::Build => SessionMode::Plan,
    });
    // PR-G item 6: Build→Plan with an in-flight turn AND an active
    // plan is a *pause*, not a refusal. Cancel the turn, capture the
    // plan id so the next Plan→Build crossing can emit a resume
    // marker, and fall through to the normal switch path.
    let is_build_to_plan_pause = app.mode == SessionMode::Build
        && target == SessionMode::Plan
        && app.turn_rx.is_some()
        && app.current_plan_id.is_some();
    if is_build_to_plan_pause {
        request_turn_interrupt(app);
        app.plan_pause = app
            .current_plan_id
            .clone()
            .map(|plan_id| PlanPauseState { plan_id });
        app.push_status("plan execution paused (Shift+Tab)".to_string());
    }

    if !is_build_to_plan_pause
        && (app.turn_rx.is_some()
            || app.pending_approval.is_some()
            || app.pending_mcp_elicitation.is_some()
            || app.pending_request_user_input.is_some()
            || app.pending_feedback.is_some())
    {
        app.status = "mode switch unavailable during active turn".to_string();
        return;
    }

    if target == app.mode {
        app.status = format!("already in {} mode", app.mode.as_str());
        return;
    }
    let previous = app.mode;
    if agent.set_session_mode(target, source) {
        app.mode = target;
        app.status = format!("mode switched to {}", app.mode.as_str());
        // A mode switch supersedes any post-plan choice prompt — the
        // user's decision has been made by toggling the mode itself.
        app.pending_plan_choice = None;
        match (previous, target) {
            (SessionMode::Plan, SessionMode::Build) => {
                if let Some(plan_id) = app.current_plan_id.as_deref() {
                    let sid = app.plan_session_id().to_string();
                    let plan_path =
                        proposed_plan::plan_file_for(&app.workspace_root, &sid, plan_id);
                    if plan_path.exists() {
                        app.pending_plan_handoff = Some(plan_path.clone());
                        // Fresh handoff: next Build turn gets the full plan
                        // body; turns 2+ get the lighter marker.
                        app.plan_handoff_turns_seen = 0;
                        // Resume marker (PR-G item 6): if the previous
                        // Build→Plan was a pause, tell the model which
                        // plan id it resumes from and whether the body
                        // changed during the pause window.
                        if let Some(pause) = app.plan_pause.take() {
                            let refined = pause.plan_id != plan_id;
                            let note = if refined {
                                format!(
                                    "[resuming from plan {plan_id} — plan refined since previous attempt ({prev})]\n",
                                    prev = pause.plan_id,
                                )
                            } else {
                                format!("[resuming from plan {plan_id} — plan unchanged]\n")
                            };
                            app.plan_resume_marker = Some(note);
                        }
                        app.push_status(format!(
                            "plan attached for next Build turn: {}",
                            compact_path(&plan_path)
                        ));
                    }
                }
            }
            (SessionMode::Build, SessionMode::Plan) => {
                // A handoff queued by an earlier Plan→Build switch is no
                // longer relevant once the user goes back to Plan; drop it
                // so the next Build entry recomputes from the current
                // plan file instead of attaching a stale path.
                app.pending_plan_handoff = None;
                app.plan_handoff_turns_seen = 0;
            }
            _ => {}
        }
    } else {
        // Agent saw no change (lock-free path is infallible, so this only
        // fires when the agent observed the same mode we requested). Resync
        // the visible status with the underlying truth so the user sees the
        // authoritative state.
        app.mode = agent.session_mode();
        app.status = format!("already in {} mode", app.mode.as_str());
    }
}

fn handle_mcp_elicitation_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    let Some(pending) = app.pending_mcp_elicitation.take() else {
        return false;
    };
    let is_form = pending.request.kind == McpElicitationKind::Form;

    if is_form
        && key.modifiers.contains(KeyModifiers::CONTROL)
        && (key.code == KeyCode::Char('j') || key.code == KeyCode::Enter)
    {
        insert_input_char(app, '\n');
        keep_mcp_elicitation_pending(app, pending);
        return true;
    }

    match key.code {
        KeyCode::Up => {
            app.mcp_elicitation_selection_index =
                app.mcp_elicitation_selection_index.saturating_sub(1);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Down => {
            app.mcp_elicitation_selection_index =
                (app.mcp_elicitation_selection_index + 1).min(mcp_elicitation_options().len() - 1);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Enter => {
            let option = mcp_elicitation_options()
                .get(app.mcp_elicitation_selection_index)
                .copied()
                .unwrap_or(MCP_ELICITATION_ACCEPT);
            send_mcp_elicitation_response(app, pending, option.choice)
        }
        KeyCode::Esc => send_mcp_elicitation_cancel(app, pending),
        KeyCode::Char('y') | KeyCode::Char('Y') => {
            send_mcp_elicitation_response(app, pending, McpElicitationChoice::Accept)
        }
        KeyCode::Char('n') | KeyCode::Char('N') | KeyCode::Char('d') | KeyCode::Char('D') => {
            send_mcp_elicitation_response(app, pending, McpElicitationChoice::Decline)
        }
        KeyCode::Backspace if is_form => {
            delete_before_cursor(app);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Delete if is_form => {
            delete_at_cursor(app);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Left if is_form => {
            move_input_cursor_left(app);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Right if is_form => {
            move_input_cursor_right(app);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Home if is_form => {
            app.input_cursor = 0;
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::End if is_form => {
            app.input_cursor = app.input.len();
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        KeyCode::Char(ch)
            if is_form && (key.modifiers.is_empty() || key.modifiers == KeyModifiers::SHIFT) =>
        {
            insert_input_char(app, ch);
            keep_mcp_elicitation_pending(app, pending);
            true
        }
        _ => {
            keep_mcp_elicitation_pending(app, pending);
            true
        }
    }
}

fn keep_mcp_elicitation_pending(app: &mut TuiApp, pending: PendingMcpElicitation) {
    app.status = format_mcp_elicitation_status_line(&pending.request);
    app.pending_mcp_elicitation = Some(pending);
}

fn send_mcp_elicitation_response(
    app: &mut TuiApp,
    pending: PendingMcpElicitation,
    choice: McpElicitationChoice,
) -> bool {
    match choice {
        McpElicitationChoice::Accept => {
            let content = if pending.request.kind == McpElicitationKind::Form {
                match parse_mcp_elicitation_form_content(&app.input) {
                    Ok(content) => Some(content),
                    Err(error) => {
                        app.status = error;
                        app.pending_mcp_elicitation = Some(pending);
                        return true;
                    }
                }
            } else {
                None
            };
            let server = pending.request.server.clone();
            let _ = pending
                .response_tx
                .send(McpElicitationResponse::accept(content));
            clear_input(app);
            app.mcp_elicitation_seeded_input = None;
            app.status = format!("accepted mcp request from {server}");
            true
        }
        McpElicitationChoice::Decline => {
            let server = pending.request.server.clone();
            let _ = pending.response_tx.send(McpElicitationResponse::decline());
            clear_mcp_elicitation_seeded_input(app);
            app.status = format!("declined mcp request from {server}");
            true
        }
    }
}

fn send_mcp_elicitation_cancel(app: &mut TuiApp, pending: PendingMcpElicitation) -> bool {
    let server = pending.request.server.clone();
    let _ = pending.response_tx.send(McpElicitationResponse::cancel());
    clear_mcp_elicitation_seeded_input(app);
    app.status = format!("cancelled mcp request from {server}");
    true
}

fn parse_mcp_elicitation_form_content(
    input: &str,
) -> std::result::Result<serde_json::Value, String> {
    let trimmed = input.trim();
    if trimmed.is_empty() {
        return Ok(serde_json::json!({}));
    }
    match serde_json::from_str::<serde_json::Value>(trimmed) {
        Ok(value @ serde_json::Value::Object(_)) => Ok(value),
        Ok(_) => Err("MCP form response must be a JSON object".to_string()),
        Err(error) => Err(format!("MCP form response JSON is invalid: {error}")),
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum McpElicitationChoice {
    Accept,
    Decline,
}

#[derive(Debug, Clone, Copy)]
struct McpElicitationOption {
    choice: McpElicitationChoice,
    label: &'static str,
    hint: &'static str,
}

const MCP_ELICITATION_ACCEPT: McpElicitationOption = McpElicitationOption {
    choice: McpElicitationChoice::Accept,
    label: "Accept",
    hint: "send response",
};

const MCP_ELICITATION_DECLINE: McpElicitationOption = McpElicitationOption {
    choice: McpElicitationChoice::Decline,
    label: "Decline",
    hint: "deny request",
};
const MCP_ELICITATION_SCHEMA_MAX_LINES: usize = 24;

fn mcp_elicitation_options() -> &'static [McpElicitationOption] {
    &[MCP_ELICITATION_ACCEPT, MCP_ELICITATION_DECLINE]
}

pub(crate) fn seed_mcp_elicitation_form_input(app: &mut TuiApp, request: &McpElicitationRequest) {
    app.mcp_elicitation_seeded_input = None;
    if request.kind != McpElicitationKind::Form || !app.input.trim().is_empty() {
        return;
    }
    let template = mcp_elicitation_form_template(request.schema.as_ref());
    app.input = template.clone();
    app.input_cursor = app.input.len();
    app.mcp_elicitation_seeded_input = Some(template);
}

pub(crate) fn clear_mcp_elicitation_seeded_input(app: &mut TuiApp) {
    if let Some(seeded) = app.mcp_elicitation_seeded_input.take()
        && app.input == seeded
    {
        clear_input(app);
    }
}

fn mcp_elicitation_form_template(schema: Option<&serde_json::Value>) -> String {
    let mut object = serde_json::Map::new();
    if let Some(schema) = schema {
        let properties = schema
            .get("properties")
            .and_then(serde_json::Value::as_object);
        let required = schema
            .get("required")
            .and_then(serde_json::Value::as_array)
            .map(|items| {
                items
                    .iter()
                    .filter_map(serde_json::Value::as_str)
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        if let Some(properties) = properties {
            let names: Vec<&str> = if required.is_empty() {
                properties.keys().map(String::as_str).collect()
            } else {
                required
            };
            for name in names {
                let value = properties
                    .get(name)
                    .map(schema_placeholder_value)
                    .unwrap_or(serde_json::Value::Null);
                object.insert(name.to_string(), value);
            }
        }
    }
    serde_json::to_string_pretty(&serde_json::Value::Object(object))
        .unwrap_or_else(|_| "{}".to_string())
}

fn schema_placeholder_value(schema: &serde_json::Value) -> serde_json::Value {
    if let Some(default) = schema.get("default") {
        return default.clone();
    }
    match schema.get("type").and_then(serde_json::Value::as_str) {
        Some("string") => serde_json::Value::String(String::new()),
        Some("integer") => serde_json::json!(0),
        Some("number") => serde_json::json!(0.0),
        Some("boolean") => serde_json::json!(false),
        Some("array") => serde_json::Value::Array(Vec::new()),
        Some("object") => serde_json::Value::Object(serde_json::Map::new()),
        _ => serde_json::Value::Null,
    }
}

fn handle_approval_key(app: &mut TuiApp, key: KeyEvent) -> bool {
    let Some(pending) = app.pending_approval.take() else {
        return false;
    };
    let options = approval_options_for(&pending.request);

    match key.code {
        KeyCode::Up => {
            app.approval_selection_index = app.approval_selection_index.saturating_sub(1);
            app.status = format_approval_status_line(&pending.request);
            app.pending_approval = Some(pending);
            true
        }
        KeyCode::Down => {
            app.approval_selection_index =
                (app.approval_selection_index + 1).min(options.len() - 1);
            app.status = format_approval_status_line(&pending.request);
            app.pending_approval = Some(pending);
            true
        }
        KeyCode::Enter => {
            let option = options
                .get(app.approval_selection_index)
                .cloned()
                .unwrap_or_else(approval_once);
            send_approval_decision(app, pending, option)
        }
        KeyCode::Char('y') | KeyCode::Char('Y') => {
            send_approval_decision(app, pending, approval_once())
        }
        KeyCode::Char('a') | KeyCode::Char('A') | KeyCode::Char('p') | KeyCode::Char('P') => {
            // Capability-scoped "always allow" — picks the per-capability
            // project option built by `approval_options_for`.
            let project = options
                .iter()
                .find(|opt| opt.choice == ApprovalChoice::ApproveProject)
                .cloned()
                .unwrap_or_else(approval_once);
            send_approval_decision(app, pending, project)
        }
        KeyCode::Char('n') | KeyCode::Char('N') | KeyCode::Char('d') | KeyCode::Char('D') => {
            send_approval_decision(app, pending, approval_deny())
        }
        _ => {
            app.status = format_approval_status_line(&pending.request);
            app.pending_approval = Some(pending);
            true
        }
    }
}

fn send_approval_decision(
    app: &mut TuiApp,
    pending: PendingApproval,
    option: ApprovalOption,
) -> bool {
    let tool_name = pending.request.tool_name.clone();
    let _ = pending.decision_tx.send(option.decision);
    app.status = match option.choice {
        ApprovalChoice::Approve => format!("approved {tool_name}"),
        ApprovalChoice::ApproveProject => format!("saved repo approval for {tool_name}"),
        ApprovalChoice::Deny => format!("denied {tool_name}"),
    };
    true
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ApprovalChoice {
    Approve,
    ApproveProject,
    Deny,
}

#[derive(Debug, Clone)]
struct ApprovalOption {
    choice: ApprovalChoice,
    label: std::borrow::Cow<'static, str>,
    hint: std::borrow::Cow<'static, str>,
    decision: ToolApprovalDecision,
}

impl ApprovalOption {
    const fn new_static(
        choice: ApprovalChoice,
        label: &'static str,
        hint: &'static str,
        decision: ToolApprovalDecision,
    ) -> Self {
        Self {
            choice,
            label: std::borrow::Cow::Borrowed(label),
            hint: std::borrow::Cow::Borrowed(hint),
            decision,
        }
    }
}

fn approval_once() -> ApprovalOption {
    ApprovalOption::new_static(
        ApprovalChoice::Approve,
        "Approve",
        "run this once",
        ToolApprovalDecision::AllowOnce,
    )
}

fn approval_deny() -> ApprovalOption {
    ApprovalOption::new_static(
        ApprovalChoice::Deny,
        "Deny",
        "skip this run",
        ToolApprovalDecision::DenyOnce,
    )
}

/// Build the per-capability allow/deny menu for a pending approval. The
/// menu keeps the obvious one-shot decision first, then offers one
/// project-scoped allow rule for users who want to persist the decision.
fn approval_options_for(request: &ToolApprovalRequest) -> Vec<ApprovalOption> {
    let (project_label, project_hint) = capability_project_label(request);
    let project = ApprovalOption {
        choice: ApprovalChoice::ApproveProject,
        label: project_label,
        hint: project_hint,
        decision: ToolApprovalDecision::AllowRuleProject,
    };
    vec![approval_once(), project, approval_deny()]
}

/// Returns `(project_label, project_hint)` for the persistent allow option.
/// Each label names the capability-specific target (binary, host, MCP
/// server/tool, write root) so the prompt makes the persisted rule shape
/// visible without forcing the user to read the rule-preview line.
fn capability_project_label(
    request: &ToolApprovalRequest,
) -> (
    std::borrow::Cow<'static, str>,
    std::borrow::Cow<'static, str>,
) {
    use std::borrow::Cow;
    let permission = &request.permission;
    let scope_name: Option<String> = match permission.capability {
        PermissionCapability::Shell => permission
            .metadata
            .get("binary")
            .cloned()
            .or_else(|| permission.metadata.get("shell_prefix").cloned()),
        PermissionCapability::Network => permission.metadata.get("host").cloned().or_else(|| {
            permission
                .target
                .strip_prefix("domain:")
                .map(str::to_string)
        }),
        PermissionCapability::Mcp => {
            let server = permission.metadata.get("server").cloned();
            let tool = permission.metadata.get("tool").cloned();
            match (server, tool) {
                (Some(server), Some(tool)) => Some(format!("{server}/{tool}")),
                (Some(server), None) => Some(server),
                _ => None,
            }
        }
        PermissionCapability::Edit => permission
            .metadata
            .get("write_root")
            .cloned()
            .or_else(|| permission.metadata.get("path").cloned()),
        PermissionCapability::Read | PermissionCapability::Search => permission
            .metadata
            .get("path")
            .cloned()
            .or_else(|| permission.metadata.get("query").cloned()),
        PermissionCapability::Git
        | PermissionCapability::Compiler
        | PermissionCapability::Destructive => None,
    };
    let Some(scope) = scope_name.and_then(|s| {
        let trimmed = s.trim().to_string();
        if trimmed.is_empty() || trimmed == "*" {
            None
        } else {
            Some(trimmed)
        }
    }) else {
        return (
            Cow::Borrowed("Always approve this command in this repo"),
            Cow::Borrowed("save a project rule"),
        );
    };
    let scope_display = compact_text(&scope, 60);
    let (kind, hint_kind) = match permission.capability {
        PermissionCapability::Shell => ("command", "command"),
        PermissionCapability::Network => ("host", "host"),
        PermissionCapability::Mcp => ("MCP tool", "MCP tool"),
        PermissionCapability::Edit => ("edits to", "edit target"),
        PermissionCapability::Read | PermissionCapability::Search => ("reads of", "read target"),
        PermissionCapability::Git
        | PermissionCapability::Compiler
        | PermissionCapability::Destructive => unreachable!(),
    };
    // On Windows, warn when the shell prefix being persisted is broad
    // (covers all commands run via pwsh, cmd, etc.) because the lower sandbox
    // tiers leave approval as the boundary for reads and/or network.
    let windows_broad_warning = if permission.capability == PermissionCapability::Shell
        && is_broad_windows_shell_prefix(&scope)
    {
        match windows_sandbox_posture(permission) {
            Some("job-object-only") => " [broad rule on job-object-only Windows shell]",
            Some("restricted-token-writes-only") => {
                " [broad rule; Windows reads/network not isolated]"
            }
            _ => "",
        }
    } else {
        ""
    };
    (
        Cow::Owned(format!(
            "Always allow {kind} {scope_display}{windows_broad_warning}"
        )),
        Cow::Owned(format!("save a project {hint_kind} rule")),
    )
}

/// True when a shell prefix target covers a broad class of Windows shell
/// commands (pwsh, powershell, cmd, gitbash with no further narrowing).
/// Handles both bare names and `.exe` suffixes since the cached binary path
/// from `which::which` always stores the full name (e.g. `pwsh.exe`).
fn is_broad_windows_shell_prefix(prefix: &str) -> bool {
    let lower = prefix.to_ascii_lowercase();
    // Strip rule-target suffix (`:*`) and any `.exe` extension so the match
    // covers both `pwsh:*` and `pwsh.exe:*` rule forms.
    let target = lower.trim_end_matches(":*").trim();
    let file_name = target.rsplit(['\\', '/']).next().unwrap_or(target);
    let bare = file_name.trim_end_matches(".exe");
    matches!(bare, "pwsh" | "powershell" | "cmd" | "gitbash" | "shell")
}

fn windows_sandbox_posture(permission: &PermissionRequest) -> Option<&str> {
    permission
        .metadata
        .get("windows_sandbox_posture")
        .map(String::as_str)
        .or_else(|| {
            permission
                .metadata
                .get("windows_no_fs_sandbox")
                .is_some_and(|v| v == "true")
                .then_some("job-object-only")
        })
}

/// Single-line status banner shown in the 1-line status bar. Compact by
/// design so the status bar remains useful for non-approval traffic.
pub(crate) fn format_approval_status_line(request: &ToolApprovalRequest) -> String {
    let permission = &request.permission;
    let windows_suffix = match windows_sandbox_posture(permission) {
        Some("job-object-only") => " sandbox=job-object-only",
        Some("restricted-token-writes-only") => " sandbox=restricted-token-writes-only",
        _ => "",
    };
    format!(
        "approval needed: {tool} risk={risk} target={target}{windows_suffix}",
        tool = request.tool_name,
        risk = permission.risk.as_str(),
        target = permission.target,
    )
}

pub(crate) fn format_mcp_elicitation_status_line(request: &McpElicitationRequest) -> String {
    format!(
        "mcp request: {} {} {}",
        request.server,
        mcp_elicitation_kind_label(&request.kind),
        compact_text(&request.message, 120),
    )
}

#[cfg(test)]
pub(crate) fn format_approval_prompt(request: &ToolApprovalRequest) -> String {
    format_approval_menu_lines(request, 0)
        .into_iter()
        .map(|line| {
            line.spans
                .iter()
                .map(|span| span.content.as_ref())
                .collect::<String>()
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn format_mcp_elicitation_menu_lines(
    request: &McpElicitationRequest,
    selected: usize,
    input: &str,
) -> Vec<Line<'static>> {
    let mut lines = vec![Line::from(vec![
        Span::styled(
            "MCP request",
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            format!(
                " · {} · {}",
                request.server,
                mcp_elicitation_kind_label(&request.kind)
            ),
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ])];
    lines.push(Line::from(vec![
        Span::raw("  "),
        Span::styled(
            compact_text(&request.message, 180),
            Style::default()
                .fg(crate::render::theme::magenta())
                .add_modifier(Modifier::BOLD),
        ),
    ]));
    match request.kind {
        McpElicitationKind::Form => {
            if let Some(schema) = request.schema.as_ref() {
                let schema = serde_json::to_string_pretty(schema)
                    .unwrap_or_else(|_| "<schema unavailable>".to_string());
                lines.push(Line::from(vec![
                    Span::raw("  "),
                    Span::styled("schema", Style::default().fg(crate::render::theme::quiet())),
                ]));
                let schema_lines = schema.lines().collect::<Vec<_>>();
                for line in schema_lines.iter().take(MCP_ELICITATION_SCHEMA_MAX_LINES) {
                    lines.push(Line::from(vec![
                        Span::raw("  "),
                        Span::styled(
                            (*line).to_string(),
                            Style::default().fg(crate::render::theme::quiet()),
                        ),
                    ]));
                }
                let omitted = schema_lines
                    .len()
                    .saturating_sub(MCP_ELICITATION_SCHEMA_MAX_LINES);
                if omitted > 0 {
                    lines.push(Line::from(vec![
                        Span::raw("  "),
                        Span::styled(
                            format!("... {omitted} schema lines omitted"),
                            Style::default().fg(crate::render::theme::quiet()),
                        ),
                    ]));
                }
            }
            lines.push(Line::from(vec![
                Span::raw("  "),
                Span::styled(
                    format!("response {}", mcp_elicitation_response_preview(input)),
                    Style::default().fg(crate::render::theme::quiet()),
                ),
            ]));
        }
        McpElicitationKind::Url => {
            if let Some(url) = request.url.as_ref() {
                lines.push(Line::from(vec![
                    Span::raw("  "),
                    Span::styled(
                        compact_text(url, 180),
                        Style::default().fg(crate::render::theme::quiet()),
                    ),
                ]));
            }
        }
    }
    for (index, option) in mcp_elicitation_options().iter().enumerate() {
        let is_selected = index == selected.min(mcp_elicitation_options().len() - 1);
        let marker = if is_selected { "› " } else { "  " };
        let label_style = if is_selected {
            Style::default().fg(crate::render::theme::secondary())
        } else {
            Style::default().fg(palette::muted_fg())
        };
        lines.push(Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(option.label, label_style),
            Span::styled(
                format!(" · {}", option.hint),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]));
    }
    lines
}

fn mcp_elicitation_kind_label(kind: &McpElicitationKind) -> &'static str {
    match kind {
        McpElicitationKind::Form => "form",
        McpElicitationKind::Url => "url",
    }
}

fn mcp_elicitation_response_preview(input: &str) -> String {
    let trimmed = input.trim();
    if trimmed.is_empty() {
        "{}".to_string()
    } else {
        compact_text(trimmed, 160)
    }
}

fn format_plan_choice_menu_lines(pending: &PendingPlanChoice) -> Vec<Line<'static>> {
    let selected = pending.selection_index.min(PLAN_CHOICES.len() - 1);
    let mut lines = vec![Line::from(vec![
        Span::styled(
            "Plan ready",
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            format!(" · {}", pending.plan_id),
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ])];
    lines.push(Line::from(vec![
        Span::raw("  "),
        Span::styled(
            compact_path(&pending.plan_path),
            Style::default().fg(palette::muted_fg()),
        ),
    ]));
    for (idx, option) in PLAN_CHOICES.iter().enumerate() {
        let is_selected = idx == selected;
        let marker = if is_selected { "› " } else { "  " };
        let label_style = if is_selected {
            Style::default().fg(crate::render::theme::secondary())
        } else {
            Style::default().fg(palette::muted_fg())
        };
        lines.push(Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(
                format!("[{}] {}", option.shortcut, option.label),
                label_style,
            ),
            Span::styled(
                format!(" · {}", option.hint),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]));
    }
    lines
}

fn format_feedback_prompt_lines(feedback: &PreparedFeedback) -> Vec<Line<'static>> {
    vec![
        Line::from(vec![
            Span::styled(
                "Send feedback?",
                Style::default()
                    .fg(crate::render::theme::secondary())
                    .add_modifier(Modifier::BOLD),
            ),
            Span::styled(
                format!(" · {}", feedback.feedback_id),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]),
        Line::from(vec![
            Span::raw("  "),
            Span::styled(
                compact_text(&feedback.message, 160),
                Style::default().fg(palette::muted_fg()),
            ),
        ]),
        Line::from(vec![
            Span::styled(
                "› Enter/Y Send",
                Style::default().fg(crate::render::theme::secondary()),
            ),
            Span::styled(" · ", Style::default().fg(crate::render::theme::quiet())),
            Span::styled("Esc/N Discard", Style::default().fg(palette::muted_fg())),
        ]),
    ]
}

fn format_request_user_input_menu_lines(
    request: &RequestUserInputRequest,
    selected: usize,
    input: &str,
) -> Vec<Line<'static>> {
    let mut lines = vec![{
        let mut spans = vec![Span::styled(
            "Plan-mode question",
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        )];
        if request.allow_freeform {
            spans.push(Span::styled(
                " · freeform allowed",
                Style::default().fg(crate::render::theme::quiet()),
            ));
        }
        Line::from(spans)
    }];
    lines.push(Line::from(vec![
        Span::raw("  "),
        Span::styled(
            compact_text(&request.question, 240),
            Style::default()
                .fg(crate::render::theme::magenta())
                .add_modifier(Modifier::BOLD),
        ),
    ]));
    for (index, choice) in request.choices.iter().enumerate() {
        let is_selected = index == selected && selected < request.choices.len();
        let marker = if is_selected { "● " } else { "  " };
        let label_style = if is_selected {
            Style::default()
                .fg(palette::footer_fg())
                .add_modifier(Modifier::BOLD)
        } else {
            // Tone-aware muted grey sits below the luminance budget so
            // the amber selection dot carries focus without turning the
            // label itself yellow.
            Style::default().fg(palette::muted_fg())
        };
        let mut spans = vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::accent()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(compact_text(&choice.label, 180), label_style),
        ];
        if choice.value != choice.label {
            spans.push(Span::styled(
                format!(" · {}", compact_text(&choice.value, 120)),
                Style::default().fg(crate::render::theme::quiet()),
            ));
        }
        lines.push(Line::from(spans));
    }
    if request.allow_freeform {
        // Dedicated answer-entry box. Lives inside the modal area so the
        // main composer below stays untouched for the user's next prompt.
        // Label + cursor share the `crate::render::theme::magenta()` warm-taupe accent so the
        // whole modal reads as one semantic surface; the typed body uses
        // a dim+bold tone-aware foreground for legibility without
        // overpowering the question line.
        let is_selected = selected >= request.choices.len();
        let marker = if is_selected { "● " } else { "  " };
        let marker_style = Style::default().fg(if is_selected {
            crate::render::theme::accent()
        } else {
            crate::render::theme::quiet()
        });
        let entry_style = Style::default()
            .fg(palette::footer_fg())
            .add_modifier(Modifier::BOLD);
        let label_style = Style::default().fg(crate::render::theme::magenta());
        let cursor_style = Style::default()
            .fg(crate::render::theme::background())
            .bg(crate::render::theme::magenta());
        let mut spans = vec![
            Span::styled(marker, marker_style),
            Span::styled("Answer › ", label_style),
        ];
        if input.is_empty() {
            spans.push(Span::styled(
                "(type your answer · Enter sends when selected)",
                Style::default().fg(crate::render::theme::quiet()),
            ));
        } else {
            // Render the answer with an inline cursor block. The cursor
            // sits at `answer_cursor` bytes, which we don't have here —
            // approximate by drawing the whole answer followed by a
            // block. Accurate cursor placement is the caller's job; for
            // now this gives the user a visible "I'm typing in the right
            // box" affordance.
            spans.push(Span::styled(compact_text(input, 200), entry_style));
            spans.push(Span::styled("▌", cursor_style));
        }
        lines.push(Line::from(spans));
    }
    lines
}

fn approval_option_lines(request: &ToolApprovalRequest, selected: usize) -> Vec<Line<'static>> {
    let options = approval_options_for(request);
    let max_index = options.len().saturating_sub(1);
    options
        .iter()
        .enumerate()
        .map(|(index, option)| {
            let is_selected = index == selected.min(max_index);
            let marker = if is_selected { "› " } else { "  " };
            // Tint the active cursor + bold its label so the highlighted choice
            // is unmistakable; unselected rows stay calm.
            let marker_style = if is_selected {
                Style::default()
                    .fg(crate::render::theme::accent())
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(crate::render::theme::quiet())
            };
            let label_style = if is_selected {
                Style::default()
                    .fg(crate::render::theme::secondary())
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(palette::muted_fg())
            };
            Line::from(vec![
                Span::styled(marker, marker_style),
                Span::styled(option.label.to_string(), label_style),
                Span::styled(
                    format!(" · {}", option.hint),
                    Style::default().fg(crate::render::theme::quiet()),
                ),
            ])
        })
        .collect()
}

fn format_approval_menu_lines(
    request: &ToolApprovalRequest,
    selected: usize,
) -> Vec<Line<'static>> {
    let mut lines = approval::render_preview(request);
    lines.extend(approval_option_lines(request, selected));
    lines
}

/// The decision keybindings, folded into the bottom of the approval block so
/// they travel with the options they describe. The status line no longer
/// carries them.
fn approval_keybind_hint() -> &'static str {
    "Up/Down choose · Enter/Y approve once · A/P always approve repo · N/D deny · Esc cancel"
}

fn approval_footer_line() -> Line<'static> {
    Line::from(Span::styled(
        format!("  {}", approval_keybind_hint()),
        Style::default().fg(crate::render::theme::footer()),
    ))
}

/// The complete approval block including the folded keybind footer — used to
/// measure the block's desired height.
fn approval_block_full(request: &ToolApprovalRequest, selected: usize) -> Vec<Line<'static>> {
    let mut lines = format_approval_menu_lines(request, selected);
    lines.push(approval_footer_line());
    lines
}

/// Render the approval block to fit `max_height` visible rows at `width`,
/// eliding the *preview* (command / rationale / rule) — never the decision
/// options or their key hints — when space is tight. This makes it
/// structurally impossible for the options to be clipped behind the status
/// line on a short terminal.
fn approval_block_capped(
    request: &ToolApprovalRequest,
    selected: usize,
    max_height: u16,
    width: u16,
) -> Vec<Line<'static>> {
    let parts = approval::render_preview_parts(request);
    let mut options = approval_option_lines(request, selected);
    let footer = approval_footer_line();
    let row = |line: &Line<'static>| visual_line_count(std::slice::from_ref(line), width) as usize;
    let rows = |lines: &[Line<'static>]| visual_line_count(lines, width) as usize;

    let header_rows = row(&parts.header);
    let footer_rows = row(&footer);
    let blank_rows = 1usize;

    // Body in display order (matches `render_preview`): rationale, subject, rule.
    let mut body: Vec<Line<'static>> = Vec::new();
    body.extend(parts.context.iter().cloned());
    body.extend(parts.subject.iter().cloned());
    body.extend(parts.rule.iter().cloned());

    let max = max_height as usize;
    let full = header_rows + rows(&body) + blank_rows + rows(&options) + footer_rows;
    if max == 0 || full <= max {
        let mut out = Vec::with_capacity(body.len() + options.len() + 3);
        out.push(parts.header);
        out.extend(body);
        out.push(Line::raw(""));
        out.extend(options);
        out.push(footer);
        return out;
    }

    // Tight layout: compact each option onto a single row so a wrapped label
    // can never push a decision off-screen on a narrow terminal. This is a
    // no-op at a roomy width — the full-fit branch above keeps the untruncated,
    // multi-row labels. The option rows are the one thing we never drop.
    for option in &mut options {
        truncate_line_to_width(option, width as usize);
    }
    let option_rows = options.len();

    // Shed the least-critical fixed rows first (footer, then the separator
    // blank, then the header); the option rows always survive.
    let reserved = |hdr: bool, blk: bool, ftr: bool| -> usize {
        (if hdr { header_rows } else { 0 })
            + (if blk { blank_rows } else { 0 })
            + option_rows
            + (if ftr { footer_rows } else { 0 })
    };
    let mut keep_header = true;
    let mut keep_blank = true;
    let mut keep_footer = true;
    if reserved(keep_header, keep_blank, keep_footer) > max {
        keep_footer = false;
    }
    if reserved(keep_header, keep_blank, keep_footer) > max {
        keep_blank = false;
    }
    if reserved(keep_header, keep_blank, keep_footer) > max {
        keep_header = false;
    }
    let preview_budget = max.saturating_sub(reserved(keep_header, keep_blank, keep_footer));

    // Elided preview: command/subject first (it is the thing being approved),
    // then the rationale, then the rule; summarise the remainder in one note.
    let mut ordered: Vec<Line<'static>> = Vec::new();
    ordered.extend(parts.subject);
    ordered.extend(parts.context);
    ordered.extend(parts.rule);
    let total = ordered.len();

    let mut out: Vec<Line<'static>> = Vec::new();
    if keep_header {
        out.push(parts.header);
    }
    if preview_budget > 0 {
        let elide = rows(&ordered) > preview_budget;
        let line_budget = if elide {
            preview_budget.saturating_sub(1)
        } else {
            preview_budget
        };
        let mut used = 0usize;
        let mut shown = 0usize;
        for line in ordered.iter() {
            let r = row(line);
            if used + r > line_budget {
                break;
            }
            used += r;
            out.push(line.clone());
            shown += 1;
        }
        if elide {
            let hidden = total - shown;
            if hidden > 0 {
                let mut note = Line::from(Span::styled(
                    format!(
                        "  … {hidden} more line{}",
                        if hidden == 1 { "" } else { "s" }
                    ),
                    Style::default().fg(crate::render::theme::quiet()),
                ));
                truncate_line_to_width(&mut note, width as usize);
                out.push(note);
            }
        }
    }
    if keep_blank {
        out.push(Line::raw(""));
    }
    out.extend(options);
    if keep_footer {
        out.push(footer);
    }
    // Hard ceiling: if the area is so short that even single-row options can't
    // all fit, keep the leading rows rather than letting ratatui clip an
    // unaccounted bottom row. Esc still denies, so no decision is lost.
    out.truncate(max);
    out
}

/// Resolved heights for the main (inline) view's vertical layout. The
/// transcript viewport height (`transcript_height`) is the single source of
/// truth shared by `render()` and the off-frame `active_transcript_geometry`,
/// so the scroll math clamps against exactly the height the renderer draws.
#[derive(Clone, Copy)]
struct MainTranscriptLayout {
    task_height: Option<u16>,
    approval_height: u16,
    plan_indicator_height: u16,
    subagent_height: u16,
    attachment_height: u16,
    transcript_prompt_gap_height: u16,
    transcript_height: u16,
    show_completed_turn_divider: bool,
    input_height: u16,
}

/// Resolve the Adaptive Density (§12.4.1) for a concrete render `area`. The
/// render path knows the exact rect it is painting, so it resolves against that
/// rather than the stamped frame size (which it is about to overwrite). Routes
/// through the same [`density::DensityMode::resolve`] as the off-frame
/// [`TuiApp::effective_density`], so the layout the renderer paints and the tier
/// a dispatch/status read reports never disagree.
fn resolved_density_for(app: &TuiApp, area: Rect) -> density::ResolvedDensity {
    // Presentation Mode (§12.4.6) elevates the resolved tier to the spacious
    // expanded layout through the *same* density table, so a screen-share gets
    // the roomy cards without a second spacing engine. A no-op when the mode is
    // off, so a normal session keeps exactly the density it resolved.
    app.presentation
        .present_density(app.density_override.resolve(area.width, area.height))
}

/// Whether the welcome / startup card is included for a render `area`, under the
/// Adaptive Density (§12.4.1) height gate. The single policy the render path and
/// the off-frame scroll-geometry paths share, so a density change moves the
/// card threshold for *both* together (the painted card decision and the
/// scroll-math card decision stay in lock-step). `Default` density keeps the
/// renderer's historical `>= 16` threshold.
fn include_startup_card_for(app: &TuiApp, area: Rect) -> bool {
    area.height >= resolved_density_for(app, area).startup_card_min_height()
}

/// Compute the main-view layout heights for `area`. Extracted from `render()`
/// so the scroll commands can recompute the transcript viewport height
/// off-frame without re-running a full frame.
fn main_transcript_layout(
    app: &TuiApp,
    area: Rect,
    include_startup_card: bool,
) -> MainTranscriptLayout {
    let input_height = input_panel_height(app, area.width);
    let approval_height = approval_menu_height(app, area.width);
    let plan_indicator_height = plan_mode_indicator_height(app);
    let subagent_height = subagent_pane_height(app);
    let show_completed_turn_divider = should_show_live_completed_turn_divider(app, None);
    let task_height = if should_show_task_panel(app, show_completed_turn_divider) {
        let h = if approval_height > 0 {
            task_panel_height(app).min(5)
        } else {
            task_panel_height(app)
        };
        Some(h)
    } else {
        None
    };
    // Cap the inline question block against the screen height so `input +
    // question + status` can never over-constrain the layout. This keeps
    // approval options and paste choices reachable on short terminals.
    let approval_height = if approval_height > 0 {
        let reserve = input_height
            .saturating_add(2)
            .saturating_add(plan_indicator_height)
            .saturating_add(task_height.unwrap_or(0));
        approval_height.min(area.height.saturating_sub(reserve))
    } else {
        approval_height
    };
    let required_height = task_height
        .unwrap_or(0)
        .saturating_add(approval_height)
        .saturating_add(input_height)
        .saturating_add(plan_indicator_height)
        .saturating_add(subagent_height)
        .saturating_add(2);
    let optional_height = area.height.saturating_sub(required_height);
    let attachment_height = attachment_panel_height(app, optional_height);
    // Adaptive Density (§12.4.1): the base call decides *whether* a
    // transcript-to-prompt breather is wanted at all (0 on an empty session,
    // 1 otherwise); the resolved density scales it — compact spends none,
    // default keeps the single row, expanded doubles it. Multiplying keeps an
    // empty session at zero regardless of density.
    let density = resolved_density_for(app, area);
    let requested_transcript_gap_height =
        transcript_prompt_gap_height(app).saturating_mul(density.transcript_prompt_gap());
    let reserved_height = required_height.saturating_add(attachment_height);
    // Count the transcript height at the SAME width `render_transcript` wraps to,
    // not the full frame width: it carves the 1-cell minimap rail (when the rail
    // is shown) and the 1-cell scrollbar gutter off the right edge before
    // wrapping (so text is `area.width - 1`, or `- 2` with the minimap). Sizing
    // at the wider full width undercounts wrapped rows, under-reserving
    // `transcript_height` so a tail-pinned view clips its top while a blank
    // filler band shows below the composer (deep-review #14).
    let show_minimap = app.show_minimap && !app.zen.chrome_suppressed();
    let (body_area, _rail) = transcript_main_body_and_rail_areas(area, show_minimap);
    let (text_area, _scrollbar) = transcript_main_text_and_scrollbar_areas(body_area);
    let transcript_visual_height =
        transcript_visual_line_count(app, text_area.width, include_startup_card);
    let available_without_gap = area.height.saturating_sub(reserved_height);
    let transcript_prompt_gap_height = if requested_transcript_gap_height > 0
        && transcript_visual_height < available_without_gap
    {
        requested_transcript_gap_height
    } else {
        0
    };
    let available_transcript_height =
        available_without_gap.saturating_sub(transcript_prompt_gap_height);
    let transcript_height = transcript_visual_height.min(available_transcript_height);
    MainTranscriptLayout {
        task_height,
        approval_height,
        plan_indicator_height,
        subagent_height,
        attachment_height,
        transcript_prompt_gap_height,
        transcript_height,
        show_completed_turn_divider,
        input_height,
    }
}

/// The main transcript viewport height for `area`, matching what `render()`
/// hands `render_transcript`. The off-frame scroll-geometry path uses this.
fn main_transcript_height(app: &TuiApp, area: Rect, include_startup_card: bool) -> u16 {
    main_transcript_layout(app, area, include_startup_card).transcript_height
}

impl MainTranscriptLayout {
    /// Snapshot this resolved layout into a `Copy` [`layout_fallback::LayoutGeometry`]
    /// keyed by the `area` it was computed for, so the Last-Known-Good Layout
    /// Fallback (§12.9.3) can record a good frame or restore a prior one. A
    /// straight field copy — the geometry mirrors this struct one-for-one.
    fn to_geometry(self, area: Rect) -> layout_fallback::LayoutGeometry {
        layout_fallback::LayoutGeometry {
            width: area.width,
            height: area.height,
            task_height: self.task_height,
            approval_height: self.approval_height,
            plan_indicator_height: self.plan_indicator_height,
            subagent_height: self.subagent_height,
            attachment_height: self.attachment_height,
            transcript_prompt_gap_height: self.transcript_prompt_gap_height,
            transcript_height: self.transcript_height,
            show_completed_turn_divider: self.show_completed_turn_divider,
            input_height: self.input_height,
        }
    }

    /// Rebuild the layout heights from a [`layout_fallback::LayoutGeometry`]
    /// snapshot the fallback restored. The inverse of [`to_geometry`]; the
    /// snapshot's `(width, height)` are dropped because the render path already
    /// holds the live `area`.
    ///
    /// [`to_geometry`]: MainTranscriptLayout::to_geometry
    fn from_geometry(geometry: layout_fallback::LayoutGeometry) -> Self {
        MainTranscriptLayout {
            task_height: geometry.task_height,
            approval_height: geometry.approval_height,
            plan_indicator_height: geometry.plan_indicator_height,
            subagent_height: geometry.subagent_height,
            attachment_height: geometry.attachment_height,
            transcript_prompt_gap_height: geometry.transcript_prompt_gap_height,
            transcript_height: geometry.transcript_height,
            show_completed_turn_divider: geometry.show_completed_turn_divider,
            input_height: geometry.input_height,
        }
    }
}

pub(crate) fn render(frame: &mut Frame<'_>, app: &TuiApp) {
    render_surfaces(frame, app);
    // The hidden render-budget HUD draws LAST so it overlays every surface
    // (main view, Ctrl+T overlay, config, status-line setup). Off unless the
    // operator toggled it on; it reserves no layout rows and clips whatever it
    // overlaps in the top-right, like the toast stack.
    if app.show_render_metrics {
        render_metrics_hud(frame, frame.area(), app);
    }
}

/// The actual per-surface dispatch: main view vs. transcript overlay / config /
/// status-line setup, selected purely from `app` state. Split from [`render`]
/// so the metrics HUD can paint on top of whichever surface this drew, without
/// duplicating the HUD call at every early return.
fn render_surfaces(frame: &mut Frame<'_>, app: &TuiApp) {
    app.begin_frame_clickables();
    let area = frame.area();
    // Record the size we're painting at so off-frame transcript geometry
    // (`active_transcript_geometry`, `jump_*_geometry`,
    // `transcript_overlay_max_scroll`, the diff-detail-pane fallback) measures
    // against the viewport the renderer used rather than a fresh
    // `terminal_size()` syscall — keeping scroll/jump math consistent with the
    // painted frame and deterministic under a headless `TestBackend`.
    app.stamp_frame_size(area);
    // Paste questions are modal in behavior but inline in layout: they render in
    // the same below-composer band as approvals and MCP questions later in this
    // function, so pasting never swaps the whole screen for a bespoke UI.
    // The clipboard-history picker (§12.6.1) paints as a fullscreen overlay over
    // everything else while open. Checked after paste questions (a pending paste
    // decision still wins) but before the transcript overlay / config screens so
    // its click targets register every frame and it owns the surface.
    if app.clipboard_history_open {
        render_clipboard_history_surface(frame, area, app);
        return;
    }
    // The Keybinding Editor UI (§12.7.1) paints as a fullscreen overlay over
    // everything else while open, registering its per-row + button click targets
    // every frame. Checked beside the clipboard picker so its targets register and
    // it owns the surface while open.
    if app.keybinding_editor.is_some() {
        render_keybinding_editor_surface(frame, area, app);
        return;
    }
    // The Prompt Snippets picker (§12.3.2) paints as a fullscreen overlay over
    // everything else while open, registering its per-snippet row + button click
    // targets every frame. Checked beside the clipboard picker so its targets
    // register and it owns the surface while open.
    if app.snippets_open {
        render_snippets_surface(frame, area, app);
        return;
    }
    // The Prompt Templates picker (§12.3.6) paints as a fullscreen overlay over
    // everything else while open, registering its per-template row / slot row /
    // button click targets every frame. Checked beside the snippets picker so its
    // targets register and it owns the surface while open.
    if app.templates_open {
        render_templates_surface(frame, area, app);
        return;
    }
    // The Local Transcript Index overlay (§12.5.1) paints as a fullscreen summary
    // over everything else while open, registering its per-category row click
    // targets every frame. Checked beside the clipboard picker so its targets
    // register and it owns the surface while open.
    if app.transcript_index_open {
        render_transcript_index_surface(frame, area, app);
        return;
    }
    // The Related-Entry Links overlay (§12.5.3) paints as a fullscreen surface
    // over everything else while open, registering its per-relation row click
    // targets every frame. Checked beside the transcript-index overlay so its
    // targets register and it owns the surface while open.
    if app.related_links_open {
        render_related_links_surface(frame, area, app);
        return;
    }
    // The Duplicate-Output Folds overlay (§12.5.4) paints as a fullscreen list
    // over everything else while open, registering its per-span row click targets
    // every frame. Checked beside the transcript index so its targets register and
    // it owns the surface while open.
    if app.duplicate_folds_open {
        render_duplicate_folds_surface(frame, area, app);
        return;
    }
    // The Error Lenses overlay (§12.5.6) paints as a fullscreen list over
    // everything else while open, registering its per-lens row click targets
    // every frame. Checked beside the duplicate-folds overlay so its targets
    // register and it owns the surface while open.
    if app.error_lens_open {
        render_error_lens_surface(frame, area, app);
        return;
    }
    // The Transcript Health Markers overlay (§12.5.7) paints as a fullscreen list
    // over everything else while open, registering its per-marker row click
    // targets every frame. Checked beside the error-lens overlay so its targets
    // register and it owns the surface while open.
    if app.health_markers_open {
        render_health_markers_surface(frame, area, app);
        return;
    }
    // The Semantic Turn Outline overlay (§12.2.1) paints as a fullscreen jump-list
    // over everything else while open, registering its per-node row click targets
    // every frame. Checked beside the health-markers overlay so its targets
    // register and it owns the surface while open.
    if app.turn_outline_open {
        render_turn_outline_surface(frame, area, app);
        return;
    }
    // The Collapsible Reasoning/Tool Lanes overlay (§12.2.2) paints as a
    // fullscreen lane panel over everything else while open, registering its
    // per-lane row click targets every frame. Checked beside the turn-outline
    // overlay so its targets register and it owns the surface while open.
    if app.lane_fold_open {
        render_lane_fold_surface(frame, area, app);
        return;
    }
    // The Reading Position Bookmarks overlay (§12.2.4) paints as a fullscreen
    // jump-list over everything else while open, registering its per-bookmark row
    // click targets every frame. Checked beside the lane-fold overlay so its
    // targets register and it owns the surface while open.
    if app.bookmarks_open {
        render_bookmarks_surface(frame, area, app);
        return;
    }
    // The Session Timeline overlay (§12.2.6) paints as a fullscreen chronological
    // rail/list over everything else while open, registering its per-event row
    // click targets every frame. Checked beside the bookmarks overlay so its
    // targets register and it owns the surface while open.
    if app.session_timeline_open {
        render_session_timeline_surface(frame, area, app);
        return;
    }
    // The Subagent Timeline Panel (§12.8.1) paints as a fullscreen navigable
    // subagent rail/list over everything else while open, registering its
    // per-subagent row click targets every frame. Checked beside the session-
    // timeline overlay (its sibling: the session's events vs. its subagents) so
    // its targets register and it owns the surface while open.
    if app.subagent_timeline_open {
        render_subagent_timeline_surface(frame, area, app);
        return;
    }
    // The Compare Subagent Outputs view (§12.8.3) paints as a fullscreen modal with
    // two equal panes (the two marked subagents' outputs, side-by-side or stacked)
    // over everything else while open, stamping each pane's text rect for the
    // wheel/click hit-test. It heals to closed when a marked subagent's record has
    // vanished, so the render path never paints an empty pane. Checked beside the
    // subagent timeline panel (its sibling: the panel marks, this compares).
    if app.subagent_compare.is_some() && subagent_compare_records_present(app) {
        render_subagent_compare_surface(frame, area, app);
        return;
    }
    // The Live Review Board (§12.8.5) paints as a fullscreen fan-out orchestration
    // dashboard — status lanes (running / blocked / capped / completed) of the
    // session's workers — over everything else while open, registering each worker
    // card's click target every frame. Checked beside the subagent timeline panel
    // (its sibling: the panel lists, this groups into lanes) so its targets register
    // and it owns the surface while open.
    if app.review_board_open {
        render_review_board_surface(frame, area, app);
        return;
    }
    // The What Changed Since Here? overlay (§12.2.7) paints as a fullscreen grouped
    // delta list over everything else while open, registering its per-change row
    // click targets every frame. Checked beside the session-timeline overlay (its
    // sibling: mark a point, review the delta) so its targets register and it owns
    // the surface while open.
    if app.changes_since_open {
        render_changes_since_surface(frame, area, app);
        return;
    }
    // The Contextual Action Palette (§12.1.2) paints as a centered action menu over
    // everything else while open, registering its per-action row click targets every
    // frame. Checked beside the other main-surface overlays so its targets register
    // and it owns the surface while open.
    if app.action_palette.is_some() {
        render_action_palette_surface(frame, area, app);
        return;
    }
    // The Actionable Tool Outputs overlay (§12.3.1) paints as a centered list of the
    // focused tool result's actionable elements over everything else while open,
    // registering its per-item row click targets every frame. Checked beside the
    // action-palette overlay so its targets register and it owns the surface while
    // open.
    if app.tool_actions.is_some() {
        render_tool_actions_surface(frame, area, app);
        return;
    }
    // The Scratchpad Pane (§12.3.3) paints as a side pane over everything else
    // while open: the live transcript on the left, the editable scratch buffer on
    // the right (reusing the §11G.10 detail-pane split machinery), falling back to
    // a centered overlay when the terminal is too narrow to split. It registers
    // its in-pane button click targets every frame. Checked beside the other
    // main-surface overlays so its targets register and it owns the surface while
    // open.
    if app.scratchpad_open {
        render_scratchpad_surface(frame, area, app);
        return;
    }
    // The Entry Annotations overlay (§12.2.5) paints as a fullscreen jump-list /
    // composer over everything else while open, registering its per-annotation row
    // click targets every frame. Checked beside the bookmarks overlay so its
    // targets register and it owns the surface while open.
    if app.annotations_open {
        render_annotations_surface(frame, area, app);
        return;
    }
    // The Universal Command Palette (§12.1.1) paints as a fullscreen fuzzy-filtered
    // command list over everything else while open, registering its per-command row
    // click targets every frame. Checked beside the other overlays so its targets
    // register and it owns the surface while open.
    if app.command_palette.is_some() {
        render_command_palette_surface(frame, area, app);
        return;
    }
    // The External Editor Handoff confirmation overlay (§12.6.5) paints as a
    // fullscreen modal over everything else while open, registering its
    // accept/reopen/discard button click targets every frame. Checked after the
    // clipboard picker but before the transcript overlay / config screens so it
    // owns the surface while a re-import decision is pending.
    if app.editor_handoff.is_some() {
        render_editor_handoff_surface(frame, area, app);
        return;
    }
    if app.transcript_overlay.is_some() {
        render_transcript_overlay_surface(frame, area, app);
        return;
    }
    if let Some(state) = &app.status_line_setup {
        status_line_setup::render(frame, area, state, app);
        return;
    }
    // The Theme Editor overlay (§12.7.2) paints as a fullscreen modal over the main
    // surface while open, registering its per-role and per-channel click targets
    // every frame. Checked before the config screen so its targets register and it
    // owns the surface while open; the main transcript previews live behind the
    // dimmed backdrop so colour changes are visible in context.
    if let Some(state) = &app.theme_editor {
        render_theme_editor_surface(frame, area, app, state);
        return;
    }
    // The Per-Workspace UI Profile overlay (§12.7.4) paints as a fullscreen modal
    // over the main surface while open, registering its per-field click targets
    // every frame. Checked before the config screen so its targets register and it
    // owns the surface while open.
    if let Some(state) = &app.workspace_profile {
        render_workspace_profile_surface(frame, area, app, state);
        return;
    }
    // The Session Auto-Save Checkpoints status overlay (§12.9.5) paints as a
    // fullscreen modal over the main surface while open, registering its
    // `[restore]` click target every frame. Checked before the config screen so
    // its target registers and it owns the surface while open.
    if let Some(checkpoint) = &app.session_checkpoint_overlay {
        render_session_checkpoint_surface(frame, area, app, checkpoint);
        return;
    }
    // The Per-Terminal Profiles overlay (§12.7.3) paints as a fullscreen modal over
    // the main surface while open, registering its per-field click targets every
    // frame. Checked before the config screen so its targets register and it owns
    // the surface while open.
    if let Some(editor) = &app.terminal_profile_editor {
        render_terminal_profile_surface(frame, area, app, editor);
        return;
    }
    // The Gesture Settings overlay (§12.7.5) paints as a fullscreen modal over the
    // main surface while open, registering its per-field click targets every frame.
    // Checked before the config screen so its targets register and it owns the
    // surface while open.
    if let Some(editor) = &app.gesture_settings_editor {
        render_gesture_settings_surface(frame, area, app, editor);
        return;
    }
    // The Minimal Glyph Mode overlay (§12.7.6) paints as a fullscreen modal over the
    // main surface while open, registering its per-mode-row click targets every
    // frame. Checked before the config screen so its targets register and it owns
    // the surface while open.
    if let Some(editor) = &app.glyph_mode_editor {
        render_glyph_mode_surface(frame, area, app, editor);
        return;
    }
    // The Smart Split Panes inspector (§12.4.2) paints as a fullscreen modal over
    // the main surface while open, registering its per-field-row click targets and
    // stamping the previewed pane rects every frame. Checked beside the glyph-mode
    // overlay so its targets register and it owns the surface while open.
    if let Some(state) = &app.smart_split {
        render_smart_split_surface(frame, area, app, *state);
        return;
    }
    if let Some(state) = &app.config_screen {
        config_screen::render(frame, area, state);
        return;
    }
    // Dockable Panels (§12.4.4): carve the docked auxiliary panel off the frame
    // BEFORE the main-view layout, so the transcript/composer block lays out
    // inside the reduced `main_area` and the panel takes its own rect. When the
    // dock is inactive (the default) or the terminal is too small to split, the
    // placement degrades to a single column and `main_area == area`, so a session
    // that never docks paints exactly as before. The panel itself is painted
    // after the main block below, so its border never underlaps the transcript.
    // Zen Mode (§12.4.5) suppresses the docked auxiliary panel (a secondary
    // panel): the dock is treated as undocked for this frame so the placement
    // degrades to a single column and the transcript/composer reclaim the whole
    // width. `app.dock` itself is untouched, so leaving zen restores the dock as it
    // was. `dock_active` below is read from the same suppressed view so the panel
    // is neither painted nor click-registered while zen is on.
    let dock_active = app.dock.is_active() && !app.zen.chrome_suppressed();
    let dock_placement = if dock_active {
        app.dock.placement(area)
    } else {
        // The default (undocked) dock state placement degrades to a single column
        // with `main == area`, so zen — or an already-undocked session — hands the
        // whole content rect to the transcript/composer.
        dock::DockState::default().placement(area)
    };
    let main_area = dock_placement.main();
    // Adaptive Density (§12.4.1): the welcome / startup card is informational
    // chrome, so its minimum-height gate scales with density — a compact (short)
    // terminal drops it sooner to spend rows on content, an expanded one keeps it
    // even on a slightly shorter window. `Default` keeps the renderer's prior
    // hard-coded `>= 16` threshold, so the default-density build is unchanged.
    let include_startup_card = include_startup_card_for(app, main_area);
    // Last-Known-Good Layout Fallback (§12.9.3): resolve the freshly-computed
    // geometry through the last-good store. A valid frame is recorded as the new
    // good snapshot and painted as-is; a degenerate frame (no composer row, or a
    // reserve that overflows the area) is replaced by the prior good geometry
    // *at the same size* rather than committed as a broken paint. With no
    // matching good snapshot the fresh geometry is painted best-effort. The store
    // is keyed by `main_area`'s size — the same seam the renderer stamps via
    // `stamp_frame_size` — so a resize never restores stale rows. Zero idle cost:
    // a valid frame is one `Cell` write, an idle session never repaints.
    let resolution = app.layout_fallback.resolve(
        main_transcript_layout(app, main_area, include_startup_card).to_geometry(main_area),
    );
    let layout = MainTranscriptLayout::from_geometry(resolution.geometry());
    let MainTranscriptLayout {
        task_height,
        approval_height,
        plan_indicator_height,
        subagent_height,
        attachment_height,
        transcript_prompt_gap_height,
        transcript_height,
        show_completed_turn_divider,
        input_height,
    } = layout;
    let mut constraints = Vec::new();
    if transcript_height > 0 {
        constraints.push(Constraint::Length(transcript_height));
    }
    if transcript_prompt_gap_height > 0 {
        constraints.push(Constraint::Length(transcript_prompt_gap_height));
    }
    if let Some(h) = task_height {
        constraints.push(Constraint::Length(h));
    }
    if attachment_height > 0 {
        constraints.push(Constraint::Length(attachment_height));
    }
    if plan_indicator_height > 0 {
        constraints.push(Constraint::Length(plan_indicator_height));
    }
    constraints.push(Constraint::Length(input_height));
    if approval_height > 0 {
        constraints.push(Constraint::Length(approval_height));
    }
    constraints.push(Constraint::Length(2));
    if subagent_height > 0 {
        constraints.push(Constraint::Length(subagent_height));
    }
    constraints.push(Constraint::Min(0));
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints(constraints)
        .split(main_area);
    let mut index = 0;
    if transcript_height > 0 {
        render_transcript(frame, chunks[index], app, include_startup_card);
        index += 1;
    }
    if transcript_prompt_gap_height > 0 {
        index += 1;
    }
    if task_height.is_some() {
        render_task_state(frame, chunks[index], app, show_completed_turn_divider);
        index += 1;
    }
    if attachment_height > 0 {
        render_attachments(frame, chunks[index], app);
        index += 1;
    }
    if plan_indicator_height > 0 {
        render_plan_mode_indicator(frame, chunks[index], app);
        index += 1;
    }
    render_input(frame, chunks[index], app);
    index += 1;
    if approval_height > 0 {
        render_approval(frame, chunks[index], app);
        index += 1;
    }
    render_status(frame, chunks[index], app);
    index += 1;
    if subagent_height > 0 {
        render_subagent_pane(frame, chunks[index], app);
        index += 1;
    }
    // Flexible filler keeps the prompt/status block attached to the transcript
    // instead of pinning it to the terminal bottom.
    let _ = chunks[index];
    // Dockable Panels (§12.4.4): paint the docked auxiliary panel into its carved
    // rect (and its one-cell separator), AFTER the main block so its border never
    // underlaps the transcript. Skipped entirely on the common undocked path so an
    // inactive dock pays nothing; when active, `render_dock_panel` itself still
    // no-ops if the terminal was too small to split. Painting registers the header
    // click target so a click cycles the dock — the mouse twin of `Ctrl+Alt+F`.
    // Zen Mode (§12.4.5) folds into `dock_active` above, so the panel is neither
    // painted nor click-registered while zen is on.
    if dock_active {
        render_dock_panel(frame, app, dock_placement);
    }
    render_toast_overlay(frame, area, app);
    // The Gentle First-Run Interaction Hint (§12.1.8) is a NON-modal dim line
    // painted on the main surface only — every fullscreen overlay returns earlier
    // and never reaches here, so the hint never leaks over a modal. It reserves no
    // layout rows and clips what it overlaps (like the toast stack); when no hint is
    // active (every hint seen, the feature off, or a transient suppression) it paints
    // nothing and registers no click target. Drawn after the toast stack so a toast
    // wins the same corner, and before the hover popover so a peek covers it.
    render_first_run_hint(frame, area, app);
    // The Automatic Degraded-Mode Suggestions banner (§12.9.4) is a NON-modal dim
    // line painted on the main surface only — every fullscreen overlay returns
    // earlier and never reaches here, so it never leaks over a modal. It reserves no
    // layout rows and clips what it overlaps (like the toast stack); it paints (and
    // registers its accept/dismiss click targets) ONLY when a degraded terminal is
    // detected and the user has not yet accepted/dismissed the suggestion, so an
    // idle / non-degraded session pays nothing. Drawn after the first-run hint so
    // the two share the bottom-left without overlapping (the banner takes the row
    // above the hint).
    render_degraded_suggestion(frame, area, app);
    // The Replayable Interaction Macros (§12.3.7) record/replay status strip is a
    // NON-modal dim line painted at the top-left of the main surface only — every
    // fullscreen overlay returns earlier and never reaches here, so the strip never
    // leaks over a modal. It reserves no layout rows and clips what it overlaps (like
    // the toast stack); it paints (and registers its click target) ONLY while the
    // recorder is active (recording or replaying), so an idle session pays nothing.
    render_macro_strip(frame, area, app);
    // The Hover Preview popover (§12.1.4) is a NON-modal peek painted LAST on the
    // main surface (only — every fullscreen overlay returns earlier and never
    // reaches here, so the popover never leaks over a modal). It is anchored to the
    // previewed entry's row and clamped inside `area`, so it never changes a row's
    // height/width and never steals focus. Off (and zero-cost) unless a hover /
    // `Alt+1` reveal set it.
    render_hover_preview_popover(frame, area, app);
    // The Subagent Hover Preview popover (§12.8.2) is a NON-modal peek painted LAST
    // on the main surface, anchored next to the previewed subagent row and clamped
    // inside `area`, so it never resizes the pane or steals focus. Off (and
    // zero-cost) unless a hover / `Alt+6` reveal set it.
    render_subagent_preview_popover(frame, area, app);
    // The Inline Rename Labels editor (§12.1.7) is a small modal painted LAST on the
    // main surface (only — every fullscreen overlay returns earlier and never
    // reaches here, so the editor never leaks over another modal). A one-line
    // bordered box centered near the top of the frame; off (and zero-cost) unless a
    // rename is in progress.
    render_rename_editor(frame, area, app);
}

/// Render the Inline Rename Labels editor (§12.1.7) as a small one-line modal box
/// near the top of `area` while a rename is active. Shows the editor buffer with a
/// trailing cursor block so the in-place edit reads as live text input; clamped
/// inside `area` so it never paints off-surface on a narrow/short frame. A complete
/// no-op when no rename is in progress (`rename_edit == None`).
fn render_rename_editor(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let Some(edit) = app.rename_edit.as_ref() else {
        return;
    };
    if area.width < 6 || area.height < 3 {
        return;
    }
    // A bordered box up to 48 cells wide (plus borders), centered horizontally and
    // parked two rows down from the top so it sits over the transcript, not the
    // composer.
    let inner_w = (area.width.saturating_sub(4)).min(rename_labels::LABEL_TEXT_LIMIT as u16 + 2);
    let box_w = inner_w + 2;
    let box_x = area.x + (area.width.saturating_sub(box_w)) / 2;
    let box_y = area.y + 1;
    let rect = Rect {
        x: box_x,
        y: box_y,
        width: box_w,
        height: 3,
    };
    frame.render_widget(ratatui::widgets::Clear, rect);
    let block = ratatui::widgets::Block::default()
        .borders(ratatui::widgets::Borders::ALL)
        .border_style(Style::default().fg(crate::render::theme::accent()))
        .title(Span::styled(
            " rename label ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ));
    let inner = block.inner(rect);
    frame.render_widget(block, rect);
    // The buffer text, clamped to the inner width with a trailing cursor block so
    // the empty editor still shows where typing lands.
    let avail = inner.width.saturating_sub(1) as usize;
    let shown: String = if edit.buffer.chars().count() > avail {
        // Keep the TAIL visible (where the cursor is) on overflow.
        edit.buffer
            .chars()
            .rev()
            .take(avail)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect()
    } else {
        edit.buffer.clone()
    };
    let line = Line::from(vec![
        Span::styled(
            shown,
            Style::default().fg(crate::render::theme::foreground()),
        ),
        Span::styled(
            "\u{2588}",
            Style::default().fg(crate::render::theme::accent()),
        ),
    ]);
    frame.render_widget(Paragraph::new(line), inner);
}

/// Render the docked auxiliary panel (§12.4.4) into the rect the dock solver
/// carved off the frame, plus the one-cell separator between it and the
/// transcript. A complete no-op when the dock is inactive or the layout degraded
/// to a single column (`placement.panel()` is `None`), so a session that never
/// docks pays nothing here.
///
/// The panel is a bordered box: row 0 is a clickable HEADER (the panel label +
/// the edge it is pinned to + a hint), and the body below is a concise,
/// panel-specific summary (scratchpad text, the subagent roster count, or the
/// focused-entry detail). The header registers a [`interaction::ChromeKey::
/// DockPanelHeader`] click target so a click cycles the dock — the mouse twin of
/// the `CycleDockPanel` (`Ctrl+Alt+F`) keyboard verb.
fn render_dock_panel(frame: &mut Frame<'_>, app: &TuiApp, placement: dock::DockPlacement) {
    // No-op when the dock degraded to a single column (inactive dock, or a
    // terminal too small to split) — nothing to paint this frame.
    if !placement.is_docked() {
        return;
    }
    let Some(panel) = placement.panel() else {
        return;
    };
    if panel.width < 2 || panel.height < 2 {
        return;
    }
    // The one-cell separator rule between the transcript and the panel, drawn in
    // the quiet border colour so the split reads as a seam, not a focus border.
    if let Some(sep) = placement.separator() {
        frame.render_widget(
            ratatui::widgets::Block::default()
                .style(Style::default().fg(crate::render::theme::quiet())),
            sep,
        );
    }
    let dock_panel = app.dock.panel();
    let edge = placement.edge();
    // A bordered box titled with the panel + edge. `Clear` underneath so the
    // panel never shows transcript bleed-through on a partial repaint.
    frame.render_widget(ratatui::widgets::Clear, panel);
    let title = format!(" {} \u{00b7} {} ", dock_panel.label(), edge.label());
    let block = ratatui::widgets::Block::default()
        .borders(ratatui::widgets::Borders::ALL)
        .border_style(Style::default().fg(crate::render::theme::quiet()))
        .title(Span::styled(
            title,
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ));
    let inner = block.inner(panel);
    frame.render_widget(block, panel);
    // The header row is the click affordance: clicking it cycles the dock the same
    // way `Ctrl+Alt+F` does. Register it over the panel's TOP border row (the
    // title), in absolute screen coordinates, so the hit-test in `handle_mouse`
    // routes there. Registered only when the panel actually painted, so an
    // undocked session registers nothing.
    let header_rect = Rect {
        x: panel.x,
        y: panel.y,
        width: panel.width,
        height: 1,
    };
    app.register_click(
        header_rect,
        interaction::TargetKey::Chrome(interaction::ChromeKey::DockPanelHeader),
        interaction::Action::CycleDockPanel,
    );
    if inner.width == 0 || inner.height == 0 {
        return;
    }
    let body = dock_panel_body_lines(app, dock_panel, inner.width, inner.height as usize);
    frame.render_widget(Paragraph::new(body), inner);
}

/// The body lines for a docked panel (§12.4.4): a concise, panel-specific summary
/// sized to `(width, max_rows)`. Pure text assembly — the docked panel mirrors
/// each auxiliary's live state without re-implementing its full interactive UI,
/// so a click on the header (or `Ctrl+Alt+F`) is the way to move it and the body
/// just reflects the current contents.
fn dock_panel_body_lines(
    app: &TuiApp,
    panel: dock::DockPanel,
    width: u16,
    max_rows: usize,
) -> Vec<Line<'static>> {
    let mut lines: Vec<Line<'static>> = Vec::new();
    let avail = width as usize;
    match panel {
        dock::DockPanel::Scratchpad => {
            if app.scratchpad.is_empty() {
                lines.push(dock_quiet_line("(scratchpad empty)"));
            } else {
                for raw in app.scratchpad.lines() {
                    lines.push(dock_text_line(raw, avail));
                    if lines.len() >= max_rows {
                        break;
                    }
                }
            }
        }
        dock::DockPanel::SubagentTimeline => {
            let count = app.subagent_pane.records.len();
            if count == 0 {
                lines.push(dock_quiet_line("(no subagents)"));
            } else {
                lines.push(dock_text_line(&format!("{count} subagent(s)"), avail));
                for record in app
                    .subagent_pane
                    .records
                    .iter()
                    .take(max_rows.saturating_sub(1))
                {
                    let summary = first_line(&record.latest);
                    lines.push(dock_text_line(
                        &format!("{}: {summary}", record.agent),
                        avail,
                    ));
                }
            }
        }
        dock::DockPanel::Detail => match focused_entry_summary(app) {
            Some(summary) => lines.push(dock_text_line(&summary, avail)),
            None => lines.push(dock_quiet_line("(no focused entry)")),
        },
    }
    lines.truncate(max_rows.max(1));
    lines
}

/// A single docked-panel body line, clipped to `avail` columns so a wide line
/// never paints past the panel border.
fn dock_text_line(text: &str, avail: usize) -> Line<'static> {
    let clipped: String = text.chars().take(avail).collect();
    Line::from(Span::styled(
        clipped,
        Style::default().fg(crate::render::theme::foreground()),
    ))
}

/// A quiet empty-state line for a docked panel body.
fn dock_quiet_line(text: &str) -> Line<'static> {
    Line::from(Span::styled(
        text.to_string(),
        Style::default().fg(crate::render::theme::quiet()),
    ))
}

/// A one-line summary of the currently-focused transcript entry, for the docked
/// detail panel (§12.4.4). Reuses the §12.2.1 outline title source so the docked
/// detail names an entry exactly the way the turn outline does. `None` when
/// nothing is selected or the index is out of range.
fn focused_entry_summary(app: &TuiApp) -> Option<String> {
    let idx = app.selected_entry?;
    let entry = app.transcript.get(idx)?;
    Some(first_line(&outline_title_of(entry)))
}

/// The first non-empty visual line of `text`, with surrounding whitespace
/// trimmed — a one-line preview for a docked panel body row.
fn first_line(text: &str) -> String {
    text.lines()
        .map(str::trim)
        .find(|l| !l.is_empty())
        .unwrap_or("")
        .to_string()
}

fn paste_preview_inline_lines(
    preview: &paste_preview::PastePreview,
    width: u16,
) -> Vec<Line<'static>> {
    let mut lines = vec![
        Line::from(vec![
            Span::styled(
                "Large paste",
                Style::default()
                    .fg(crate::render::theme::warn())
                    .add_modifier(Modifier::BOLD),
            ),
            Span::styled(
                format!(" · {}", preview.summary()),
                Style::default().fg(crate::render::theme::secondary()),
            ),
        ]),
        Line::from(vec![
            Span::styled(
                "› Accept",
                Style::default()
                    .fg(crate::render::theme::warn())
                    .add_modifier(Modifier::BOLD),
            ),
            Span::styled(
                " (Enter/Y)",
                Style::default().fg(crate::render::theme::quiet()),
            ),
            Span::styled("   Discard", Style::default().fg(palette::muted_fg())),
            Span::styled(
                " (Esc/N)",
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]),
        Line::from(Span::styled(
            "Preview",
            Style::default().fg(crate::render::theme::quiet()),
        )),
    ];
    for raw in preview.preview_lines(width.saturating_sub(2) as usize) {
        lines.push(Line::from(Span::styled(
            raw,
            Style::default().fg(crate::render::theme::foreground()),
        )));
    }
    lines
}

fn render_paste_preview_inline(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    preview: &paste_preview::PastePreview,
) {
    let lines = paste_preview_inline_lines(preview, area.width);
    frame.render_widget(
        Paragraph::new(lines)
            .style(Style::default().fg(crate::render::theme::quiet()))
            .wrap(Wrap { trim: false }),
        area,
    );
    if area.height < 2 {
        return;
    }
    let row = area.y.saturating_add(1);
    let accept_w = "› Accept (Enter/Y)".chars().count() as u16;
    app.register_click(
        Rect {
            x: area.x,
            y: row,
            width: accept_w.min(area.width),
            height: 1,
        },
        interaction::TargetKey::Chrome(interaction::ChromeKey::PasteConfirm),
        interaction::Action::ConfirmPaste,
    );
    let discard_x = area.x.saturating_add(accept_w).saturating_add(3);
    if discard_x < area.x.saturating_add(area.width) {
        app.register_click(
            Rect {
                x: discard_x,
                y: row,
                width: "Discard (Esc/N)"
                    .chars()
                    .count()
                    .min(area.x.saturating_add(area.width).saturating_sub(discard_x) as usize)
                    as u16,
                height: 1,
            },
            interaction::TargetKey::Chrome(interaction::ChromeKey::PasteCancel),
            interaction::Action::CancelPaste,
        );
    }
}

fn paste_transform_inline_lines(menu: &paste_transform::PasteTransformMenu) -> Vec<Line<'static>> {
    let payload = menu.payload();
    let mut lines = vec![
        Line::from(vec![
            Span::styled(
                "Paste",
                Style::default()
                    .fg(crate::render::theme::accent())
                    .add_modifier(Modifier::BOLD),
            ),
            Span::styled(
                format!(" · {}", payload.summary()),
                Style::default().fg(crate::render::theme::secondary()),
            ),
        ]),
        Line::from(Span::styled(
            "↑↓ choose · Enter apply · Esc cancel",
            Style::default().fg(crate::render::theme::quiet()),
        )),
    ];
    let accent = crate::render::theme::accent();
    let foreground = crate::render::theme::foreground();
    let quiet = crate::render::theme::quiet();
    for (index, transform) in menu.items().iter().enumerate() {
        let selected = index == menu.selected();
        let caret = if selected { "› " } else { "  " };
        let style = if selected {
            Style::default().fg(accent).add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(foreground)
        };
        let mut spans = vec![
            Span::styled(caret, style),
            Span::styled(format!("{:<12}", transform.label()), style),
        ];
        if selected {
            spans.push(Span::styled(
                transform.description(),
                Style::default().fg(quiet),
            ));
        }
        lines.push(Line::from(spans));
    }
    lines
}

fn render_paste_transform_inline(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    menu: &paste_transform::PasteTransformMenu,
) {
    let lines = paste_transform_inline_lines(menu);
    frame.render_widget(
        Paragraph::new(lines)
            .style(Style::default().fg(crate::render::theme::quiet()))
            .wrap(Wrap { trim: false }),
        area,
    );
    let rows_top = area.y.saturating_add(2);
    for (index, _) in menu.items().iter().enumerate() {
        let row_y = rows_top.saturating_add(index as u16);
        if row_y >= area.y.saturating_add(area.height) {
            break;
        }
        app.register_click(
            Rect {
                x: area.x,
                y: row_y,
                width: area.width,
                height: 1,
            },
            interaction::TargetKey::Chrome(interaction::ChromeKey::PasteTransformItem(index)),
            interaction::Action::PasteTransformSelect(index),
        );
    }
}

/// Render the in-app clipboard-history picker (§12.6.1) over the whole frame.
///
/// Lays out a centered bordered modal (via the shared [`modal::surface`])
/// containing: a one-line header (entry count · total bytes), a scrollable list
/// of recent copies (newest first, the selected row highlighted, each row's rect
/// registered as a [`interaction::TargetKey::ClipboardEntry`] click target so a
/// click selects/re-copies it), and a `[ Re-copy ]` / `[ Delete ]` / `[ Clear ]`
/// button strip whose rects are registered as chrome targets — giving the mouse
/// path the same reach as the picker's Enter/`d`/`c` keyboard verbs. An empty
/// history shows an explanatory line instead of a list. Every registered rect is
/// in absolute screen coordinates because the modal paints fullscreen (matching
/// the hit-test in [`handle_mouse`]).
fn render_clipboard_history_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Clipboard history ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "— Squeezy's recent copies (never the OS clipboard) ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 100, 24, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header line: count + total bytes (or an empty-state hint).
    let header = if app.clipboard_history.is_empty() {
        Line::from(Span::styled(
            "No copies yet — copy something (Ctrl+Y, Alt+c, …) and it lands here.",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "{} · {} bytes total · ↑↓ select · Enter re-copy · d delete · p pin · c clear",
                count_label_entries(app.clipboard_history.len()),
                app.clipboard_history.total_bytes(),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    let header_rect = Rect { height: 1, ..inner };
    frame.render_widget(Paragraph::new(header), header_rect);

    // The list occupies the rows between the header and the bottom button strip
    // (last inner row, second-to-last a gap).
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height).saturating_sub(2);
    if list_bottom > list_top {
        let list_rect = Rect {
            x: inner.x,
            y: list_top,
            width: inner.width,
            height: list_bottom - list_top,
        };
        render_clipboard_history_list(frame, list_rect, app);
    }

    render_clipboard_history_buttons(frame, inner, app);
}

/// Paint the windowed list of history rows into `list_rect` and register each
/// visible row's rect as a [`interaction::TargetKey::ClipboardEntry`] click
/// target. The window scrolls to keep the selected row visible; each row shows a
/// pin marker, the copy label, and a bounded one-line preview of the payload.
fn render_clipboard_history_list(frame: &mut Frame<'_>, list_rect: Rect, app: &TuiApp) {
    let entries = app.clipboard_history.entries();
    if entries.is_empty() || list_rect.height == 0 {
        return;
    }
    let rows = list_rect.height as usize;
    let selected = app.clipboard_history.selected_index();
    // Scroll the window so the selected row stays visible.
    let start = selected
        .saturating_sub(rows.saturating_sub(1))
        .min(entries.len().saturating_sub(rows.min(entries.len())));
    let end = (start + rows).min(entries.len());

    for (offset, entry) in entries[start..end].iter().enumerate() {
        let index = start + offset;
        let is_selected = index == selected;
        let row_y = list_rect.y + offset as u16;
        let row_rect = Rect {
            x: list_rect.x,
            y: row_y,
            width: list_rect.width,
            height: 1,
        };

        let marker = if is_selected { "› " } else { "  " };
        // ASCII pin tag (not an emoji) so the marker is terminal-safe, fixed
        // width, and screen-reader-friendly — matching the rest of Squeezy's
        // chrome, which spells "pins" rather than using a glyph.
        let pin = if entry.pinned { "[pin] " } else { "" };
        let label_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{pin}{}", entry.label), label_style),
            Span::styled(
                format!("  {}", entry.preview()),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        // Register the whole row as a click target keyed by the entry's stable
        // id (NOT its index), so a click selects/re-copies the right entry even
        // after an eviction reshuffles the list.
        app.register_click(
            row_rect,
            interaction::TargetKey::ClipboardEntry(entry.id),
            interaction::Action::ClipboardSelect(entry.id),
        );
    }
}

/// Paint the `[ Re-copy ]` / `[ Delete ]` / `[ Clear all ]` button strip on the
/// modal's bottom inner row and register each button's rect as a chrome click
/// target. Split out so the labels, spacing, and registered rects are one place
/// the mouse hit-test and the rendered glyphs cannot drift. The re-copy / delete
/// buttons act on the currently-selected entry (resolved by id at click time);
/// they are still painted (greyed) on an empty history but register no target.
fn render_clipboard_history_buttons(frame: &mut Frame<'_>, inner: Rect, app: &TuiApp) {
    const RECOPY: &str = "[ Re-copy (Enter) ]";
    const DELETE: &str = "[ Delete (d) ]";
    const CLEAR: &str = "[ Clear all (c) ]";
    let row = inner.y + inner.height.saturating_sub(1);
    let has_entries = !app.clipboard_history.is_empty();

    let accent = crate::render::theme::accent();
    let quiet = crate::render::theme::quiet();
    let active = if has_entries { accent } else { quiet };
    let strip = Line::from(vec![
        Span::styled(
            RECOPY,
            Style::default().fg(active).add_modifier(Modifier::BOLD),
        ),
        Span::raw("  "),
        Span::styled(DELETE, Style::default().fg(active)),
        Span::raw("  "),
        Span::styled(CLEAR, Style::default().fg(quiet)),
    ]);
    let strip_rect = Rect {
        x: inner.x,
        y: row,
        width: inner.width,
        height: 1,
    };
    frame.render_widget(Paragraph::new(strip), strip_rect);

    // Register button rects left-to-right, clamped to the inner width. The
    // re-copy / delete buttons only register when there is a selected entry to
    // act on; clear-all always registers (it is valid on any non-empty history,
    // and a no-op otherwise).
    let selected_id = app.clipboard_history.selected_entry().map(|e| e.id);
    let mut x = inner.x;
    let right = inner.x.saturating_add(inner.width);

    if let Some(id) = selected_id {
        let w = (RECOPY.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::ClipboardRecopy),
                interaction::Action::ClipboardRecopy(id),
            );
        }
    }
    x = x
        .saturating_add(RECOPY.chars().count() as u16)
        .saturating_add(2);

    if let Some(id) = selected_id
        && x < right
    {
        let w = (DELETE.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::ClipboardDelete),
                interaction::Action::ClipboardDelete(id),
            );
        }
    }
    x = x
        .saturating_add(DELETE.chars().count() as u16)
        .saturating_add(2);

    if has_entries && x < right {
        let w = (CLEAR.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::ClipboardClear),
                interaction::Action::ClipboardClear,
            );
        }
    }
}

/// Paint the Keybinding Editor UI (§12.7.1) as a centered modal: a title, a
/// header (the capture prompt while capturing, else the column legend), the
/// windowed list of action rows, and a bottom button strip. Each visible row and
/// each button registers a click target so the mouse path mirrors the keyboard.
fn render_keybinding_editor_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let Some(editor) = app.keybinding_editor.as_ref() else {
        return;
    };
    let title = Line::from(vec![
        Span::styled(
            " Keybindings ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "— view and rebind actions (Ctrl+Alt+B) ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 100, 28, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header: the capture prompt + verdict while capturing, else the legend.
    let header = if editor.is_capturing() {
        let style = match editor.pending().map(|p| &p.outcome) {
            Some(keybinding_editor::CaptureOutcome::Reserved { .. })
            | Some(keybinding_editor::CaptureOutcome::Unsafe { .. })
            | Some(keybinding_editor::CaptureOutcome::Conflict { .. }) => Style::default()
                .fg(crate::render::theme::warn())
                .add_modifier(Modifier::BOLD),
            _ => Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        };
        Line::from(Span::styled(keybinding_editor_capture_status(app), style))
    } else {
        Line::from(Span::styled(
            "↑↓ select · Enter rebind · r/Del reset to default · Esc close",
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    let header_rect = Rect { height: 1, ..inner };
    frame.render_widget(Paragraph::new(header), header_rect);

    // The list occupies the rows between the header and the bottom button strip
    // (last inner row, second-to-last a gap).
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height).saturating_sub(2);
    if list_bottom > list_top {
        let list_rect = Rect {
            x: inner.x,
            y: list_top,
            width: inner.width,
            height: list_bottom - list_top,
        };
        render_keybinding_editor_list(frame, list_rect, app, editor);
    }

    render_keybinding_editor_buttons(frame, inner, app, editor);
}

/// Paint the windowed list of action rows into `list_rect` and register each
/// visible row's rect as a [`interaction::ChromeKey::KeybindingRow`] click target.
/// The window scrolls to keep the selected row visible. Each row shows a cursor
/// marker, the action slug, its current binding, an `(override)` tag when it
/// differs from the default, and a `[terminal-dependent]` note when the action
/// carries one.
fn render_keybinding_editor_list(
    frame: &mut Frame<'_>,
    list_rect: Rect,
    app: &TuiApp,
    editor: &keybinding_editor::KeybindingEditorState,
) {
    let rows = editor.rows();
    if rows.is_empty() || list_rect.height == 0 {
        return;
    }
    let visible = list_rect.height as usize;
    let selected = editor.selected_index();
    // Scroll the window so the selected row stays visible.
    let start = selected
        .saturating_sub(visible.saturating_sub(1))
        .min(rows.len().saturating_sub(visible.min(rows.len())));
    let end = (start + visible).min(rows.len());
    // Pad the slug column so the bindings line up.
    let slug_width = rows
        .iter()
        .map(|row| row.action.slug().len())
        .max()
        .unwrap_or(0);

    for (offset, row) in rows[start..end].iter().enumerate() {
        let index = start + offset;
        let is_selected = index == selected;
        let row_y = list_rect.y + offset as u16;
        let row_rect = Rect {
            x: list_rect.x,
            y: row_y,
            width: list_rect.width,
            height: 1,
        };

        let marker = if is_selected { "› " } else { "  " };
        let slug_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let mut spans = vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{:<slug_width$}", row.action.slug()), slug_style),
            Span::styled(
                format!("  {}", row.binding.display()),
                Style::default()
                    .fg(crate::render::theme::accent())
                    .add_modifier(Modifier::BOLD),
            ),
        ];
        if row.is_override {
            spans.push(Span::styled(
                "  (override)",
                Style::default().fg(crate::render::theme::secondary()),
            ));
        }
        if let Some(note) = row.action.terminal_compat_note() {
            spans.push(Span::styled(
                format!("  [{note}]"),
                Style::default().fg(crate::render::theme::quiet()),
            ));
        }
        frame.render_widget(Paragraph::new(Line::from(spans)), row_rect);

        // Register the whole row as a click target keyed by its index in the row
        // list (stable for the open editor — the list never reorders while open).
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::KeybindingRow(index)),
            interaction::Action::KeybindingSelect(index),
        );
    }
}

/// Paint the `[ Rebind (Enter) ]` / `[ Reset (r) ]` button strip on the modal's
/// bottom inner row and register each button's rect as a chrome click target.
/// Split out so the labels, spacing, and registered rects are one place the mouse
/// hit-test and the rendered glyphs cannot drift. Both buttons act on the
/// currently-selected row.
fn render_keybinding_editor_buttons(
    frame: &mut Frame<'_>,
    inner: Rect,
    app: &TuiApp,
    editor: &keybinding_editor::KeybindingEditorState,
) {
    const REBIND: &str = "[ Rebind (Enter) ]";
    const RESET: &str = "[ Reset (r) ]";
    let row = inner.y + inner.height.saturating_sub(1);
    let has_rows = !editor.is_empty();

    let accent = crate::render::theme::accent();
    let quiet = crate::render::theme::quiet();
    let active = if has_rows { accent } else { quiet };
    let strip = Line::from(vec![
        Span::styled(
            REBIND,
            Style::default().fg(active).add_modifier(Modifier::BOLD),
        ),
        Span::raw("  "),
        Span::styled(RESET, Style::default().fg(active)),
    ]);
    let strip_rect = Rect {
        x: inner.x,
        y: row,
        width: inner.width,
        height: 1,
    };
    frame.render_widget(Paragraph::new(strip), strip_rect);

    if !has_rows {
        return;
    }
    let mut x = inner.x;
    let right = inner.x.saturating_add(inner.width);

    let w = (REBIND.chars().count() as u16).min(right.saturating_sub(x));
    if w > 0 {
        app.register_click(
            Rect {
                x,
                y: row,
                width: w,
                height: 1,
            },
            interaction::TargetKey::Chrome(interaction::ChromeKey::KeybindingRebind),
            interaction::Action::KeybindingRebind,
        );
    }
    x = x
        .saturating_add(REBIND.chars().count() as u16)
        .saturating_add(2);

    if x < right {
        let w = (RESET.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::KeybindingReset),
                interaction::Action::KeybindingReset,
            );
        }
    }
}

/// Paint the Prompt Snippets picker (§12.3.2) as a centered modal: a title, a
/// header with the snippet count + total bytes (or an empty-state hint), the
/// windowed list of snippet rows, and a bottom button strip. Mirrors the
/// clipboard-history picker's layout so the two overlays read consistently.
fn render_snippets_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Prompt snippets ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "— reusable bits saved from selections (Alt+3) ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 100, 24, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    let total_bytes: usize = app.snippets.snippets().iter().map(|s| s.bytes()).sum();
    let header = if app.snippets.is_empty() {
        Line::from(Span::styled(
            "No snippets yet — select transcript text and press Alt+3 to save one here.",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "{} · {total_bytes} bytes total · ↑↓ select · Enter insert · q queue · d delete · c clear",
                count_label_snippets(app.snippets.len()),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    let header_rect = Rect { height: 1, ..inner };
    frame.render_widget(Paragraph::new(header), header_rect);

    // The list occupies the rows between the header and the bottom button strip
    // (last inner row, second-to-last a gap).
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height).saturating_sub(2);
    if list_bottom > list_top {
        let list_rect = Rect {
            x: inner.x,
            y: list_top,
            width: inner.width,
            height: list_bottom - list_top,
        };
        render_snippets_list(frame, list_rect, app);
    }

    render_snippets_buttons(frame, inner, app);
}

/// Paint the windowed list of snippet rows into `list_rect` and register each
/// visible row's rect as a [`interaction::TargetKey::SnippetEntry`] click target.
/// The window scrolls to keep the selected row visible; each row shows the
/// snippet name, a `[large]` tag when it is big enough to bloat a prompt, and a
/// bounded one-line preview of the body.
fn render_snippets_list(frame: &mut Frame<'_>, list_rect: Rect, app: &TuiApp) {
    let snippets = app.snippets.snippets();
    if snippets.is_empty() || list_rect.height == 0 {
        return;
    }
    let rows = list_rect.height as usize;
    let selected = app.snippets.selected_index();
    // Scroll the window so the selected row stays visible.
    let start = selected
        .saturating_sub(rows.saturating_sub(1))
        .min(snippets.len().saturating_sub(rows.min(snippets.len())));
    let end = (start + rows).min(snippets.len());

    for (offset, snippet) in snippets[start..end].iter().enumerate() {
        let index = start + offset;
        let is_selected = index == selected;
        let row_y = list_rect.y + offset as u16;
        let row_rect = Rect {
            x: list_rect.x,
            y: row_y,
            width: list_rect.width,
            height: 1,
        };

        let marker = if is_selected { "› " } else { "  " };
        // ASCII tag (not an emoji) so the marker is terminal-safe, fixed width,
        // and screen-reader-friendly — matching the rest of Squeezy's chrome.
        let large = if snippet.is_large() { "[large] " } else { "" };
        let name_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{large}{}", snippet.name), name_style),
            Span::styled(
                format!("  {}", snippet.preview()),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        // Register the whole row as a click target keyed by the snippet's stable
        // id (NOT its index), so a click selects/inserts the right snippet even
        // after a delete/drop reshuffles the list.
        app.register_click(
            row_rect,
            interaction::TargetKey::SnippetEntry(snippet.id),
            interaction::Action::SnippetSelect(snippet.id),
        );
    }
}

/// Paint the `[ Insert ]` / `[ Queue ]` / `[ Delete ]` / `[ Clear all ]` button
/// strip on the modal's bottom inner row and register each button's rect as a
/// chrome click target. The insert/queue/delete buttons act on the
/// currently-selected snippet (resolved by id at click time); they are still
/// painted (greyed) on an empty stash but register no target.
fn render_snippets_buttons(frame: &mut Frame<'_>, inner: Rect, app: &TuiApp) {
    const INSERT: &str = "[ Insert (Enter) ]";
    const QUEUE: &str = "[ Queue (q) ]";
    const DELETE: &str = "[ Delete (d) ]";
    const CLEAR: &str = "[ Clear all (c) ]";
    let row = inner.y + inner.height.saturating_sub(1);
    let has_snippets = !app.snippets.is_empty();

    let accent = crate::render::theme::accent();
    let quiet = crate::render::theme::quiet();
    let active = if has_snippets { accent } else { quiet };
    let strip = Line::from(vec![
        Span::styled(
            INSERT,
            Style::default().fg(active).add_modifier(Modifier::BOLD),
        ),
        Span::raw("  "),
        Span::styled(QUEUE, Style::default().fg(active)),
        Span::raw("  "),
        Span::styled(DELETE, Style::default().fg(active)),
        Span::raw("  "),
        Span::styled(CLEAR, Style::default().fg(quiet)),
    ]);
    let strip_rect = Rect {
        x: inner.x,
        y: row,
        width: inner.width,
        height: 1,
    };
    frame.render_widget(Paragraph::new(strip), strip_rect);

    // Register button rects left-to-right, clamped to the inner width. The
    // insert/queue/delete buttons only register when there is a selected snippet
    // to act on; clear-all always registers (valid on any non-empty stash).
    let selected_id = app.snippets.selected_snippet().map(|s| s.id);
    let mut x = inner.x;
    let right = inner.x.saturating_add(inner.width);

    if let Some(id) = selected_id {
        let w = (INSERT.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::SnippetInsert),
                interaction::Action::SnippetInsertCompose(id),
            );
        }
    }
    x = x
        .saturating_add(INSERT.chars().count() as u16)
        .saturating_add(2);

    if let Some(id) = selected_id
        && x < right
    {
        let w = (QUEUE.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::SnippetQueue),
                interaction::Action::SnippetEnqueue(id),
            );
        }
    }
    x = x
        .saturating_add(QUEUE.chars().count() as u16)
        .saturating_add(2);

    if let Some(id) = selected_id
        && x < right
    {
        let w = (DELETE.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::SnippetDelete),
                interaction::Action::SnippetDelete(id),
            );
        }
    }
    x = x
        .saturating_add(DELETE.chars().count() as u16)
        .saturating_add(2);

    if has_snippets && x < right {
        let w = (CLEAR.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::SnippetClear),
                interaction::Action::SnippetClear,
            );
        }
    }
}

/// Paint the Prompt Templates picker (§12.3.6) over the whole frame.
///
/// Two modes share the modal surface: the template LIST (browse + select) and an
/// instantiated CARD (fill its `{slot}`s then enqueue). The mode is chosen by
/// `app.template_card` so the picker can be a thin shell over the pure model.
fn render_templates_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Prompt templates ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "— reusable prompts with editable slots (Ctrl+Alt+T) ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 100, 24, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }
    if app.template_card.is_some() {
        render_template_card(frame, inner, app);
    } else {
        render_template_list(frame, inner, app);
    }
}

/// Paint the LIST mode: a header stat line, the windowed list of template rows
/// (each registered as a [`interaction::TargetKey::TemplateEntry`] click target),
/// and the `[ Delete ]` / `[ Clear all ]` button strip.
fn render_template_list(frame: &mut Frame<'_>, inner: Rect, app: &TuiApp) {
    let header = if app.templates.is_empty() {
        Line::from(Span::styled(
            "No templates yet — they appear here as fillable queue cards (Ctrl+Alt+T).",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "{} · ↑↓ select · Enter fill slots · d delete · c clear",
                count_label_templates(app.templates.len()),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height).saturating_sub(2);
    if list_bottom > list_top {
        let list_rect = Rect {
            x: inner.x,
            y: list_top,
            width: inner.width,
            height: list_bottom - list_top,
        };
        render_template_rows(frame, list_rect, app);
    }
    render_template_list_buttons(frame, inner, app);
}

/// Paint the windowed list of template rows into `list_rect` and register each
/// visible row's rect as a [`interaction::TargetKey::TemplateEntry`] click target.
/// The window scrolls to keep the selected row visible; each row shows the
/// template name, a slot count, and a bounded one-line preview of the body.
fn render_template_rows(frame: &mut Frame<'_>, list_rect: Rect, app: &TuiApp) {
    let templates = app.templates.templates();
    if templates.is_empty() || list_rect.height == 0 {
        return;
    }
    let rows = list_rect.height as usize;
    let selected = app.templates.selected_index();
    let start = selected
        .saturating_sub(rows.saturating_sub(1))
        .min(templates.len().saturating_sub(rows.min(templates.len())));
    let end = (start + rows).min(templates.len());

    for (offset, template) in templates[start..end].iter().enumerate() {
        let index = start + offset;
        let is_selected = index == selected;
        let row_rect = Rect {
            x: list_rect.x,
            y: list_rect.y + offset as u16,
            width: list_rect.width,
            height: 1,
        };
        let marker = if is_selected { "› " } else { "  " };
        let slot_count = template.slot_count();
        let slots = if slot_count == 1 {
            "1 slot".to_string()
        } else {
            format!("{slot_count} slots")
        };
        let name_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(
                format!("[{slots}] "),
                Style::default().fg(crate::render::theme::quiet()),
            ),
            Span::styled(template.name.clone(), name_style),
            Span::styled(
                format!("  {}", template.preview()),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        app.register_click(
            row_rect,
            interaction::TargetKey::TemplateEntry(template.id),
            interaction::Action::TemplateSelect(template.id),
        );
    }
}

/// Paint the `[ Delete ]` / `[ Clear all ]` button strip on the LIST mode's bottom
/// inner row and register each button's rect as a chrome click target. The delete
/// button acts on the currently-selected template (resolved by id at click time);
/// both are painted greyed on an empty store but register no target.
fn render_template_list_buttons(frame: &mut Frame<'_>, inner: Rect, app: &TuiApp) {
    const DELETE: &str = "[ Delete (d) ]";
    const CLEAR: &str = "[ Clear all (c) ]";
    let row = inner.y + inner.height.saturating_sub(1);
    let has_templates = !app.templates.is_empty();
    let accent = crate::render::theme::accent();
    let quiet = crate::render::theme::quiet();
    let active = if has_templates { accent } else { quiet };
    let strip = Line::from(vec![
        Span::styled(DELETE, Style::default().fg(active)),
        Span::raw("  "),
        Span::styled(CLEAR, Style::default().fg(quiet)),
    ]);
    frame.render_widget(
        Paragraph::new(strip),
        Rect {
            x: inner.x,
            y: row,
            width: inner.width,
            height: 1,
        },
    );
    let right = inner.x.saturating_add(inner.width);
    let mut x = inner.x;
    if let Some(id) = app.templates.selected_template().map(|t| t.id) {
        let w = (DELETE.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::TemplateDelete),
                interaction::Action::TemplateDelete(id),
            );
        }
    }
    x = x
        .saturating_add(DELETE.chars().count() as u16)
        .saturating_add(2);
    if has_templates && x < right {
        let w = (CLEAR.chars().count() as u16).min(right.saturating_sub(x));
        if w > 0 {
            app.register_click(
                Rect {
                    x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::TemplateClear),
                interaction::Action::TemplateClear,
            );
        }
    }
}

/// Paint the CARD mode: a header naming the template, the resolved-prompt preview,
/// the per-slot editor rows (each a [`interaction::ChromeKey::TemplateSlotRow`]
/// click target), an inline missing-slots status, and the `[ Enqueue ]` button.
fn render_template_card(frame: &mut Frame<'_>, inner: Rect, app: &TuiApp) {
    let Some(card) = app.template_card.as_ref() else {
        return;
    };
    // Name the focused slot in the header so the user always knows which slot a
    // keystroke lands in, even when the slot list is scrolled.
    let focus_label = match card.focused_slot() {
        Some(name) => format!(
            "Fill '{}' · slot {}/{} {{{name}}}",
            card.name,
            card.focused_index() + 1,
            card.slot_count(),
        ),
        None => format!("Fill '{}'", card.name),
    };
    let header = Line::from(vec![
        Span::styled(
            focus_label,
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "  Tab next · type to fill · Ctrl+U clear · Enter enqueue · Esc back",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    // Slot editor rows occupy the band between the header and the bottom button +
    // status rows (last inner row = button, second-to-last = inline status).
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height).saturating_sub(2);
    if card.has_no_slots() {
        if list_bottom > list_top {
            frame.render_widget(
                Paragraph::new(Line::from(Span::styled(
                    "  (this template has no slots — press Enter to enqueue it)",
                    Style::default().fg(crate::render::theme::quiet()),
                ))),
                Rect {
                    x: inner.x,
                    y: list_top,
                    width: inner.width,
                    height: 1,
                },
            );
        }
    } else if list_bottom > list_top {
        let band = Rect {
            x: inner.x,
            y: list_top,
            width: inner.width,
            height: list_bottom - list_top,
        };
        render_template_slot_rows(frame, band, app, card);
    }

    // Inline missing-slots status on the second-to-last inner row.
    let status_row = inner.y + inner.height.saturating_sub(2);
    if status_row >= list_top {
        let missing = card.missing_slots();
        let status = if missing.is_empty() {
            Line::from(Span::styled(
                "all slots filled — Enter to enqueue",
                Style::default().fg(crate::render::theme::accent()),
            ))
        } else {
            Line::from(Span::styled(
                format!(
                    "blocked: fill {} ({} left)",
                    missing.join(", "),
                    missing.len()
                ),
                Style::default().fg(crate::render::theme::warn()),
            ))
        };
        frame.render_widget(
            Paragraph::new(status),
            Rect {
                x: inner.x,
                y: status_row,
                width: inner.width,
                height: 1,
            },
        );
    }

    // The Enqueue button on the bottom inner row. Greyed (no target) while a slot
    // is still empty so a click cannot enqueue an unresolved card; the keyboard
    // Enter is likewise blocked with status by `enqueue_template_card`.
    const ENQUEUE: &str = "[ Enqueue (Enter) ]";
    let row = inner.y + inner.height.saturating_sub(1);
    let runnable = card.missing_slots().is_empty();
    let color = if runnable {
        crate::render::theme::accent()
    } else {
        crate::render::theme::quiet()
    };
    frame.render_widget(
        Paragraph::new(Line::from(Span::styled(
            ENQUEUE,
            Style::default().fg(color).add_modifier(Modifier::BOLD),
        ))),
        Rect {
            x: inner.x,
            y: row,
            width: inner.width,
            height: 1,
        },
    );
    if runnable {
        let w = (ENQUEUE.chars().count() as u16).min(inner.width);
        if w > 0 {
            app.register_click(
                Rect {
                    x: inner.x,
                    y: row,
                    width: w,
                    height: 1,
                },
                interaction::TargetKey::Chrome(interaction::ChromeKey::TemplateEnqueue),
                interaction::Action::TemplateEnqueue,
            );
        }
    }
}

/// Paint one editor row per slot into `band` and register each as a
/// [`interaction::ChromeKey::TemplateSlotRow`] click target keyed by slot index.
/// The focused slot is marked with `›` and its value shown with a `_` caret; an
/// empty slot reads `(empty)` in the quiet colour so the user sees what is left to
/// fill.
fn render_template_slot_rows(
    frame: &mut Frame<'_>,
    band: Rect,
    app: &TuiApp,
    card: &prompt_template::TemplateCard,
) {
    let slots = card.slots();
    let rows = band.height as usize;
    let focused = card.focused_index();
    // Scroll the window so the focused slot stays visible.
    let start = focused
        .saturating_sub(rows.saturating_sub(1))
        .min(slots.len().saturating_sub(rows.min(slots.len())));
    let end = (start + rows).min(slots.len());

    for (offset, name) in slots[start..end].iter().enumerate() {
        let index = start + offset;
        let is_focused = index == focused;
        let row_rect = Rect {
            x: band.x,
            y: band.y + offset as u16,
            width: band.width,
            height: 1,
        };
        let marker = if is_focused { "› " } else { "  " };
        let value = card.value_at(index);
        let value_span = if value.is_empty() {
            Span::styled(
                "(empty)",
                Style::default().fg(crate::render::theme::quiet()),
            )
        } else {
            Span::styled(
                value.to_string(),
                Style::default().fg(crate::render::theme::foreground()),
            )
        };
        let name_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let mut spans = vec![
            Span::styled(
                marker,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{{{name}}}"), name_style),
            Span::styled("  =  ", Style::default().fg(crate::render::theme::quiet())),
            value_span,
        ];
        // A caret on the focused row so the editor reads as a text field.
        if is_focused {
            spans.push(Span::styled(
                "_",
                Style::default().fg(crate::render::theme::accent()),
            ));
        }
        frame.render_widget(Paragraph::new(Line::from(spans)), row_rect);
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::TemplateSlotRow(index)),
            interaction::Action::TemplateFocusSlot(index),
        );
    }
}

/// Paint the Scratchpad Pane (§12.3.3) over the whole frame.
///
/// Clears the surface and draws a bordered block, then reuses the §11G.10
/// detail-pane split machinery ([`diff_detail_pane::split_overlay_content`]) to
/// carve the inner area into a LEFT transcript-context column (read-only, so the
/// user keeps their bearings while jotting notes) and a RIGHT editable scratch
/// column. When the terminal is too narrow to split usefully the scratch column
/// takes the full inner width — a graceful fallback, never a corrupted squeeze.
/// The bottom inner row holds the `[ Insert ]` / `[ Queue ]` / `[ Append ]` /
/// `[ Clear ]` button strip whose rects register as chrome click targets (the
/// mouse twins of `Ctrl+I` / `Ctrl+Q` / `Ctrl+L` / `Ctrl+K`).
fn render_scratchpad_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let dirty = if app.scratchpad.is_dirty() { " *" } else { "" };
    let title = format!(
        " Scratchpad{dirty} — session notes (never sent unless inserted) · {} or Esc to close ",
        key_hint(app, keymap::Action::ToggleScratchpad),
    );
    frame.render_widget(ratatui::widgets::Clear, area);
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(crate::render::theme::accent()))
        .title(Span::styled(
            title,
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ));
    let inner = block.inner(area);
    frame.render_widget(block, area);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Reserve the bottom inner row for the button strip; the columns get the rest.
    let body = Rect {
        height: inner.height.saturating_sub(1),
        ..inner
    };

    // Reuse the detail-pane split: transcript context on the left, scratch on the
    // right. Too narrow to split → scratch takes the whole body (graceful no-op).
    let scratch_rect = match diff_detail_pane::split_overlay_content(body) {
        Some(layout) if body.height > 0 => {
            render_scratchpad_context(frame, layout.transcript, app);
            // The one-cell separator gutter between the columns is the transcript
            // rail — Squeezy chrome — so resolve it from the active Minimal Glyph
            // Mode (§12.7.6) rail token. Unicode mode resolves to the same `│` as
            // before (default snapshots stay byte-identical); Compact keeps `│` and
            // ASCII drops to `|`.
            if layout.separator.height > 0 {
                let rail = app.glyph_mode.tokens().border_vertical;
                let sep: String = rail.repeat(layout.separator.height as usize);
                let mut sep_lines = Vec::new();
                for ch in sep.chars() {
                    sep_lines.push(Line::from(Span::styled(
                        ch.to_string(),
                        Style::default().fg(crate::render::theme::quiet()),
                    )));
                }
                frame.render_widget(Paragraph::new(sep_lines), layout.separator);
            }
            layout.pane
        }
        _ => body,
    };
    render_scratchpad_editor(frame, scratch_rect, app);
    render_scratchpad_buttons(frame, inner, app);
}

/// Paint the read-only transcript-context column on the LEFT of the scratchpad
/// split: a quiet header plus the tail of the live transcript so the user keeps
/// their place while jotting notes. Reuses the cached overlay row projection, so
/// it does no extra transcript walk; shows the LAST rows that fit (the most
/// recent context). Read-only — it registers no click targets and paints no
/// selection/cursor.
fn render_scratchpad_context(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    if area.width == 0 || area.height == 0 {
        return;
    }
    let header = Line::from(Span::styled(
        "transcript (context)",
        Style::default()
            .fg(crate::render::theme::quiet())
            .add_modifier(Modifier::BOLD),
    ));
    let header_rect = Rect { height: 1, ..area };
    frame.render_widget(Paragraph::new(header), header_rect);
    let rows_h = area.height.saturating_sub(1);
    if rows_h == 0 {
        return;
    }
    let rows_rect = Rect {
        x: area.x,
        y: area.y + 1,
        width: area.width,
        height: rows_h,
    };
    with_transcript_overlay_rows(app, rows_rect.width, |rows| {
        // Show the TAIL of the transcript (the most recent rows) so the context
        // column tracks where the conversation is now.
        let take = (rows_rect.height as usize).min(rows.len());
        let start = rows.len().saturating_sub(take);
        let shown: Vec<Line<'static>> = rows[start..].to_vec();
        frame.render_widget(Paragraph::new(shown), rows_rect);
    });
}

/// Paint the editable scratch buffer into `area`: a quiet header, then the buffer
/// text windowed vertically to keep the caret line in view, with a block cursor
/// painted at the caret's `(line, column)`. The buffer is plain text with
/// embedded newlines, exactly like the composer; long lines are clipped to the
/// column width (the pane is for notes, not wide code).
fn render_scratchpad_editor(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    if area.width == 0 || area.height == 0 {
        return;
    }
    let header = Line::from(Span::styled(
        "notes (Ctrl+I → composer · Ctrl+Q → queue · Ctrl+L append · Ctrl+K clear)",
        Style::default().fg(crate::render::theme::secondary()),
    ));
    let header_rect = Rect { height: 1, ..area };
    frame.render_widget(Paragraph::new(header), header_rect);
    let body_h = area.height.saturating_sub(1);
    if body_h == 0 {
        return;
    }
    let body_rect = Rect {
        x: area.x,
        y: area.y + 1,
        width: area.width,
        height: body_h,
    };

    if app.scratchpad.is_empty() {
        // The caret block leads, then the dim placeholder hint — so the block
        // never clobbers the hint's first glyph (which it would at column 0).
        let hint = Line::from(vec![
            Span::styled(
                "\u{2588}",
                Style::default().fg(crate::render::theme::accent()),
            ),
            Span::styled(
                "Empty — type notes, or Ctrl+L to append the selection.",
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(hint), body_rect);
        return;
    }

    let lines = app.scratchpad.lines();
    let (cursor_line, cursor_col) = app.scratchpad.cursor_line_col();
    let viewport = body_rect.height as usize;
    // Scroll the window so the caret line stays visible (keep it on the last row
    // when the buffer overflows downward).
    let start = cursor_line.saturating_sub(viewport.saturating_sub(1));
    let width = body_rect.width as usize;
    let mut painted = Vec::with_capacity(viewport);
    for line in lines.iter().skip(start).take(viewport) {
        // Clip each display line to the column width so a long note never spills.
        let clipped: String = line.chars().take(width).collect();
        painted.push(Line::from(Span::styled(
            clipped,
            Style::default().fg(crate::render::theme::foreground()),
        )));
    }
    frame.render_widget(Paragraph::new(painted), body_rect);

    // Paint the block cursor at the caret, clamped into the visible window.
    if cursor_line >= start && cursor_line < start + viewport {
        let row = (cursor_line - start) as u16;
        let col = (cursor_col.min(width.saturating_sub(1))) as u16;
        paint_scratchpad_cursor(frame, body_rect, row, col);
    }
}

/// Paint a single block-cursor cell at `(row, col)` offset inside `body_rect`,
/// clamped to the rect so it never paints out of bounds. Shared by the empty and
/// populated editor paths so the caret always reads as a live text cursor.
fn paint_scratchpad_cursor(frame: &mut Frame<'_>, body_rect: Rect, row: u16, col: u16) {
    if row >= body_rect.height || col >= body_rect.width {
        return;
    }
    let cell = Rect {
        x: body_rect.x + col,
        y: body_rect.y + row,
        width: 1,
        height: 1,
    };
    frame.render_widget(
        Paragraph::new(Line::from(Span::styled(
            "\u{2588}",
            Style::default().fg(crate::render::theme::accent()),
        ))),
        cell,
    );
}

/// Paint the `[ Insert ]` / `[ Queue ]` / `[ Append ]` / `[ Clear ]` button strip
/// on the scratchpad's bottom inner row and register each button's rect as a
/// chrome click target (the mouse twins of `Ctrl+I` / `Ctrl+Q` / `Ctrl+L` /
/// `Ctrl+K`). Insert/Queue grey out on an empty buffer and register no target
/// then; Append and Clear always register (Append works off a selection even when
/// the buffer is empty; Clear is a safe no-op on an empty buffer).
fn render_scratchpad_buttons(frame: &mut Frame<'_>, inner: Rect, app: &TuiApp) {
    const INSERT: &str = "[ Insert (Ctrl+I) ]";
    const QUEUE: &str = "[ Queue (Ctrl+Q) ]";
    const APPEND: &str = "[ Append (Ctrl+L) ]";
    const CLEAR: &str = "[ Clear (Ctrl+K) ]";
    let row = inner.y + inner.height.saturating_sub(1);
    let has_text = !app.scratchpad.is_empty();

    let accent = crate::render::theme::accent();
    let quiet = crate::render::theme::quiet();
    let active = if has_text { accent } else { quiet };
    let strip = Line::from(vec![
        Span::styled(
            INSERT,
            Style::default().fg(active).add_modifier(Modifier::BOLD),
        ),
        Span::raw("  "),
        Span::styled(QUEUE, Style::default().fg(active)),
        Span::raw("  "),
        Span::styled(APPEND, Style::default().fg(accent)),
        Span::raw("  "),
        Span::styled(CLEAR, Style::default().fg(accent)),
    ]);
    let strip_rect = Rect {
        x: inner.x,
        y: row,
        width: inner.width,
        height: 1,
    };
    frame.render_widget(Paragraph::new(strip), strip_rect);

    // Register button rects left-to-right, clamped to the inner width.
    let mut x = inner.x;
    let right = inner.x.saturating_add(inner.width);
    let mut place =
        |label: &str, key: interaction::ChromeKey, action: interaction::Action, enabled: bool| {
            let span = label.chars().count() as u16;
            if enabled && x < right {
                let w = span.min(right.saturating_sub(x));
                if w > 0 {
                    app.register_click(
                        Rect {
                            x,
                            y: row,
                            width: w,
                            height: 1,
                        },
                        interaction::TargetKey::Chrome(key),
                        action,
                    );
                }
            }
            x = x.saturating_add(span).saturating_add(2);
        };
    place(
        INSERT,
        interaction::ChromeKey::ScratchpadInsert,
        interaction::Action::ScratchpadInsertCompose,
        has_text,
    );
    place(
        QUEUE,
        interaction::ChromeKey::ScratchpadQueue,
        interaction::Action::ScratchpadEnqueue,
        has_text,
    );
    place(
        APPEND,
        interaction::ChromeKey::ScratchpadAppend,
        interaction::Action::ScratchpadAppend,
        true,
    );
    place(
        CLEAR,
        interaction::ChromeKey::ScratchpadClear,
        interaction::Action::ScratchpadClear,
        true,
    );
}

/// Map a click column on a Theme Editor (§12.7.2) channel bar to a 0..=255 value.
/// The bar's `track` cells (the rect minus its leading "R " label) span the full
/// 0..=255 range; a click left of the track reads as 0 and right of it as 255, so
/// a click anywhere along the bar is well-defined. Pure geometry, unit-tested.
fn theme_editor_channel_value_at(bar: Rect, column: u16) -> u8 {
    // The first 2 cells of the bar are the "R "/"G "/"B " label; the rest is the
    // 256-step track.
    let track_x = bar.x.saturating_add(THEME_EDITOR_BAR_LABEL_WIDTH);
    let track_w = bar.width.saturating_sub(THEME_EDITOR_BAR_LABEL_WIDTH);
    if track_w == 0 {
        return 0;
    }
    if column <= track_x {
        return 0;
    }
    let offset = (column - track_x).min(track_w.saturating_sub(1));
    // Spread the click offset across 0..=255 so the leftmost track cell is 0 and
    // the rightmost is 255 (a single-cell track maps everything to 0).
    let denom = track_w.saturating_sub(1).max(1) as u32;
    ((offset as u32 * 255) / denom).min(255) as u8
}

/// Width of the single-letter channel label ("R ", "G ", "B ") at the head of a
/// Theme Editor channel bar, in cells. The remaining bar width is the value track.
const THEME_EDITOR_BAR_LABEL_WIDTH: u16 = 2;

/// Paint the Theme Editor overlay (§12.7.2) as a centered modal: a left rail of
/// the curated palette ROLES (the focused one marked) and a right panel showing
/// the focused role's live preview swatch, its hex value, and three R/G/B channel
/// bars (the focused channel marked). Each role row registers a
/// [`interaction::ChromeKey::ThemeEditorRole`] click target so a click focuses it
/// (the mouse twin of ↑↓); each channel bar registers a
/// [`interaction::ChromeKey::ThemeEditorChannel`] target so a click along it sets
/// that channel's value (the mouse twin of ←→ + +/-). Reads only the pure editor
/// state, so painting is constant-time and does no transcript walk.
fn render_theme_editor_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    state: &theme_editor::ThemeEditorState,
) {
    let title = Line::from(vec![
        Span::styled(
            " Theme editor ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} pick palette colours with live preview ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 78, 22, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header: the in-overlay verb legend.
    let header = Line::from(Span::styled(
        "\u{2191}\u{2193} role \u{00b7} \u{2190}\u{2192} channel \u{00b7} +/- adjust \u{00b7} Enter save \u{00b7} Bksp reset \u{00b7} Esc close",
        Style::default()
            .fg(crate::render::theme::secondary())
            .add_modifier(Modifier::BOLD),
    ));
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    let body_top = inner.y.saturating_add(2);
    let body_h = inner
        .y
        .saturating_add(inner.height)
        .saturating_sub(body_top);
    if body_h == 0 {
        return;
    }

    // Split the body: a fixed-width role rail on the left, the preview panel on
    // the right. Fall back to rail-only when too narrow to show both.
    let rail_w = inner.width.min(22);
    let rail = Rect {
        x: inner.x,
        y: body_top,
        width: rail_w,
        height: body_h,
    };
    render_theme_editor_roles(frame, rail, app, state);

    let panel_x = inner.x.saturating_add(rail_w).saturating_add(1);
    let panel_right = inner.x.saturating_add(inner.width);
    if panel_x < panel_right {
        let panel = Rect {
            x: panel_x,
            y: body_top,
            width: panel_right - panel_x,
            height: body_h,
        };
        render_theme_editor_panel(frame, panel, app, state);
    }
}

/// Paint the role rail (left column) of the Theme Editor (§12.7.2): one row per
/// curated palette role, each prefixed with a small live-colour swatch and marked
/// when focused. Every row registers a [`interaction::ChromeKey::ThemeEditorRole`]
/// click target so a click focuses that role.
fn render_theme_editor_roles(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    state: &theme_editor::ThemeEditorState,
) {
    if area.width == 0 || area.height == 0 {
        return;
    }
    let focused = state.role_index();
    let rows = area.height as usize;
    for (index, role) in theme_editor::ROLES.iter().enumerate().take(rows) {
        let is_focused = index == focused;
        let row_rect = Rect {
            x: area.x,
            y: area.y + index as u16,
            width: area.width,
            height: 1,
        };
        let swatch_rgb = crate::render::theme::rgb(role.token);
        let swatch_color = Color::Rgb(swatch_rgb[0], swatch_rgb[1], swatch_rgb[2]);
        let marker = if is_focused { "\u{203a} " } else { "  " };
        let label_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled("\u{25a0} ", Style::default().fg(swatch_color)),
            Span::styled(role.label, label_style),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::ThemeEditorRole(index)),
            interaction::Action::ThemeEditorSelectRole(index),
        );
    }
}

/// Paint the preview panel (right column) of the Theme Editor (§12.7.2): the
/// focused role's description, a large live-colour preview swatch, its hex value,
/// and the three R/G/B channel bars. The focused channel is marked; each bar
/// registers a [`interaction::ChromeKey::ThemeEditorChannel`] click target so a
/// click along it sets that channel's value.
fn render_theme_editor_panel(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    state: &theme_editor::ThemeEditorState,
) {
    if area.width == 0 || area.height == 0 {
        return;
    }
    let role = state.current_role();
    let [r, g, b] = state.rgb();
    let preview_color = Color::Rgb(r, g, b);

    let mut y = area.y;
    let bottom = area.y.saturating_add(area.height);

    // Role description line.
    if y < bottom {
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                role.description,
                Style::default().fg(crate::render::theme::quiet()),
            ))),
            Rect {
                x: area.x,
                y,
                width: area.width,
                height: 1,
            },
        );
        y = y.saturating_add(1);
    }

    // Preview swatch (a solid block run in the live colour) plus the hex value.
    if y < bottom {
        let swatch_w = area.width.min(10);
        let swatch: String = "\u{2588}".repeat(swatch_w as usize);
        frame.render_widget(
            Paragraph::new(Line::from(vec![
                Span::styled(swatch, Style::default().fg(preview_color)),
                Span::raw("  "),
                Span::styled(
                    format!("#{r:02X}{g:02X}{b:02X}"),
                    Style::default()
                        .fg(crate::render::theme::foreground())
                        .add_modifier(Modifier::BOLD),
                ),
            ])),
            Rect {
                x: area.x,
                y,
                width: area.width,
                height: 1,
            },
        );
        y = y.saturating_add(2);
    }

    // One bar per channel.
    for (channel_index, channel) in theme_editor::Channel::ALL.iter().enumerate() {
        if y >= bottom {
            break;
        }
        let is_focused = state.channel() == *channel;
        let value = state.channel_value(*channel);
        let bar_rect = Rect {
            x: area.x,
            y,
            width: area.width,
            height: 1,
        };
        render_theme_editor_bar(frame, bar_rect, *channel, value, is_focused);
        app.register_click(
            bar_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::ThemeEditorChannel(
                channel_index,
            )),
            // The value baked in is a placeholder; the mouse handler recomputes it
            // from the clicked column against this bar's rect.
            interaction::Action::ThemeEditorSetChannel(channel_index, value),
        );
        y = y.saturating_add(1);
    }
}

/// Build the display [`workspace_profile::UiProfile`] for the overlay from the
/// LIVE app state plus the runtime theme name. Render-only and agent-free, so the
/// overlay shows the current on-screen preferences without a config snapshot.
fn workspace_profile_live(app: &TuiApp) -> workspace_profile::UiProfile {
    workspace_profile::UiProfile::new(
        app.tool_output_verbosity,
        app.transcript_default,
        app.show_minimap,
        render::theme::current_theme_name(),
    )
}

/// Paint the Per-Workspace UI Profile overlay (§12.7.4) as a centered modal: a
/// header naming where the profile is stored, a list of the remembered fields
/// (density, transcript detail, minimap pane, theme) with their LIVE values (the
/// focused one marked), and a footer with the verb legend. Each field row
/// registers a [`interaction::ChromeKey::WorkspaceProfileField`] click target so a
/// click focuses it (the mouse twin of ↑↓). Reads only the live app state, so
/// painting is constant-time and does no transcript walk.
fn render_workspace_profile_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    state: &workspace_profile::WorkspaceProfileState,
) {
    let title = Line::from(vec![
        Span::styled(
            " Workspace UI profile ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} remembered per workspace ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 16, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header: where this workspace's profile is stored (source label).
    let header = Line::from(vec![
        Span::styled(
            "stored at ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
        Span::styled(
            state.source_label().to_string(),
            Style::default().fg(crate::render::theme::secondary()),
        ),
    ]);
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    let live = workspace_profile_live(app);
    let focused = state.field_index();
    let rows_top = inner.y.saturating_add(2);
    let rows_avail = inner
        .y
        .saturating_add(inner.height)
        .saturating_sub(rows_top)
        .saturating_sub(1); // reserve the last inner row for the footer legend
    let value_col = inner.x.saturating_add(20).min(inner.x + inner.width);

    for (index, field) in workspace_profile::FIELDS
        .iter()
        .enumerate()
        .take(rows_avail as usize)
    {
        let is_focused = index == focused;
        let row_rect = Rect {
            x: inner.x,
            y: rows_top + index as u16,
            width: inner.width,
            height: 1,
        };
        let marker = if is_focused { "\u{203a} " } else { "  " };
        let label_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let label_line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(field.label(), label_style),
        ]);
        frame.render_widget(Paragraph::new(label_line), row_rect);

        // The current live value, painted in a fixed value column.
        if value_col < inner.x.saturating_add(inner.width) {
            let value_rect = Rect {
                x: value_col,
                y: row_rect.y,
                width: inner
                    .x
                    .saturating_add(inner.width)
                    .saturating_sub(value_col),
                height: 1,
            };
            frame.render_widget(
                Paragraph::new(Line::from(Span::styled(
                    field.value_str(&live),
                    Style::default().fg(crate::render::theme::foreground()),
                ))),
                value_rect,
            );
        }

        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::WorkspaceProfileField(index)),
            interaction::Action::WorkspaceProfileSelectField(index),
        );
    }

    // Footer: the in-overlay verb legend on the last inner row.
    let footer_y = inner.y.saturating_add(inner.height).saturating_sub(1);
    if footer_y >= rows_top {
        let footer_rect = Rect {
            x: inner.x,
            y: footer_y,
            width: inner.width,
            height: 1,
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                "\u{2191}\u{2193} field \u{00b7} s save live \u{00b7} r restore saved \u{00b7} x reset \u{00b7} Esc close",
                Style::default()
                    .fg(crate::render::theme::secondary())
                    .add_modifier(Modifier::BOLD),
            ))),
            footer_rect,
        );
    }
}

/// Paint the Session Auto-Save Checkpoints status overlay (§12.9.5) as a centered
/// modal: a header naming the session whose checkpoint this is, a read-only list
/// of the logical fields the checkpoint would restore (scroll anchor, focused
/// entry, search, minimap pane), a `[restore]` affordance, and a footer with the
/// verb legend. The `[restore]` line registers a
/// [`interaction::ChromeKey::CheckpointRestore`] click target so a click restores
/// it (the mouse twin of `r`). Reads only the captured checkpoint snapshot, so
/// painting is constant-time and does no transcript walk.
fn render_session_checkpoint_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    checkpoint: &session_checkpoint::UiStateCheckpoint,
) {
    let title = Line::from(vec![
        Span::styled(
            " Session checkpoint ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} auto-saved UI state ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 64, 14, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    let has_saved = !checkpoint.session_id.is_empty();

    // Header: whether a checkpoint exists for this session, and for which session.
    let header = if has_saved {
        Line::from(vec![
            Span::styled(
                "saved for session ",
                Style::default().fg(crate::render::theme::quiet()),
            ),
            Span::styled(
                checkpoint.session_id.clone(),
                Style::default().fg(crate::render::theme::secondary()),
            ),
        ])
    } else {
        Line::from(Span::styled(
            "no checkpoint saved yet \u{2014} one is auto-saved as you work",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    };
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    // The logical fields the checkpoint would restore, as read-only rows.
    let scroll_value = if checkpoint.following_tail {
        "following tail".to_string()
    } else {
        format!("{} line(s) up", checkpoint.scroll_from_bottom)
    };
    let selected_value = match checkpoint.selected_entry {
        Some(index) => format!("entry #{index}"),
        None => "\u{2014}".to_string(),
    };
    let search_value = checkpoint
        .search_query
        .clone()
        .unwrap_or_else(|| "\u{2014}".to_string());
    let minimap_value = if checkpoint.show_minimap {
        "shown"
    } else {
        "hidden"
    };
    let rows: [(&str, String); 4] = [
        ("Scroll", scroll_value),
        ("Focused entry", selected_value),
        ("Search", search_value),
        ("Minimap pane", minimap_value.to_string()),
    ];
    let rows_top = inner.y.saturating_add(2);
    let value_col = inner.x.saturating_add(18).min(inner.x + inner.width);
    let rows_bottom = inner.y.saturating_add(inner.height).saturating_sub(2);
    for (offset, (label, value)) in rows.iter().enumerate() {
        let row_y = rows_top + offset as u16;
        if row_y >= rows_bottom {
            break;
        }
        let label_rect = Rect {
            x: inner.x,
            y: row_y,
            width: inner.width,
            height: 1,
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                *label,
                Style::default().fg(crate::render::theme::foreground()),
            ))),
            label_rect,
        );
        if value_col < inner.x.saturating_add(inner.width) {
            let value_rect = Rect {
                x: value_col,
                y: row_y,
                width: inner
                    .x
                    .saturating_add(inner.width)
                    .saturating_sub(value_col),
                height: 1,
            };
            frame.render_widget(
                Paragraph::new(Line::from(Span::styled(
                    value.clone(),
                    Style::default().fg(crate::render::theme::secondary()),
                ))),
                value_rect,
            );
        }
    }

    // The `[restore]` affordance row (the mouse twin of `r`), painted just above
    // the footer when there is a checkpoint to restore.
    let restore_y = inner.y.saturating_add(inner.height).saturating_sub(2);
    if has_saved && restore_y >= rows_top {
        let restore_rect = Rect {
            x: inner.x,
            y: restore_y,
            width: inner.width,
            height: 1,
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                "[restore]",
                Style::default()
                    .fg(crate::render::theme::accent())
                    .add_modifier(Modifier::BOLD),
            ))),
            restore_rect,
        );
        // Register the click target over the `[restore]` glyph (9 cells wide).
        let target_rect = Rect {
            x: inner.x,
            y: restore_y,
            width: 9u16.min(inner.width),
            height: 1,
        };
        app.register_click(
            target_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::CheckpointRestore),
            interaction::Action::CheckpointRestore,
        );
    }

    // Footer: the in-overlay verb legend on the last inner row.
    let footer_y = inner.y.saturating_add(inner.height).saturating_sub(1);
    if footer_y >= rows_top {
        let footer_rect = Rect {
            x: inner.x,
            y: footer_y,
            width: inner.width,
            height: 1,
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                "r restore \u{00b7} x forget \u{00b7} Esc close",
                Style::default()
                    .fg(crate::render::theme::secondary())
                    .add_modifier(Modifier::BOLD),
            ))),
            footer_rect,
        );
    }
}

/// Paint one R/G/B channel bar (§12.7.2): a single-letter label, a proportional
/// filled track in the channel's own hue, and the numeric value. The focused
/// channel's label is bolded so the keyboard +/- target is obvious.
fn render_theme_editor_bar(
    frame: &mut Frame<'_>,
    area: Rect,
    channel: theme_editor::Channel,
    value: u8,
    is_focused: bool,
) {
    if area.width <= THEME_EDITOR_BAR_LABEL_WIDTH {
        return;
    }
    let channel_color = match channel {
        theme_editor::Channel::Red => Color::Rgb(value, 40, 40),
        theme_editor::Channel::Green => Color::Rgb(40, value, 40),
        theme_editor::Channel::Blue => Color::Rgb(40, 40, value),
    };
    let label_style = if is_focused {
        Style::default()
            .fg(crate::render::theme::accent())
            .add_modifier(Modifier::BOLD)
    } else {
        Style::default().fg(crate::render::theme::quiet())
    };
    // Reserve 4 trailing cells for " 255" so the value never overflows the row.
    let track_w = area
        .width
        .saturating_sub(THEME_EDITOR_BAR_LABEL_WIDTH)
        .saturating_sub(4);
    let filled = if track_w == 0 {
        0
    } else {
        ((value as u32 * track_w as u32) / 255) as u16
    };
    let mut spans = vec![Span::styled(format!("{} ", channel.label()), label_style)];
    if track_w > 0 {
        spans.push(Span::styled(
            "\u{2588}".repeat(filled as usize),
            Style::default().fg(channel_color),
        ));
        spans.push(Span::styled(
            "\u{2591}".repeat(track_w.saturating_sub(filled) as usize),
            Style::default().fg(crate::render::theme::quiet()),
        ));
    }
    spans.push(Span::styled(
        format!(" {value:>3}"),
        Style::default().fg(crate::render::theme::foreground()),
    ));
    frame.render_widget(Paragraph::new(Line::from(spans)), area);
}

/// Paint the Per-Terminal Profiles overlay (§12.7.3) as a centered modal: a verb
/// legend, a read-only line describing the detected terminal + capabilities, then
/// one selectable row per editable profile field (glyph set, mouse mode, color
/// depth) showing the field label, its current value, and a one-line description.
/// The focused row is marked; each row registers a
/// [`interaction::ChromeKey::TerminalProfileField`] click target so a click reaches
/// the same focus+cycle path as ↑↓ + ←→/Space.
fn render_terminal_profile_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    editor: &terminal_profile::TerminalProfileEditor,
) {
    let title = Line::from(vec![
        Span::styled(
            " Terminal profile ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} adapt UX policy to this terminal ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 16, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header: the in-overlay verb legend.
    let header = Line::from(Span::styled(
        "\u{2191}\u{2193} field \u{00b7} \u{2190}\u{2192}/Space cycle \u{00b7} Enter save \u{00b7} r reset \u{00b7} Esc close",
        Style::default()
            .fg(crate::render::theme::secondary())
            .add_modifier(Modifier::BOLD),
    ));
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    // Read-only detected-terminal context line: the bounded terminal kind plus the
    // probed capability hints (truecolor / SSH / multiplexer). Detection is
    // probabilistic, so the line makes the basis for the defaults visible and the
    // override honest.
    let caps = editor.capabilities();
    let mut hints: Vec<&str> = Vec::new();
    if caps.truecolor_env {
        hints.push("truecolor");
    }
    if caps.no_color {
        hints.push("no-color");
    }
    if caps.over_ssh {
        hints.push("ssh");
    }
    if caps.inside_multiplexer {
        hints.push("mux");
    }
    let hint_str = if hints.is_empty() {
        String::new()
    } else {
        format!("  [{}]", hints.join(" "))
    };
    let context_y = inner.y.saturating_add(1);
    if context_y < inner.y.saturating_add(inner.height) {
        frame.render_widget(
            Paragraph::new(Line::from(vec![
                Span::styled(
                    "detected: ",
                    Style::default().fg(crate::render::theme::quiet()),
                ),
                Span::styled(
                    caps.kind.as_str(),
                    Style::default()
                        .fg(crate::render::theme::foreground())
                        .add_modifier(Modifier::BOLD),
                ),
                Span::styled(hint_str, Style::default().fg(crate::render::theme::quiet())),
            ])),
            Rect {
                x: inner.x,
                y: context_y,
                width: inner.width,
                height: 1,
            },
        );
    }

    let working = editor.working();
    let focused = editor.field_index();
    let body_top = inner.y.saturating_add(3);
    let bottom = inner.y.saturating_add(inner.height);
    for (index, field) in terminal_profile::ProfileField::ALL.iter().enumerate() {
        let y = body_top.saturating_add(index as u16);
        if y >= bottom {
            break;
        }
        let is_focused = index == focused;
        let row_rect = Rect {
            x: inner.x,
            y,
            width: inner.width,
            height: 1,
        };
        let marker = if is_focused { "\u{203a} " } else { "  " };
        let value_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(
                format!("{:<12}", field.label()),
                Style::default().fg(crate::render::theme::foreground()),
            ),
            Span::styled(format!("{:<11}", field.value_label(working)), value_style),
            Span::styled(
                field.description(),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::TerminalProfileField(index)),
            interaction::Action::TerminalProfileCycleField(index),
        );
    }

    // Footer: whether a manual override is in effect (vs the built-in default). When
    // overridden, name the focused field's built-in default value so the user can
    // see what `r` (reset) will restore.
    let footer_y = body_top.saturating_add(terminal_profile::ProfileField::ALL.len() as u16 + 1);
    if footer_y < bottom {
        let (text, color) = if editor.is_overridden() {
            let default_value = editor.focused_field().value_label(editor.default_profile());
            (
                format!(
                    "manual override \u{00b7} default {default_value} \u{00b7} Enter save \u{00b7} r reset"
                ),
                crate::render::theme::secondary(),
            )
        } else {
            (
                "showing built-in defaults for this terminal".to_string(),
                crate::render::theme::quiet(),
            )
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(text, Style::default().fg(color)))),
            Rect {
                x: inner.x,
                y: footer_y,
                width: inner.width,
                height: 1,
            },
        );
    }
}

/// Paint the Gesture Settings overlay (§12.7.5) as a centered modal: a verb-legend
/// header, a read-only context line naming the recognizer's double-click window
/// (single-sourced from [`interaction`]), then one row per editable gesture field
/// (label, value, description). The focused row is marked; each row is registered
/// as an [`interaction::ChromeKey::GestureSettingsField`] click target so a click
/// reaches the same focus+step path as ↑↓ + →/+/Space. A footer shows whether a
/// manual override is in effect. Reads only the already-built editor model, so
/// painting is constant-time.
fn render_gesture_settings_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    editor: &gesture_settings::GestureSettingsEditor,
) {
    let title = Line::from(vec![
        Span::styled(
            " Gesture settings ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} tune mouse / trackpad behaviour ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 74, 18, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header: the in-overlay verb legend.
    let header = Line::from(Span::styled(
        "\u{2191}\u{2193} field \u{00b7} \u{2190}\u{2192}/Space/+\u{2212} adjust \u{00b7} Enter save \u{00b7} r reset \u{00b7} Esc close",
        Style::default()
            .fg(crate::render::theme::secondary())
            .add_modifier(Modifier::BOLD),
    ));
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    // Read-only context line: the recognizer's double-click window, single-sourced
    // from `interaction::MULTI_CLICK_MS`, so the user can see the timing their
    // chosen double-click action fires within.
    let context_y = inner.y.saturating_add(1);
    if context_y < inner.y.saturating_add(inner.height) {
        frame.render_widget(
            Paragraph::new(Line::from(vec![
                Span::styled(
                    "double-click window: ",
                    Style::default().fg(crate::render::theme::quiet()),
                ),
                Span::styled(
                    format!(
                        "{} ms",
                        gesture_settings::GestureSettings::multi_click_window_ms()
                    ),
                    Style::default()
                        .fg(crate::render::theme::foreground())
                        .add_modifier(Modifier::BOLD),
                ),
            ])),
            Rect {
                x: inner.x,
                y: context_y,
                width: inner.width,
                height: 1,
            },
        );
    }

    let working = editor.working();
    let focused = editor.field_index();
    let body_top = inner.y.saturating_add(3);
    let bottom = inner.y.saturating_add(inner.height);
    for (index, field) in gesture_settings::GestureField::ALL.iter().enumerate() {
        let y = body_top.saturating_add(index as u16);
        if y >= bottom {
            break;
        }
        let is_focused = index == focused;
        let row_rect = Rect {
            x: inner.x,
            y,
            width: inner.width,
            height: 1,
        };
        let marker = if is_focused { "\u{203a} " } else { "  " };
        let value_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(
                format!("{:<16}", field.label()),
                Style::default().fg(crate::render::theme::foreground()),
            ),
            Span::styled(format!("{:<14}", field.value_label(working)), value_style),
            Span::styled(
                field.description(),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::GestureSettingsField(index)),
            interaction::Action::GestureSettingsStepField(index),
        );
    }

    // Footer: whether a manual override is in effect (vs the built-in default).
    let footer_y = body_top.saturating_add(gesture_settings::GestureField::ALL.len() as u16 + 1);
    if footer_y < bottom {
        let (text, color) = if editor.is_overridden() {
            // Name the focused field's built-in default so the user can see what
            // `r` (reset) will restore for the row they are on.
            let default_value = editor
                .focused_field()
                .value_label(editor.default_settings());
            (
                format!(
                    "manual override \u{00b7} default {default_value} \u{00b7} Enter save \u{00b7} r reset"
                ),
                crate::render::theme::secondary(),
            )
        } else {
            (
                "showing built-in gesture defaults".to_string(),
                crate::render::theme::quiet(),
            )
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(text, Style::default().fg(color)))),
            Rect {
                x: inner.x,
                y: footer_y,
                width: inner.width,
                height: 1,
            },
        );
    }
}

/// Paint the Minimal Glyph Mode overlay (§12.7.6) as a centered modal: a header
/// with the in-overlay verb legend, one selectable row per [`glyph_mode::GlyphMode`]
/// (showing its label, slug, and description), and a live preview strip of the
/// chrome token glyphs the focused/working mode resolves to. Each mode row is
/// registered as an [`interaction::ChromeKey::GlyphModeRow`] click target so a
/// click reaches the same select path as ↑↓. Reads only the editor's working mode,
/// so painting is constant-time and does no transcript walk.
fn render_glyph_mode_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    editor: &glyph_mode::GlyphModeEditor,
) {
    let title = Line::from(vec![
        Span::styled(
            " Glyph mode ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} ASCII-safe chrome for limited terminals ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 14, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Header: the in-overlay verb legend.
    let header = Line::from(Span::styled(
        "\u{2191}\u{2193} mode \u{00b7} \u{2190}\u{2192}/Space cycle \u{00b7} Enter save \u{00b7} r reset \u{00b7} Esc close",
        Style::default()
            .fg(crate::render::theme::secondary())
            .add_modifier(Modifier::BOLD),
    ));
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    let working = editor.working();
    let cursor = editor.cursor();
    let bottom = inner.y.saturating_add(inner.height);
    let body_top = inner.y.saturating_add(2);
    for (index, mode) in glyph_mode::GlyphMode::ALL.iter().enumerate() {
        let y = body_top.saturating_add(index as u16);
        if y >= bottom {
            break;
        }
        let is_focused = index == cursor;
        let is_active = *mode == working;
        let row_rect = Rect {
            x: inner.x,
            y,
            width: inner.width,
            height: 1,
        };
        let marker = if is_focused { "\u{203a} " } else { "  " };
        let label_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{:<10}", mode.label()), label_style),
            Span::styled(
                if is_active { "[active] " } else { "         " },
                Style::default().fg(crate::render::theme::secondary()),
            ),
            Span::styled(
                mode.description(),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::GlyphModeRow(index)),
            interaction::Action::GlyphModeSelect(index),
        );
    }

    // Live preview strip: the chrome token glyphs the working mode resolves to, so
    // the user can see the swap before committing.
    let preview_y = body_top.saturating_add(glyph_mode::GlyphMode::ALL.len() as u16 + 1);
    if preview_y < bottom {
        let tokens = working.tokens();
        let preview: String = tokens
            .labelled()
            .iter()
            .map(|(_, glyph)| *glyph)
            .collect::<Vec<_>>()
            .join(" ");
        frame.render_widget(
            Paragraph::new(Line::from(vec![
                Span::styled(
                    "preview: ",
                    Style::default().fg(crate::render::theme::quiet()),
                ),
                Span::styled(
                    preview,
                    Style::default().fg(crate::render::theme::foreground()),
                ),
            ])),
            Rect {
                x: inner.x,
                y: preview_y,
                width: inner.width,
                height: 1,
            },
        );
    }

    // Footer: whether the working mode differs from the one the overlay opened
    // with (an unsaved change), so the user knows Enter has something to save.
    let footer_y = preview_y.saturating_add(2);
    if footer_y < bottom {
        let (text, color) = if editor.is_changed() {
            (
                format!(
                    "unsaved \u{00b7} was {} \u{00b7} Enter save \u{00b7} r reset",
                    editor.opened_with().label()
                ),
                crate::render::theme::secondary(),
            )
        } else {
            (
                "only Squeezy chrome changes; transcript content is untouched".to_string(),
                crate::render::theme::quiet(),
            )
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(text, Style::default().fg(color)))),
            Rect {
                x: inner.x,
                y: footer_y,
                width: inner.width,
                height: 1,
            },
        );
    }
}

/// Paint the Smart Split Panes inspector (§12.4.2) as a centered modal: a header
/// with the in-overlay verb legend, one selectable field row per control (pane
/// kind / orientation / split ratio), and a live preview of the placement the
/// §12.4.2 solver would choose for the current terminal — including the "single
/// column" graceful-fallback state on a too-narrow terminal. Registers each field
/// row's click target and stamps the previewed `(main, pane)` rects into the
/// frame-local registry so the wheel/click hit-test can route a pointer to the
/// previewed pane.
fn render_smart_split_surface(
    frame: &mut Frame<'_>,
    area: Rect,
    app: &TuiApp,
    state: smart_split::SmartSplitState,
) {
    let title = Line::from(vec![
        Span::styled(
            " Smart split ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} adaptive pane layout ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 16, title);
    if inner.width == 0 || inner.height == 0 {
        app.smart_split_rect_cache.set(None);
        return;
    }

    // The placement the solver picks for the live terminal — what the preview
    // diagram and the footer describe.
    let content = smart_split_preview_content(app);
    let placement = state.solve(content);

    // Header: the in-overlay verb legend.
    let header = Line::from(Span::styled(
        "\u{2191}\u{2193} field \u{00b7} \u{2190}\u{2192}/Space adjust \u{00b7} r reset \u{00b7} Esc close",
        Style::default()
            .fg(crate::render::theme::secondary())
            .add_modifier(Modifier::BOLD),
    ));
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    // The three control rows: pane kind, orientation, split ratio. Each is a
    // clickable field; the focused row gets a caret + emphasis, and ←→/Space (or a
    // click on the focused row) adjusts its value.
    let cursor = state.cursor();
    let bottom = inner.y.saturating_add(inner.height);
    let body_top = inner.y.saturating_add(2);
    for (index, field) in smart_split::SplitField::ALL.iter().enumerate() {
        let y = body_top.saturating_add(index as u16);
        if y >= bottom {
            break;
        }
        let is_focused = index == cursor;
        let row_rect = Rect {
            x: inner.x,
            y,
            width: inner.width,
            height: 1,
        };
        let caret = if is_focused { "\u{203a} " } else { "  " };
        let value = match field {
            smart_split::SplitField::Kind => state.kind().label().to_string(),
            smart_split::SplitField::Orientation => state.orientation().label().to_string(),
            smart_split::SplitField::Ratio => {
                let steps = state.ratio().steps();
                match steps.cmp(&0) {
                    std::cmp::Ordering::Equal => "balanced".to_string(),
                    std::cmp::Ordering::Greater => format!("pane +{steps}"),
                    std::cmp::Ordering::Less => format!("pane {steps}"),
                }
            }
        };
        let value_style = if is_focused {
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                caret,
                Style::default().fg(if is_focused {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(
                format!("{:<13}", field.label()),
                Style::default().fg(crate::render::theme::quiet()),
            ),
            Span::styled(format!("{value:<14}"), value_style),
            Span::styled(
                match field {
                    smart_split::SplitField::Kind => state.kind().description(),
                    smart_split::SplitField::Orientation => "Auto picks from terminal aspect ratio",
                    smart_split::SplitField::Ratio => "\u{2190}\u{2192} resize the pane",
                },
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::SmartSplitField(index)),
            interaction::Action::SmartSplitAdjustField(index),
        );
    }

    // Preview line: the placement the solver chose for the live terminal, in plain
    // words, so the user sees the decision (and the graceful single-column fallback
    // when too narrow) before any real split is drawn.
    let preview_y = body_top.saturating_add(smart_split::SplitField::ALL.len() as u16 + 1);
    if preview_y < bottom {
        let summary = match placement {
            smart_split::PanePlacement::Side { main, pane, .. } => format!(
                "side-by-side: transcript {}w \u{00b7} {} pane {}w",
                main.width,
                state.kind().label(),
                pane.width,
            ),
            smart_split::PanePlacement::Stacked { main, pane, .. } => format!(
                "stacked: transcript {}h \u{00b7} {} pane {}h",
                main.height,
                state.kind().label(),
                pane.height,
            ),
            smart_split::PanePlacement::SingleColumn { .. } => format!(
                "single column ({}x{} too small to split) \u{2014} pane \u{2192} overlay",
                content.width, content.height,
            ),
        };
        frame.render_widget(
            Paragraph::new(Line::from(vec![
                Span::styled(
                    "layout: ",
                    Style::default().fg(crate::render::theme::quiet()),
                ),
                Span::styled(
                    summary,
                    Style::default()
                        .fg(if placement.is_split() {
                            crate::render::theme::secondary()
                        } else {
                            crate::render::theme::quiet()
                        })
                        .add_modifier(Modifier::BOLD),
                ),
            ])),
            Rect {
                x: inner.x,
                y: preview_y,
                width: inner.width,
                height: 1,
            },
        );
    }

    // A small on-screen DIAGRAM of the placement, in the footer band of the modal.
    // Running the SAME solver against this little box (rather than the live frame)
    // gives a faithful, to-scale picture of where the pane lands — side, stacked, or
    // a single column on a box too small to split. The diagram's real screen rects
    // are stamped into the frame-local registry so the wheel/click hit-test
    // (`rect_contains`) routes a pointer to the previewed pane.
    let diagram_top = preview_y.saturating_add(2);
    let diagram_h = bottom.saturating_sub(diagram_top);
    if diagram_top < bottom && diagram_h >= 3 && inner.width >= 4 {
        let box_rect = Rect {
            x: inner.x,
            y: diagram_top,
            width: inner.width,
            height: diagram_h.min(5),
        };
        // Solve the *same* layout against the diagram box (default thresholds lowered
        // here so even a small diagram can show a split shape; the live decision
        // above already reported the true frame placement).
        let diagram_solver = smart_split::LayoutSolver {
            min_side_width: 12,
            min_stack_height: 4,
        };
        let shape =
            diagram_solver.solve(box_rect, state.kind(), state.orientation(), state.ratio());
        // Draw the main (transcript) region.
        draw_split_region(
            frame,
            shape.main(),
            "transcript",
            crate::render::theme::secondary(),
        );
        // Draw the separator rule, if the diagram split at all.
        if let Some(sep) = shape.separator() {
            let sep_glyph = if sep.width == 1 {
                "\u{2502}"
            } else {
                "\u{2500}"
            };
            for row in sep.y..sep.y.saturating_add(sep.height) {
                for col in sep.x..sep.x.saturating_add(sep.width) {
                    frame.render_widget(
                        Paragraph::new(Line::from(Span::styled(
                            sep_glyph,
                            Style::default().fg(crate::render::theme::quiet()),
                        ))),
                        Rect {
                            x: col,
                            y: row,
                            width: 1,
                            height: 1,
                        },
                    );
                }
            }
        }
        // Draw the pane region (when the diagram split), labelled with the pane kind.
        if let Some(pane) = shape.pane() {
            draw_split_region(
                frame,
                pane,
                state.kind().label(),
                crate::render::theme::accent(),
            );
        }
        // Stamp the diagram's real on-screen rects so the mouse handler can route a
        // pointer to the previewed pane. The inner (border-stripped) rects are what a
        // click should land on, so use `pane_inner` for both.
        app.smart_split_rect_cache.set(shape.pane().map(|pane| {
            (
                smart_split::pane_inner(shape.main()),
                smart_split::pane_inner(pane),
            )
        }));
    } else {
        // No room for the diagram: clear the cache so a stale rect never routes a
        // pointer to a pane that is not painted this frame.
        app.smart_split_rect_cache.set(None);
    }
}

/// Draw one region of the Smart Split preview diagram: a rounded border block with
/// a centered label, used for both the transcript and the pane sub-rects. A no-op
/// for a region too small to hold a border (so a tiny diagram degrades cleanly).
fn draw_split_region(frame: &mut Frame<'_>, rect: Rect, label: &str, color: ratatui::style::Color) {
    if rect.width < 2 || rect.height < 2 {
        return;
    }
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(color));
    let body = block.inner(rect);
    frame.render_widget(block, rect);
    // Center the (truncated) label in the bordered body.
    let inner = smart_split::pane_inner(rect);
    if inner.width > 0 && inner.height > 0 {
        let truncated: String = label.chars().take(inner.width as usize).collect();
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                truncated,
                Style::default().fg(color),
            )))
            .alignment(ratatui::layout::Alignment::Center),
            Rect {
                x: body.x,
                y: body.y + body.height / 2,
                width: body.width,
                height: 1,
            },
        );
    }
}

/// Paint the Local Transcript Index overlay (§12.5.1) as a centered modal: a
/// header with the total entry count, then one selectable row per populated
/// category showing its label and count. The selected row is marked; each row is
/// registered as an [`interaction::ChromeKey::TranscriptIndexRow`] click target so
/// a click reaches the same `transcript_index_jump_to_selected` path as ↑↓+Enter.
/// Reads the already-refreshed index (kept current by `draw_app` while open), so
/// painting is constant-time and does no transcript walk.
fn render_transcript_index_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Transcript index ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} jump by category ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 18, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    let categories = app.transcript_index.non_empty_categories();
    // Header: total + navigation hint, or an empty-state line.
    let header = if categories.is_empty() {
        Line::from(Span::styled(
            "No transcript entries to index yet.",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "{} indexed \u{00b7} \u{2191}\u{2193} category \u{00b7} Enter jump \u{00b7} Esc close",
                count_label_entries(app.transcript_index.total()),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    if categories.is_empty() {
        return;
    }

    // Clamp the cursor to the populated-category count so a category that emptied
    // out (e.g. after a clear) can never leave the cursor past the end.
    let selected = app.transcript_index_selected.min(categories.len() - 1);
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height);
    let rows = list_bottom.saturating_sub(list_top) as usize;

    for (index, &category) in categories.iter().enumerate().take(rows) {
        let is_selected = index == selected;
        let row_rect = Rect {
            x: inner.x,
            y: list_top + index as u16,
            width: inner.width,
            height: 1,
        };
        let marker = if is_selected { "\u{203a} " } else { "  " };
        let label_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let count = app.transcript_index.count(category);
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{:<12}", category.label()), label_style),
            Span::styled(
                format!("{count}"),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        // Register the whole row as a click target keyed by its category-list
        // index so a click selects + jumps to exactly that category.
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::TranscriptIndexRow(index)),
            interaction::Action::TranscriptIndexSelect(index),
        );
    }
}

/// Paint the Related-Entry Links overlay (§12.5.3) as a centered modal listing
/// the entries related to the anchored (focused / latest) transcript entry,
/// ranked strongest-first. Each relation row names the link verb, the related
/// entry, and (debug-honest) its confidence. Each row is registered as an
/// [`interaction::ChromeKey::RelatedLinkRow`] click target so a click reaches the
/// same `related_links_jump_to_selected` path as ↑↓+Enter. Reads the already-
/// refreshed graph (kept current by `draw_app` while open), so painting is
/// constant-time and does no transcript walk.
fn render_related_links_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Related links ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} jump to related entries ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 18, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    // Resolve the anchor entry and its relations. With no anchor (empty
    // transcript) or no relations, paint an honest empty-state line.
    let anchor = app.related_links_anchor;
    let anchor_label = anchor.and_then(|id| jump_mark_entry_label(app, id));
    let relations = anchor
        .map(|id| app.related_links.relations(id))
        .unwrap_or(&[]);

    let header = if anchor.is_none() {
        Line::from(Span::styled(
            "No transcript entry to relate yet.",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else if relations.is_empty() {
        Line::from(Span::styled(
            format!(
                "{} has no related entries.",
                anchor_label.as_deref().unwrap_or("this entry"),
            ),
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "related to {} \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} Esc close",
                anchor_label.as_deref().unwrap_or("this entry"),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    if relations.is_empty() {
        return;
    }

    // Clamp the cursor to the relation count so a graph that shrank (e.g. after a
    // clear) can never leave the cursor past the end.
    let selected = app.related_links_selected.min(relations.len() - 1);
    let list_top = inner.y.saturating_add(2);
    // Reserve the bottom row for the selected relation's provenance (debug-honest
    // "why this link"), so a weak link explains itself rather than just showing
    // its confidence tag.
    let list_bottom = inner.y.saturating_add(inner.height).saturating_sub(1);
    let rows = list_bottom.saturating_sub(list_top) as usize;

    for (index, relation) in relations.iter().enumerate().take(rows) {
        let is_selected = index == selected;
        let row_rect = Rect {
            x: inner.x,
            y: list_top + index as u16,
            width: inner.width,
            height: 1,
        };
        let marker = if is_selected { "\u{203a} " } else { "  " };
        let label_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let target_label = jump_mark_entry_label(app, relation.target)
            .unwrap_or_else(|| format!("#{}", relation.target));
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{:<16}", relation.kind.label()), label_style),
            Span::styled(
                format!("{target_label}  "),
                Style::default().fg(crate::render::theme::foreground()),
            ),
            Span::styled(
                format!("({})", relation.confidence.label()),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        // Register the whole row as a click target keyed by its relation-list
        // index so a click selects + jumps to exactly that related entry.
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::RelatedLinkRow(index)),
            interaction::Action::RelatedLinkSelect(index),
        );
    }

    // Provenance footer for the selected relation: debug-honest "why this link",
    // so a low-confidence heuristic explains itself in plain words.
    if let Some(relation) = relations.get(selected) {
        let footer_rect = Rect {
            x: inner.x,
            y: list_bottom,
            width: inner.width,
            height: 1,
        };
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                format!("why: {}", relation.provenance),
                Style::default().fg(crate::render::theme::quiet()),
            ))),
            footer_rect,
        );
    }
}

/// Paint the Duplicate-Output Folds overlay (§12.5.4) as a centered modal: a
/// header with the fold summary, then one selectable row per detected fold span
/// showing its count, expand state, and a one-line preview of the repeated
/// output. The selected row is marked; each row is registered as an
/// [`interaction::ChromeKey::DuplicateFoldRow`] click target so a click reaches
/// the same `duplicate_fold_activate_selected` path as ↑↓+Enter. Reads the
/// already-refreshed fold model (kept current by `draw_app` while open), so
/// painting is constant-time and does no transcript walk.
fn render_duplicate_folds_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Duplicate folds ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} fold repeated output ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 72, 18, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    let span_count = app.duplicate_folds.span_count();
    // Header: summary + navigation hint, or an empty-state line.
    let header = if span_count == 0 {
        Line::from(Span::styled(
            "No repeated tool outputs to fold yet.",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "{} \u{00b7} \u{2191}\u{2193} fold \u{00b7} Enter jump/expand \u{00b7} Esc close",
                app.duplicate_folds.summary(),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    if span_count == 0 {
        return;
    }

    // Clamp the cursor to the span count so a fold that broke up (e.g. after a
    // clear) can never leave the cursor past the end.
    let selected = app.duplicate_folds_selected.min(span_count - 1);
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height);
    let rows = list_bottom.saturating_sub(list_top) as usize;

    for (index, span) in app.duplicate_folds.spans().iter().enumerate().take(rows) {
        let is_selected = index == selected;
        let row_rect = Rect {
            x: inner.x,
            y: list_top + index as u16,
            width: inner.width,
            height: 1,
        };
        let marker = if is_selected { "\u{203a} " } else { "  " };
        let expanded = app.duplicate_folds.is_expanded(span.lead_id);
        // A folder glyph stand-in: open vs collapsed, ASCII-only to match chrome.
        let state = if expanded { "[-]" } else { "[+]" };
        let label_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(format!("{state} "), label_style),
            Span::styled(
                format!("{:<18}", format!("x{} output", span.count())),
                label_style,
            ),
            Span::styled(
                format!("#{}", span.lead_id),
                Style::default().fg(crate::render::theme::quiet()),
            ),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        // Register the whole row as a click target keyed by its span-list index
        // so a click selects + jumps + toggles exactly that fold.
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::DuplicateFoldRow(index)),
            interaction::Action::DuplicateFoldSelect(index),
        );
    }
}

/// Paint the Error Lenses overlay (§12.5.6) as a centered modal: a header with
/// the per-class summary + navigation hint, then one selectable row per detected
/// lens. Each row shows its severity/class tag, message, and any extracted
/// `file:line` location, and registers an
/// [`interaction::ChromeKey::ErrorLensRow`] click target so a click reaches the
/// same `error_lens_jump_to_selected` path as ↑↓+Enter. Reads the
/// already-refreshed lens model (kept current by `draw_app` while open), so
/// painting is constant-time and does no transcript walk.
fn render_error_lens_surface(frame: &mut Frame<'_>, area: Rect, app: &TuiApp) {
    let title = Line::from(vec![
        Span::styled(
            " Error lenses ",
            Style::default()
                .fg(crate::render::theme::accent())
                .add_modifier(Modifier::BOLD),
        ),
        Span::styled(
            "\u{2014} actionable errors in failed output ",
            Style::default().fg(crate::render::theme::quiet()),
        ),
    ]);
    let inner = modal::surface(frame, area, 88, 20, title);
    if inner.width == 0 || inner.height == 0 {
        return;
    }

    let count = app.error_lenses.len();
    // Header: summary + navigation hint, or an empty-state line.
    let header = if count == 0 {
        Line::from(Span::styled(
            "No actionable errors detected in failed output.",
            Style::default().fg(crate::render::theme::quiet()),
        ))
    } else {
        Line::from(Span::styled(
            format!(
                "{} \u{00b7} \u{2191}\u{2193} select \u{00b7} Enter jump \u{00b7} Esc close",
                app.error_lenses.summary(),
            ),
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD),
        ))
    };
    frame.render_widget(Paragraph::new(header), Rect { height: 1, ..inner });

    if count == 0 {
        return;
    }

    // Clamp the cursor to the lens count so a lens that vanished (e.g. after a
    // clear) can never leave the cursor past the end.
    let selected = app.error_lens_selected.min(count - 1);
    let list_top = inner.y.saturating_add(2);
    let list_bottom = inner.y.saturating_add(inner.height);
    let rows = list_bottom.saturating_sub(list_top) as usize;

    for (index, lens) in app.error_lenses.lenses().iter().enumerate().take(rows) {
        let is_selected = index == selected;
        let row_rect = Rect {
            x: inner.x,
            y: list_top + index as u16,
            width: inner.width,
            height: 1,
        };
        let marker = if is_selected { "\u{203a} " } else { "  " };
        // A red error / yellow warning tag so severity carries color *and* a
        // text label (no color-only meaning), the [class] in brackets, the
        // location (if any), then the trimmed message.
        let severity_color = match lens.severity {
            error_lens::ErrorSeverity::Error => crate::render::theme::red(),
            error_lens::ErrorSeverity::Warning => crate::render::theme::warn(),
        };
        let message_style = if is_selected {
            Style::default()
                .fg(crate::render::theme::secondary())
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(crate::render::theme::foreground())
        };
        let location_text = lens
            .location
            .as_ref()
            .map(|loc| format!("{} ", loc.display()))
            .unwrap_or_default();
        let line = Line::from(vec![
            Span::styled(
                marker,
                Style::default().fg(if is_selected {
                    crate::render::theme::secondary()
                } else {
                    crate::render::theme::quiet()
                }),
            ),
            Span::styled(
                format!("{:<5} ", lens.severity.label()),
                Style::default()
                    .fg(severity_color)
                    .add_modifier(Modifier::BOLD),
            ),
            Span::styled(
                format!("{:<11} ", format!("[{}]", lens.class.label())),
                Style::default().fg(crate::render::theme::quiet()),
            ),
            Span::styled(
                location_text,
                Style::default().fg(crate::render::theme::accent()),
            ),
            Span::styled(lens.message.clone(), message_style),
        ]);
        frame.render_widget(Paragraph::new(line), row_rect);

        // Register the whole row as a click target keyed by its lens-list index
        // so a click selects + jumps to exactly that lens.
        app.register_click(
            row_rect,
            interaction::TargetKey::Chrome(interaction::ChromeKey::ErrorLensRow(index)),
            interaction::Action::ErrorLensSelect(index),
        );
    }
}

